// Definition of an AI Tool model
data class CreatorTool(
    val id: String,
    val name: String,
    val category: String,
    val description: String,
    val icon: ImageVector,
    val isPremium: Boolean = false,
    val params: List<ToolParam> = emptyList()
)

sealed interface ToolParam {
    val label: String
    data class Text(override val label: String, val hint: String, val defaultValue: String = "") : ToolParam
    data class Choices(override val label: String, val options: List<String>, val defaultIndex: Int = 0) : ToolParam
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun CreatorHubApp(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val currentScreen by viewModel.currentScreen.collectAsState()
    val userStats by viewModel.userStats.collectAsState()
    val downloadStatus by viewModel.downloadStatus.collectAsState()
    val pendingPayment by viewModel.pendingPaymentRequest.collectAsState()
    val clipboardManager = LocalClipboardManager.current
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    var showProfileDialog by remember { mutableStateOf(false) }
    var showAdMobSettingsDialog by remember { mutableStateOf(false) }

    val adMobBannerUnitId by viewModel.adMobBannerUnitId.collectAsState()
    val adMobRewardedUnitId by viewModel.adMobRewardedUnitId.collectAsState()

    // User Profile Dialog overlay
    if (showProfileDialog && userStats?.isLoggedIn == true) {
        UserProfileDialog(
            userStats = userStats,
            onDismiss = { showProfileDialog = false },
            onLogout = { viewModel.logout() },
            onOpenAdMobSettings = { 
                showProfileDialog = false
                showAdMobSettingsDialog = true 
            }
        )
    }

    if (showAdMobSettingsDialog) {
        AdMobSettingsDialog(
            viewModel = viewModel,
            onDismiss = { showAdMobSettingsDialog = false }
        )
    }

    // Download Notification alert slider
    LaunchedEffect(downloadStatus) {
        if (downloadStatus != null) {
            delay(4000)
            viewModel.clearDownloadStatus()
        }
    }

    // Rewarded Ad overlay for premium downloads and history
    RewardedAdOverlay(
        viewModel = viewModel,
        adUnitId = adMobRewardedUnitId
    )

    Scaffold(
        containerColor = PureBlack,
        topBar = {
            if (currentScreen != "splash") {
                Column {
                    CreatorTopAppBar(
                        userStats = userStats,
                        onNavigate = { viewModel.navigateTo(it) },
                        currentScreen = currentScreen,
                        onLogout = { viewModel.logout() }
                    )
                    AdMobBannerView(
                        adUnitId = adMobBannerUnitId,
                        modifier = Modifier
                            .fillMaxWidth()
                    )
                }
            }
        },
        bottomBar = {
            if (currentScreen != "splash") {
                CreatorBottomNavBar(
                    currentScreen = currentScreen,
                    userStats = userStats,
                    onNavigate = { viewModel.navigateTo(it) },
                    onProfileClick = { viewModel.navigateTo("profile") }
                )
            }
        },
        modifier = modifier.fillMaxSize()
    ) { innerPadding ->
        Box(
            modifier = Modifier
                .padding(if (currentScreen == "splash") PaddingValues(0.dp) else innerPadding)
                .fillMaxSize()
                .drawBehind {
                    // Draw futuristic deep ambient neon radial glow gradients
                    drawCircle(
                        brush = Brush.radialGradient(
                            colors = listOf(NeonPurpleGlow.copy(alpha = 0.15f), Color.Transparent),
                            center = Offset(0f, 0f),
                            radius = size.width * 0.8f
                        )
                    )
                    drawCircle(
                        brush = Brush.radialGradient(
                            colors = listOf(NeonCyanGlow.copy(alpha = 0.12f), Color.Transparent),
                            center = Offset(size.width, size.height * 0.7f),
                            radius = size.width * 0.9f
                        )
                    )
                }
        ) {
            // Screen router
            AnimatedContent(
                targetState = currentScreen,
                transitionSpec = {
                    fadeIn(animationSpec = spring()) togetherWith fadeOut(animationSpec = spring())
                },
                label = "Screen_Transitions"
            ) { screen ->
                when (screen) {
                    "splash" -> SplashScreenView(viewModel = viewModel)
                    "home" -> HomeScreenView(viewModel = viewModel)
                    "dashboard" -> DashboardScreenView(viewModel = viewModel)
                    "saved" -> SavedScreenView(viewModel = viewModel)
                    "history" -> HistoryScreenView(viewModel = viewModel)
                    "profile" -> ProfileScreenView(viewModel = viewModel)
                    "admin" -> AdminScreenView(viewModel = viewModel)
                    "auth" -> AuthScreenView(viewModel = viewModel)
                    "tools" -> WorkbenchScreenView(viewModel = viewModel)
                    else -> HomeScreenView(viewModel = viewModel)
                }
            }

            // Download Hub Success Alert Banner
            AnimatedVisibility(
                visible = downloadStatus != null,
                enter = slideInVertically(initialOffsetY = { it }) + fadeIn(),
                exit = slideOutVertically(targetOffsetY = { it }) + fadeOut(),
                modifier = Modifier
                    .align(Alignment.BottomCenter)
                    .padding(bottom = 16.dp, start = 24.dp, end = 24.dp)
            ) {
                Card(
                    colors = CardDefaults.cardColors(containerColor = GlassCardBg),
                    shape = RoundedCornerShape(12.dp),
                    border = BorderStroke(1.dp, Brush.horizontalGradient(listOf(NeonCyan, NeonBlue))),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Row(
                        modifier = Modifier
                            .padding(14.dp)
                            .fillMaxWidth(),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            imageVector = Icons.Filled.CloudDownload,
                            contentDescription = "Download Center Notification",
                            tint = NeonCyan,
                            modifier = Modifier.size(24.dp)
                        )
                        Spacer(modifier = Modifier.width(12.dp))
                        Text(
                            text = downloadStatus ?: "",
                            color = Color.White,
                            fontSize = 14.sp,
                            fontWeight = FontWeight.Medium,
                            modifier = Modifier.weight(1f)
                        )
                    }
                }
            }

            // Centralized Secure Checkout Global Dialog (Paisa confirm gate)
            pendingPayment?.let { r ->
                PaymentCheckoutDialog(
                    planName = r.plan,
                    priceString = r.priceString,
                    credits = r.credits,
                    onDismiss = { viewModel.clearPaymentRequest() },
                    onPaymentSuccess = { plan, credits ->
                        viewModel.confirmAndBlockUpgrade(plan, credits)
                        Toast.makeText(context, "🎉 Payment Verified! Upgraded to $plan successfully.", Toast.LENGTH_LONG).show()
                    }
                )
            }
        }
    }
}

// ==========================================
// USER PROFILE DIALOG
// ==========================================
@Composable
fun UserProfileDialog(
    userStats: UserStatsEntity?,
    onDismiss: () -> Unit,
    onLogout: () -> Unit,
    onOpenAdMobSettings: () -> Unit
) {
    if (userStats == null) return
    val context = LocalContext.current
    val clipboardManager = LocalClipboardManager.current

    Dialog(onDismissRequest = onDismiss) {
        Card(
            shape = RoundedCornerShape(24.dp),
            colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0F1A)),
            border = BorderStroke(1.5.dp, Brush.linearGradient(listOf(NeonPurple, NeonCyan))),
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
                .testTag("user_profile_modal")
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(24.dp),
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.End
                ) {
                    IconButton(
                        onClick = onDismiss,
                        modifier = Modifier.size(32.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.Close,
                            contentDescription = "Close Profile",
                            tint = Color.LightGray,
                            modifier = Modifier.size(18.dp)
                        )
                    }
                }

                Box(
                    modifier = Modifier
                        .size(80.dp)
                        .clip(CircleShape)
                        .background(Brush.linearGradient(listOf(NeonPurple, NeonCyan)))
                        .padding(3.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .clip(CircleShape)
                            .background(Color(0xFF07070E)),
                        contentAlignment = Alignment.Center
                    ) {
                        val initial = userStats.email.take(1).uppercase()
                        Text(
                            text = initial,
                            color = NeonCyan,
                            fontSize = 32.sp,
                            fontWeight = FontWeight.Black
                        )
                    }
                }

                Spacer(modifier = Modifier.height(16.dp))

                Text(
                    text = "CLIP AI - PROFILE",
                    fontSize = 18.sp,
                    fontWeight = FontWeight.ExtraBold,
                    letterSpacing = 2.sp,
                    color = Color.White
                )

                Spacer(modifier = Modifier.height(4.dp))

                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    modifier = Modifier
                        .clip(RoundedCornerShape(8.dp))
                        .background(Color(0xFF14142B))
                        .padding(horizontal = 12.dp, vertical = 6.dp)
                        .clickable {
                            clipboardManager.setText(AnnotatedString(userStats.email))
                            Toast.makeText(context, "Email copied!", Toast.LENGTH_SHORT).show()
                        }
                ) {
                    Text(
                        text = userStats.email,
                        color = Color.LightGray,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Medium,
                        maxLines = 1,
                        overflow = TextOverflow.Ellipsis
                    )
                    Spacer(modifier = Modifier.width(6.dp))
                    Icon(
                        imageVector = Icons.Filled.ContentCopy,
                        contentDescription = "Copy Email",
                        tint = NeonCyan,
                        modifier = Modifier.size(13.dp)
                    )
                }

                Spacer(modifier = Modifier.height(20.dp))

                Divider(color = Color.DarkGray.copy(alpha = 0.5f), thickness = 0.5.dp)
                Spacer(modifier = Modifier.height(12.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Column(horizontalAlignment = Alignment.Start) {
                        Text("Active Tier", color = Color.Gray, fontSize = 10.sp)
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier.padding(top = 2.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Filled.VerifiedUser,
                                contentDescription = "Verified Plan",
                                tint = NeonCyan,
                                modifier = Modifier.size(13.dp)
                            )
                            Spacer(modifier = Modifier.width(4.dp))
                            Text(
                                text = userStats.subscriptionPlan,
                                color = Color.White,
                                fontSize = 13.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }

                    Column(horizontalAlignment = Alignment.End) {
                        Text("Login Provider", color = Color.Gray, fontSize = 10.sp)
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier.padding(top = 2.dp)
                        ) {
                            Icon(
                                imageVector = if (userStats.loginProvider.equals("Google", ignoreCase = true)) {
                                    Icons.Filled.AccountBox
                                } else {
                                    Icons.Filled.MailOutline
                                },
                                contentDescription = "Provider",
                                tint = NeonPurple,
                                modifier = Modifier.size(13.dp)
                            )
                            Spacer(modifier = Modifier.width(4.dp))
                            Text(
                                text = userStats.loginProvider,
                                color = Color.White,
                                fontSize = 13.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }
                }

                Spacer(modifier = Modifier.height(16.dp))

                Card(
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(12.dp),
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF14142B)),
                    border = BorderStroke(1.dp, Color.DarkGray.copy(alpha = 0.4f))
                ) {
                    Column(
                        modifier = Modifier.padding(14.dp)
                    ) {
                        Text(
                            text = "CLIP AI RESOURCE STATISTICS",
                            color = NeonPurple,
                            fontWeight = FontWeight.Bold,
                            fontSize = 11.sp,
                            letterSpacing = 1.sp
                        )
                        Spacer(modifier = Modifier.height(10.dp))

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Column {
                                val creditsLeft = userStats.totalCredits - userStats.creditsUsed
                                Text("Remaining Credits", color = Color.Gray, fontSize = 9.sp)
                                Text("$creditsLeft / ${userStats.totalCredits}", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                
                                Spacer(modifier = Modifier.height(8.dp))
                                
                                Text("Image Generations", color = Color.Gray, fontSize = 9.sp)
                                Text("${userStats.imageGenerations} Runs", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                            }

                            Column {
                                Text("Video Creations", color = Color.Gray, fontSize = 9.sp)
                                Text("${userStats.videoGenerations} Runs", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                
                                Spacer(modifier = Modifier.height(8.dp))
                                
                                Text("Audio / Voice Synthesis", color = Color.Gray, fontSize = 9.sp)
                                Text("${userStats.audioGenerations} Runs", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(16.dp))

                Button(
                    onClick = onOpenAdMobSettings,
                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF06B6D4).copy(alpha = 0.2f)),
                    shape = RoundedCornerShape(12.dp),
                    border = BorderStroke(1.dp, Color(0xFF06B6D4)),
                    modifier = Modifier.fillMaxWidth().height(48.dp)
                ) {
                    Icon(
                        imageVector = Icons.Filled.AttachMoney,
                        contentDescription = "Monetization Settings",
                        tint = Color(0xFF06B6D4),
                        modifier = Modifier.size(20.dp)
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                    Text("Monetization Settings", color = Color(0xFF06B6D4), fontSize = 13.sp, fontWeight = FontWeight.Bold)
                }

                Spacer(modifier = Modifier.height(24.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    OutlinedButton(
                        onClick = onDismiss,
                        border = BorderStroke(1.dp, Color.LightGray.copy(alpha = 0.5f)),
                        shape = RoundedCornerShape(10.dp),
                        modifier = Modifier.weight(1f).height(46.dp)
                    ) {
                        Text("Close", color = Color.White, fontSize = 13.sp)
                    }

                    Button(
                        onClick = {
                            onDismiss()
                            onLogout()
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = Color.Red.copy(alpha = 0.85f)),
                        shape = RoundedCornerShape(10.dp),
                        modifier = Modifier.weight(1f).height(46.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.Logout,
                            contentDescription = "Logout",
                            tint = Color.White,
                            modifier = Modifier.size(16.dp)
                        )
                        Spacer(modifier = Modifier.width(6.dp))
                        Text("Logout", color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }
        }
    }
}

// ==========================================
// CUSTOM TOP BAR
// ==========================================
@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun CreatorTopAppBar(
    userStats: UserStatsEntity?,
    onNavigate: (String) -> Unit,
    currentScreen: String,
    onLogout: () -> Unit
) {
    CenterAlignedTopAppBar(
        colors = TopAppBarDefaults.centerAlignedTopAppBarColors(
            containerColor = Color.Transparent,
            titleContentColor = Color.White
        ),
        title = {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier.clickable { onNavigate("home") }
            ) {
                androidx.compose.foundation.Image(
                    painter = androidx.compose.ui.res.painterResource(id = com.example.R.drawable.ic_clip_ai_logo),
                    contentDescription = "Clip AI Logo",
                    modifier = Modifier.size(28.dp)
                )
                Spacer(modifier = Modifier.width(8.dp))
                Text(
                    text = "CLIP AI PRO",
                    fontSize = 18.sp,
                    fontWeight = FontWeight.ExtraBold,
                    letterSpacing = 4.sp,
                    color = Color.White
                )
            }
        },
        navigationIcon = {
            if (userStats?.isLoggedIn == true) {
                IconButton(
                    onClick = { onNavigate("admin") },
                    modifier = Modifier.size(32.dp).testTag("admin_panel_button")
                ) {
                    Icon(
                        imageVector = Icons.Outlined.AdminPanelSettings,
                        contentDescription = "Admin Area",
                        tint = if (currentScreen == "admin") NeonPurple else Color.LightGray,
                        modifier = Modifier.size(20.dp)
                    )
                }
            }
        },
        actions = {
            // Splash Welcome Screen Replay Toggle Button
            IconButton(
                onClick = { onNavigate("splash") }
            ) {
                Icon(
                    imageVector = Icons.Filled.RocketLaunch,
                    contentDescription = "Show Splash Welcome Screen",
                    tint = NeonCyan,
                    modifier = Modifier.size(22.dp)
                )
            }
            Spacer(modifier = Modifier.width(4.dp))
            if (userStats?.isLoggedIn == true) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    modifier = Modifier
                        .padding(end = 12.dp)
                        .clickable { onNavigate("dashboard") }
                        .border(
                            1.dp,
                            Brush.linearGradient(listOf(NeonPurple, NeonCyan)),
                            RoundedCornerShape(20.dp)
                        )
                        .background(Color(0x33A78BFA), RoundedCornerShape(20.dp))
                        .padding(horizontal = 12.dp, vertical = 4.dp)
                ) {
                    val creditsLeft = userStats.totalCredits - userStats.creditsUsed
                    Icon(
                        imageVector = Icons.Filled.ElectricBolt,
                        contentDescription = "Credits",
                        tint = NeonCyan,
                        modifier = Modifier.size(16.dp)
                    )
                    Spacer(modifier = Modifier.width(4.dp))
                    Text(
                        text = "$creditsLeft Credits",
                        color = Color.White,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
                IconButton(
                    onClick = onLogout,
                    modifier = Modifier.testTag("auth_logout_button")
                ) {
                    Icon(
                        imageVector = Icons.Filled.Logout,
                        contentDescription = "Logout",
                        tint = Color.Red.copy(alpha = 0.85f),
                        modifier = Modifier.size(20.dp)
                    )
                }
            } else {
                TextButton(
                    onClick = { onNavigate("auth") },
                    colors = ButtonDefaults.textButtonColors(contentColor = NeonCyan)
                ) {
                    Text("Login", fontWeight = FontWeight.Bold)
                }
            }
        }
    )
}

// ==========================================
// BOTTOM NAVIGATION BAR
// ==========================================
@Composable
fun CreatorBottomNavBar(
    currentScreen: String,
    userStats: UserStatsEntity?,
    onNavigate: (String) -> Unit,
    onProfileClick: () -> Unit
) {
    NavigationBar(
        containerColor = Color(0x99050510),
        tonalElevation = 8.dp,
        modifier = Modifier
            .border(0.5.dp, Color(0x3360A5FA), RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp))
            .clip(RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp))
    ) {
        NavigationBarItem(
            selected = currentScreen == "home",
            onClick = { onNavigate("home") },
            colors = NavigationBarItemDefaults.colors(
                selectedIconColor = NeonPurple,
                selectedTextColor = NeonPurple,
                unselectedIconColor = Color.Gray,
                unselectedTextColor = Color.Gray,
                indicatorColor = Color(0x22A78BFA)
            ),
            icon = { Icon(imageVector = Icons.Outlined.Home, contentDescription = "Home") },
            label = { Text("Explore", fontSize = 11.sp, fontWeight = FontWeight.Bold) }
        )
        NavigationBarItem(
            selected = currentScreen == "dashboard" || currentScreen == "tools",
            onClick = { onNavigate("dashboard") },
            colors = NavigationBarItemDefaults.colors(
                selectedIconColor = NeonBlue,
                selectedTextColor = NeonBlue,
                unselectedIconColor = Color.Gray,
                unselectedTextColor = Color.Gray,
                indicatorColor = Color(0x223B82F6)
            ),
            icon = { Icon(imageVector = Icons.Outlined.Analytics, contentDescription = "Dashboard") },
            label = { Text("Workspace", fontSize = 11.sp, fontWeight = FontWeight.Bold) }
        )
        NavigationBarItem(
            selected = currentScreen == "saved",
            onClick = { onNavigate("saved") },
            colors = NavigationBarItemDefaults.colors(
                selectedIconColor = NeonCyan,
                selectedTextColor = NeonCyan,
                unselectedIconColor = Color.Gray,
                unselectedTextColor = Color.Gray,
                indicatorColor = Color(0x2206B6D4)
            ),
            icon = { Icon(imageVector = Icons.Outlined.Star, contentDescription = "Saved Projects") },
            label = { Text("Saved", fontSize = 11.sp, fontWeight = FontWeight.Bold) }
        )
        NavigationBarItem(
            selected = currentScreen == "history",
            onClick = { onNavigate("history") },
            colors = NavigationBarItemDefaults.colors(
                selectedIconColor = NeonPurple,
                selectedTextColor = NeonPurple,
                unselectedIconColor = Color.Gray,
                unselectedTextColor = Color.Gray,
                indicatorColor = Color(0x228B5CF6)
            ),
            icon = { Icon(imageVector = Icons.Outlined.History, contentDescription = "AI History") },
            label = { Text("History", fontSize = 11.sp, fontWeight = FontWeight.Bold) }
        )
        NavigationBarItem(
            selected = currentScreen == "profile",
            onClick = onProfileClick,
            colors = NavigationBarItemDefaults.colors(
                selectedIconColor = NeonCyan,
                selectedTextColor = NeonCyan,
                unselectedIconColor = Color.Gray,
                unselectedTextColor = Color.Gray,
                indicatorColor = Color(0x2206B6D4)
            ),
            icon = {
                if (userStats != null && userStats.isLoggedIn) {
                    Box(
                        modifier = Modifier
                            .size(24.dp)
                            .clip(CircleShape)
                            .background(Brush.linearGradient(listOf(NeonPurple, NeonCyan)))
                            .padding(1.5.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .clip(CircleShape)
                                .background(Color(0xFF0F0F1A)),
                            contentAlignment = Alignment.Center
                        ) {
                            val initial = userStats.email.take(1).uppercase()
                            Text(
                                text = initial,
                                color = NeonCyan,
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }
                } else {
                    Icon(
                        imageVector = Icons.Outlined.AccountCircle,
                        contentDescription = "Profile",
                        modifier = Modifier.size(24.dp)
                    )
                }
            },
            label = { Text("Profile", fontSize = 11.sp, fontWeight = FontWeight.Bold) },
            modifier = Modifier.testTag("profile_button")
        )
    }
}

// ==========================================
// PREMIUM GRADIENT NEON BORDER MODIFIER
// ==========================================
fun Modifier.neonBorder(glowColor: Color = NeonPurple): Modifier = this.then(
    Modifier.border(
        width = 1.dp,
        brush = Brush.linearGradient(
            colors = listOf(
                glowColor.copy(alpha = 0.8f),
                glowColor.copy(alpha = 0.2f),
                glowColor.copy(alpha = 0.6f)
            )
        ),
        shape = RoundedCornerShape(16.dp)
    )
)

// ==========================================
// EXPLORE (HOME) SCREEN VIEW
// ==========================================
@Composable
fun HomeScreenView(
    viewModel: CreatorViewModel
) {
    val searchQuery by viewModel.searchQuery.collectAsState()
    val currentCategory by viewModel.currentCategory.collectAsState()
    val userStats by viewModel.userStats.collectAsState()
    val isFreePlan = userStats?.subscriptionPlan == "Free"

    var showUpgradeAlert by remember { mutableStateOf(false) }
    var lockedToolName by remember { mutableStateOf("") }

    val categories = listOf("All", "Text Tools", "Image Tools", "Video Tools", "Audio Tools", "Business Tools")

    // Filter tools based on search and category choice
    val filteredTools = remember(searchQuery, currentCategory) {
        getStaticTools().filter { tool ->
            val matchesCategory = currentCategory == "All" || tool.category == currentCategory
            val matchesSearch = tool.name.contains(searchQuery, ignoreCase = true) ||
                    tool.description.contains(searchQuery, ignoreCase = true)
            matchesCategory && matchesSearch
        }
    }

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 20.dp),
        verticalArrangement = Arrangement.spacedBy(20.dp)
    ) {
        // Hero Section
        item {
            HeroSection(onStartClick = { viewModel.navigateTo("dashboard") })
        }

        // Stats Panel
        item {
            StatsGridSection()
        }

        // Search Bar Area
        item {
            OutlinedTextField(
                value = searchQuery,
                onValueChange = { viewModel.updateSearchQuery(it) },
                placeholder = { Text("Search AI Tools...", color = Color.Gray) },
                leadingIcon = { Icon(imageVector = Icons.Filled.Search, contentDescription = "Search", tint = NeonCyan) },
                trailingIcon = {
                    if (searchQuery.isNotEmpty()) {
                        IconButton(onClick = { viewModel.updateSearchQuery("") }) {
                            Icon(imageVector = Icons.Filled.Close, contentDescription = "Clear", tint = Color.Gray)
                        }
                    }
                },
                singleLine = true,
                colors = OutlinedTextFieldDefaults.colors(
                    focusedTextColor = Color.White,
                    unfocusedTextColor = Color.White,
                    focusedBorderColor = NeonCyan,
                    unfocusedBorderColor = Color(0x3322D3EE),
                    focusedContainerColor = Color(0xFF07070F),
                    unfocusedContainerColor = Color(0xFF07070F)
                ),
                shape = RoundedCornerShape(12.dp),
                modifier = Modifier
                    .fillMaxWidth()
                    .testTag("ai_tool_search_bar")
            )
        }

        // Subcategory Chips
        item {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .horizontalScroll(rememberScrollState()),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                categories.forEach { category ->
                    val isSelected = currentCategory == category
                    val chipBorderColor = if (isSelected) {
                        when (category) {
                            "Text Tools" -> NeonPurple
                            "Image Tools" -> NeonCyan
                            "Video Tools" -> NeonBlue
                            "Audio Tools" -> NeonPurple
                            "Business Tools" -> NeonCyan
                            else -> NeonPurple
                        }
                    } else Color(0x22FFFFFF)

                    val chipBg = if (isSelected) {
                        Brush.linearGradient(listOf(chipBorderColor.copy(alpha = 0.3f), chipBorderColor.copy(alpha = 0.1f)))
                    } else {
                        Brush.linearGradient(listOf(Color(0xFF0F0F1A), Color(0xFF0B0B12)))
                    }

                    Box(
                        modifier = Modifier
                            .clip(RoundedCornerShape(20.dp))
                            .background(chipBg)
                            .border(1.dp, chipBorderColor, RoundedCornerShape(20.dp))
                            .clickable { viewModel.selectCategory(category) }
                            .padding(horizontal = 16.dp, vertical = 8.dp)
                    ) {
                        Text(
                            text = category,
                            color = if (isSelected) Color.White else Color.Gray,
                            fontWeight = if (isSelected) FontWeight.ExtraBold else FontWeight.Bold,
                            fontSize = 12.sp
                        )
                    }
                }
            }
        }

        // Grid Title
        item {
            Text(
                text = if (searchQuery.isNotEmpty()) "Search Results (${filteredTools.size})" else "$currentCategory Library",
                color = Color.White,
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold,
                modifier = Modifier.padding(top = 10.dp)
            )
        }

        // Tool Display Box List
        if (filteredTools.isEmpty()) {
            item {
                Box(
                    contentAlignment = Alignment.Center,
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 40.dp)
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            imageVector = Icons.Filled.Info,
                            contentDescription = "No tools found",
                            tint = Color.Gray,
                            modifier = Modifier.size(54.dp)
                        )
                        Spacer(modifier = Modifier.height(12.dp))
                        Text(
                            text = "No tools match your search criteria.",
                            color = Color.LightGray,
                            fontSize = 14.sp
                        )
                    }
                }
            }
        } else {
            // Displaying tool cards in staggered items, wrapping in chunks since we are inside LazyColumn
            val rows = filteredTools.chunked(2)
            items(rows) { rowItems ->
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(14.dp)
                ) {
                    rowItems.forEach { tool ->
                        ToolGridItem(
                            tool = tool,
                            modifier = Modifier.weight(1f),
                            onClick = {
                                viewModel.selectTool(tool.name)
                                viewModel.navigateTo("tools")
                            }
                        )
                    }
                    if (rowItems.size < 2) {
                        Spacer(modifier = Modifier.weight(1f))
                    }
                }
            }
        }

        // Clip AI Overview & Promotional App Banner Card at the bottom of the library
        item {
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(vertical = 12.dp)
                    .border(
                        width = 1.dp,
                        brush = Brush.linearGradient(listOf(NeonCyan, NeonPurple)),
                        shape = RoundedCornerShape(16.dp)
                    ),
                shape = RoundedCornerShape(16.dp),
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E18))
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp)
                ) {
                    Text(
                        text = "ℹ️ APP SHOWCASE & INFO",
                        fontWeight = FontWeight.Bold,
                        fontSize = 13.sp,
                        color = NeonCyan,
                        letterSpacing = 1.2.sp
                    )

                    Spacer(modifier = Modifier.height(12.dp))

                    Image(
                        painter = painterResource(id = com.example.R.drawable.img_app_thumbnail),
                        contentDescription = "Clip AI Features Detail Showcase",
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(160.dp)
                            .clip(RoundedCornerShape(12.dp)),
                        contentScale = ContentScale.Crop
                    )

                    Spacer(modifier = Modifier.height(14.dp))

                    Text(
                        text = "🚀 What is Clip AI?",
                        fontWeight = FontWeight.Bold,
                        fontSize = 14.sp,
                        color = Color.White
                    )

                    Spacer(modifier = Modifier.height(6.dp))

                    Text(
                        text = "Clip AI is an extremely easy all-in-one AI application. Here, you can make full use of AI without any coding or technical knowledge.",
                        fontSize = 11.sp,
                        color = Color.LightGray.copy(alpha = 0.85f),
                        lineHeight = 16.sp
                    )

                    Spacer(modifier = Modifier.height(10.dp))

                    Text(
                        text = "🔑 What can you do?",
                        fontWeight = FontWeight.Bold,
                        fontSize = 11.5.sp,
                        color = NeonPurple
                    )

                    Spacer(modifier = Modifier.height(8.dp))

                    val featuresListMapped = listOf(
                        "💬 AI Chat - Spark engaging chats on any interest",
                        "🎨 Magic Images - Generate beautiful artwork from text inputs",
                        "🎬 Easy Video - Render cinematic short clips from text",
                        "🎙️ Amazing Voice - Synthesize and clone synthetic vocoders"
                    )

                    featuresListMapped.forEach { feature ->
                        Row(
                            verticalAlignment = Alignment.Top,
                            modifier = Modifier.padding(bottom = 5.dp)
                        ) {
                            Text("⚡ ", color = NeonCyan, fontSize = 11.sp)
                            Text(feature, color = Color.LightGray, fontSize = 10.5.sp, lineHeight = 14.sp)
                        }
                    }
                }
            }
        }

        // Spacer at the bottom
        item {
            Spacer(modifier = Modifier.height(40.dp))
        }
    }

    if (showUpgradeAlert) {
        AlertDialog(
            onDismissRequest = { showUpgradeAlert = false },
            title = {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(imageVector = Icons.Filled.Lock, contentDescription = null, tint = NeonPurple)
                    Text("Premium Feature Locked", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 18.sp)
                }
            },
            text = {
                Text(
                    text = "The tool '$lockedToolName' is a premium feature. Please upgrade your subscription plan to Pro or Agency in your Workspace Dashboard to unlock all 24 professional premium AI tools!",
                    color = Color.LightGray,
                    fontSize = 14.sp
                )
            },
            confirmButton = {
                Button(
                    onClick = {
                        showUpgradeAlert = false
                        viewModel.navigateTo("dashboard")
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple)
                ) {
                    Text("Upgrade Plan", color = Color.White, fontWeight = FontWeight.Bold)
                }
            },
            dismissButton = {
                TextButton(onClick = { showUpgradeAlert = false }) {
                    Text("Dismiss", color = Color.Gray, fontWeight = FontWeight.SemiBold)
                }
            },
            containerColor = Color(0xFF0F0F1A),
            shape = RoundedCornerShape(16.dp),
            modifier = Modifier.border(1.dp, NeonPurple.copy(alpha = 0.5f), RoundedCornerShape(16.dp))
        )
    }
}

