}

// Beautiful glassmorphic library card
@Composable
fun ToolGridItem(
    tool: CreatorTool,
    onClick: () -> Unit,
    modifier: Modifier = Modifier
) {
    val outlineBrush = when (tool.category) {
        "Text Tools" -> Brush.sweepGradient(listOf(NeonPurple, Color(0xFF331F5C)))
        "Image Tools" -> Brush.sweepGradient(listOf(NeonCyan, Color(0xFF154C54)))
        "Video Tools" -> Brush.sweepGradient(listOf(NeonBlue, Color(0xFF1D325E)))
        "Audio Tools" -> Brush.sweepGradient(listOf(NeonPurple, Color(0xFF331F5C)))
        "Business Tools" -> Brush.sweepGradient(listOf(NeonCyan, Color(0xFF154C54)))
        else -> Brush.sweepGradient(listOf(NeonPurple, NeonCyan))
    }

    val iconColor = when (tool.category) {
        "Text Tools" -> NeonPurple
        "Image Tools" -> NeonCyan
        "Video Tools" -> NeonBlue
        "Audio Tools" -> NeonPurple
        "Business Tools" -> NeonCyan
        else -> NeonPurple
    }

    Card(
        onClick = onClick,
        colors = CardDefaults.cardColors(containerColor = GlassCardBg),
        shape = RoundedCornerShape(16.dp),
        border = BorderStroke(1.dp, outlineBrush),
        modifier = modifier
            .height(160.dp)
            .testTag("tool_card_${tool.name.replace(" ", "_").lowercase()}")
    ) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(14.dp),
            verticalArrangement = Arrangement.SpaceBetween
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.Top
            ) {
                Box(
                    modifier = Modifier
                        .background(iconColor.copy(alpha = 0.15f), RoundedCornerShape(10.dp))
                        .padding(8.dp)
                ) {
                    Icon(
                        imageVector = tool.icon,
                        contentDescription = tool.name,
                        tint = iconColor,
                        modifier = Modifier.size(24.dp)
                    )
                }

                if (tool.isPremium) {
                    Box(
                        modifier = Modifier
                            .background(
                                Brush.horizontalGradient(listOf(NeonPurpleGlow, NeonBlueGlow)),
                                RoundedCornerShape(6.dp)
                            )
                            .padding(horizontal = 6.dp, vertical = 2.dp)
                    ) {
                        Text(
                            text = "PRO (10 CR)",
                            color = Color.White,
                            fontSize = 8.sp,
                            fontWeight = FontWeight.Black
                        )
                    }
                } else {
                    Box(
                        modifier = Modifier
                            .background(Color(0x338B5CF6), RoundedCornerShape(6.dp))
                            .padding(horizontal = 6.dp, vertical = 2.dp)
                    ) {
                        Text(
                            text = "FREE",
                            color = NeonPurple,
                            fontSize = 8.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }

            Column {
                Text(
                    text = tool.name,
                    color = Color.White,
                    fontSize = 14.sp,
                    fontWeight = FontWeight.ExtraBold,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis
                )
                Spacer(modifier = Modifier.height(4.dp))
                Text(
                    text = tool.description,
                    color = Color.Gray,
                    fontSize = 11.sp,
                    lineHeight = 14.sp,
                    maxLines = 2,
                    overflow = TextOverflow.Ellipsis
                )
            }
        }
    }
}

// ==========================================
// WORKSPACE / STATS / SUBSCRIPTION DASHBOARD
// ==========================================
@Composable
fun DashboardScreenView(
    viewModel: CreatorViewModel
) {
    val userStats by viewModel.userStats.collectAsState()
    val scope = rememberCoroutineScope()

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 20.dp),
        verticalArrangement = Arrangement.spacedBy(20.dp)
    ) {
        item {
            Text(
                text = "Workspace Dashboard",
                color = Color.White,
                fontSize = 24.sp,
                fontWeight = FontWeight.Black,
                modifier = Modifier.padding(top = 16.dp)
            )
        }

        userStats?.let { stats ->
            // Credit Balance Panel
            item {
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0A0A16)),
                    border = BorderStroke(1.dp, Brush.horizontalGradient(listOf(NeonCyan, NeonBlue))),
                    shape = RoundedCornerShape(16.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(20.dp)) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text("CREDIT ALLOCATION", color = Color.Gray, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(4.dp))
                                val used = stats.creditsUsed
                                val total = stats.totalCredits
                                Text("$used / $total Credits Used", color = Color.White, fontSize = 20.sp, fontWeight = FontWeight.Black)
                            }
                            Box(
                                modifier = Modifier
                                    .background(NeonCyan.copy(alpha = 0.1f), RoundedCornerShape(12.dp))
                                    .padding(8.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Filled.ElectricBolt,
                                    contentDescription = "Credits",
                                    tint = NeonCyan,
                                    modifier = Modifier.size(28.dp)
                                )
                            }
                        }

                        Spacer(modifier = Modifier.height(18.dp))

                        // Linear progress with glow style
                        val progressFraction = if (stats.totalCredits > 0) {
                            stats.creditsUsed.toFloat() / stats.totalCredits.toFloat()
                        } else 0f
                        LinearProgressIndicator(
                            progress = { progressFraction.coerceIn(0f, 1f) },
                            color = NeonCyan,
                            trackColor = Color(0xFF1E1E2E),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(8.dp)
                                .clip(RoundedCornerShape(4.dp))
                        )

                        Spacer(modifier = Modifier.height(16.dp))

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Text(
                                text = "Plan Tier: ${stats.subscriptionPlan}",
                                color = NeonPurple,
                                fontSize = 13.sp,
                                fontWeight = FontWeight.Bold
                            )

                            Text(
                                text = "Reset Usage",
                                color = NeonCyan,
                                fontSize = 13.sp,
                                fontWeight = FontWeight.Bold,
                                modifier = Modifier.clickable { viewModel.simulateCreditReset() }
                            )
                        }
                    }
                }
            }

            // Staggered Usage Statistics
            item {
                Text("Creation Analytics", color = Color.White, fontSize = 16.sp, fontWeight = FontWeight.Bold)
            }

            item {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    StatMetricCard(
                        title = "Text",
                        count = stats.textGenerations,
                        color = NeonPurple,
                        icon = Icons.Outlined.TextSnippet,
                        modifier = Modifier.weight(1f)
                    )
                    StatMetricCard(
                        title = "Image",
                        count = stats.imageGenerations,
                        color = NeonCyan,
                        icon = Icons.Outlined.Brush,
                        modifier = Modifier.weight(1f)
                    )
                }
            }

            item {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    StatMetricCard(
                        title = "Video",
                        count = stats.videoGenerations,
                        color = NeonBlue,
                        icon = Icons.Outlined.VideoCameraBack,
                        modifier = Modifier.weight(1f)
                    )
                    StatMetricCard(
                        title = "Business",
                        count = stats.businessGenerations,
                        color = NeonCyan,
                        icon = Icons.Outlined.PhoneAndroid,
                        modifier = Modifier.weight(1f)
                    )
                }
            }

            // Subscription Upgrade Section
            item {
                Text("Subscription Plans", color = Color.White, fontSize = 18.sp, fontWeight = FontWeight.Bold, modifier = Modifier.padding(top = 10.dp))
            }

            item {
                PricingTiers(
                    currentPlan = stats.subscriptionPlan,
                    onSelectPlan = { plan, credits ->
                        viewModel.updateSubscription(plan, credits)
                    }
                )
            }
        }

        item {
            Spacer(modifier = Modifier.height(40.dp))
        }
    }
}

@Composable
fun StatMetricCard(
    title: String,
    count: Int,
    color: Color,
    icon: ImageVector,
    modifier: Modifier = Modifier
) {
    Card(
        colors = CardDefaults.cardColors(containerColor = GlassCardBg),
        border = BorderStroke(0.5.dp, color.copy(alpha = 0.5f)),
        shape = RoundedCornerShape(12.dp),
        modifier = modifier.height(100.dp)
    ) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(14.dp),
            verticalArrangement = Arrangement.SpaceBetween
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(title.uppercase(), color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Black)
                Icon(imageVector = icon, contentDescription = title, tint = color, modifier = Modifier.size(20.dp))
            }
            Text(
                text = count.toString(),
                color = Color.White,
                fontSize = 28.sp,
                fontWeight = FontWeight.Black
            )
        }
    }
}

// ==========================================
// SECURE CHECKOUT & PAYMENT DIALOG (Paisa dene ka check)
// ==========================================
@Composable
fun PaymentCheckoutDialog(
    planName: String,
    priceString: String,
    credits: Int,
    onDismiss: () -> Unit,
    onPaymentSuccess: (String, Int) -> Unit
) {
    val coroutineScope = rememberCoroutineScope()
    val context = androidx.compose.ui.platform.LocalContext.current
    val clipboardManager = androidx.compose.ui.platform.LocalClipboardManager.current
    var paymentMethod by remember { mutableStateOf("UPI") } // "UPI" or "CARD"
    
    // Card inputs
    var cardNumber by remember { mutableStateOf("") }
    var cardExpiry by remember { mutableStateOf("") }
    var cardCvv by remember { mutableStateOf("") }
    var cardName by remember { mutableStateOf("") }
    
    // UPI inputs
    val upiId = "9303991466@ptyes"
    var upiRefNo by remember { mutableStateOf("") }
    var isUpiQrVisible by remember { mutableStateOf(true) }

    // Checkout processing states
    var isProcessing by remember { mutableStateOf(false) }
    var currentProcessingStep by remember { mutableStateOf("") }
    var processingProgress by remember { mutableStateOf(0.0f) }
    
    // Payment complete success state
    var isSuccess by remember { mutableStateOf(false) }
    var transactionId by remember { mutableStateOf("") }

    val LocalNeonPurple = Color(0xFFA855F7)
    val LocalNeonCyan = Color(0xFF06B6D4)
    val LocalNeonGreen = Color(0xFF10B981)
    val LocalGold = Color(0xFFF59E0B)

    Dialog(onDismissRequest = { if (!isProcessing) onDismiss() }) {
        Surface(
            modifier = Modifier
                .fillMaxWidth()
                .wrapContentHeight()
                .padding(12.dp),
            shape = RoundedCornerShape(24.dp),
            color = Color(0xFF0B0B16),
            border = BorderStroke(1.5.dp, Brush.horizontalGradient(listOf(LocalNeonPurple, LocalNeonCyan)))
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(20.dp)
                    .verticalScroll(rememberScrollState()),
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                if (!isProcessing && !isSuccess) {
                    // Header
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text("Secure Checkout", color = Color.White, fontSize = 20.sp, fontWeight = FontWeight.Bold)
                            Text("Clip AI Billing Service", color = Color.Gray, fontSize = 11.sp)
                        }
                        IconButton(onClick = onDismiss) {
                            Icon(imageVector = Icons.Default.Close, contentDescription = "Close", tint = Color.Gray)
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    // Plan summary card
                    Card(
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF14142B)),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(14.dp),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Box(
                                    modifier = Modifier
                                        .background(LocalNeonPurple.copy(alpha = 0.2f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 6.dp, vertical = 2.dp)
                                ) {
                                    Text(planName.uppercase(), color = LocalNeonPurple, fontSize = 8.sp, fontWeight = FontWeight.Black)
                                }
                                Spacer(modifier = Modifier.height(4.dp))
                                Text("Upgrade includes $credits Total Credits", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.SemiBold)
                            }
                            Text(
                                text = priceString,
                                color = LocalNeonCyan,
                                fontSize = 18.sp,
                                fontWeight = FontWeight.Black
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    // Payment Method selector (Tab style)
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF1C1C36), RoundedCornerShape(10.dp))
                            .padding(4.dp)
                    ) {
                        Button(
                            onClick = { paymentMethod = "UPI" },
                            colors = ButtonDefaults.buttonColors(
                                containerColor = if (paymentMethod == "UPI") Color(0xFF0F0F1A) else Color.Transparent
                            ),
                            shape = RoundedCornerShape(8.dp),
                            modifier = Modifier.weight(1f)
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = Icons.Default.QrCodeScanner,
                                    contentDescription = null,
                                    tint = if (paymentMethod == "UPI") LocalNeonCyan else Color.Gray,
                                    modifier = Modifier.size(16.dp)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    "UPI (GPay/Paytm)",
                                    color = if (paymentMethod == "UPI") Color.White else Color.Gray,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }

                        Button(
                            onClick = { paymentMethod = "CARD" },
                            colors = ButtonDefaults.buttonColors(
                                containerColor = if (paymentMethod == "CARD") Color(0xFF0F0F1A) else Color.Transparent
                            ),
                            shape = RoundedCornerShape(8.dp),
                            modifier = Modifier.weight(1f)
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Icon(
                                    imageVector = Icons.Default.CreditCard,
                                    contentDescription = null,
                                    tint = if (paymentMethod == "CARD") LocalNeonPurple else Color.Gray,
                                    modifier = Modifier.size(16.dp)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    "Debit/Credit Card",
                                    color = if (paymentMethod == "CARD") Color.White else Color.Gray,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    if (paymentMethod == "UPI") {
                        // UPI Payment Form
                        Column(
                            modifier = Modifier.fillMaxWidth(),
                            verticalArrangement = Arrangement.spacedBy(12.dp)
                        ) {
                            // Professional Step-by-Step Payment Instructions
                            Card(
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF0D0D1E)),
                                border = BorderStroke(0.5.dp, Color(0x3360A5FA)),
                                shape = RoundedCornerShape(12.dp),
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                Column(modifier = Modifier.padding(14.dp)) {
                                    Text(
                                        "Follow steps to activate Pro plan:",
                                        color = Color.White,
                                        fontSize = 12.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                    Spacer(modifier = Modifier.height(8.dp))
                                    listOf(
                                        "1. Copy UPI ID or Scan the QR code below using GPay, PhonePe, Paytm, or any banking app.",
                                        "2. Pay the exact amount ($priceString) to authenticate your purchase.",
                                        "3. After transaction success, copy the 12-digit UTR / Ref No. from the payment app.",
                                        "4. Enter the UTR / Ref No. in the input box below and click Verify to initiate instant activation."
                                    ).forEach { stepText ->
                                        Row(
                                            modifier = Modifier.padding(vertical = 3.dp),
                                            verticalAlignment = Alignment.Top
                                        ) {
                                            Text(
                                                "•",
                                                color = LocalNeonCyan,
                                                fontSize = 13.sp,
                                                modifier = Modifier.padding(end = 6.dp)
                                            )
                                            Text(
                                                stepText,
                                                color = Color.LightGray,
                                                fontSize = 11.sp,
                                                lineHeight = 15.sp
                                            )
                                        }
                                    }
                                }
                            }

                            // Receiver UPI ID copy panel
                            Card(
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF14142B)),
                                shape = RoundedCornerShape(10.dp),
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(horizontal = 14.dp, vertical = 10.dp),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Column {
                                        Text("RECEIVER UPI ID", color = Color.Gray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                        Spacer(modifier = Modifier.height(2.dp))
                                        Text(upiId, color = Color.White, fontSize = 14.sp, fontWeight = FontWeight.ExtraBold, fontFamily = FontFamily.Monospace)
                                    }
                                    Button(
                                        onClick = {
                                            clipboardManager.setText(androidx.compose.ui.text.AnnotatedString(upiId))
                                            android.widget.Toast.makeText(context, "UPI ID Copied!", android.widget.Toast.LENGTH_SHORT).show()
                                        },
                                        colors = ButtonDefaults.buttonColors(containerColor = LocalNeonCyan.copy(alpha = 0.15f)),
                                        shape = RoundedCornerShape(8.dp),
                                        contentPadding = PaddingValues(horizontal = 12.dp, vertical = 4.dp),
                                        modifier = Modifier.height(32.dp)
                                    ) {
                                        Icon(imageVector = Icons.Filled.ContentCopy, contentDescription = "Copy", tint = LocalNeonCyan, modifier = Modifier.size(14.dp))
                                        Spacer(modifier = Modifier.width(4.dp))
                                        Text("Copy", color = LocalNeonCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }

                            // Dynamic UPI Scan QR Code Card
                            Card(
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF14142B)),
                                border = BorderStroke(1.5.dp, Brush.verticalGradient(listOf(Color(0xFF00B4DB), Color(0xFF0083B0)))), // Blue theme frame precisely matching screen request
                                shape = RoundedCornerShape(14.dp),
                                modifier = Modifier
                                    .align(Alignment.CenterHorizontally)
                                    .wrapContentWidth()
                                    .padding(vertical = 4.dp)
                            ) {
                                Column(
                                    horizontalAlignment = Alignment.CenterHorizontally,
                                    modifier = Modifier.padding(16.dp)
                                ) {
                                    val amountNum = if (priceString.contains("2,999") || priceString.contains("2999")) "2999" else "499"
                                    val upiPayData = "upi://pay?pa=$upiId&pn=Clip%20AI%20Hub&am=$amountNum&cu=INR"
                                    val encodedData = java.net.URLEncoder.encode(upiPayData, "UTF-8")
                                    val finalQrUrl = "https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=$encodedData"

                                    Box(
                                        modifier = Modifier
                                            .background(Color.White, RoundedCornerShape(10.dp))
                                            .border(4.dp, Color(0xFF00D2FF), RoundedCornerShape(10.dp)) // Vibrant light blue frame outline
                                            .padding(14.dp)
                                            .size(170.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        AsyncImage(
                                            model = finalQrUrl,
                                            contentDescription = "UPI Payment QR Code",
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }

                                    Spacer(modifier = Modifier.height(10.dp))
                                    Text(
                                        "SCAN TO PAY $priceString",
                                        color = Color.White,
                                        fontSize = 11.sp,
                                        fontWeight = FontWeight.Bold,
                                        fontFamily = FontFamily.Monospace
                                    )
                                    Spacer(modifier = Modifier.height(2.dp))
                                    Text(
                                        "9303991466@ptyes",
                                        color = Color.Gray,
                                        fontSize = 10.sp,
                                        fontFamily = FontFamily.Monospace
                                    )
                                }
                            }

                            // UPI Transaction ref number Input
                            Column(modifier = Modifier.fillMaxWidth()) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Text("Enter 12-digit UTR/Ref No.", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                    Text("Required", color = LocalGold, fontSize = 10.sp, fontWeight = FontWeight.SemiBold)
                                }
                                Spacer(modifier = Modifier.height(6.dp))
                                OutlinedTextField(
                                    value = upiRefNo,
                                    onValueChange = { input ->
                                        if (input.length <= 16) {
                                            upiRefNo = input.filter { it.isDigit() || it.isLetter() }
                                        }
                                    },
                                    placeholder = { Text("e.g. 611234567890", color = Color.Gray, fontSize = 12.sp) },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .testTag("upi_ref_input"),
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = LocalNeonCyan,
                                        unfocusedBorderColor = Color(0x33FFFFFF),
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White
                                    ),
                                    shape = RoundedCornerShape(10.dp),
                                    singleLine = true,
                                    leadingIcon = {
                                        Icon(imageVector = Icons.Default.QrCode, contentDescription = null, tint = LocalNeonCyan)
                                    }
                                )
                                Spacer(modifier = Modifier.height(4.dp))
                                Text("Tip: Look for Ref No. or UTR after successful payment.", color = Color.Gray, fontSize = 10.sp)
                            }
                        }
                    } else {
                        // Debit/Credit Card Payment Form
                        Column(modifier = Modifier.fillMaxWidth(), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                            Column {
                                Text("Cardholder Name", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(4.dp))
                                OutlinedTextField(
                                    value = cardName,
                                    onValueChange = { cardName = it },
                                    placeholder = { Text("Enter full name", color = Color.Gray, fontSize = 12.sp) },
                                    modifier = Modifier.fillMaxWidth().testTag("card_name_input"),
                                    singleLine = true,
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = LocalNeonPurple,
                                        unfocusedBorderColor = Color(0x22FFFFFF),
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White
                                    ),
                                    shape = RoundedCornerShape(8.dp)
                                )
                            }

                            Column {
                                Text("Card Number", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(4.dp))
                                OutlinedTextField(
                                    value = cardNumber,
                                    onValueChange = { if (it.length <= 16) cardNumber = it.filter { char -> char.isDigit() } },
                                    placeholder = { Text("4532 9012 3456 7890", color = Color.Gray, fontSize = 12.sp) },
                                    modifier = Modifier.fillMaxWidth().testTag("card_number_input"),
                                    singleLine = true,
                                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = LocalNeonPurple,
                                        unfocusedBorderColor = Color(0x22FFFFFF),
                                        focusedTextColor = Color.White,
                                        unfocusedTextColor = Color.White
                                    ),
                                    shape = RoundedCornerShape(8.dp),
                                    leadingIcon = {
                                        Icon(imageVector = Icons.Default.CreditCard, contentDescription = null, tint = LocalNeonPurple)
                                    }
                                )
                            }

                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(12.dp)) {
                                Column(modifier = Modifier.weight(1.2f)) {
                                    Text("Expiry Date", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    Spacer(modifier = Modifier.height(4.dp))
                                    OutlinedTextField(
                                        value = cardExpiry,
                                        onValueChange = { if (it.length <= 5) cardExpiry = it },
                                        placeholder = { Text("MM/YY", color = Color.Gray, fontSize = 12.sp) },
                                        modifier = Modifier.fillMaxWidth().testTag("card_expiry_input"),
                                        singleLine = true,
                                        colors = OutlinedTextFieldDefaults.colors(
                                            focusedBorderColor = LocalNeonPurple,
                                            unfocusedBorderColor = Color(0x22FFFFFF),
                                            focusedTextColor = Color.White,
                                            unfocusedTextColor = Color.White
                                        ),
                                        shape = RoundedCornerShape(8.dp)
                                    )
                                }

                                Column(modifier = Modifier.weight(0.8f)) {
                                    Text("CVV", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    Spacer(modifier = Modifier.height(4.dp))
                                    OutlinedTextField(
                                        value = cardCvv,
                                        onValueChange = { if (it.length <= 3) cardCvv = it.filter { char -> char.isDigit() } },
                                        placeholder = { Text("123", color = Color.Gray, fontSize = 12.sp) },
                                        modifier = Modifier.fillMaxWidth().testTag("card_cvv_input"),
                                        singleLine = true,
                                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
                                        colors = OutlinedTextFieldDefaults.colors(
                                            focusedBorderColor = LocalNeonPurple,
                                            unfocusedBorderColor = Color(0x22FFFFFF),
                                            focusedTextColor = Color.White,
                                            unfocusedTextColor = Color.White
                                        ),
                                        shape = RoundedCornerShape(8.dp)
                                    )
                                }
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(20.dp))

                    // Deciding trigger pay validity button
                    val isPayEnabled = if (paymentMethod == "UPI") {
                        upiRefNo.trim().length >= 6
                    } else {
                        cardNumber.length == 16 && cardExpiry.length >= 4 && cardCvv.length == 3 && cardName.isNotBlank()
                    }

                    Button(
                        onClick = {
                            coroutineScope.launch {
                                isProcessing = true
                                if (paymentMethod == "UPI") {
                                    currentProcessingStep = "Submitting transaction UTR and connecting to UPI Gateway..."
                                    processingProgress = 0.2f
                                    delay(850)

                                    currentProcessingStep = "Verifying pending settlement of $priceString with bank ledger..."
                                    processingProgress = 0.5f
                                    delay(950)

                                    currentProcessingStep = "Matching transaction reference ID with Clip AI billing database..."
                                    processingProgress = 0.8f
                                    delay(750)

                                    currentProcessingStep = "Approved! UTR confirmed and Pro features unlocked."
                                    processingProgress = 1.0f
                                    delay(500)
                                } else {
                                    // Simulated payment steps
                                    currentProcessingStep = "Connecting securely to Visa/Mastercard Sandbox..."
                                    processingProgress = 0.1f
                                    delay(600)

                                    currentProcessingStep = "Generating dynamic digital checkout intent..."
                                    processingProgress = 0.3f
                                    delay(600)

                                    currentProcessingStep = "Authenticating transaction with Bank Server..."
                                    processingProgress = 0.5f
                                    delay(800)

                                    currentProcessingStep = "Waiting for payment confirmation ledger status..."
                                    processingProgress = 0.8f
                                    delay(800)

                                    currentProcessingStep = "Approved! Fund flow confirmation verified."
                                    processingProgress = 1.0f
                                    delay(500)
                                }

                                transactionId = "TXN-CLIP-AI-${System.currentTimeMillis().toString().takeLast(6)}"
                                isProcessing = false
                                isSuccess = true
                            }
                        },
                        enabled = isPayEnabled,
                        colors = ButtonDefaults.buttonColors(
                            containerColor = if (paymentMethod == "UPI") LocalNeonCyan else LocalNeonPurple,
                            disabledContainerColor = Color(0x1EFFFFFF)
                        ),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(46.dp)
                            .testTag("pay_securely_button")
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Icon(imageVector = Icons.Default.Lock, contentDescription = null, modifier = Modifier.size(16.dp))
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                if (paymentMethod == "UPI") "Verify & Activate Pro" else "Pay $priceString Securely",
                                color = if (isPayEnabled) Color.White else Color.Gray,
                                fontWeight = FontWeight.Bold,
                                fontSize = 13.sp
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(8.dp))
                    Text(
                        "🛡️ 256-bit Secure Gateway Payment. Refundable under 7-day policy.",
                        color = Color.Gray,
                        fontSize = 9.sp,
                        textAlign = TextAlign.Center
                    )
                }

                // Processing State
                if (isProcessing) {
                    Spacer(modifier = Modifier.height(20.dp))
                    Icon(
                        imageVector = Icons.Default.Shield,
                        contentDescription = null,
                        tint = LocalGold,
                        modifier = Modifier
                            .size(70.dp)
                            .animateContentSize()
                    )
                    Spacer(modifier = Modifier.height(16.dp))
                    Text("Gateway Payment Processing", color = Color.White, fontSize = 18.sp, fontWeight = FontWeight.Bold)
                    Spacer(modifier = Modifier.height(6.dp))
                    Text(currentProcessingStep, color = Color.Gray, fontSize = 11.sp, textAlign = TextAlign.Center)

                    Spacer(modifier = Modifier.height(20.dp))
                    CircularProgressIndicator(
                        progress = { processingProgress },
                        color = LocalNeonPurple,
                        trackColor = Color(0x22FFFFFF),
                        modifier = Modifier.size(50.dp)
                    )

                    Spacer(modifier = Modifier.height(12.dp))
                    Text("${(processingProgress * 100).toInt()}% Secure", color = LocalNeonPurple, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                    Spacer(modifier = Modifier.height(20.dp))
                }

                // Success Confirmation State (Actual purchase confirmed)
                if (isSuccess) {
                    Spacer(modifier = Modifier.height(20.dp))
                    Icon(
                        imageVector = Icons.Default.CheckCircle,
                        contentDescription = "Success",
                        tint = LocalNeonGreen,
                        modifier = Modifier.size(80.dp)
                    )
                    Spacer(modifier = Modifier.height(16.dp))
                    Text(
                        "Payment Confirmed!",
                        color = LocalNeonGreen,
                        fontSize = 22.sp,
                        fontWeight = FontWeight.ExtraBold
                    )
                    Text("Paisa mila, confirmation code: $transactionId", color = Color.LightGray, fontSize = 12.sp, textAlign = TextAlign.Center)

                    Spacer(modifier = Modifier.height(16.dp))

                    Card(
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF142B1A)),
                        border = BorderStroke(0.5.dp, LocalNeonGreen),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Column(modifier = Modifier.padding(14.dp), horizontalAlignment = Alignment.CenterHorizontally) {
                            Text("TRANSACTION SUCCESS RECEIPT", color = LocalNeonGreen, fontSize = 9.sp, fontWeight = FontWeight.Black)
                            Spacer(modifier = Modifier.height(6.dp))
                            Divider(color = Color(0x22FFFFFF))
                            Spacer(modifier = Modifier.height(8.dp))

                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Purchased Plan:", color = Color.Gray, fontSize = 11.sp)
                                Text(planName, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Spacer(modifier = Modifier.height(4.dp))
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Amount Paid:", color = Color.Gray, fontSize = 11.sp)
                                Text(priceString, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Spacer(modifier = Modifier.height(4.dp))
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Reference ID:", color = Color.Gray, fontSize = 11.sp)
                                Text(transactionId, color = Color.White, fontSize = 11.sp, fontFamily = FontFamily.Monospace)
                            }
                            Spacer(modifier = Modifier.height(4.dp))
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Status:", color = Color.Gray, fontSize = 11.sp)
                                Text("SECURE SETTLED", color = LocalNeonGreen, fontSize = 11.sp, fontWeight = FontWeight.Black)
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(24.dp))

                    Button(
                        onClick = {
                            onPaymentSuccess(planName, credits)
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = LocalNeonGreen),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(46.dp)
                            .testTag("activate_workspace_button")
                    ) {
                        Text("Activate Pro Workspace Features", color = PureBlack, fontWeight = FontWeight.Bold)
                    }
                    Spacer(modifier = Modifier.height(10.dp))
                }
            }
        }
    }
}

