// ==========================================
// SAVED PROJECTS (DOWNLOAD CENTER CAPABILITIES)
// ==========================================
@Composable
fun SavedScreenView(
    viewModel: CreatorViewModel
) {
    val savedProjects by viewModel.savedCreations.collectAsState()

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 20.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        item {
            Text(
                text = "Saved Creations",
                color = Color.White,
                fontSize = 24.sp,
                fontWeight = FontWeight.Black,
                modifier = Modifier.padding(top = 16.dp)
            )
        }

        if (savedProjects.isEmpty()) {
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 120.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            imageVector = Icons.Outlined.Star,
                            contentDescription = "No Saved Projects",
                            tint = Color.Gray,
                            modifier = Modifier.size(72.dp)
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            text = "No saved creations yet.",
                            color = Color.White,
                            fontSize = 16.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Spacer(modifier = Modifier.height(6.dp))
                        Text(
                            text = "Open any tool, click generate, and press save!",
                            color = Color.Gray,
                            fontSize = 12.sp,
                            textAlign = TextAlign.Center
                        )
                    }
                }
            }
        } else {
            items(savedProjects, key = { it.id }) { creation ->
                CreationCard(
                    creation = creation,
                    onSaveToggle = { viewModel.toggleSaveProject(creation) },
                    onDownload = { viewModel.triggerMockDownload(creation) },
                    onDelete = { viewModel.deleteHistoryId(creation.id) },
                    onReopen = { viewModel.reopenCreation(creation) }
                )
            }
        }

        item {
            Spacer(modifier = Modifier.height(40.dp))
        }
    }
}

// ==========================================
// AI HISTORY SCREEN
// ==========================================
fun extractMediaUrls(creation: CreationEntity): List<String> {
    val regex = Regex("https?://[^\\s\\n\\\"']+")
    val matches = regex.findAll(creation.outputText).map { it.value }.toList()
    return matches.filter { url ->
        url.contains("pollinations.ai") ||
        url.contains("picsum") ||
        url.contains("modelslab.com") ||
        url.contains("cloudinary") ||
        url.contains("googleapis") ||
        url.endsWith(".gif") ||
        url.endsWith(".png") ||
        url.endsWith(".jpg") ||
        url.endsWith(".jpeg") ||
        url.endsWith(".webp") ||
        url.endsWith(".mp4")
    }.distinct()
}

@Composable
fun HistoryScreenView(
    viewModel: CreatorViewModel
) {
    val historyList by viewModel.history.collectAsState()
    var selectedMode by remember { mutableStateFlowOf("gallery") } // Default to "gallery" for a pristine media visual experience
    var inspectorItem by remember { mutableStateFlowOf<Pair<CreationEntity, String>?>(null) }
    val context = LocalContext.current

    val mediaCreations = remember(historyList) {
        historyList.filter { creation ->
            creation.category.contains("Image", ignoreCase = true) ||
            creation.category.contains("Video", ignoreCase = true) ||
            creation.toolName.contains("Image", ignoreCase = true) ||
            creation.toolName.contains("Video", ignoreCase = true) ||
            creation.toolName.contains("Avatar", ignoreCase = true) ||
            creation.toolName.contains("Thumbnail", ignoreCase = true) ||
            creation.toolName.contains("Remover", ignoreCase = true) ||
            creation.toolName.contains("Enhancer", ignoreCase = true)
        }.mapNotNull { creation ->
            val urls = extractMediaUrls(creation)
            if (urls.isNotEmpty()) {
                Pair(creation, urls.first())
            } else {
                null
            }
        }
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 20.dp)
    ) {
        // SCREEN HEADER
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(top = 16.dp, bottom = 8.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                text = "AI Workspace Studio",
                color = Color.White,
                fontSize = 24.sp,
                fontWeight = FontWeight.Black
            )
            if (historyList.isNotEmpty()) {
                TextButton(
                    onClick = { viewModel.clearAllHistory() },
                    colors = ButtonDefaults.textButtonColors(contentColor = Color.Red)
                ) {
                    Text("Clear All", fontWeight = FontWeight.Bold)
                }
            }
        }

        // TAB SWITCHER
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color(0xFF0C0B18), RoundedCornerShape(12.dp))
                .padding(4.dp),
            horizontalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            // GALLERY TAB
            Box(
                contentAlignment = Alignment.Center,
                modifier = Modifier
                    .weight(1f)
                    .height(38.dp)
                    .clip(RoundedCornerShape(10.dp))
                    .background(if (selectedMode == "gallery") Color(0xFF1D1B2D) else Color.Transparent)
                    .clickable { selectedMode = "gallery" }
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(
                        imageVector = Icons.Filled.GridView,
                        contentDescription = "Gallery",
                        tint = if (selectedMode == "gallery") NeonCyan else Color.Gray,
                        modifier = Modifier.size(16.dp)
                    )
                    Text(
                        text = "MEDIA GALLERY",
                        color = if (selectedMode == "gallery") Color.White else Color.Gray,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                    if (mediaCreations.isNotEmpty()) {
                        Box(
                            modifier = Modifier
                                .background(NeonCyan, CircleShape)
                                .padding(horizontal = 5.dp, vertical = 2.dp)
                        ) {
                            Text(
                                text = mediaCreations.size.toString(),
                                color = Color.Black,
                                fontSize = 9.sp,
                                fontWeight = FontWeight.Black
                            )
                        }
                    }
                }
            }

            // ACTIVITY LOGS TAB
            Box(
                contentAlignment = Alignment.Center,
                modifier = Modifier
                    .weight(1f)
                    .height(38.dp)
                    .clip(RoundedCornerShape(10.dp))
                    .background(if (selectedMode == "logs") Color(0xFF1D1B2D) else Color.Transparent)
                    .clickable { selectedMode = "logs" }
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(
                        imageVector = Icons.Filled.List,
                        contentDescription = "Logs",
                        tint = if (selectedMode == "logs") NeonPurple else Color.Gray,
                        modifier = Modifier.size(16.dp)
                    )
                    Text(
                        text = "ACTIVITY FEED",
                        color = if (selectedMode == "logs") Color.White else Color.Gray,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }
        }

        Spacer(modifier = Modifier.height(16.dp))

        // CONDITIONAL RENDERING OF VIEWS Based on Tab State
        if (selectedMode == "gallery") {
            if (mediaCreations.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(1f)
                        .padding(vertical = 80.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            imageVector = Icons.Filled.Image,
                            contentDescription = "No Media",
                            tint = Color.Gray,
                            modifier = Modifier.size(72.dp)
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            text = "No Generated Media Found",
                            color = Color.White,
                            fontSize = 16.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Spacer(modifier = Modifier.height(6.dp))
                        Text(
                            text = "Images and videos generated in the tools will appear here in high-fidelity.",
                            color = Color.Gray,
                            fontSize = 12.sp,
                            textAlign = TextAlign.Center,
                            modifier = Modifier.padding(horizontal = 24.dp)
                        )
                    }
                }
            } else {
                LazyVerticalGrid(
                    columns = GridCells.Fixed(2),
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(1f),
                    horizontalArrangement = Arrangement.spacedBy(12.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    items(mediaCreations, key = { it.first.id }) { itemPair ->
                        val (creation, mediaUrl) = itemPair
                        val isVideo = creation.toolName.contains("Video", ignoreCase = true) || creation.category.contains("Video", ignoreCase = true)

                        Card(
                            colors = CardDefaults.cardColors(containerColor = GlassCardBg),
                            border = BorderStroke(0.5.dp, Color(0x33A78BFA)),
                            shape = RoundedCornerShape(14.dp),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(190.dp)
                                .clickable {
                                    viewModel.triggerActionWithAd {
                                        inspectorItem = itemPair
                                    }
                                }
                        ) {
                            Box(modifier = Modifier.fillMaxSize()) {
                                // Background preview using AsyncImage (Coil library)
                                AsyncImage(
                                    model = mediaUrl,
                                    contentDescription = creation.inputPrompt,
                                    contentScale = ContentScale.Crop,
                                    modifier = Modifier.fillMaxSize()
                                )

                                // Dark overlay for text readability at bottom
                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .align(Alignment.BottomCenter)
                                        .background(
                                            Brush.verticalGradient(
                                                colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.85f))
                                            )
                                        )
                                        .padding(8.dp)
                                ) {
                                    Column {
                                        Text(
                                            text = creation.toolName.uppercase(),
                                            color = if (isVideo) NeonPurple else NeonCyan,
                                            fontSize = 8.sp,
                                            fontWeight = FontWeight.Black,
                                            letterSpacing = 1.sp
                                        )
                                        Spacer(modifier = Modifier.height(2.dp))
                                        val cleanPromptLine = creation.inputPrompt.replace(Regex("Prompt:\\s*"), "")
                                        Text(
                                            text = cleanPromptLine,
                                            color = Color.White,
                                            fontSize = 10.sp,
                                            fontWeight = FontWeight.Bold,
                                            maxLines = 1,
                                            overflow = TextOverflow.Ellipsis
                                        )
                                    }
                                }

                                // Interactive play indication / media badge at top right
                                Box(
                                    modifier = Modifier
                                        .align(Alignment.TopEnd)
                                        .padding(8.dp)
                                        .background(Color.Black.copy(alpha = 0.6f), CircleShape)
                                        .size(28.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = if (isVideo) Icons.Filled.PlayArrow else Icons.Filled.ZoomIn,
                                        contentDescription = "Action Overlay",
                                        tint = if (isVideo) NeonPurple else NeonCyan,
                                        modifier = Modifier.size(14.dp)
                                    )
                                }

                                // Favorites / Save indicator
                                if (creation.isSaved) {
                                    Box(
                                        modifier = Modifier
                                            .align(Alignment.TopStart)
                                            .padding(8.dp)
                                            .background(NeonCyan.copy(alpha = 0.8f), CircleShape)
                                            .size(20.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Icon(
                                            imageVector = Icons.Filled.Star,
                                            contentDescription = "Saved Logo",
                                            tint = Color.Black,
                                            modifier = Modifier.size(10.dp)
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }
        } else {
            // LOG FEED LIST MODE
            if (historyList.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(1f)
                        .padding(vertical = 120.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            imageVector = Icons.Outlined.History,
                            contentDescription = "No History",
                            tint = Color.Gray,
                            modifier = Modifier.size(72.dp)
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            text = "Generation history is empty.",
                            color = Color.White,
                            fontSize = 16.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Spacer(modifier = Modifier.height(6.dp))
                        Text(
                            text = "Your creations will appear here.",
                            color = Color.Gray,
                            fontSize = 12.sp
                        )
                    }
                }
            } else {
                LazyColumn(
                    modifier = Modifier
                        .fillMaxWidth()
                        .weight(1f),
                    verticalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    items(historyList, key = { it.id }) { creation ->
                        CreationCard(
                            creation = creation,
                            onSaveToggle = { viewModel.toggleSaveProject(creation) },
                            onDownload = { viewModel.triggerMockDownload(creation) },
                            onDelete = { viewModel.deleteHistoryId(creation.id) },
                            onReopen = {
                                viewModel.triggerActionWithAd {
                                    viewModel.reopenCreation(creation)
                                }
                            }
                        )
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(24.dp))
    }

    // GALLERY DETAILED INSPECTOR DIALOG OVERLAY
    if (inspectorItem != null) {
        val (creation, mediaUrl) = inspectorItem!!
        val isVideo = creation.toolName.contains("Video", ignoreCase = true) || creation.category.contains("Video", ignoreCase = true)
        val clipboard = LocalClipboardManager.current

        androidx.compose.ui.window.Dialog(
            onDismissRequest = { inspectorItem = null }
        ) {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF07060F)),
                border = BorderStroke(1.dp, NeonPurple.copy(alpha = 0.5f)),
                shape = RoundedCornerShape(20.dp),
                modifier = Modifier
                    .fillMaxWidth()
                    .wrapContentHeight()
                    .padding(10.dp)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    // Header title & Close Button
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text(
                                text = creation.toolName,
                                color = Color.White,
                                fontSize = 16.sp,
                                fontWeight = FontWeight.Black
                            )
                            Text(
                                text = creation.category,
                                color = Color.Gray,
                                fontSize = 11.sp
                            )
                        }
                        IconButton(
                            onClick = { inspectorItem = null },
                            modifier = Modifier
                                .background(Color.White.copy(alpha = 0.05f), CircleShape)
                                .size(32.dp)
                        ) {
                            Icon(imageVector = Icons.Filled.Close, contentDescription = "Close", tint = Color.White, modifier = Modifier.size(16.dp))
                        }
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    // Big Preview area
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(260.dp)
                            .clip(RoundedCornerShape(12.dp))
                            .background(Color(0xFF030308))
                    ) {
                        AsyncImage(
                            model = mediaUrl,
                            contentDescription = "Inspector Preview",
                            contentScale = ContentScale.Fit,
                            modifier = Modifier.fillMaxSize()
                        )

                        // If video loop model, overlay running video simulator indicators of Premium dream model
                        if (isVideo) {
                            Box(
                                modifier = Modifier
                                    .align(Alignment.BottomCenter)
                                    .fillMaxWidth()
                                    .background(Color.Black.copy(alpha = 0.6f))
                                    .padding(vertical = 6.dp, horizontal = 12.dp)
                            ) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    CircularProgressIndicator(
                                        color = NeonPurple,
                                        strokeWidth = 2.dp,
                                        modifier = Modifier.size(12.dp)
                                    )
                                    Text(
                                        text = "Looping Cinematic Movie Flow...",
                                        color = NeonPurple,
                                        fontSize = 10.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(14.dp))

                    // Input Prompt details
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF020205), RoundedCornerShape(10.dp))
                            .padding(12.dp)
                    ) {
                        Text(
                            text = "CREATIVE SOURCE PROMPT",
                            color = NeonCyan,
                            fontSize = 9.sp,
                            fontWeight = FontWeight.Black,
                            letterSpacing = 1.sp
                        )
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = creation.inputPrompt,
                            color = Color.LightGray,
                            fontSize = 11.sp,
                            lineHeight = 15.sp
                        )
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    // PRIMARY AD-SUPPORTED DOWNLOAD BUTTON
                    Button(
                        onClick = {
                            viewModel.triggerMockDownload(creation)
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = NeonCyan),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(44.dp),
                        contentPadding = PaddingValues(vertical = 10.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.Download,
                            contentDescription = "Download Item",
                            tint = Color.Black,
                            modifier = Modifier.size(16.dp)
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(
                            text = if (isVideo) "DOWNLOAD HIGH RES VIDEO 📥" else "DOWNLOAD PREMIUM HD IMAGE 📥",
                            color = Color.Black,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Black
                        )
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    // Interactive control buttons
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        // REUSE BUTTON
                        Button(
                            onClick = {
                                inspectorItem = null
                                viewModel.reopenCreation(creation)
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = NeonPurple.copy(alpha = 0.15f)),
                            border = BorderStroke(1.dp, NeonPurple.copy(alpha = 0.8f)),
                            shape = RoundedCornerShape(10.dp),
                            modifier = Modifier.weight(1f),
                            contentPadding = PaddingValues(vertical = 10.dp)
                        ) {
                            Icon(imageVector = Icons.Filled.Refresh, contentDescription = "Reuse", tint = Color.White, modifier = Modifier.size(15.dp))
                            Spacer(modifier = Modifier.width(6.dp))
                            Text("Reuse", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }

                        // FAVORITE STAR BUTTON
                        Button(
                            onClick = {
                                viewModel.toggleSaveProject(creation)
                                inspectorItem = inspectorItem?.copy(first = creation.copy(isSaved = !creation.isSaved))
                                Toast.makeText(context, if (!creation.isSaved) "Saved to Bookmarks!" else "Removed from Bookmarks", Toast.LENGTH_SHORT).show()
                            },
                            colors = ButtonDefaults.buttonColors(
                                containerColor = if (creation.isSaved) NeonCyan.copy(alpha = 0.15f) else Color(0xFF131322)
                            ),
                            border = BorderStroke(1.dp, if (creation.isSaved) NeonCyan else Color.DarkGray),
                            shape = RoundedCornerShape(10.dp),
                            modifier = Modifier.weight(1f),
                            contentPadding = PaddingValues(vertical = 10.dp)
                        ) {
                            Icon(
                                imageVector = if (creation.isSaved) Icons.Filled.Star else Icons.Outlined.Star,
                                contentDescription = "Star",
                                tint = if (creation.isSaved) NeonCyan else Color.White,
                                modifier = Modifier.size(15.dp)
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text(
                                text = if (creation.isSaved) "Starred" else "Star",
                                color = Color.White,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(8.dp))

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        // COPY LINK BUTTON
                        Button(
                            onClick = {
                                clipboard.setText(AnnotatedString(mediaUrl))
                                Toast.makeText(context, "Copied active media URL to clipboard!", Toast.LENGTH_SHORT).show()
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF10111F)),
                            border = BorderStroke(0.5.dp, Color.Gray),
                            shape = RoundedCornerShape(10.dp),
                            modifier = Modifier.weight(1.1f),
                            contentPadding = PaddingValues(vertical = 10.dp)
                        ) {
                            Icon(imageVector = Icons.Filled.ContentCopy, contentDescription = "Copy Url", tint = NeonCyan, modifier = Modifier.size(14.dp))
                            Spacer(modifier = Modifier.width(6.dp))
                            Text("Copy Link", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }

                        // DELETE BUTTON
                        Button(
                            onClick = {
                                viewModel.deleteHistoryId(creation.id)
                                inspectorItem = null
                                Toast.makeText(context, "Deleted from history session!", Toast.LENGTH_SHORT).show()
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF2B0B14)),
                            border = BorderStroke(1.dp, Color.Red.copy(alpha = 0.5f)),
                            shape = RoundedCornerShape(10.dp),
                            modifier = Modifier.weight(0.9f),
                            contentPadding = PaddingValues(vertical = 10.dp)
                        ) {
                            Icon(imageVector = Icons.Filled.Delete, contentDescription = "Delete", tint = Color.Red, modifier = Modifier.size(14.dp))
                            Spacer(modifier = Modifier.width(6.dp))
                            Text("Delete", color = Color.Red, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun CreationCard(
    creation: CreationEntity,
    onSaveToggle: () -> Unit,
    onDownload: () -> Unit,
    onDelete: () -> Unit,
    onReopen: () -> Unit
) {
    var expanded by remember { mutableStateFlowOf(false) }
    val clipboard = LocalClipboardManager.current
    val context = LocalContext.current

    Card(
        colors = CardDefaults.cardColors(containerColor = GlassCardBg),
        border = BorderStroke(0.5.dp, Color(0x33A78BFA)),
        shape = RoundedCornerShape(16.dp),
        modifier = Modifier
            .fillMaxWidth()
            .clickable { onReopen() }
            .testTag("creation_card_${creation.id}")
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column(modifier = Modifier.weight(1f)) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Box(
                            modifier = Modifier
                                .background(Color(0x22A78BFA), RoundedCornerShape(6.dp))
                                .padding(horizontal = 6.dp, vertical = 2.dp)
                        ) {
                            Text(
                                text = creation.category.uppercase(),
                                color = NeonPurple,
                                fontSize = 8.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(
                            text = creation.toolName,
                            color = Color.White,
                            fontSize = 14.sp,
                            fontWeight = FontWeight.ExtraBold
                        )
                    }
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        text = "Prompt: ${creation.inputPrompt}",
                        color = Color.LightGray,
                        fontSize = 12.sp,
                        maxLines = 1,
                        overflow = TextOverflow.Ellipsis
                    )
                }

                Row {
                    IconButton(onClick = onSaveToggle) {
                        Icon(
                            imageVector = if (creation.isSaved) Icons.Filled.Star else Icons.Outlined.Star,
                            contentDescription = "Save Project",
                            tint = if (creation.isSaved) NeonCyan else Color.Gray
                        )
                    }
                    IconButton(onClick = onDownload) {
                        Icon(
                            imageVector = Icons.Filled.CloudDownload,
                            contentDescription = "Download Creation",
                            tint = NeonBlue
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(8.dp))

            // Text output view or preview image
            val showPreview = creation.category == "Image Tools" || creation.category == "Video Tools"
            
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF040409), RoundedCornerShape(10.dp))
                    .padding(12.dp)
                    .clickable { expanded = !expanded }
            ) {
                Column {
                    if (showPreview) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(120.dp)
                                .clip(RoundedCornerShape(8.dp))
                                .background(Color.DarkGray)
                        ) {
                            // Since standard web previews are unavailable, draw custom animated layout or visual simulation
                            Text(
                                "Generated Media Content Simulator\n(Click to read Prompt Details)",
                                color = Color.White,
                                fontSize = 12.sp,
                                fontWeight = FontWeight.Bold,
                                textAlign = TextAlign.Center,
                                modifier = Modifier.align(Alignment.Center)
                            )
                        }
                        Spacer(modifier = Modifier.height(8.dp))
                    }

                    Text(
                        text = creation.outputText,
                        color = Color.White,
                        fontSize = 13.sp,
                        lineHeight = 18.sp,
                        maxLines = if (expanded) 100 else 3,
                        overflow = TextOverflow.Ellipsis
                    )

                    Spacer(modifier = Modifier.height(8.dp))

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = if (expanded) "Click to Collapse" else "Click to Expand Content",
                            color = NeonPurple,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )

                        Row {
                            TextButton(
                                onClick = onReopen,
                                contentPadding = PaddingValues()
                            ) {
                                Icon(imageVector = Icons.Filled.PlayArrow, contentDescription = "Re-use", tint = NeonPurple, modifier = Modifier.size(16.dp))
                                Spacer(modifier = Modifier.width(4.dp))
                                Text("Re-use & Open", color = NeonPurple, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Spacer(modifier = Modifier.width(10.dp))
                            TextButton(
                                onClick = {
                                    clipboard.setText(AnnotatedString(creation.outputText))
                                    Toast.makeText(context, "Copied generation code!", Toast.LENGTH_SHORT).show()
                                },
                                contentPadding = PaddingValues()
                            ) {
                                Icon(imageVector = Icons.Filled.ContentCopy, contentDescription = "Copy", tint = NeonCyan, modifier = Modifier.size(16.dp))
                                Spacer(modifier = Modifier.width(4.dp))
                                Text("Copy", color = NeonCyan, fontSize = 11.sp)
                            }
                            Spacer(modifier = Modifier.width(8.dp))
                            TextButton(
                                onClick = onDelete,
                                contentPadding = PaddingValues()
                            ) {
                                Icon(imageVector = Icons.Filled.Delete, contentDescription = "Delete", tint = Color.Red, modifier = Modifier.size(16.dp))
                                Spacer(modifier = Modifier.width(4.dp))
                                Text("Delete", color = Color.Red, fontSize = 11.sp)
                            }
                        }
                    }
                }
            }
        }
    }
}

// ==========================================
// MOCK AUTH SCREEN
// ==========================================
@Composable
fun AuthScreenView(
    viewModel: CreatorViewModel
) {
    var emailInput by remember { mutableStateFlowOf("") }
    var passwordInput by remember { mutableStateFlowOf("") }
    var isSigningUp by remember { mutableStateFlowOf(false) }

    val authError by viewModel.authError.collectAsState()
    val isAuthenticating by viewModel.isAuthenticating.collectAsState()
    val context = LocalContext.current

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(24.dp)
            .verticalScroll(rememberScrollState()),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Box(
            modifier = Modifier
                .background(Color(0x33A78BFA), RoundedCornerShape(20.dp))
                .neonBorder(NeonPurple)
                .padding(24.dp)
                .fillMaxWidth()
        ) {
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                Icon(
                    imageVector = Icons.Filled.AutoAwesome,
                    contentDescription = "Lock Logo",
                    tint = NeonPurple,
                    modifier = Modifier.size(48.dp)
                )

                Spacer(modifier = Modifier.height(16.dp))

                Text(
                    text = "CLIP AI GATEWAY",
                    color = Color.White,
                    fontSize = 20.sp,
                    fontWeight = FontWeight.Black,
                    letterSpacing = 1.sp
                )

                Spacer(modifier = Modifier.height(4.dp))

                Text(
                    text = if (isSigningUp) "Create credentials for immediate access Pro" else "Secure authentication portal",
                    color = Color.Gray,
                    fontSize = 12.sp
                )

                Spacer(modifier = Modifier.height(20.dp))

                // Error Message Dialog block
                if (authError != null) {
                    Card(
                        colors = CardDefaults.cardColors(containerColor = Color.Red.copy(alpha = 0.15f)),
                        shape = RoundedCornerShape(8.dp),
                        border = BorderStroke(1.dp, Color.Red.copy(alpha = 0.5f)),
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(bottom = 16.dp)
                    ) {
                        Row(
                            modifier = Modifier.padding(12.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Icon(
                                imageVector = Icons.Filled.Warning,
                                contentDescription = "Error",
                                tint = Color.Red,
                                modifier = Modifier.size(20.dp)
                            )
                            Spacer(modifier = Modifier.width(10.dp))
                            Text(
                                text = authError ?: "Unknown credentials error.",
                                color = Color.White,
                                fontSize = 12.sp,
                                modifier = Modifier.weight(1f)
                            )
                        }
                    }
                }

                // Email
                OutlinedTextField(
                    value = emailInput,
                    onValueChange = { 
                        emailInput = it 
                        viewModel.clearAuthError()
                    },
                    label = { Text("Email Address", color = Color.Gray) },
                    singleLine = true,
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedTextColor = Color.White,
                        unfocusedTextColor = Color.White,
                        focusedBorderColor = NeonCyan,
                        unfocusedBorderColor = Color.DarkGray
                    ),
                    modifier = Modifier.fillMaxWidth().testTag("auth_email_input"),
                    enabled = !isAuthenticating
                )

                Spacer(modifier = Modifier.height(14.dp))

                // Password
                OutlinedTextField(
                    value = passwordInput,
                    onValueChange = { 
                        passwordInput = it 
                        viewModel.clearAuthError()
                    },
                    label = { Text("Password (min 6 chars)", color = Color.Gray) },
                    visualTransformation = PasswordVisualTransformation(),
                    singleLine = true,
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedTextColor = Color.White,
                        unfocusedTextColor = Color.White,
                        focusedBorderColor = NeonCyan,
                        unfocusedBorderColor = Color.DarkGray
                    ),
                    modifier = Modifier.fillMaxWidth().testTag("auth_password_input"),
                    enabled = !isAuthenticating
                )

                Spacer(modifier = Modifier.height(24.dp))

                // Auth Submission button
                if (isAuthenticating) {
                    CircularProgressIndicator(
                        color = NeonPurple,
                        modifier = Modifier
                            .size(36.dp)
                            .padding(bottom = 8.dp)
                    )
                } else {
                    Button(
                        onClick = {
                            if (emailInput.isEmpty() || passwordInput.isEmpty()) {
                                Toast.makeText(context, "Please enter your email and password.", Toast.LENGTH_SHORT).show()
                                return@Button
                            }
                            if (isSigningUp) {
                                viewModel.firebaseSignup(emailInput, passwordInput)
                            } else {
                                viewModel.firebaseLogin(emailInput, passwordInput)
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent),
                        contentPadding = PaddingValues(),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(50.dp)
                            .clip(RoundedCornerShape(12.dp))
                            .background(Brush.horizontalGradient(listOf(NeonPurple, NeonCyan)))
                            .testTag("auth_submit_button")
                    ) {
                        Text(
                            text = if (isSigningUp) "Sign Up" else "Login via Email",
                            color = PureBlack,
                            fontWeight = FontWeight.ExtraBold,
                            fontSize = 15.sp
                        )
                    }
                }

                Spacer(modifier = Modifier.height(16.dp))

                Divider(color = Color(0x33FFFFFF), thickness = 1.dp)

                Spacer(modifier = Modifier.height(16.dp))

                // Google simulated login
                OutlinedButton(
                    onClick = {
                        if (!isAuthenticating) {
                            viewModel.login("chankikawde7@gmail.com", "Google")
                        }
                    },
                    border = BorderStroke(1.dp, NeonBlue),
                    shape = RoundedCornerShape(12.dp),
                    colors = ButtonDefaults.outlinedButtonColors(contentColor = NeonBlue),
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(50.dp)
                        .testTag("google_login_button"),
                    enabled = !isAuthenticating
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(imageVector = Icons.Filled.AccountCircle, contentDescription = "Google", tint = NeonBlue)
                        Spacer(modifier = Modifier.width(10.dp))
                        Text("Connect Google ID", fontWeight = FontWeight.Bold, fontSize = 14.sp)
                    }
                }

                Spacer(modifier = Modifier.height(20.dp))

                Text(
                    text = if (isSigningUp) "Already have an account? Login" else "Don't have an account? Sign Up",
                    color = NeonCyan,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier
                        .clickable { 
                            if (!isAuthenticating) {
                                isSigningUp = !isSigningUp 
                                viewModel.clearAuthError()
                            }
                        }
                        .padding(8.dp)
                )
            }
        }
    }
}

// ==========================================
// WORKBENCH SCREEN VIEW (MAIN GENERATION)
// ==========================================
@Composable
fun WorkbenchScreenView(
    viewModel: CreatorViewModel
) {
    val context = LocalContext.current
    val selectedToolName by viewModel.selectedTool.collectAsState()
    val generationState by viewModel.generationState.collectAsState()
    val generatedImageRes by viewModel.generatedImageRes.collectAsState()
    val userStats by viewModel.userStats.collectAsState()
    val chatHistory by viewModel.chatHistory.collectAsState()
    val selectedLanguage by viewModel.selectedLanguage.collectAsState()
    val preloadedPrompt by viewModel.preloadedPrompt.collectAsState()

    val tool = remember(selectedToolName) {
        getStaticTools().find { it.name == selectedToolName } ?: getStaticTools().first()
    }

    // Capture user inputs dynamized
    val paramStateMap = remember(selectedToolName, preloadedPrompt) {
        mutableStateMapOf<String, String>().apply {
            tool.params.forEach { param ->
                when (param) {
                    is ToolParam.Text -> {
                        if (preloadedPrompt != null) {
                            put(param.label, preloadedPrompt ?: "")
                        } else {
                            put(param.label, param.defaultValue)
                        }
                    }
                    is ToolParam.Choices -> put(param.label, param.options.getOrNull(param.defaultIndex) ?: "")
                }
            }
        }
    }

    LaunchedEffect(selectedLanguage, selectedToolName) {
        val cleanLang = selectedLanguage.split(" ").first()
        tool.params.forEach { param ->
            if (param.label.equals("Language", ignoreCase = true) && param is ToolParam.Choices) {
                // Find matching or closest option in the choices
                val matchingOption = param.options.find { option ->
                    option.contains(cleanLang, ignoreCase = true) ||
                    cleanLang.contains(option.split(" ").first(), ignoreCase = true)
                }
                if (matchingOption != null) {
                    paramStateMap[param.label] = matchingOption
                }
            }
        }
    }

    var chatInputText by remember { mutableStateFlowOf("") }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 20.dp)
    ) {
        // Back toolbar
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(vertical = 12.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            IconButton(onClick = { viewModel.navigateTo("home") }) {
                Icon(imageVector = Icons.Filled.ArrowBack, contentDescription = "Back", tint = Color.LightGray)
            }
            Text(
                text = tool.name,
                color = Color.White,
                fontSize = 18.sp,
                fontWeight = FontWeight.ExtraBold
            )
            Spacer(modifier = Modifier.width(8.dp))
            Box(
                modifier = Modifier
                    .background(Color(0x333B82F6), RoundedCornerShape(6.dp))
                    .padding(horizontal = 8.dp, vertical = 2.dp)
            ) {
                Text(
                    text = tool.category.replace(" Tools", ""),
                    color = NeonBlue,
                    fontSize = 9.sp,
                    fontWeight = FontWeight.Bold
                )
            }

            Spacer(modifier = Modifier.weight(1f))

            // Adaptive Language Dropdown Selector
            var langDropdownExpanded by remember { mutableStateFlowOf(false) }
            val languagesList = listOf(
                "English", "Hindi (हिंदी)", "Spanish (Español)", "French (Français)",
                "German (Deutsch)", "Arabic (العربية)", "Bengali (বাংলা)",
                "Portuguese (Português)", "Japanese (日本語)", "Chinese (中文)"
            )

            Box(
                modifier = Modifier
                    .clip(RoundedCornerShape(8.dp))
                    .background(Color(0x1F22D3EE))
                    .border(0.5.dp, Color(0x3322D3EE), RoundedCornerShape(8.dp))
                    .clickable { langDropdownExpanded = true }
                    .padding(horizontal = 10.dp, vertical = 6.dp)
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(
                        imageVector = Icons.Outlined.Translate,
                        contentDescription = "Language Selector",
                        tint = NeonCyan,
                        modifier = Modifier.size(15.dp)
                    )
                    Text(
                        text = selectedLanguage.split(" ").first(),
                        color = Color.White,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.SemiBold
                    )
                    Icon(
                        imageVector = Icons.Filled.ArrowDropDown,
                        contentDescription = null,
                        tint = Color.LightGray,
                        modifier = Modifier.size(14.dp)
                    )
                }

                DropdownMenu(
                    expanded = langDropdownExpanded,
                    onDismissRequest = { langDropdownExpanded = false },
                    modifier = Modifier.background(Color(0xFF0F0F1A))
                ) {
                    languagesList.forEach { language ->
                        val isSelected = language == selectedLanguage
                        DropdownMenuItem(
                            text = {
                                Text(
                                    text = language,
                                    color = if (isSelected) NeonCyan else Color.White,
                                    fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                                    fontSize = 13.sp
                                )
                            },
                            onClick = {
                                viewModel.updateLanguage(language)
                                langDropdownExpanded = false
                            }
                        )
                    }
                }
            }
        }

        Divider(color = Color(0x22FFFFFF))

        var isBannerDismissed by remember(selectedToolName) { mutableStateOf(false) }
        val isFreeTierUser = userStats?.isProPlan != true

        val isPremiumPlan = userStats?.isProPlan == true
        val isLocked = tool.isPremium && !isPremiumPlan

        if (isLocked) {
            Column(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth()
                    .padding(vertical = 24.dp),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.Center
            ) {
                Box(
                    modifier = Modifier
                        .background(Color(0x11FF0055), RoundedCornerShape(24.dp))
                        .border(1.dp, Color(0x44FF0055), RoundedCornerShape(24.dp))
                        .padding(24.dp)
                ) {
                    Icon(
                        imageVector = Icons.Filled.Lock,
                        contentDescription = "Locked tool icon",
                        tint = Color(0xFFFF0055),
                        modifier = Modifier.size(54.dp)
                    )
                }
                Spacer(modifier = Modifier.height(24.dp))
                Text(
                    text = "${tool.name} is Locked",
                    color = Color.White,
                    fontSize = 20.sp,
                    fontWeight = FontWeight.Bold,
                    textAlign = TextAlign.Center
                )
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = "This premium creation tool requires a Pro or Agency subscription plan. Unlock all 24 professional AI tools immediately.",
                    color = Color.LightGray,
                    fontSize = 14.sp,
                    textAlign = TextAlign.Center,
                    lineHeight = 20.sp,
                    modifier = Modifier.padding(horizontal = 24.dp)
                )
                Spacer(modifier = Modifier.height(30.dp))
                Button(
                    onClick = { viewModel.navigateTo("dashboard") },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
                    shape = RoundedCornerShape(12.dp),
                    modifier = Modifier
                        .height(48.dp)
                        .testTag("unlock_premium_button")
                ) {
                    Text("Upgrade Plan & Unlock", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 14.sp)
                }
            }
        } else {
        // Unique handle for chat vs fields
        if (tool.name == "AI Chat Studio") {
            // Chat style view
            Column(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth()
            ) {
                LazyColumn(
                    modifier = Modifier
                        .weight(1f)
                        .fillMaxWidth(),
                    verticalArrangement = Arrangement.spacedBy(10.dp),
                    contentPadding = PaddingValues(vertical = 12.dp)
                ) {
                    items(chatHistory) { msg ->
                        val isUser = msg.sender == "user"
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = if (isUser) Arrangement.End else Arrangement.Start
                        ) {
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(
                                        topStart = 16.dp,
                                        topEnd = 16.dp,
                                        bottomStart = if (isUser) 16.dp else 2.dp,
                                        bottomEnd = if (isUser) 2.dp else 16.dp
                                    ))
                                    .background(
                                        if (isUser) {
                                            Brush.linearGradient(listOf(Color(0xFF3B82F6), Color(0xFF1E40AF)))
                                        } else {
                                            Brush.linearGradient(listOf(Color(0xFF1F1F2E), Color(0xFF1F1F24)))
                                        }
                                    )
                                    .border(
                                        width = 0.5.dp,
                                        color = if (isUser) NeonBlue else Color(0x33A78BFA),
                                        shape = RoundedCornerShape(
                                            topStart = 16.dp, 
                                            topEnd = 16.dp, 
                                            bottomStart = if (isUser) 16.dp else 2.dp, 
                                            bottomEnd = if (isUser) 2.dp else 16.dp
                                        )
                                    )
                                    .padding(14.dp)
                                    .widthIn(max = 280.dp)
                            ) {
                                MarkdownText(
                                    text = msg.text,
                                    color = Color.White,
                                    fontSize = 13.sp,
                                    lineHeight = 18.sp
                                )
                            }
                        }
                    }

                    if (generationState is GenerationUiState.Loading) {
                        item {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.Start
                            ) {
                                Card(
                                    colors = CardDefaults.cardColors(containerColor = GlassCardBg),
                                    modifier = Modifier.padding(8.dp)
                                ) {
                                    Text(
                                        text = "AI is thinking...",
                                        color = NeonCyan,
                                        fontSize = 12.sp,
                                        fontWeight = FontWeight.Bold,
                                        modifier = Modifier.padding(10.dp)
                                    )
                                }
                            }
                        }
                    }
                }

                // Input chat box
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(bottom = 12.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    OutlinedTextField(
                        value = chatInputText,
                        onValueChange = { chatInputText = it },
                        placeholder = { Text("What would you like to create?", color = Color.Gray) },
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            unfocusedTextColor = Color.White,
                            focusedBorderColor = NeonCyan,
                            unfocusedBorderColor = Color.DarkGray,
                            focusedContainerColor = Color(0xFF040409),
                            unfocusedContainerColor = Color(0xFF040409)
                        ),
                        modifier = Modifier.weight(1f),
                        shape = RoundedCornerShape(12.dp)
                    )

                    IconButton(
                        onClick = {
                            if (chatInputText.trim().isNotEmpty()) {
                                viewModel.sendChatMessage(chatInputText)
                                chatInputText = ""
                            }
                        },
                        modifier = Modifier
                            .background(
                                Brush.radialGradient(listOf(NeonPurple, NeonCyan)),
                                RoundedCornerShape(12.dp)
                            )
                            .size(48.dp)
                    ) {
                        Icon(imageVector = Icons.Filled.Send, contentDescription = "Send", tint = PureBlack)
                    }
                }
            }
        } else if (tool.id == "txt_to_img") {
            TextToImageWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "img_enhancer") {
            ImageEnhancerWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "img_to_video") {
            ImageToVideoWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "txt_to_video") {
            TextToVideoWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "bg_remover") {
            BackgroundRemoverWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "face_enhancer") {
            FaceEnhancerWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "avatar_gen") {
            AvatarGeneratorWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "video_editor") {
            AIVideoEditorWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "thumbnail_maker") {
            AIThumbnailMakerWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "voice_gen") {
            AIVoiceGeneratorWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "voice_clone") {
            AIVoiceCloneWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "presentation_maker") {
            AIPresentationMakerWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else if (tool.id == "pdf_chat") {
            PDFChatWorkspace(
                viewModel = viewModel,
                modifier = Modifier.weight(1f)
            )
        } else {
            // Form parameter fields + Response panel
            Column(
                modifier = Modifier
                    .weight(1f)
                    .verticalScroll(rememberScrollState())
            ) {
                Spacer(modifier = Modifier.height(14.dp))

                // Display form fields
                tool.params.forEach { param ->
                    when (param) {
                        is ToolParam.Text -> {
                            Text(
                                text = param.label,
                                color = Color.White,
                                fontSize = 12.sp,
                                fontWeight = FontWeight.Black,
                                modifier = Modifier.padding(bottom = 4.dp, top = 8.dp)
                            )
                            OutlinedTextField(
                                value = paramStateMap[param.label] ?: "",
                                onValueChange = { paramStateMap[param.label] = it },
                                placeholder = { Text(param.hint, color = Color.Gray) },
                                colors = OutlinedTextFieldDefaults.colors(
                                    focusedTextColor = Color.White,
                                    unfocusedTextColor = Color.White,
                                    focusedBorderColor = NeonCyan,
                                    unfocusedBorderColor = Color.DarkGray,
                                    focusedContainerColor = Color(0xFF07070F),
                                    unfocusedContainerColor = Color(0xFF07070F)
                                ),
                                shape = RoundedCornerShape(10.dp),
                                modifier = Modifier.fillMaxWidth().testTag("field_${param.label.replace(" ", "_")}")
                            )
                        }
                        is ToolParam.Choices -> {
                            var dropdownExpanded by remember { mutableStateFlowOf(false) }
                            val currentValue = paramStateMap[param.label] ?: ""

                            Text(
                                text = param.label,
                                color = Color.White,
                                fontSize = 12.sp,
                                fontWeight = FontWeight.Black,
                                modifier = Modifier.padding(bottom = 4.dp, top = 8.dp)
                            )

                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .border(1.dp, Color.DarkGray, RoundedCornerShape(10.dp))
                                    .background(Color(0xFF07070F), RoundedCornerShape(10.dp))
                                    .clickable { dropdownExpanded = true }
                                    .padding(vertical = 14.dp, horizontal = 12.dp)
                            ) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Text(text = currentValue, color = Color.White)
                                    Icon(imageVector = Icons.Filled.ArrowDropDown, contentDescription = "Dropdown", tint = Color.Gray)
                                }

                                DropdownMenu(
                                    expanded = dropdownExpanded,
                                    onDismissRequest = { dropdownExpanded = false },
                                    modifier = Modifier.background(Color(0xFF0F0F1A))
                                ) {
                                    param.options.forEach { option ->
                                        DropdownMenuItem(
                                            text = { Text(option, color = Color.White) },
                                            onClick = {
                                                paramStateMap[param.label] = option
                                                dropdownExpanded = false
                                            }
                                        )
                                    }
                                }
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(20.dp))

                // Submit button
                Button(
                    onClick = {
                        viewModel.generateContent(
                            toolName = tool.name,
                            categoryName = tool.category,
                            promptMap = paramStateMap.toMap()
                        )
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent),
                    contentPadding = PaddingValues(),
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(50.dp)
                        .clip(RoundedCornerShape(12.dp))
                        .background(Brush.horizontalGradient(listOf(NeonPurple, NeonCyan)))
                        .testTag("submit_generation_button")
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(imageVector = Icons.Filled.PlayArrow, contentDescription = "Go", tint = PureBlack)
                        Spacer(modifier = Modifier.width(6.dp))
                        Text("Launch AI Engine", color = PureBlack, fontWeight = FontWeight.Black, fontSize = 15.sp)
                    }
                }

                Spacer(modifier = Modifier.height(24.dp))

                // UI Loading / Error / Success States
                when (val execution = generationState) {
                    is GenerationUiState.Loading -> {
                        Box(
                            contentAlignment = Alignment.Center,
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(160.dp)
                                .neonBorder(NeonCyan)
                                .background(GlassCardBg, RoundedCornerShape(16.dp))
                        ) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                CircularProgressIndicator(color = NeonCyan)
                                Spacer(modifier = Modifier.height(14.dp))
                                Text("Engaging Creator Neural Network...", color = Color.LightGray, fontSize = 12.sp)
                            }
                        }
                    }
                    is GenerationUiState.Error -> {
                        Card(
                            colors = CardDefaults.cardColors(containerColor = Color(0x33FF0000)),
                            border = BorderStroke(1.dp, Color.Red),
                            shape = RoundedCornerShape(12.dp),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Column(modifier = Modifier.padding(16.dp)) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(imageVector = Icons.Filled.Error, contentDescription = "Error", tint = Color.Red)
                                    Spacer(modifier = Modifier.width(8.dp))
                                    Text("Generation Unsuccessful", color = Color.White, fontWeight = FontWeight.Bold)
                                }
                                Spacer(modifier = Modifier.height(6.dp))
                                Text(execution.message, color = Color.LightGray, fontSize = 12.sp)
                            }
                        }
                    }
                    is GenerationUiState.Success -> {
                        if (tool.id == "app_builder") {
                            InteractiveAppBuilderWorkspace(
                                topic = paramStateMap["Topic"] ?: "My Smart App",
                                architecture = paramStateMap["Architecture"] ?: "Compose Kotlin Structure",
                                generatedCode = execution.result,
                                viewModel = viewModel
                            )
                        } else if (tool.id == "web_builder") {
                            InteractiveWebsiteBuilderWorkspace(
                                topic = paramStateMap["Topic"] ?: "My Concept Website",
                                format = paramStateMap["Format"] ?: "Generate Websites",
                                generatedCode = execution.result,
                                viewModel = viewModel
                            )
                        } else {
                            // Success View
                            Card(
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF090912)),
                                border = BorderStroke(1.dp, NeonPurple),
                                shape = RoundedCornerShape(16.dp),
                                modifier = Modifier.fillMaxWidth().testTag("generation_result_card")
                            ) {
                                Column(modifier = Modifier.padding(16.dp)) {
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Text("GENERATED ARTIFACT", color = NeonCyan, fontSize = 11.sp, fontWeight = FontWeight.Black)

                                        Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                            IconButton(
                                                onClick = {
                                                    val mockCreation = CreationEntity(
                                                        id = 101, // Mock temporary ID
                                                        toolName = tool.name,
                                                        category = tool.category,
                                                        inputPrompt = paramStateMap.values.joinToString(" | "),
                                                        outputText = execution.result,
                                                        isSaved = true
                                                    )
                                                    viewModel.toggleSaveProject(mockCreation)
                                                    Toast.makeText(context, "Added project to Saved Repository!", Toast.LENGTH_SHORT).show()
                                                }
                                            ) {
                                                Icon(imageVector = Icons.Filled.Star, contentDescription = "Save", tint = NeonCyan)
                                            }

                                            IconButton(
                                                onClick = {
                                                    val mockCreation = CreationEntity(
                                                        id = 101,
                                                        toolName = tool.name,
                                                        category = tool.category,
                                                        inputPrompt = paramStateMap.values.joinToString(" | "),
                                                        outputText = execution.result
                                                    )
                                                    viewModel.triggerMockDownload(mockCreation)
                                                }
                                            ) {
                                                Icon(imageVector = Icons.Filled.CloudDownload, contentDescription = "Export File", tint = NeonBlue)
                                            }
                                        }
                                    }

                                    if (generatedImageRes != null) {
                                        Spacer(modifier = Modifier.height(10.dp))
                                        val isVideoTool = tool.category == "Video Tools" || tool.name.contains("Video")
                                        Box(
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .height(200.dp)
                                                .clip(RoundedCornerShape(10.dp))
                                                .background(Color.DarkGray)
                                        ) {
                                            if (isVideoTool) {
                                                val infiniteTransition = rememberInfiniteTransition(label = "workbench_video_transition")
                                                val animatedScale by infiniteTransition.animateFloat(
                                                    initialValue = 1.0f,
                                                    targetValue = 1.15f,
                                                    animationSpec = infiniteRepeatable(
                                                        animation = tween(durationMillis = 6000, easing = LinearEasing),
                                                        repeatMode = RepeatMode.Reverse
                                                    ),
                                                    label = "scale"
                                                )
                                                val animatedTranslateX by infiniteTransition.animateFloat(
                                                    initialValue = -15f,
                                                    targetValue = 15f,
                                                    animationSpec = infiniteRepeatable(
                                                        animation = tween(durationMillis = 6000, easing = LinearEasing),
                                                        repeatMode = RepeatMode.Reverse
                                                    ),
                                                    label = "translateX"
                                                )
                                                val animatedTranslateY by infiniteTransition.animateFloat(
                                                    initialValue = -10f,
                                                    targetValue = 10f,
                                                    animationSpec = infiniteRepeatable(
                                                        animation = tween(durationMillis = 4000, easing = LinearEasing),
                                                        repeatMode = RepeatMode.Reverse
                                                    ),
                                                    label = "translateY"
                                                )
                                                AsyncImage(
                                                    model = generatedImageRes,
                                                    contentDescription = "Generated Cinematic Video Render",
                                                    contentScale = ContentScale.Crop,
                                                    modifier = Modifier
                                                        .fillMaxSize()
                                                        .graphicsLayer {
                                                            scaleX = animatedScale
                                                            scaleY = animatedScale
                                                            translationX = animatedTranslateX
                                                            translationY = animatedTranslateY
                                                        }
                                                )
                                                Box(
                                                    modifier = Modifier
                                                        .fillMaxSize()
                                                        .background(
                                                            Brush.radialGradient(
                                                                colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.72f))
                                                            )
                                                        )
                                                )
                                            } else {
                                                AsyncImage(
                                                    model = generatedImageRes,
                                                    contentDescription = "Generated Media Content",
                                                    contentScale = ContentScale.Crop,
                                                    modifier = Modifier.fillMaxSize()
                                                )
                                            }
                                        }
                                    }

                                    if (generatedImageRes == null) {
                                        Spacer(modifier = Modifier.height(12.dp))

                                        SelectionContainer {
                                            Text(
                                                text = execution.result,
                                                color = Color.White,
                                                fontSize = 14.sp,
                                                lineHeight = 20.sp
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }
                    else -> {}
                }

                Spacer(modifier = Modifier.height(40.dp))
            }
        }
        }
    }
}

// ==========================================
// ADMIN CONTROL PANEL VIEW
// ==========================================
@Composable
fun AdminScreenView(
    viewModel: CreatorViewModel
) {
    val userStats by viewModel.userStats.collectAsState()

    var activeModerationBlock by remember { mutableStateFlowOf(true) }

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 20.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        item {
            Text(
                text = "Operational Admin Control",
                color = Color.White,
                fontSize = 24.sp,
                fontWeight = FontWeight.Black,
                modifier = Modifier.padding(top = 16.dp)
            )
        }

        // Operational server pulses metrics
        item {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                AdminServerIndicatorCard(
                    service = "API Gateway",
                    isOnline = true,
                    modifier = Modifier.weight(1f)
                )
                AdminServerIndicatorCard(
                    service = "Database Sync",
                    isOnline = true,
                    modifier = Modifier.weight(1f)
                )
            }
        }

        userStats?.let { stats ->
            // Moderation Block switch
            item {
                Card(
                    colors = CardDefaults.cardColors(containerColor = GlassCardBg),
                    border = BorderStroke(0.5.dp, Color(0x3322D3EE)),
                    shape = RoundedCornerShape(16.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text("CUSTOMER ACCOUNT CONTROLS", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Black)
                        Spacer(modifier = Modifier.height(12.dp))

                        Text("Viewing Account: ${stats.email}", color = Color.White, fontSize = 14.sp, fontWeight = FontWeight.Bold)
                        Spacer(modifier = Modifier.height(6.dp))

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text("Account Moderation Status", color = Color.LightGray, fontSize = 13.sp)
                            Switch(
                                checked = activeModerationBlock,
                                onCheckedChange = {
                                    activeModerationBlock = it
                                    viewModel.adminUpdateUserStats(stats.copy(isSystemApproved = it))
                                },
                                colors = SwitchDefaults.colors(
                                    checkedThumbColor = NeonCyan,
                                    checkedTrackColor = Color(0xFF163E44)
                                )
                            )
                        }
                    }
                }
            }

            // Simulated financial analytics / transactions
            item {
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0B0715)),
                    border = BorderStroke(0.5.dp, NeonPurple.copy(alpha = 0.5f)),
                    shape = RoundedCornerShape(16.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text("PLATFORM FINANCIAL INTEL", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Black)
                        Spacer(modifier = Modifier.height(14.dp))

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Column {
                                Text("ESTIMATED ARR", color = Color.Gray, fontSize = 11.sp)
                                Text("$128,450", color = Color.White, fontSize = 20.sp, fontWeight = FontWeight.Black)
                            }
                            Column {
                                Text("TOTAL REV MO", color = Color.Gray, fontSize = 11.sp)
                                Text("$12,400", color = NeonCyan, fontSize = 20.sp, fontWeight = FontWeight.Black)
                            }
                        }

                        Spacer(modifier = Modifier.height(16.dp))

                        Divider(color = Color(0x22FFFFFF), thickness = 0.5.dp)

                        Spacer(modifier = Modifier.height(12.dp))

                        Text(
                            text = "Revenue tracking includes subscription upgrades and extra credit bundle purchases.",
                            color = Color.Gray,
                            fontSize = 11.sp,
                            lineHeight = 14.sp
                        )
                    }
                }
            }
        }

        item {
            Spacer(modifier = Modifier.height(40.dp))
        }
    }
}

@Composable
fun AdminServerIndicatorCard(
    service: String,
    isOnline: Boolean,
    modifier: Modifier = Modifier
) {
    Card(
        colors = CardDefaults.cardColors(containerColor = GlassCardBg),
        border = BorderStroke(0.5.dp, Color(0x22FFFFFF)),
        shape = RoundedCornerShape(12.dp),
        modifier = modifier.height(68.dp)
    ) {
        Row(
            modifier = Modifier
                .fillMaxSize()
                .padding(12.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            Column {
                Text(service, color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                Spacer(modifier = Modifier.height(2.dp))
                Text(if (isOnline) "OPERATIONAL" else "OFFLINE", color = if (isOnline) NeonCyan else Color.Red, fontSize = 9.sp, fontWeight = FontWeight.Black)
            }

            Box(
                modifier = Modifier
                    .size(10.dp)
                    .clip(RoundedCornerShape(5.dp))
                    .background(if (isOnline) NeonCyan else Color.Red)
            )
        }
    }
}

