// Helper helper state
@Composable
fun <T> rememberState(initialValue: T): MutableState<T> = remember { mutableStateOf(initialValue) }

fun <T> mutableStateFlowOf(initialValue: T): MutableState<T> = mutableStateOf(initialValue)

// ==========================================
// INTERACTIVE APP BUILDER MODEL & COMPONENT
// ==========================================
data class ChatMessage(
    val sender: String, // "user", "gemini"
    val text: String,
    val timestamp: String = "Just now"
)

@Composable
fun AiCopilotChatPanel(
    messages: List<ChatMessage>,
    inputValue: String,
    onValueChange: (String) -> Unit,
    onSend: () -> Unit,
    modifier: Modifier = Modifier
) {
    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFF030307))
            .padding(6.dp)
    ) {
        // AI Header bar with glowing status indicator
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color(0xFF0C0C1B), RoundedCornerShape(8.dp))
                .border(0.5.dp, NeonCyan.copy(alpha = 0.3f), RoundedCornerShape(8.dp))
                .padding(horizontal = 8.dp, vertical = 6.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Box(
                modifier = Modifier
                    .size(6.dp)
                    .background(Color(0xFF10B981), RoundedCornerShape(3.dp))
            )
            Spacer(modifier = Modifier.width(6.dp))
            Text(
                text = "🤖 GEMINI CODING AGENT",
                color = Color.White,
                fontSize = 11.sp,
                fontWeight = FontWeight.Bold,
                letterSpacing = 0.5.sp
            )
        }

        Spacer(modifier = Modifier.height(6.dp))

        // Chats Scroll Stream
        val scrollState = rememberScrollState()
        Box(
            modifier = Modifier
                .weight(1f)
                .fillMaxWidth()
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .verticalScroll(scrollState)
                    .padding(horizontal = 2.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                messages.forEach { msg ->
                    val isGemini = msg.sender == "gemini"
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = if (isGemini) Arrangement.Start else Arrangement.End
                    ) {
                        Row(
                            horizontalArrangement = Arrangement.spacedBy(6.dp),
                            modifier = Modifier.widthIn(max = 220.dp)
                        ) {
                            if (isGemini) {
                                Box(
                                    modifier = Modifier
                                        .size(20.dp)
                                        .background(
                                            Brush.linearGradient(listOf(NeonPurple, NeonCyan)),
                                            RoundedCornerShape(10.dp)
                                        ),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text("AI", color = PureBlack, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            Column(
                                modifier = Modifier
                                    .background(
                                        color = if (isGemini) Color(0xFF0D0D19) else NeonPurple.copy(alpha = 0.15f),
                                        shape = RoundedCornerShape(
                                            topStart = if (isGemini) 0.dp else 10.dp,
                                            topEnd = if (isGemini) 10.dp else 0.dp,
                                            bottomStart = 10.dp,
                                            bottomEnd = 10.dp
                                        )
                                    )
                                    .border(
                                        width = 0.5.dp,
                                        color = if (isGemini) Color(0x2222D3EE) else NeonPurple.copy(alpha = 0.4f),
                                        shape = RoundedCornerShape(
                                            topStart = if (isGemini) 0.dp else 10.dp,
                                            topEnd = if (isGemini) 10.dp else 0.dp,
                                            bottomStart = 10.dp,
                                            bottomEnd = 10.dp
                                        )
                                    )
                                    .padding(8.dp)
                            ) {
                                Text(
                                    text = msg.text,
                                    color = Color.White,
                                    fontSize = 11.sp,
                                    lineHeight = 15.sp
                                )
                                Spacer(modifier = Modifier.height(2.dp))
                                Text(
                                    text = msg.timestamp,
                                    color = Color.DarkGray,
                                    fontSize = 8.sp,
                                    textAlign = TextAlign.End,
                                    modifier = Modifier.fillMaxWidth()
                                )
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(6.dp))

        // Small context suggestion chips
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .horizontalScroll(rememberScrollState())
                .padding(bottom = 4.dp),
            horizontalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            val suggestions = listOf("🔑 Add Login Screen", "💾 Add SQLite Room DB", "🎨 Use Forest Green Theme")
            suggestions.forEach { chipText ->
                Box(
                    modifier = Modifier
                        .background(Color(0xFF060612), RoundedCornerShape(12.dp))
                        .border(0.5.dp, Color(0x3322D3EE), RoundedCornerShape(12.dp))
                        .clickable { onValueChange(chipText.substring(2)) }
                        .padding(horizontal = 8.dp, vertical = 4.dp)
                ) {
                    Text(text = chipText, color = NeonCyan, fontSize = 9.sp, fontWeight = FontWeight.SemiBold)
                }
            }
        }

        // Input send box
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.spacedBy(4.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            OutlinedTextField(
                value = inputValue,
                onValueChange = onValueChange,
                placeholder = { Text("Ask Gemini AI to build features...", color = Color.Gray, fontSize = 10.sp) },
                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                singleLine = true,
                maxLines = 1,
                colors = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor = NeonCyan,
                    unfocusedBorderColor = Color(0x2222D3EE),
                    focusedContainerColor = Color(0xFF060611),
                    unfocusedContainerColor = Color(0xFF030307)
                ),
                shape = RoundedCornerShape(8.dp),
                modifier = Modifier.weight(1f),
                keyboardOptions = KeyboardOptions(imeAction = ImeAction.Send),
                keyboardActions = KeyboardActions(onSend = { onSend() })
            )

            IconButton(
                onClick = onSend,
                modifier = Modifier
                    .size(34.dp)
                    .clip(RoundedCornerShape(8.dp))
                    .background(NeonPurple)
            ) {
                Icon(
                    imageVector = Icons.Filled.Send,
                    contentDescription = "Send prompts to Builder",
                    tint = Color.White,
                    modifier = Modifier.size(14.dp)
                )
            }
        }
    }
}

// ==========================================
// INTERACTIVE APP BUILDER WORKSPACE
// ==========================================
@Composable
fun InteractiveAppBuilderWorkspace(
    topic: String,
    architecture: String,
    generatedCode: String,
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    var cleanTopic by remember { mutableStateOf(if (topic.isBlank()) "Smart Concept App" else topic) }
    
    // Derived camelName
    val camelTopic = remember(cleanTopic) {
        cleanTopic.split(" ").joinToString("") { it.replaceFirstChar { c -> if (c.isLowerCase()) c.uppercase() else c.toString() } }
    }

    var activeAppType by remember {
        val initialTopic = topic.lowercase()
        val defaultType = when {
            initialTopic.contains("game") || initialTopic.contains("running") || initialTopic.contains("play") -> "game"
            initialTopic.contains("finance") || initialTopic.contains("money") || initialTopic.contains("budget") -> "finance"
            initialTopic.contains("weather") || initialTopic.contains("temp") -> "weather"
            initialTopic.contains("task") || initialTopic.contains("todo") || initialTopic.contains("list") -> "todo"
            else -> "general"
        }
        mutableStateOf(defaultType)
    }

    // Tab state: 0 = Explorer, 1 = Editor, 2 = Terminal, 3 = Emulator (mobile)
    var activeTab by remember { mutableStateOf(0) }
    var selectedFile by remember { mutableStateOf("MainActivity.kt") }

    // Target Platform selection & services states
    var targetPlatform by remember { mutableStateOf("Android") } // "Android" or "iOS"
