                    // SwiftUI API Call and JSON Decoder Integration
                    struct TelemetryData: Codable, Identifiable {
                        let id = UUID()
                        let key: String
                        let value: Double
                    }

                    class ApiService: ObservableObject {
                        @Published var logs: [TelemetryData] = []
                        
                        func fetchTelemetryLogs() {
                            guard let url = URL(string: "https://api.${cleanTopic.lowercase().replace(" ", "")}.com/v1/telemetry") else { return }
                            URLSession.shared.dataTaskPublisher(for: url)
