    // Clean Build Trigger Action
    val triggerBuild: () -> Unit = {
        if (!isCompiling) {
            isCompiling = true
            compileProgress = 0.0f
            terminalLogs.clear()
            terminalLogs.add("[GRADLE] Starting build task...")
            terminalLogs.add("[INFO] Resolving model context dependencies...")
            
            coroutineScope.launch {
                val steps = listOf(
                    "Executing: gradle build" to 0.1f,
                    "Resolving version catalog standard definitions..." to 0.25f,
                    "> Task :app:preBuild UP-TO-DATE" to 0.35f,
                    "> Task :app:preDebugBuild UP-TO-DATE" to 0.45f,
                    "> Task :app:generateDebugBuildConfig" to 0.6f,
                    "> Task :app:kspDebugKotlin successfully executed" to 0.75f,
                    "> Task :app:compileDebugKotlin (analyzing class maps)" to 0.85f,
                    "[SUCCESS] Gradle execution completed successfully (exit code 0)" to 0.95f,
                    "Virtual Emulator synced & updated successfully!" to 1.0f
                )
                
                for (step in steps) {
                    delay(250)
                    terminalLogs.add(step.first)
                    compileProgress = step.second
                }
                isCompiling = false
                Toast.makeText(context, "Build successful! Live emulator updated.", Toast.LENGTH_SHORT).show()
            }
        }
    }

    // AI Chat submission callback
    val submitAiChat: () -> Unit = {
        if (chatInputValue.isNotBlank() && !isCompiling) {
            val userPrompt = chatInputValue
            chatMessages.add(ChatMessage(sender = "user", text = userPrompt))
            chatInputValue = ""

            // Switch layout automatically to Compiler Terminal so user can see it compile live!
            activeTab = 2 // Log tab in Center
            isCompiling = true
            compileProgress = 0.0f

            coroutineScope.launch {
                terminalLogs.clear()
                terminalLogs.add("[AI AGENT] Received prompt directive: \"$userPrompt\"")
                delay(300)
                terminalLogs.add("[AI AGENT] Checking selected workspace topic: \"$cleanTopic\"...")
                delay(200)
                terminalLogs.add("[AI AGENT] Restructuring MainActivity AST and Theme components...")
                delay(400)
                terminalLogs.add("[INFO] Synced incremental code maps.")

                var matchingTitle = "General Interface Accent"
                val lowerPrompt = userPrompt.lowercase()

                val isGameIntent = lowerPrompt.contains("game") || lowerPrompt.contains("run") || lowerPrompt.contains("jump") || lowerPrompt.contains("play") || lowerPrompt.contains("mario") || lowerPrompt.contains("arcade")
                val isFinanceIntent = lowerPrompt.contains("finance") || lowerPrompt.contains("money") || lowerPrompt.contains("budget") || lowerPrompt.contains("expense") || lowerPrompt.contains("credit") || lowerPrompt.contains("pay") || lowerPrompt.contains("transaction") || lowerPrompt.contains("bank")

                if (isGameIntent) {
                    matchingTitle = "Playable Running Arcade Game"
                    activeAppType = "game"
                    cleanTopic = "Run Jump Run Adventure"
                    activeEmulatorScreen = "dashboard"
                } else if (isFinanceIntent) {
                    matchingTitle = "Wealth Transaction Ledger"
                    activeAppType = "finance"
                    cleanTopic = "Gold Capital Tracker"
