                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                listOf("Android APK", "iOS IPA Archive").forEach { pack ->
                                    val isSel = (pack.startsWith("Android") && exportModeType == "Android") ||
                                                (pack.startsWith("iOS") && exportModeType == "iOS")
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .clip(RoundedCornerShape(6.dp))
                                            .background(if (isSel) NeonPurple.copy(alpha = 0.3f) else Color.Transparent)
                                            .border(1.dp, if (isSel) NeonPurple else Color.Transparent, RoundedCornerShape(6.dp))
                                            .clickable { if (!isExportingProgress) exportModeType = if (pack.startsWith("Android")) "Android" else "iOS" }
                                            .padding(vertical = 8.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(pack, color = if (isSel) Color.White else Color.Gray, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }
                            
                            if (isExportingProgress) {
                                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                    LinearProgressIndicator(
                                        progress = exportProgressValue,
                                        color = NeonCyan,
                                        trackColor = Color(0xFF151528),
                                        modifier = Modifier.fillMaxWidth().height(6.dp).clip(RoundedCornerShape(3.dp))
                                    )
                                    Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                                        Text(exportStatusText, color = Color.Gray, fontSize = 9.sp)
                                        Text("${(exportProgressValue * 100).toInt()}%", color = NeonCyan, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            } else {
                                // Specs information card
                                Card(
                                    colors = CardDefaults.cardColors(containerColor = Color(0xFF050511)),
                                    border = BorderStroke(1.dp, NeonPurple.copy(alpha = 0.3f)),
