                                        Text("BUNDLE ATTRIBUTES:", color = NeonPurple, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                        Text("• Target: ${if (exportModeType == "Android") "Android APK (SDK 34)" else "Swift iOS Archive (v17)"}", color = Color.White, fontSize = 9.sp)
                                        Text("• Modules: ${listOfNotNull(
                                            "UI Components",
                                            if (databaseEnabled) "Database Core" else null,
                                            if (firebaseEnabled) "Firebase SDK" else null,
                                            if (loginEnabled) "Biometric Auth" else null,
                                            if (apiEnabled) "REST Client" else null,
                                            if (notificationsEnabled) "FCM Push" else null
                                        ).joinToString(", ")}", color = Color.White, fontSize = 9.sp)
                                        Text("• Key Signing: SHA-256 Dynamic AI Signature", color = Color.White, fontSize = 9.sp)
                                    }
                                }
                            }
                        }
                    },
                    confirmButton = {
