                            if (exportProgressValue >= 1f) {
                                Button(
                                    onClick = {
                                        val mockCreation = CreationEntity(
                                            id = (100..999).random(),
                                            toolName = if (exportModeType == "Android") "Android Package Export" else "iOS Archive Export",
                                            category = "Package Manager",
                                            inputPrompt = "$cleanTopic compilation bundle output",
                                            outputText = "Compilation export successfully built for $cleanTopic.",
                                            isSaved = true
                                        )
                                        viewModel.triggerMockDownload(mockCreation)
                                        showExportDialog = false
                                        exportProgressValue = 0f
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF10B981))
                                ) {
                                    Text("Download Final Package 📥", fontSize = 11.sp, color = PureBlack, fontWeight = FontWeight.Bold)
                                }
                            } else {
                                Button(
                                    onClick = {
                                        isExportingProgress = true
                                        exportProgressValue = 0f
