                                            val logSteps = listOf(
                                                "Synchronizing workspace directory trees..." to 0.15f,
                                                "Analyzing dynamic resource constraints..." to 0.30f,
                                                "Injecting localized translation models..." to 0.45f,
                                                "Compiling asset maps and dynamic indexers..." to 0.60f,
                                                "Executing package optimizer class mergers..." to 0.75f,
                                                "Cryptographically signing certificate blocks..." to 0.90f,
                                                "Package production generated successfully!" to 1.0f
                                            )
                                            for (step in logSteps) {
                                                exportStatusText = step.first
                                                delay(350)
                                                exportProgressValue = step.second
                                            }
                                            isExportingProgress = false
                                        }
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = NeonCyan)
                                ) {
                                    Text("Initiate Compilation Export", fontSize = 11.sp, color = PureBlack, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    },
                    dismissButton = {
                        if (!isExportingProgress) {
                            TextButton(onClick = { showExportDialog = false; exportProgressValue = 0f }) {
                                Text("Cancel", color = Color.Gray)
                            }
                        }
                    }
