            HorizontalDivider(color = Color(0x3322D3EE), thickness = 1.dp)
            Spacer(modifier = Modifier.height(10.dp))

            // Horizon Registry of Configured SDKs & Integrations
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF070716)),
                border = BorderStroke(1.dp, NeonPurple.copy(alpha = 0.3f)),
                shape = RoundedCornerShape(12.dp),
                modifier = Modifier.fillMaxWidth().padding(bottom = 12.dp)
            ) {
                Column(modifier = Modifier.padding(12.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "🛠️ SDK & INTEGRATIONS SERVICE REGISTRY",
                            color = NeonCyan,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Black
                        )
                        Row(
                            horizontalArrangement = Arrangement.spacedBy(6.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text("Active: $targetPlatform", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Box(
                                modifier = Modifier
