                                    .border(1.dp, Color(0x3322D3EE), RoundedCornerShape(12.dp))
                            ) {
                                when (activeTab) {
                                    0 -> FileExplorerView(
                                        files = filesState,
                                        selectedFile = selectedFile,
                                        onFileSelect = { selectedFile = it; activeTab = 1 }
                                    )
                                    1 -> CodeEditorTab(
                                        fileName = selectedFile,
                                        content = filesState[selectedFile] ?: ""
                                    )
                                    2 -> TerminalTab(
