                                .fillMaxWidth()
                                .background(Color(0xFF030307), RoundedCornerShape(12.dp))
                                .border(1.dp, Color(0x3322D3EE), RoundedCornerShape(12.dp))
                        ) {
                            when (activeTab) {
                                0 -> AiCopilotChatPanel(
                                    messages = chatMessages,
                                    inputValue = chatInputValue,
                                    onValueChange = { chatInputValue = it },
                                    onSend = submitAiChat
                                )
                                1 -> FileExplorerView(
                                    files = filesState,
                                    selectedFile = selectedFile,
                                    onFileSelect = { selectedFile = it; activeTab = 2 }
                                )
                                2 -> CodeEditorTab(
                                    fileName = selectedFile,
                                    content = filesState[selectedFile] ?: ""
                                )
                                3 -> TerminalTab(
                                    logs = terminalLogs,
                                    isCompiling = isCompiling,
                                    progress = compileProgress
                                )
                                4 -> VirtualEmulatorFrame(
                                    appLabel = cleanTopic,
                                    activeScreen = activeEmulatorScreen,
                                    onScreenChange = { activeEmulatorScreen = it },
                                    primaryColor = emulatorPrimaryColor,
                                    itemList = emulatorList,
                                    itemText = emulatorItemText,
                                    onTextChange = { emulatorItemText = it },
                                    onAddItem = {
                                        if (emulatorItemText.isNotBlank()) {
                                            emulatorList.add(0, emulatorItemText)
                                            emulatorItemText = ""
                                        }
                                    },
                                    onRemoveItem = { item -> emulatorList.remove(item) },
                                    targetPlatform = targetPlatform,
                                    activePushMessage = activePushMessage,
                                    onDismissPush = { activePushMessage = null },
                                    activeAppType = activeAppType
                                )
                                else -> AiCopilotChatPanel(
                                    messages = chatMessages,
                                    inputValue = chatInputValue,
                                    onValueChange = { chatInputValue = it },
                                    onSend = submitAiChat
                                )
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun FileExplorerView(
    files: Map<String, String>,
    selectedFile: String,
    onFileSelect: (String) -> Unit
) {
    val scrollState = rememberScrollState()
    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(scrollState)
            .padding(12.dp),
        verticalArrangement = Arrangement.spacedBy(6.dp)
    ) {
        Text(
            text = "📁 PROJECT ROOT (com.example.conceptapp)",
            color = Color.Gray,
            fontSize = 11.sp,
            fontWeight = FontWeight.Bold,
            modifier = Modifier.padding(bottom = 6.dp)
        )
        
        for (fileName in files.keys) {
            val isSelected = fileName == selectedFile
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .clip(RoundedCornerShape(8.dp))
                    .background(if (isSelected) Color(0x1F22D3EE) else Color.Transparent)
                    .clickable { onFileSelect(fileName) }
                    .padding(horizontal = 10.dp, vertical = 10.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Icon(
                    imageVector = when {
                        fileName.endsWith(".xml") -> Icons.Filled.List
                        fileName.endsWith(".kts") -> Icons.Filled.Build
                        else -> Icons.Filled.Code
                    },
                    contentDescription = null,
                    tint = if (isSelected) NeonCyan else Color.LightGray,
                    modifier = Modifier.size(16.dp)
                )
                Text(
                    text = fileName,
                    color = if (isSelected) NeonCyan else Color.White,
                    fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                    fontSize = 13.sp
                )
            }
        }
    }
}

@Composable
fun CodeEditorTab(
    fileName: String,
    content: String
) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(8.dp)
    ) {
        // Filename bar
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color(0xFF0F0F1A), RoundedCornerShape(topStart = 8.dp, topEnd = 8.dp))
                .padding(horizontal = 12.dp, vertical = 6.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Icon(
                imageVector = Icons.Filled.Code,
                contentDescription = null,
                tint = NeonCyan,
                modifier = Modifier.size(14.dp)
            )
            Spacer(modifier = Modifier.width(6.dp))
            Text(
                text = fileName,
                color = Color.White,
                fontSize = 11.sp,
                fontWeight = FontWeight.Bold
            )
        }
        
        // Code lines scrollable area
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFF07070F))
                .padding(8.dp)
        ) {
            val scrollState = rememberScrollState()
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .verticalScroll(scrollState)
            ) {
                val lines = content.split("\n")
                for (idx in lines.indices) {
                    val line = lines[idx]
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Text(
                            text = String.format("%02d", idx + 1),
                            color = Color.DarkGray,
                            fontSize = 10.sp,
                            fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                            textAlign = TextAlign.End,
                            modifier = Modifier.width(18.dp)
                        )
                        SyntaxHighlightedText(code = line)
                    }
                }
            }
        }
    }
}

@Composable
fun TerminalTab(
    logs: List<String>,
    isCompiling: Boolean,
    progress: Float
) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(12.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(6.dp)
            ) {
                Icon(
                    imageVector = Icons.Filled.Build,
                    contentDescription = null,
                    tint = NeonCyan,
                    modifier = Modifier.size(14.dp)
                )
                Text(
                    text = "GRADLE BUILD TERMINAL",
                    color = Color.White,
                    fontSize = 11.sp,
                    fontWeight = FontWeight.Bold
                )
            }
            
            if (isCompiling) {
                Text(
                    text = "${(progress * 100).toInt()}% compiled",
                    color = NeonCyan,
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Bold
                )
            }
        }

        Spacer(modifier = Modifier.height(8.dp))

        if (isCompiling) {
            LinearProgressIndicator(
                progress = progress,
                color = NeonCyan,
                trackColor = Color(0xFF151528),
                modifier = Modifier
                    .fillMaxWidth()
                    .height(4.dp)
                    .clip(RoundedCornerShape(2.dp))
            )
            Spacer(modifier = Modifier.height(10.dp))
        }

        Box(
            modifier = Modifier
                .weight(1f)
                .fillMaxWidth()
                .background(Color(0xFF020205), RoundedCornerShape(8.dp))
                .border(0.5.dp, Color(0x3322D3EE), RoundedCornerShape(8.dp))
                .padding(10.dp)
        ) {
            val scrollState = rememberScrollState()
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .verticalScroll(scrollState),
                verticalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                logs.forEach { logLine ->
                    val color = when {
                        logLine.contains("[SUCCESS]") || logLine.contains("successfully") -> Color(0xFF10B981)
                        logLine.contains("[ERROR]") || logLine.contains("FAILED") -> Color(0xFFEF4444)
                        logLine.contains("[GRADLE]") || logLine.startsWith(">") -> NeonPurple
                        logLine.contains("[SYSTEM]") -> NeonCyan
                        else -> Color.LightGray
                    }
                    Text(
                        text = logLine,
                        color = color,
                        fontSize = 11.sp,
                        fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                        lineHeight = 15.sp
                    )
                }
            }
        }
    }
}

@Composable
fun VirtualEmulatorFrame(
    appLabel: String,
    activeScreen: String,
    onScreenChange: (String) -> Unit,
    primaryColor: Color,
    itemList: List<String>,
    itemText: String,
    onTextChange: (String) -> Unit,
    onAddItem: () -> Unit,
    onRemoveItem: (String) -> Unit,
    targetPlatform: String = "Android",
    activePushMessage: String? = null,
    onDismissPush: () -> Unit = {},
    activeAppType: String = "general"
) {
    val isIos = targetPlatform == "iOS"
    val frameBorderColor = if (isIos) Color(0xFFCCCCCC) else NeonPurple
    val frameBackgroundColor = if (isIos) Color(0xFF0F0F12) else Color(0xFF0F0F1E)

    Box(
        modifier = Modifier
            .width(280.dp)
            .fillMaxHeight()
            .clip(RoundedCornerShape(32.dp))
            .background(frameBackgroundColor)
            .border(3.dp, frameBorderColor, RoundedCornerShape(32.dp))
    ) {
        Column(modifier = Modifier.fillMaxSize()) {
            // System Status Bar Mock
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(28.dp)
                    .background(Color(0xFF0B0B15))
                    .padding(horizontal = 16.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = "09:41",
                    color = Color.White,
                    fontSize = 10.sp,
                    fontWeight = FontWeight.Bold
                )

                if (isIos) {
                    // Apple Dynamic Island Pill
                    Box(
                        modifier = Modifier
                            .width(60.dp)
                            .height(14.dp)
                            .clip(RoundedCornerShape(7.dp))
                            .background(Color.Black)
                    )
                } else {
                    // Android Punch Hole
                    Box(
                        modifier = Modifier
                            .size(10.dp)
                            .clip(CircleShape)
                            .background(Color.Black)
                    )
                }

                Row(
                    horizontalArrangement = Arrangement.spacedBy(4.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    if (isIos) {
                        Icon(imageVector = Icons.Filled.Wifi, contentDescription = null, tint = Color.White, modifier = Modifier.size(10.dp))
                        Icon(imageVector = Icons.Filled.Star, contentDescription = null, tint = Color.Green, modifier = Modifier.size(10.dp))
                    } else {
                        Icon(imageVector = Icons.Filled.Star, contentDescription = null, tint = Color.White, modifier = Modifier.size(10.dp))
                        Icon(imageVector = Icons.Filled.Check, contentDescription = null, tint = Color.White, modifier = Modifier.size(10.dp))
                    }
                }
            }

            // Screen Canvas Box
            Box(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth()
                    .background(Color(0xFF07070C))
            ) {
                Column(modifier = Modifier.fillMaxSize()) {
                    // Customized dynamic toolbar Header
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Brush.horizontalGradient(listOf(primaryColor, NeonPurple)))
                            .padding(horizontal = 12.dp, vertical = 10.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.SpaceBetween
                    ) {
                        Text(
                            text = appLabel.take(20),
                            color = PureBlack,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black
                        )
                        Box(
                            modifier = Modifier
                                .background(PureBlack.copy(alpha = 0.2f), RoundedCornerShape(4.dp))
                                .padding(horizontal = 4.dp, vertical = 2.dp)
                        ) {
                            Text(
                                text = if (isIos) "iOS 17" else "SDK 34",
                                color = PureBlack,
                                fontSize = 8.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }

                    // Interactive Content Switcher based on Active Simulated Screen
                    Column(
                        modifier = Modifier
                            .weight(1f)
                            .fillMaxWidth()
                            .padding(10.dp)
                    ) {
                        when (activeScreen) {
                            "login" -> {
                                // Biometric/Auth custom portal
                                Column(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(vertical = 4.dp),
                                    horizontalAlignment = Alignment.CenterHorizontally,
                                    verticalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    Spacer(modifier = Modifier.height(10.dp))
                                    Box(
                                        modifier = Modifier
                                            .size(46.dp)
                                            .background(Brush.linearGradient(listOf(primaryColor, NeonPurple.copy(alpha = 0.5f))), RoundedCornerShape(12.dp)),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text("🔑", fontSize = 20.sp)
                                    }
                                    Text(
                                        text = "Access Login Portal",
                                        color = Color.White,
                                        fontSize = 12.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                    Text(
                                        text = "biometrics on $appLabel",
                                        color = Color.Gray,
                                        fontSize = 9.sp,
                                        modifier = Modifier.padding(bottom = 6.dp)
                                    )
                                    
                                    OutlinedTextField(
                                        value = "",
                                        onValueChange = {},
                                        placeholder = { Text("Enter ID / Username", color = Color.Gray, fontSize = 9.sp) },
                                        enabled = false,
                                        colors = OutlinedTextFieldDefaults.colors(
                                            unfocusedBorderColor = primaryColor.copy(alpha = 0.3f),
                                            unfocusedContainerColor = Color(0xFF0F0F1E)
                                        ),
                                        shape = RoundedCornerShape(6.dp),
                                        modifier = Modifier.fillMaxWidth().height(42.dp)
                                    )
                                    OutlinedTextField(
                                        value = "",
                                        onValueChange = {},
                                        placeholder = { Text("Security Access PIN", color = Color.Gray, fontSize = 9.sp) },
                                        enabled = false,
                                        colors = OutlinedTextFieldDefaults.colors(
                                            unfocusedBorderColor = primaryColor.copy(alpha = 0.3f),
                                            unfocusedContainerColor = Color(0xFF0F0F1E)
                                        ),
                                        shape = RoundedCornerShape(6.dp),
                                        modifier = Modifier.fillMaxWidth().height(42.dp)
                                    )
                                    Button(
                                        onClick = {},
                                        colors = ButtonDefaults.buttonColors(containerColor = primaryColor),
                                        shape = RoundedCornerShape(8.dp),
                                        modifier = Modifier.fillMaxWidth().height(32.dp),
                                        contentPadding = PaddingValues(0.dp)
                                    ) {
                                        Text("Log In Portal", color = PureBlack, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }
                            "database" -> {
                                // custom active SQLite/SwiftData database viewer
                                Column(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(vertical = 4.dp),
                                    verticalArrangement = Arrangement.spacedBy(6.dp)
                                ) {
                                    Text(if (isIos) "SwiftData Model Context" else "Room DB Table Registry", color = primaryColor, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    Card(
                                        colors = CardDefaults.cardColors(containerColor = Color(0xFF14142B)),
                                        shape = RoundedCornerShape(8.dp)
                                    ) {
                                        Column(modifier = Modifier.padding(8.dp).fillMaxWidth()) {
                                            Text("Database Replica Schema:", color = Color.Gray, fontSize = 8.sp)
                                            Text(if (isIos) "${appLabel.replace(" ", "")}Model.sqlite" else "${appLabel.replace(" ", "")}DB.sqlite", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalArrangement = Arrangement.spacedBy(4.dp),
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        OutlinedTextField(
                                            value = itemText,
                                            onValueChange = onTextChange,
                                            placeholder = { Text("Insert table row records...", color = Color.Gray, fontSize = 9.sp) },
                                            singleLine = true,
                                            colors = OutlinedTextFieldDefaults.colors(
                                                unfocusedBorderColor = primaryColor.copy(alpha = 0.3f),
                                                focusedBorderColor = primaryColor
                                            ),
                                            shape = RoundedCornerShape(6.dp),
                                            modifier = Modifier.weight(1f).height(42.dp)
                                        )
                                        IconButton(
                                            onClick = onAddItem,
                                            modifier = Modifier.size(34.dp).background(primaryColor, RoundedCornerShape(6.dp))
                                        ) {
                                            Icon(imageVector = Icons.Filled.Add, contentDescription = null, tint = PureBlack, modifier = Modifier.size(14.dp))
                                        }
                                    }
                                    LazyColumn(
                                        modifier = Modifier.fillMaxWidth().height(110.dp),
                                        verticalArrangement = Arrangement.spacedBy(4.dp)
                                    ) {
                                        if (itemList.isEmpty()) {
                                            item {
                                                Text("No database records found.", color = Color.Gray, fontSize = 9.sp)
                                            }
                                        } else {
                                            items(itemList) { item ->
                                                Row(
                                                    modifier = Modifier
                                                        .fillMaxWidth()
                                                        .background(Color(0xFF141424), RoundedCornerShape(4.dp))
                                                        .padding(horizontal = 6.dp, vertical = 4.dp),
                                                    horizontalArrangement = Arrangement.SpaceBetween,
                                                    verticalAlignment = Alignment.CenterVertically
                                                ) {
                                                    Row(
                                                        modifier = Modifier.weight(1f),
                                                        horizontalArrangement = Arrangement.spacedBy(4.dp),
                                                        verticalAlignment = Alignment.CenterVertically
                                                    ) {
                                                        Icon(imageVector = Icons.Filled.Check, contentDescription = null, tint = primaryColor, modifier = Modifier.size(8.dp))
                                                        Text(item, color = Color.White, fontSize = 9.sp, maxLines = 1, overflow = TextOverflow.Ellipsis)
                                                    }
                                                    IconButton(onClick = { onRemoveItem(item) }, modifier = Modifier.size(12.dp)) {
                                                        Icon(imageVector = Icons.Filled.Delete, contentDescription = null, tint = Color.Gray, modifier = Modifier.size(10.dp))
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                            "theme" -> {
                                // Aesthetic Palette view
                                Column(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(vertical = 4.dp),
                                    horizontalAlignment = Alignment.CenterHorizontally,
                                    verticalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    Spacer(modifier = Modifier.height(10.dp))
                                    Box(
                                        modifier = Modifier
                                            .size(46.dp)
                                            .background(primaryColor.copy(alpha = 0.1f), RoundedCornerShape(23.dp))
                                            .border(2.dp, primaryColor, RoundedCornerShape(23.dp)),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text("🎨", fontSize = 22.sp)
                                    }
                                    Text("Aesthetic Theme Selected", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    Text("Dynamic hex colors:", color = Color.Gray, fontSize = 8.sp)
                                    Box(
                                        modifier = Modifier
                                            .background(Color(0xFF1F1F35), RoundedCornerShape(4.dp))
                                            .padding(horizontal = 6.dp, vertical = 3.dp)
                                    ) {
                                        Text(
                                            text = "#" + primaryColor.hashCode().toString(16).take(6).uppercase(),
                                            color = primaryColor,
                                            fontSize = 9.sp,
                                            fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace
                                        )
                                    }
                                    Card(
                                        colors = CardDefaults.cardColors(containerColor = Color(0xFF0C0C1F)),
                                        border = BorderStroke(0.5.dp, primaryColor.copy(alpha = 0.3f)),
                                        shape = RoundedCornerShape(8.dp),
                                        modifier = Modifier.fillMaxWidth().padding(top = 4.dp)
                                    ) {
                                        Column(modifier = Modifier.padding(8.dp), horizontalAlignment = Alignment.CenterHorizontally) {
                                            Text(if (isIos) "Primary accent variables configured in SwiftUI palette are synchronized." else "Primary accent variables compiled in Theme.kt are synced.", color = Color.LightGray, fontSize = 9.sp, textAlign = TextAlign.Center)
                                        }
                                    }
                                }
                            }
                            else -> {
                                when (activeAppType) {
                                    "game" -> {
                                        // Our amazing playable jumping mini-game!
                                        var score by remember { mutableStateOf(0) }
                                        var isJumping by remember { mutableStateOf(false) }
                                        var playerYOffset by remember { mutableStateOf(0) }
                                        var obstacleXPos by remember { mutableStateOf(200f) }
                                        var isPlaying by remember { mutableStateOf(false) }
                                        var isGameOver by remember { mutableStateOf(false) }

                                        // Game loop
                                        LaunchedEffect(isPlaying) {
                                            if (isPlaying) {
                                                isGameOver = false
                                                while (isPlaying) {
                                                    delay(35)
                                                    obstacleXPos -= 10f
                                                    if (obstacleXPos < -20f) {
                                                        obstacleXPos = 210f
                                                        score += 10
                                                    }

                                                    // Jump physics
                                                    if (isJumping) {
                                                        playerYOffset += 15
                                                        if (playerYOffset >= 90) {
                                                            isJumping = false
                                                        }
                                                    } else if (playerYOffset > 0) {
                                                        playerYOffset -= 15
                                                    }

                                                    // Simple collision
                                                    if (obstacleXPos in 20f..60f && playerYOffset < 30) {
                                                        isPlaying = false
                                                        isGameOver = true
                                                    }
                                                }
                                            }
                                        }

                                        Column(
                                            modifier = Modifier.fillMaxWidth(),
                                            verticalArrangement = Arrangement.spacedBy(8.dp),
                                            horizontalAlignment = Alignment.CenterHorizontally
                                        ) {
                                            Row(
                                                modifier = Modifier.fillMaxWidth(),
                                                horizontalArrangement = Arrangement.SpaceBetween,
                                                verticalAlignment = Alignment.CenterVertically
                                            ) {
                                                Text("🏃 SUPER RUNNER ARCADE", color = primaryColor, fontSize = 9.sp, fontWeight = FontWeight.Black)
                                                Text("SCORE: $score", color = Color.Yellow, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                            }

                                            Box(
                                                modifier = Modifier
                                                    .fillMaxWidth()
                                                    .height(130.dp)
                                                    .background(Color(0xFF03030F), RoundedCornerShape(8.dp))
                                                    .border(0.5.dp, primaryColor.copy(alpha = 0.3f), RoundedCornerShape(8.dp)),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                if (!isPlaying && !isGameOver) {
                                                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                                        Text("Ready to Play?", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                                        Text("Tap button to start running!", color = Color.Gray, fontSize = 8.sp)
                                                        Spacer(modifier = Modifier.height(10.dp))
                                                        Button(
                                                            onClick = { isPlaying = true; score = 0; obstacleXPos = 200f; playerYOffset = 0 },
                                                            colors = ButtonDefaults.buttonColors(containerColor = primaryColor),
                                                            shape = RoundedCornerShape(6.dp),
                                                            modifier = Modifier.height(26.dp),
                                                            contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp)
                                                        ) {
                                                            Text("START GAME 🎮", color = PureBlack, fontSize = 8.sp, fontWeight = FontWeight.Black)
                                                        }
                                                    }
                                                } else if (isGameOver) {
                                                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                                        Text("💥 GAME OVER!", color = Color.Red, fontSize = 11.sp, fontWeight = FontWeight.Black)
                                                        Text("Final Score: $score", color = Color.Yellow, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                                        Spacer(modifier = Modifier.height(10.dp))
                                                        Button(
                                                            onClick = { isPlaying = true; score = 0; obstacleXPos = 200f; playerYOffset = 0; isGameOver = false },
                                                            colors = ButtonDefaults.buttonColors(containerColor = primaryColor),
                                                            shape = RoundedCornerShape(6.dp),
                                                            modifier = Modifier.height(26.dp),
                                                            contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp)
                                                        ) {
                                                            Text("TRY AGAIN 🔁", color = PureBlack, fontSize = 8.sp, fontWeight = FontWeight.Black)
                                                        }
                                                    }
                                                } else {
                                                    Box(modifier = Modifier.fillMaxSize()) {
                                                        Text("☁️", fontSize = 12.sp, modifier = Modifier.offset(x = 140.dp, y = 14.dp))
                                                        Text("☁️", fontSize = 10.sp, modifier = Modifier.offset(x = 30.dp, y = 25.dp))
                                                        
                                                        Canvas(modifier = Modifier.fillMaxWidth().align(Alignment.BottomCenter).height(1.dp)) {
                                                            drawLine(color = Color.DarkGray, start = androidx.compose.ui.geometry.Offset.Zero, end = androidx.compose.ui.geometry.Offset(size.width, 0f), strokeWidth = 2f)
                                                        }

                                                        Box(modifier = Modifier.align(Alignment.TopCenter).padding(4.dp)) {
                                                            Text("Dodge Cactus 🌵", fontSize = 7.sp, color = Color.LightGray)
                                                        }

                                                        Text(
                                                            text = if (isJumping) "🏃‍♀️" else "🏃",
