@Composable
fun SyntaxHighlightedText(code: String) {
    val annotatedString = remember<AnnotatedString>(code) {
        buildAnnotatedString {
            val words = code.split(Regex("(?<=\\b)|(?=\\b)|(?<=\\W)|(?=\\W)"))
            val keywords = setOf(
                "package", "import", "class", "fun", "val", "var", "interface", "override", 
                "return", "this", "null", "true", "false", "if", "else", "when", "for", 
                "while", "dependencies", "plugins", "implementation", "annotationProcessor"
            )
            val composeAnnotations = setOf(
                "@Composable", "@Entity", "@PrimaryKey", "@Dao", "@Query", "@Insert", "@Update", "@Delete"
            )

            for (word in words) {
                when {
                    keywords.contains(word) -> {
                        withStyle(
                            style = SpanStyle(color = NeonPurple, fontWeight = FontWeight.Bold)
                        ) {
                            append(word)
                        }
                    }
                    composeAnnotations.contains(word) -> {
                        withStyle(
                            style = SpanStyle(color = NeonCyan, fontWeight = FontWeight.Bold)
                        ) {
                            append(word)
                        }
                    }
                    word.startsWith("\"") && word.endsWith("\"") -> {
                        withStyle(
                            style = SpanStyle(color = Color(0xFFA3E635))
                        ) {
                            append(word)
                        }
                    }
                    word.toIntOrNull() != null -> {
                        withStyle(
                            style = SpanStyle(color = Color(0xFFFBBF24))
                        ) {
                            append(word)
                        }
                    }
                    word.startsWith("//") -> {
                        withStyle(
                            style = SpanStyle(color = Color.Gray)
                        ) {
                            append(word)
                        }
                    }
                    else -> {
                        append(word)
                    }
                }
            }
        }
    }
    Text(
        text = annotatedString,
        color = Color.White,
        fontSize = 11.sp,
        fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
        lineHeight = 16.sp
    )
}

@Composable
fun MarkdownText(
    text: String,
    modifier: Modifier = Modifier,
    color: Color = Color.White,
    fontSize: androidx.compose.ui.unit.TextUnit = 13.sp,
    lineHeight: androidx.compose.ui.unit.TextUnit = 18.sp
) {
    val lines = text.split("\n")
    Column(modifier = modifier, verticalArrangement = Arrangement.spacedBy(4.dp)) {
        lines.forEach { line ->
            if (line.trim().startsWith("###")) {
                Text(
                    text = line.replace("###", "").trim(),
                    color = NeonCyan,
                    fontSize = (fontSize.value + 2).sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier.padding(top = 4.dp, bottom = 1.dp)
                )
            } else if (line.trim().startsWith("##")) {
                Text(
                    text = line.replace("##", "").trim(),
                    color = NeonCyan,
                    fontSize = (fontSize.value + 3).sp,
                    fontWeight = FontWeight.ExtraBold,
                    modifier = Modifier.padding(top = 6.dp, bottom = 2.dp)
                )
            } else if (line.trim().startsWith("#") && !line.trim().startsWith("# ")) {
                val annotatedText = parseBoldText(line, fontSize, color)
                Text(
                    text = annotatedText,
                    lineHeight = lineHeight
                )
            } else if (line.trim().startsWith("#")) {
                Text(
                    text = line.replace("#", "").trim(),
                    color = Color.White,
                    fontSize = (fontSize.value + 4).sp,
                    fontWeight = FontWeight.Black,
                    modifier = Modifier.padding(top = 8.dp, bottom = 2.dp)
                )
            } else {
                val annotatedText = parseBoldText(line, fontSize, color)
                Text(
                    text = annotatedText,
                    lineHeight = lineHeight
                )
            }
        }
    }
}

fun parseBoldText(line: String, fontSize: androidx.compose.ui.unit.TextUnit, defaultColor: Color): androidx.compose.ui.text.AnnotatedString {
    return androidx.compose.ui.text.buildAnnotatedString {
        val parts = line.split("**")
        parts.forEachIndexed { index, part ->
            if (index % 2 == 1) {
                withStyle(style = androidx.compose.ui.text.SpanStyle(fontWeight = FontWeight.Bold, color = NeonCyan)) {
                    append(part)
                }
            } else {
                withStyle(style = androidx.compose.ui.text.SpanStyle(fontSize = fontSize, color = defaultColor)) {
                    append(part)
                }
            }
        }
    }
}

