fun TextToImageWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val generationState by viewModel.generationState.collectAsState()
    val generatedImageRes by viewModel.generatedImageRes.collectAsState()
    val textToImageUrls by viewModel.textToImageUrls.collectAsState()
    val userStats by viewModel.userStats.collectAsState()
    val history by viewModel.history.collectAsState()

    // Inputs States
    var prompt by remember { mutableStateOf("A beautiful futuristic floating island with crystal waterfalls, cinematic lighting, style of cyberpunk city in background") }
    var negativePrompt by remember { mutableStateOf("blurry, low quality, distorted, extra limbs, bad hands") }
    var selectedStyle by remember { mutableStateOf("Realistic") }
    var selectedAspectRatio by remember { mutableStateOf("1:1") }
    var numImages by remember { mutableStateOf(1) }
    var isHD by remember { mutableStateOf(false) }

    // Multi-Image active sliding index
    var activeImageIndex by remember { mutableStateOf(0) }
    var isEnhancing by remember { mutableStateOf(false) }

    // Filter past text to image items
    val imgHistory = remember(history) {
        history.filter { it.toolName == "Text to Image" }
    }

    Column(
        modifier = modifier
            .fillMaxWidth()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 14.dp, vertical = 8.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // Core workspace header
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    text = "Text to Image Studio",
                    color = Color.White,
                    fontWeight = FontWeight.Black,
                    fontSize = 20.sp
                )
                Text(
                    text = "Generate professional, hyper-realistic, stylistic graphics",
                    color = Color.Gray,
                    fontSize = 11.sp
                )
            }

            // Credit status indicator
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF111122)),
                border = BorderStroke(1.dp, NeonCyan.copy(alpha = 0.4f)),
                shape = RoundedCornerShape(10.dp)
            ) {
                Row(
                    modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(imageVector = Icons.Filled.Star, contentDescription = "Credits", tint = NeonCyan, modifier = Modifier.size(14.dp))
                    Text(
                        text = "Credits: ${userStats?.let { it.totalCredits - it.creditsUsed } ?: "--"} / ${userStats?.totalCredits ?: "--"}",
                        color = Color.White,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }
        }

        if (generationState !is GenerationUiState.Success) {
            // Prompt Input Section
            Column {
                Text(
                    text = "Creative Text Prompt",
                    color = Color.White,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier.padding(bottom = 6.dp)
                )

                OutlinedTextField(
                    value = prompt,
                    onValueChange = { prompt = it },
                    placeholder = { Text("What would you like to generate?", color = Color.Gray) },
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedTextColor = Color.White,
                        unfocusedTextColor = Color.White,
                        focusedBorderColor = NeonCyan,
                        unfocusedBorderColor = Color.DarkGray,
                        focusedContainerColor = Color(0xFF07070F),
                        unfocusedContainerColor = Color(0xFF07070F)
                    ),
                    shape = RoundedCornerShape(12.dp),
                    textStyle = androidx.compose.ui.text.TextStyle(fontSize = 13.sp, lineHeight = 18.sp),
                    modifier = Modifier.fillMaxWidth(),
                    trailingIcon = {
                        if (prompt.trim().isNotEmpty()) {
                            IconButton(onClick = { prompt = "" }) {
                                Icon(imageVector = Icons.Filled.Clear, contentDescription = "Clear", tint = Color.Gray)
                            }
                        }
                    }
                )

                Spacer(modifier = Modifier.height(6.dp))

                // Prompt enhancer button
                Button(
                    onClick = {
                        if (prompt.isNotBlank() && !isEnhancing) {
                            isEnhancing = true
                            coroutineScope.launch {
                                val enhanced = viewModel.enhancePrompt(prompt, selectedStyle, selectedAspectRatio)
                                prompt = enhanced
                                isEnhancing = false
                                Toast.makeText(context, "Prompt Enhanced with Gemini power!", Toast.LENGTH_SHORT).show()
                            }
                        }
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = if (isEnhancing) Color.DarkGray else Color(0xFF14142B)),
                    border = BorderStroke(0.5.dp, if (isEnhancing) Color.Transparent else NeonPurple.copy(alpha = 0.5f)),
                    shape = RoundedCornerShape(10.dp),
                    modifier = Modifier.align(Alignment.End)
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        if (isEnhancing) {
                            CircularProgressIndicator(color = NeonPurple, modifier = Modifier.size(12.dp), strokeWidth = 2.dp)
                            Text("Gemini is Enhancing...", color = Color.LightGray, fontSize = 11.sp)
                        } else {
                            Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = "Enhance", tint = NeonPurple, modifier = Modifier.size(14.dp))
                            Text("Enhance Prompt with AI", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }
            }

            // Negative Prompt Input
            Column {
                Text(
                    text = "Negative Prompt (Things to avoid)",
                    color = Color.White,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier.padding(bottom = 6.dp)
                )

                OutlinedTextField(
                    value = negativePrompt,
                    onValueChange = { negativePrompt = it },
                    placeholder = { Text("e.g. photorealistic details, text captions...", color = Color.Gray) },
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedTextColor = Color.White,
                        unfocusedTextColor = Color.White,
                        focusedBorderColor = NeonCyan,
                        unfocusedBorderColor = Color.DarkGray,
                        focusedContainerColor = Color(0xFF07070F),
                        unfocusedContainerColor = Color(0xFF07070F)
                    ),
                    shape = RoundedCornerShape(10.dp),
                    textStyle = androidx.compose.ui.text.TextStyle(fontSize = 12.sp),
                    modifier = Modifier.fillMaxWidth()
                )
            }

            // Style Selection Section (Realistic, Anime, Cartoon, 3D, Fantasy, Cyberpunk)
            Column {
                Text(
                    text = "Aesthetic Generation Style",
                    color = Color.White,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier.padding(bottom = 6.dp)
                )

                val styles = listOf(
                    "Realistic" to "📸 Realistic",
                    "Recraftv3" to "✨ Recraft v3",
                    "Anime" to "🌸 Anime Art",
                    "Cartoon" to "🎨 Cartoon",
                    "3D" to "🧊 3D Render",
                    "Fantasy" to "🦄 Fantasy",
                    "Cyberpunk" to "🌌 Cyberpunk"
                )

                Row(
                    modifier = Modifier.horizontalScroll(rememberScrollState()),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    styles.forEach { (styleKey, styleDisplay) ->
                        val isSelected = selectedStyle == styleKey
                        Card(
                            modifier = Modifier
                                .clickable { selectedStyle = styleKey }
                                .width(105.dp),
                            colors = CardDefaults.cardColors(
                                containerColor = if (isSelected) Color(0xFF0F0C24) else Color(0xFF080811)
                            ),
                            border = BorderStroke(1.5.dp, if (isSelected) NeonPurple else Color.DarkGray.copy(alpha = 0.5f)),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Column(
                                modifier = Modifier.padding(10.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Text(
                                    text = styleDisplay,
                                    color = if (isSelected) NeonCyan else Color.White,
                                    fontWeight = if (isSelected) FontWeight.Black else FontWeight.Normal,
                                    fontSize = 12.sp,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }
                    }
                }
            }

            // Aspect Ratio selection (1:1, 16:9, 9:16)
            Column {
                Text(
                    text = "Aspect Ratio Selection",
                    color = Color.White,
                    fontSize = 12.sp,
                    fontWeight = FontWeight.Bold,
                    modifier = Modifier.padding(bottom = 6.dp)
                )

                val ratios = listOf(
                    "1:1" to "1:1 Square",
                    "16:9" to "16:9 Cinema",
                    "9:16" to "9:16 Portrait"
                )

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    ratios.forEach { (ratioKey, ratioDisplay) ->
                        val isSelected = selectedAspectRatio == ratioKey
                        Card(
                            modifier = Modifier
                                .weight(1f)
                                .clickable { selectedAspectRatio = ratioKey },
                            colors = CardDefaults.cardColors(
                                containerColor = if (isSelected) Color(0xFF0B1424) else Color(0xFF080811)
                            ),
                            border = BorderStroke(1.5.dp, if (isSelected) NeonCyan else Color.DarkGray.copy(alpha = 0.5f)),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Column(
                                modifier = Modifier.padding(vertical = 12.dp, horizontal = 4.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Text(
                                    text = ratioDisplay,
                                    color = if (isSelected) NeonCyan else Color.White,
                                    fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                                    fontSize = 11.sp
                                )
                            }
                        }
                    }
                }
            }

            // Multiple Image Generation count (1, 2, 4) & Quality Mode (Fast, HD)
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                // Count
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = "Multiple Images Count",
                        color = Color.White,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Bold,
                        modifier = Modifier.padding(bottom = 6.dp)
                    )

                    Row(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        listOf(1, 2, 4).forEach { count ->
                            val isSelected = numImages == count
                            Box(
                                contentAlignment = Alignment.Center,
                                modifier = Modifier
                                    .weight(1f)
                                    .height(38.dp)
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(if (isSelected) NeonPurple.copy(alpha = 0.3f) else Color(0xFF07070F))
                                    .border(1.dp, if (isSelected) NeonPurple else Color.DarkGray, RoundedCornerShape(8.dp))
                                    .clickable { numImages = count }
                            ) {
                                Text(
                                    text = "${count}x",
                                    color = if (isSelected) NeonCyan else Color.LightGray,
                                    fontSize = 12.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }

                // Quality mode toggle
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = "Performance Mode",
                        color = Color.White,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Bold,
                        modifier = Modifier.padding(bottom = 6.dp)
                    )

                    Row(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        val modes = listOf(false to "Fast", true to "HD")
                        modes.forEach { (hdKey, label) ->
                            val isSelected = isHD == hdKey
                            Box(
                                contentAlignment = Alignment.Center,
                                modifier = Modifier
                                    .weight(1f)
                                    .height(38.dp)
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(if (isSelected) NeonCyan.copy(alpha = 0.2f) else Color(0xFF07070F))
                                    .border(1.dp, if (isSelected) NeonCyan else Color.DarkGray, RoundedCornerShape(8.dp))
                                    .clickable { isHD = hdKey }
                            ) {
                                Text(
                                    text = label,
                                    color = if (isSelected) NeonCyan else Color.LightGray,
                                    fontSize = 12.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }
            }

            // Action Trigger Button
            Button(
                onClick = {
                    activeImageIndex = 0
                    viewModel.generateImageWithDetails(
                        prompt = prompt,
                        negativePrompt = negativePrompt,
                        style = selectedStyle,
                        aspectRatio = selectedAspectRatio,
                        imageCount = numImages,
                        isHD = isHD
                    )
                },
                colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent),
                contentPadding = PaddingValues(),
                modifier = Modifier
                    .fillMaxWidth()
                    .height(52.dp)
                    .clip(RoundedCornerShape(12.dp))
                    .background(Brush.horizontalGradient(listOf(NeonPurple, NeonCyan)))
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(imageVector = Icons.Filled.ElectricBolt, contentDescription = "generate", tint = PureBlack)
                    Text(
                        text = "Generate AI Artwork (${numImages * (if (isHD) 3 else 1)} Credits)",
                        color = PureBlack,
                        fontWeight = FontWeight.ExtraBold,
                        fontSize = 14.sp
                    )
                }
            }
        }

        // Preview rendering area
        when (val genState = generationState) {
            is GenerationUiState.Loading -> {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF090915)),
                    border = BorderStroke(1.dp, NeonCyan.copy(alpha = 0.5f))
                ) {
                    Column(
                        modifier = Modifier.padding(24.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        CircularProgressIndicator(color = NeonCyan)
                        Text(
                            text = "Diffusion Neural Core Generating...",
                            color = Color.LightGray,
                            fontWeight = FontWeight.Bold,
                            fontSize = 13.sp
                        )
                        LinearProgressIndicator(
                            color = NeonPurple,
                            trackColor = Color.DarkGray,
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(4.dp)
                                .clip(RoundedCornerShape(2.dp))
                        )
                        Text(
                            text = "Denoising process steps: 28/28\nHD Upscaler configuration applying...",
                            color = Color.Gray,
                            fontSize = 10.sp,
                            textAlign = TextAlign.Center
                        )
                    }
                }
            }
            is GenerationUiState.Error -> {
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0x22FF0000)),
                    border = BorderStroke(1.dp, Color.Red),
                    shape = RoundedCornerShape(12.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            Icon(imageVector = Icons.Filled.Error, contentDescription = "error", tint = Color.Red)
                            Text("Artwork Generation Failed", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 14.sp)
                        }
                        Text(genState.message, color = Color.LightGray, fontSize = 12.sp, modifier = Modifier.padding(top = 6.dp))
                    }
                }
            }
            is GenerationUiState.Success -> {
                val urls = remember(genState, textToImageUrls) {
                    val metaUrls = genState.meta["urls"]?.split(",")
                    if (!metaUrls.isNullOrEmpty() && metaUrls.first().isNotEmpty()) metaUrls else textToImageUrls
                }

                if (urls.isNotEmpty()) {
                    Column(
                        modifier = Modifier.fillMaxWidth(),
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Text(
                            text = "Generated Masterpiece",
                            color = Color.White,
                            fontWeight = FontWeight.Bold,
                            fontSize = 14.sp
                        )

                        val activeUrl = urls.getOrNull(activeImageIndex) ?: urls.first()

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(320.dp)
                                .clip(RoundedCornerShape(14.dp))
                                .border(1.dp, NeonCyan.copy(alpha = 0.2f), RoundedCornerShape(14.dp))
                                .background(Color(0xFF06060F)),
                            contentAlignment = Alignment.Center
                        ) {
                            val boxModifier = when (selectedAspectRatio) {
                                "16:9" -> Modifier.fillMaxWidth().aspectRatio(16f / 9f)
                                "9:16" -> Modifier.fillMaxHeight().aspectRatio(9f / 16f, matchHeightConstraintsFirst = true)
                                else -> Modifier.fillMaxHeight().aspectRatio(1f, matchHeightConstraintsFirst = true) // 1:1
                            }
                            Box(
                                modifier = boxModifier
                                    .clip(RoundedCornerShape(10.dp))
                                    .border(1.dp, NeonCyan.copy(alpha = 0.5f), RoundedCornerShape(10.dp))
                                    .background(Color.Black)
                            ) {
                                SubcomposeAsyncImage(
                                    model = activeUrl,
                                    contentDescription = "Generated Art",
                                    contentScale = ContentScale.Crop,
                                    modifier = Modifier.fillMaxSize(),
                                    loading = {
                                        Box(
                                            modifier = Modifier.fillMaxSize(),
                                            contentAlignment = Alignment.Center
                                        ) {
                                            Column(
                                                horizontalAlignment = Alignment.CenterHorizontally,
                                                verticalArrangement = Arrangement.spacedBy(8.dp)
                                            ) {
                                                CircularProgressIndicator(color = NeonCyan, modifier = Modifier.size(36.dp))
                                                Text(
                                                    text = "Rendering visual art details...\n(Slow first request is normal)",
                                                    color = Color.LightGray,
                                                    fontSize = 11.sp,
                                                    textAlign = TextAlign.Center
                                                )
                                            }
                                        }
                                    },
                                    error = {
                                        Box(
                                            modifier = Modifier.fillMaxSize().padding(16.dp),
                                            contentAlignment = Alignment.Center
                                        ) {
                                            Column(
                                                horizontalAlignment = Alignment.CenterHorizontally,
                                                verticalArrangement = Arrangement.spacedBy(8.dp)
                                            ) {
                                                Icon(
                                                    imageVector = Icons.Filled.Error,
                                                    contentDescription = "Failed to render",
                                                    tint = Color.Red,
                                                    modifier = Modifier.size(32.dp)
                                                )
                                                Text(
                                                    text = "Generation server did not respond.\nPlease try generating again.",
                                                    color = Color.LightGray,
                                                    fontSize = 11.sp,
                                                    textAlign = TextAlign.Center
                                                )
                                            }
                                        }
                                    }
                                )

                                // Custom Badge label showing style
                                Box(
                                    modifier = Modifier
                                        .padding(10.dp)
                                        .align(Alignment.TopStart)
                                        .background(Color.Black.copy(alpha = 0.7f), RoundedCornerShape(6.dp))
                                        .border(0.5.dp, NeonCyan, RoundedCornerShape(6.dp))
                                        .padding(horizontal = 8.dp, vertical = 4.dp)
                                ) {
                                    Text(
                                        text = "$selectedStyle • $selectedAspectRatio${if(isHD) " HD" else ""}",
                                        color = NeonCyan,
                                        fontSize = 10.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                        }

                        // Slider Controls if multi-images count > 1
                        if (urls.size > 1) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                TextButton(
                                    onClick = { if (activeImageIndex > 0) activeImageIndex-- },
                                    enabled = activeImageIndex > 0
                                ) {
                                    Text("◀ Previous", color = if (activeImageIndex > 0) NeonCyan else Color.Gray, fontSize = 12.sp)
                                }

                                Text(
                                    text = "Artwork ${activeImageIndex + 1} of ${urls.size}",
                                    color = Color.White,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 12.sp
                                )

                                TextButton(
                                    onClick = { if (activeImageIndex < urls.size - 1) activeImageIndex++ },
                                    enabled = activeImageIndex < urls.size - 1
                                ) {
                                    Text("Next ▶", color = if (activeImageIndex < urls.size - 1) NeonCyan else Color.Gray, fontSize = 12.sp)
                                }
                            }

                            // Horizontal thumbnail rows
                            Row(
                                modifier = Modifier
                                    .horizontalScroll(rememberScrollState())
                                    .fillMaxWidth(),
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                urls.forEachIndexed { index, url ->
                                    val isSelected = activeImageIndex == index
                                    Card(
                                        modifier = Modifier
                                            .size(54.dp)
                                            .clickable { activeImageIndex = index },
                                        shape = RoundedCornerShape(8.dp),
                                        border = BorderStroke(1.5.dp, if (isSelected) NeonCyan else Color.Transparent)
                                    ) {
                                        AsyncImage(
                                            model = url,
                                            contentDescription = "Thumb",
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }
                                }
                            }
                        }

                        // Action rows (Download, Share, Favorite/Project Saved)
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(10.dp)
                        ) {
                            Button(
                                onClick = {
                                    Toast.makeText(context, "Directing download pipeline. Saved to gallery!", Toast.LENGTH_LONG).show()
                                    viewModel.triggerMockDownload(
                                        CreationEntity(
                                            id = 999,
                                            toolName = "Text to Image",
                                            category = "Image Tools",
                                            inputPrompt = prompt,
                                            outputText = activeUrl
                                        )
                                    )
                                },
                                modifier = Modifier.weight(1f),
                                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF10B981)),
                                shape = RoundedCornerShape(10.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Icon(imageVector = Icons.Filled.CloudDownload, contentDescription = "Download", modifier = Modifier.size(16.dp))
                                    Text("Download", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            Button(
                                onClick = {
                                    val shareIntent = android.content.Intent().apply {
                                        action = android.content.Intent.ACTION_SEND
                                        putExtra(android.content.Intent.EXTRA_TEXT, "Look at this incredible high fidelity AI artwork I generated: $activeUrl\n\nPrompt: $prompt")
                                        type = "text/plain"
                                    }
                                    context.startActivity(android.content.Intent.createChooser(shareIntent, "Share generated masterpiece"))
                                },
                                modifier = Modifier.weight(1f),
                                colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF4F46E5)),
                                shape = RoundedCornerShape(10.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Icon(imageVector = Icons.Filled.Share, contentDescription = "Share", modifier = Modifier.size(16.dp))
                                    Text("Share Art", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }

                        Spacer(modifier = Modifier.height(14.dp))

                        // Clean New Generation Action Button
                        Button(
                            onClick = {
                                viewModel.resetGenerationState()
                            },
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(48.dp),
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF131124)),
                            border = BorderStroke(1.dp, NeonPurple.copy(alpha = 0.6f)),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Icon(imageVector = Icons.Filled.ArrowBack, contentDescription = "back", tint = Color.White, modifier = Modifier.size(15.dp))
                                Text("New Generation / Modify Prompt", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }
                }
            }
            else -> {}
        }

        // Horizontal History selection section
        if (generationState !is GenerationUiState.Success && imgHistory.isNotEmpty()) {
            Column(
                modifier = Modifier.fillMaxWidth().padding(top = 10.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Text(
                    text = "Your Magic Gallery History",
                    color = Color.White,
                    fontWeight = FontWeight.Bold,
                    fontSize = 13.sp
                )

                Row(
                    modifier = Modifier.horizontalScroll(rememberScrollState()),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    imgHistory.forEach { item ->
                        // Try to parse URL or find fallback
                        val itemUrls = item.outputText.lines()
                            .filter { it.startsWith("https://") }
                            .ifEmpty { listOf("https://picsum.photos/300/300?sig=${item.id}") }

                        Card(
                            modifier = Modifier
                                .width(120.dp)
                                .clickable {
                                    // Extract components back in the prompt states
                                    val parts = item.inputPrompt.split(" | ")
                                    parts.forEach { part ->
                                        if (part.startsWith("Prompt: ")) prompt = part.replace("Prompt: ", "")
                                        if (part.startsWith("Style: ")) selectedStyle = part.replace("Style: ", "")
                                        if (part.startsWith("Aspect: ")) selectedAspectRatio = part.replace("Aspect: ", "")
                                        if (part.startsWith("HD: ")) isHD = part.replace("HD: ", "").toBoolean()
                                        if (part.startsWith("Multiple: ")) numImages = part.replace("Multiple: ", "").toIntOrNull() ?: 1
                                    }
                                    viewModel.loadImagesFromUrls(itemUrls)
                                    activeImageIndex = 0
                                },
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF06060F)),
                            shape = RoundedCornerShape(8.dp),
                            border = BorderStroke(0.5.dp, Color.DarkGray)
                        ) {
                            Column {
                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(80.dp)
                                ) {
                                    AsyncImage(
                                        model = itemUrls.first(),
                                        contentDescription = "History Item",
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                }
                                Text(
                                    text = item.inputPrompt.replace("Prompt: ", "").take(30) + "...",
                                    color = Color.LightGray,
                                    fontSize = 9.sp,
                                    modifier = Modifier.padding(6.dp),
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis
                                )
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(30.dp))
    }
}

// ==========================================
// PROFESSIONAL AI IMAGE ENHANCER WORKSPACE
// ==========================================
@Composable
fun ImageEnhancerWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val history by viewModel.history.collectAsState()
    val userStats by viewModel.userStats.collectAsState()

    // Definition of presets with high quality public images from Unsplash
    // Parametrized for quality/blur to achieve organic before/after comparison
    val presets = remember {
        listOf(
            com.example.ui.views.EnhancerPreset(
                title = "Vintage Portrait",
                subtitle = "Fix blur, scratches, & restore facial skin structures",
                beforeUrl = "https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=20&w=400&blur=8&auto=format&fit=crop",
                afterUrl = "https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=100&w=1200&auto=format&fit=crop",
                defaultFlags = "HD Enhancement, Face Restoration, Color Correction"
            ),
            com.example.ui.views.EnhancerPreset(
                title = "Cyberpunk Alley",
                subtitle = "Remove extreme camera movement blur & light bleeding",
                beforeUrl = "https://images.unsplash.com/photo-1515621061946-eff1c2a352bd?q=30&w=400&auto=format&fit=crop",
                afterUrl = "https://images.unsplash.com/photo-1515621061946-eff1c2a352bd?q=100&w=1200&auto=format&fit=crop",
                defaultFlags = "HD Enhancement, Blur Removal"
            ),
            com.example.ui.views.EnhancerPreset(
                title = "Sleeping Pug",
                subtitle = "Eradicate noise & JPG compression artifacts in fur",
                beforeUrl = "https://images.unsplash.com/photo-1517841905240-472988babdf9?q=20&w=400&blur=3&auto=format&fit=crop",
                afterUrl = "https://images.unsplash.com/photo-1517841905240-472988babdf9?q=100&w=1200&auto=format&fit=crop",
                defaultFlags = "HD Enhancement, Noise Reduction, Color Correction"
            ),
            com.example.ui.views.EnhancerPreset(
                title = "Sci-Fi Prismatic Glass",
                subtitle = "Perfect for abstract illustrations and upscale edge-lines",
                beforeUrl = "https://images.unsplash.com/photo-1506318137071-a8e063b4bec0?q=15&w=400&blur=5&auto=format&fit=crop",
                afterUrl = "https://images.unsplash.com/photo-1506318137071-a8e063b4bec0?q=100&w=1200&auto=format&fit=crop",
                defaultFlags = "HD Enhancement, Blur Removal, Color Correction"
            )
        )
    }

    // Input state controls
    var activeTab by remember { mutableStateOf("presets") } // "presets" or "custom"
    var selectedPresetIndex by remember { mutableStateOf(0) }
    var customImageUris by remember { mutableStateOf<List<Uri>>(emptyList()) }
    var selectedCustomImageIndex by remember { mutableStateOf(0) }

    // Toggle options
    var hdEnhancement by remember { mutableStateOf(true) }
    var blurRemoval by remember { mutableStateOf(true) }
    var noiseReduction by remember { mutableStateOf(false) }
    var colorCorrection by remember { mutableStateOf(true) }
    var faceRestoration by remember { mutableStateOf(true) }
    var upscaleFactor by remember { mutableStateOf("4x") } // "2x", "4x", "8x"

    // Fine-Tuning Precision Sliders Controls
    var sharpnessSlider by remember { mutableStateOf(65f) } // default: highly clear focus
    var vibrancySlider by remember { mutableStateOf(68f) } // default: vibrant colors
    var exposureSlider by remember { mutableStateOf(12f) } // default: slightly illuminated dynamics
    var denoiseSlider by remember { mutableStateOf(35f) }  // default: smooth high-ISO
    var faceFusionSlider by remember { mutableStateOf(70f) } // default: optimized facial landmarks smoothness

    // Process state machine
    var processState by remember { mutableStateOf("idle") } // "idle", "processing", "success"
    var processProgress by remember { mutableStateOf(0f) }
    var activeProgressStep by remember { mutableStateOf("") }
    
    // Interactive sliding reveal fraction
    var sliderFraction by remember { mutableStateOf(0.42f) }

    // Fetch previous Image Enhancer database history items
    val enhancerHistory = remember(history) {
        history.filter { it.toolName == "Image Enhancer" }
    }

    // Resolve model URL outputs dynamically
    val activeBeforeUrl = remember(selectedPresetIndex, customImageUris, selectedCustomImageIndex, activeTab) {
        if (activeTab == "custom" && customImageUris.isNotEmpty()) {
            customImageUris.getOrNull(selectedCustomImageIndex)?.toString() ?: ""
        } else {
            presets.getOrNull(selectedPresetIndex)?.beforeUrl ?: ""
        }
    }

    val activeAfterUrl = remember(selectedPresetIndex, customImageUris, selectedCustomImageIndex, activeTab, processState) {
        if (activeTab == "custom" && customImageUris.isNotEmpty()) {
            customImageUris.getOrNull(selectedCustomImageIndex)?.toString() ?: ""
        } else {
            presets.getOrNull(selectedPresetIndex)?.afterUrl ?: ""
        }
    }

    // Traditional document picker fallback
    val pickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetMultipleContents()
    ) { uris ->
        if (uris.isNotEmpty()) {
            customImageUris = uris
            selectedCustomImageIndex = 0
            activeTab = "custom"
            processState = "idle" // Reset processing for new uploads
            Toast.makeText(context, "Loaded ${uris.size} image(s) successfully!", Toast.LENGTH_SHORT).show()
        }
    }

    // Direct Gallery Picker launcher using MediaStore intent (opens system gallery directly)
    val galleryPickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == android.app.Activity.RESULT_OK) {
            val intent = result.data
            val uris = mutableListOf<Uri>()
            if (intent?.clipData != null) {
                val clipData = intent.clipData!!
                for (i in 0 until clipData.itemCount) {
                    uris.add(clipData.getItemAt(i).uri)
                }
            } else if (intent?.data != null) {
                uris.add(intent.data!!)
            }
            if (uris.isNotEmpty()) {
                customImageUris = uris
                selectedCustomImageIndex = 0
                activeTab = "custom"
                processState = "idle" // Reset processing for new uploads
                Toast.makeText(context, "Loaded ${uris.size} image(s) from Gallery!", Toast.LENGTH_SHORT).show()
            }
        }
    }

    val launchGallery = {
        val intent = Intent(Intent.ACTION_PICK, android.provider.MediaStore.Images.Media.EXTERNAL_CONTENT_URI).apply {
            putExtra(Intent.EXTRA_ALLOW_MULTIPLE, true)
        }
        try {
            galleryPickerLauncher.launch(intent)
        } catch (e: Exception) {
            pickerLauncher.launch("image/*")
        }
    }

    // Dynamic High-Fidelity HDR Reconstruction Matrix
    val colorMatrix = remember(vibrancySlider, exposureSlider, sharpnessSlider, colorCorrection, hdEnhancement, blurRemoval) {
        val rawVibrancy = if (colorCorrection) vibrancySlider else 50f
        val rawExposure = if (hdEnhancement) exposureSlider else 0f
        val rawSharpness = if (blurRemoval) sharpnessSlider else 50f

        val s = rawVibrancy / 50f // 1.0f is neutral
        val contrastRatio = 1.0f + ((rawSharpness - 50f) / 100f) * 0.45f // 1.0f is neutral. Max contrast is 1.45x
        val brightOffset = (rawExposure / 50f) * 45f // range -45 to +45
        val contrastOffset = 128f * (1.0f - contrastRatio) + brightOffset

        val wr = 0.213f
        val wg = 0.715f
        val wb = 0.072f

        val r_r = ((1f - s) * wr + s) * contrastRatio
        val r_g = ((1f - s) * wg) * contrastRatio
        val r_b = ((1f - s) * wb) * contrastRatio

        val g_r = ((1f - s) * wr) * contrastRatio
        val g_g = ((1f - s) * wg + s) * contrastRatio
        val g_b = ((1f - s) * wb) * contrastRatio

        val b_r = ((1f - s) * wr) * contrastRatio
        val b_g = ((1f - s) * wg) * contrastRatio
        val b_b = ((1f - s) * wb + s) * contrastRatio

        val values = floatArrayOf(
            r_r, r_g, r_b, 0f, contrastOffset,
            g_r, g_g, g_b, 0f, contrastOffset,
            b_r, b_g, b_b, 0f, contrastOffset,
            0f,  0f,  0f,  1f, 0f
        )
        ColorMatrix(values)
    }

    // Unenhanced dull base raw photo state simulation
    val beforeColorMatrix = remember {
        val wr = 0.213f
        val wg = 0.715f
        val wb = 0.072f
        
        val s = 0.72f // slightly desaturated raw look
        val contrastRatio = 0.84f // lower contrast raw sensor
        val contrastOffset = 128f * (1.0f - contrastRatio) - 8f // duller shadows
        
        val r_r = ((1f - s) * wr + s) * contrastRatio
        val r_g = ((1f - s) * wg) * contrastRatio
        val r_b = ((1f - s) * wb) * contrastRatio

        val g_r = ((1f - s) * wr) * contrastRatio
        val g_g = ((1f - s) * wg + s) * contrastRatio
        val g_b = ((1f - s) * wb) * contrastRatio

        val b_r = ((1f - s) * wr) * contrastRatio
        val b_g = ((1f - s) * wg) * contrastRatio
        val b_b = ((1f - s) * wb + s) * contrastRatio

        val values = floatArrayOf(
            r_r, r_g, r_b, 0f, contrastOffset,
            g_r, g_g, g_b, 0f, contrastOffset,
            b_r, b_g, b_b, 0f, contrastOffset,
            0f,  0f,  0f,  1f, 0f
        )
        ColorMatrix(values)
    }

    Column(
        modifier = modifier
            .fillMaxWidth()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 14.dp, vertical = 8.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // WORKSPACE HEADER
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    text = "AI Image Enhancer Studio",
                    color = Color.White,
                    fontWeight = FontWeight.Black,
                    fontSize = 20.sp
                )
                Text(
                    text = "Super-resolution, face restoration, and denoiser pipeline",
                    color = Color.Gray,
                    fontSize = 11.sp
                )
            }

            // Balance credit stats
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF111122)),
                border = BorderStroke(1.dp, NeonCyan.copy(alpha = 0.4f)),
                shape = RoundedCornerShape(10.dp)
            ) {
                Row(
                    modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(imageVector = Icons.Filled.Star, contentDescription = "Credits", tint = NeonCyan, modifier = Modifier.size(13.dp))
                    Text(
                        text = "Credits: ${userStats?.let { it.totalCredits - it.creditsUsed } ?: "--"}",
                        color = Color.White,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // IF OUTPUT IS READY: SHOW COMPARISON SLIDER & ACTIONS FIRST
        // -------------------------------------------------------------
        if (processState == "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(1.dp, NeonPurple.copy(alpha = 0.3f)),
                shape = RoundedCornerShape(16.dp),
                modifier = Modifier.fillMaxWidth().testTag("enhanced_display_card")
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "✦ Enhancement Masterpiece Ready",
                            color = NeonCyan,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black
                        )

                        Text(
                            text = if (customImageUris.size > 1) "File ${selectedCustomImageIndex + 1} of ${customImageUris.size} (Batch)" else "Single Image",
                            color = Color.LightGray,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold,
                            modifier = Modifier
                                .background(Color(0xFF231E39), RoundedCornerShape(4.dp))
                                .padding(horizontal = 8.dp, vertical = 2.dp)
                        )
                    }

                    // Before/After Interactive Wipe Slider Composable
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(260.dp)
                            .clip(RoundedCornerShape(12.dp))
                            .border(0.5.dp, Color.DarkGray, RoundedCornerShape(12.dp))
                    ) {
                        // Background: "Before" Image
                        AsyncImage(
                            model = activeBeforeUrl,
                            contentDescription = "Before Enhancement",
                            contentScale = ContentScale.Crop,
                            colorFilter = if (activeTab == "custom") ColorFilter.colorMatrix(beforeColorMatrix) else null,
                            modifier = Modifier
                                .fillMaxSize()
                                .then(
                                    if (activeTab == "custom" && (blurRemoval || hdEnhancement)) {
                                        Modifier.blur(4.dp)
                                    } else {
                                        Modifier
                                    }
                                )
                        )

                        // Top Overlay clipped manually to slider fraction representing the "After" HD Image
                        val beforeAfterClipShape = remember(sliderFraction) {
                            object : androidx.compose.ui.graphics.Shape {
                                override fun createOutline(
                                    size: androidx.compose.ui.geometry.Size,
                                    layoutDirection: androidx.compose.ui.unit.LayoutDirection,
                                    density: androidx.compose.ui.unit.Density
                                ): androidx.compose.ui.graphics.Outline {
                                    return androidx.compose.ui.graphics.Outline.Rectangle(
                                        androidx.compose.ui.geometry.Rect(
                                            0f, 0f, size.width * sliderFraction, size.height
                                        )
                                    )
                                }
                            }
                        }

                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .clip(beforeAfterClipShape)
                        ) {
                            AsyncImage(
                                model = activeAfterUrl,
                                contentDescription = "After HD Enhanced",
                                contentScale = ContentScale.Crop,
                                colorFilter = if (activeTab == "custom") ColorFilter.colorMatrix(colorMatrix) else null,
                                modifier = Modifier.fillMaxSize()
                            )
                        }

                        // Labels
                        Text(
                            text = "BEFORE",
                            color = Color.White,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.ExtraBold,
                            modifier = Modifier
                                .align(Alignment.BottomEnd)
                                .padding(10.dp)
                                .background(Color(0xE6101010), RoundedCornerShape(4.dp))
                                .padding(horizontal = 6.dp, vertical = 2.dp)
                        )

                        Text(
                            text = "AFTER (HD)",
                            color = NeonCyan,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.ExtraBold,
                            modifier = Modifier
                                .align(Alignment.BottomStart)
                                .padding(10.dp)
                                .background(Color(0xE60D0C15), RoundedCornerShape(4.dp))
                                .padding(horizontal = 6.dp, vertical = 2.dp)
                        )

                        // Draggable Slider Dividers
                        BoxWithConstraints(modifier = Modifier.fillMaxSize()) {
                            val grabX = maxWidth * sliderFraction

                            // Dividers
                            Box(
                                modifier = Modifier
                                    .fillMaxHeight()
                                    .width(2.5.dp)
                                    .offset(x = grabX - 1.25.dp)
                                    .background(NeonCyan)
                            )

                            // Slider Grab handle
                            Box(
                                modifier = Modifier
                                    .offset(x = grabX - 18.dp, y = (maxHeight / 2) - 18.dp)
                                    .size(36.dp)
                                    .background(Color(0xFF0F0E17), CircleShape)
                                    .border(1.5.dp, NeonCyan, CircleShape)
                                    .pointerInput(Unit) {
                                        detectHorizontalDragGestures { change, dragAmount ->
                                            change.consume()
                                            sliderFraction = (sliderFraction + (dragAmount / size.width)).coerceIn(0f, 1f)
                                        }
                                    },
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(
                                    imageVector = Icons.Filled.Compare,
                                    contentDescription = "Swipe Handle",
                                    tint = NeonCyan,
                                    modifier = Modifier.size(16.dp)
                                )
                            }
                        }
                    }

                    // Description of active parameters applied
                    Text(
                        text = "Enhanced to $upscaleFactor resolution using " +
                               listOfNotNull(
                                   if (hdEnhancement) "HD-Dynamic Engine" else null,
                                   if (blurRemoval) "De-blurring" else null,
                                   if (noiseReduction) "De-noising" else null,
                                   if (colorCorrection) "Aesthetic Color-HDR" else null,
                                   if (faceRestoration) "Neural Face Fusion" else null
                               ).joinToString(", "),
                        fontSize = 11.sp,
                        color = Color.LightGray.copy(alpha = 0.8f),
                        lineHeight = 16.sp
                    )

                    // Real-Time Aesthetic Fine-Tuning controls
                    if (activeTab == "custom") {
                        var isLiveTuningExpanded by remember { mutableStateOf(false) }
                        Card(
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF040409)),
                            border = BorderStroke(0.5.dp, NeonCyan.copy(alpha = 0.4f)),
                            shape = RoundedCornerShape(10.dp),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Column(modifier = Modifier.padding(10.dp)) {
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .clickable { isLiveTuningExpanded = !isLiveTuningExpanded },
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                                    ) {
                                        Icon(
                                            imageVector = Icons.Filled.Tune,
                                            contentDescription = "Manual Adjustments",
                                            tint = NeonCyan,
                                            modifier = Modifier.size(14.dp)
                                        )
                                        Text(
                                            text = "Aesthetic Live Calibration",
                                            color = Color.White,
                                            fontSize = 11.5.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                    Icon(
                                        imageVector = Icons.Filled.ArrowDropDown,
                                        contentDescription = "Expand Live Tuning",
                                        tint = Color.Gray,
                                        modifier = Modifier
                                            .size(16.dp)
                                            .graphicsLayer(rotationZ = if (isLiveTuningExpanded) 180f else 0f)
                                    )
                                }

                                if (isLiveTuningExpanded) {
                                    Spacer(modifier = Modifier.height(10.dp))
                                    Divider(color = Color(0x19FFFFFF), modifier = Modifier.padding(bottom = 8.dp))

                                    // Contrast/Sharpness Adjuster Slider
                                    Column {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween
                                        ) {
                                            Text("Sharpness (Contrast Detail)", color = Color.LightGray, fontSize = 10.sp)
                                            Text("${sharpnessSlider.toInt()}%", color = NeonCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                        Slider(
                                            value = sharpnessSlider,
                                            onValueChange = { sharpnessSlider = it },
                                            valueRange = 0f..100f,
                                            colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray)
                                        )
                                    }

                                    Spacer(modifier = Modifier.height(4.dp))

                                    // Vibrancy Adjuster Slider
                                    Column {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween
                                        ) {
                                            Text("Dynamic Vibrancy (Saturation)", color = Color.LightGray, fontSize = 10.sp)
                                            Text("${vibrancySlider.toInt()}%", color = NeonCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                        Slider(
                                            value = vibrancySlider,
                                            onValueChange = { vibrancySlider = it },
                                            valueRange = 0f..100f,
                                            colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray)
                                        )
                                    }

                                    Spacer(modifier = Modifier.height(4.dp))

                                    // Exposure Adjuster Slider
                                    Column {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween
                                        ) {
                                            Text("Luminance Exposure Boost", color = Color.LightGray, fontSize = 10.sp)
                                            val offsetText = if (exposureSlider >= 0) "+${exposureSlider.toInt()}" else "${exposureSlider.toInt()}"
                                            Text(offsetText, color = NeonCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        }
                                        Slider(
                                            value = exposureSlider,
                                            onValueChange = { exposureSlider = it },
                                            valueRange = -50f..50f,
                                            colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray)
                                        )
                                    }
                                }
                            }
                        }
                    }

                    // BATCH RESULTS SWITCHER CARDS
                    if (customImageUris.size > 1 && activeTab == "custom") {
                        Column {
                            Text(
                                text = "Select batch target to preview comparison:",
                                color = Color.White,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold,
                                modifier = Modifier.padding(bottom = 6.dp)
                            )
                            Row(
                                modifier = Modifier.horizontalScroll(rememberScrollState()),
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                customImageUris.forEachIndexed { idx, uri ->
                                    val isSelected = idx == selectedCustomImageIndex
                                    Card(
                                        modifier = Modifier
                                            .size(54.dp)
                                            .border(
                                                1.5.dp,
                                                if (isSelected) NeonCyan else Color.Transparent,
                                                RoundedCornerShape(6.dp)
                                            )
                                            .clickable { selectedCustomImageIndex = idx },
                                        shape = RoundedCornerShape(6.dp)
                                    ) {
                                        AsyncImage(
                                            model = uri.toString(),
                                            contentDescription = "File thumbnail",
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }
                                }
                            }
                        }
                    }

                    // DOWNLOAD ACTIONS FOR ACTIVE IMAGE
                    Row(
                        modifier = Modifier.fillMaxWidth().padding(top = 4.dp),
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Button(
                            onClick = {
                                Toast.makeText(context, "Directing download pipeline. Saved to gallery!", Toast.LENGTH_LONG).show()
                                viewModel.triggerMockDownload(
                                    CreationEntity(
                                        id = (100..999).random(),
                                        toolName = "Image Enhancer",
                                        category = "Image Tools",
                                        inputPrompt = "Upscale: $upscaleFactor | Custom Image ID",
                                        outputText = activeAfterUrl
                                    )
                                )
                            },
                            modifier = Modifier.weight(1f).height(44.dp).testTag("download_enhanced_button"),
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF10B981)),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(6.dp)
                            ) {
                                Icon(imageVector = Icons.Filled.CloudDownload, contentDescription = "Download", modifier = Modifier.size(16.dp))
                                Text("Download HD Image", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        OutlinedButton(
                            onClick = { processState = "idle" },
                            modifier = Modifier.weight(0.7f).height(44.dp),
                            border = BorderStroke(1.dp, Color.Gray),
                            colors = ButtonDefaults.outlinedButtonColors(contentColor = Color.White),
                            shape = RoundedCornerShape(10.dp)
                        ) {
                            Text("Enhance Another", fontSize = 12.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // IF PROCESSING: SHOW SOPHISTICATED NEURAL TIMELINE STEPS
        // -------------------------------------------------------------
        else if (processState == "processing") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0C0A12)),
                border = BorderStroke(1.5.dp, Brush.linearGradient(listOf(NeonCyan, NeonPurple))),
                shape = RoundedCornerShape(16.dp),
                modifier = Modifier.fillMaxWidth().padding(vertical = 12.dp)
            ) {
                Column(
                    modifier = Modifier.padding(24.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    Box(contentAlignment = Alignment.Center, modifier = Modifier.size(90.dp)) {
                        CircularProgressIndicator(
                            progress = { processProgress },
                            color = NeonCyan,
                            strokeWidth = 5.dp,
                            modifier = Modifier.fillMaxSize()
                        )
                        CircularProgressIndicator(
                            color = NeonPurple,
                            strokeWidth = 2.dp,
                            modifier = Modifier.fillMaxSize(0.8f)
                        )
                        Text(
                            text = "${(processProgress * 100).toInt()}%",
                            color = Color.White,
                            fontSize = 16.sp,
                            fontWeight = FontWeight.Black
                        )
                    }

                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Text(
                            text = "AI NEURAL ENHANCEMENT ENGINE RUNNING",
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Black,
                            color = NeonPurple,
                            letterSpacing = 1.2.sp
                        )
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = activeProgressStep,
                            fontSize = 14.sp,
                            fontWeight = FontWeight.Bold,
                            color = Color.White,
                            textAlign = TextAlign.Center
                        )
                    }

                    // Futuristic system progress timeline
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF040409), RoundedCornerShape(10.dp))
                            .padding(14.dp),
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        val stepsList = listOf(
                            "Parsing source pixels & metadata..." to (processProgress >= 0.15f),
                            "Scanning optical focus vectors (De-blurring)..." to (processProgress >= 0.35f),
                            "Eradicating high frequency compression noise..." to (processProgress >= 0.55f),
                            "Executing 4K pixel structure synthesis (Upscaling)..." to (processProgress >= 0.75f),
                            "Re-mapping dynamic HDR contrast & face coordinates..." to (processProgress >= 0.90f)
                        )

                        stepsList.forEach { (msg, isDone) ->
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(10.dp)
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(14.dp)
                                        .background(
                                            if (isDone) NeonCyan else Color.DarkGray,
                                            CircleShape
                                        ),
                                    contentAlignment = Alignment.Center
                                ) {
                                    if (isDone) {
                                        Icon(
                                            imageVector = Icons.Filled.Check,
                                            contentDescription = "Success",
                                            tint = PureBlack,
                                            modifier = Modifier.size(10.dp)
                                        )
                                    }
                                }

                                Text(
                                    text = msg,
                                    color = if (isDone) Color.White else Color.Gray,
                                    fontSize = 11.sp,
                                    fontWeight = if (isDone) FontWeight.Bold else FontWeight.Normal
                                )
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // IF IDLE: CORE SELECTION INTERACTIVE PANEL WORKFLOW
        // -------------------------------------------------------------
        else {
            // TABS: PRESET TEMPLATES OR LOCAL UPLOADS
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0x1F22D3EE), RoundedCornerShape(10.dp))
                    .padding(3.dp),
                horizontalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                Button(
                    onClick = { activeTab = "presets" },
                    modifier = Modifier.weight(1f).height(38.dp),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (activeTab == "presets") Color(0xFF0D0C15) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    contentPadding = PaddingValues()
                ) {
                    Text(
                        text = "Expert Presets",
                        color = if (activeTab == "presets") NeonCyan else Color.LightGray,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Bold
                    )
                }

                Button(
                    onClick = { 
                        activeTab = "custom"
                        if (customImageUris.isEmpty()) {
                            launchGallery()
                        }
                    },
                    modifier = Modifier.weight(1f).height(38.dp).testTag("select_custom_upload_tab"),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (activeTab == "custom") Color(0xFF0D0C15) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    contentPadding = PaddingValues()
                ) {
                    Text(
                        text = "Upload My Image(s)",
                        color = if (activeTab == "custom") NeonCyan else Color.LightGray,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }

            // TAB CONTENT: PRESETS GRID
            if (activeTab == "presets") {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text(
                        text = "Select an Expert Sample Preset",
                        color = Color.White,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Bold
                    )

                    presets.forEachIndexed { index, preset ->
                        val isSelected = index == selectedPresetIndex
                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .border(
                                    width = 1.dp,
                                    brush = if (isSelected) Brush.horizontalGradient(listOf(NeonCyan, NeonPurple)) else Brush.linearGradient(listOf(Color.Transparent, Color.Transparent)),
                                    shape = RoundedCornerShape(12.dp)
                                )
                                .clickable { selectedPresetIndex = index },
                            shape = RoundedCornerShape(12.dp),
                            colors = CardDefaults.cardColors(
                                containerColor = if (isSelected) Color(0xFF141221) else Color(0x12FFFFFF)
                            )
                        ) {
                            Row(
                                modifier = Modifier.padding(10.dp),
                                horizontalArrangement = Arrangement.spacedBy(12.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Card(
                                    modifier = Modifier.size(64.dp),
                                    shape = RoundedCornerShape(8.dp)
                                ) {
                                    AsyncImage(
                                        model = preset.beforeUrl,
                                        contentDescription = preset.title,
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                }

                                Column(modifier = Modifier.weight(1f)) {
                                    Text(
                                        text = preset.title,
                                        color = Color.White,
                                        fontSize = 13.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                    Text(
                                        text = preset.subtitle,
                                        color = Color.Gray,
                                        fontSize = 11.sp,
                                        lineHeight = 15.sp
                                    )
                                }

                                if (isSelected) {
                                    Icon(
                                        imageVector = Icons.Filled.CheckCircle,
                                        contentDescription = "Selected",
                                        tint = NeonCyan,
                                        modifier = Modifier.size(20.dp)
                                    )
                                }
                            }
                        }
                    }
                }
            }
            // TAB CONTENT: DRAG-AND-DROP STYLE FILE PICKER
            else {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text(
                        text = "Source Target Registration",
                        color = Color.White,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Bold
                    )

                    if (customImageUris.isEmpty()) {
                        // Empty drop card
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(160.dp)
                                .background(Color(0xFF06060C), RoundedCornerShape(14.dp))
                                .border(
                                    2.dp,
                                    Brush.linearGradient(listOf(Color.DarkGray, Color.Gray)),
                                    RoundedCornerShape(14.dp)
                                )
                                .clickable { launchGallery() }
                                .testTag("file_picker_trigger_card"),
                            contentAlignment = Alignment.Center
                        ) {
                            Column(
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.Center,
                                modifier = Modifier.padding(16.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Filled.CloudUpload,
                                    contentDescription = "Upload Icon",
                                    tint = NeonCyan,
                                    modifier = Modifier.size(40.dp)
                                )
                                Spacer(modifier = Modifier.height(10.dp))
                                Text(
                                    text = "TAP TO CHOOSE PHOTOS",
                                    color = Color.White,
                                    fontSize = 12.sp,
                                    fontWeight = FontWeight.ExtraBold
                                )
                                Text(
                                    text = "Select single or multiple files for batch processing",
                                    color = Color.Gray,
                                    fontSize = 10.sp,
                                    textAlign = TextAlign.Center,
                                    modifier = Modifier.padding(top = 4.dp)
                                )
                            }
                        }
                    } else {
                        // Display thumbnails list of loaded uris
                        Card(
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Text(
                                        text = "${customImageUris.size} Images Imported for Batch",
                                        color = Color.White,
                                        fontSize = 12.sp,
                                        fontWeight = FontWeight.Bold
                                    )

                                    IconButton(
                                        onClick = { customImageUris = emptyList() },
                                        modifier = Modifier.size(24.dp)
                                    ) {
                                        Icon(imageVector = Icons.Filled.Clear, contentDescription = "Clear All", tint = Color.Gray)
                                    }
                                }

                                Row(
                                    modifier = Modifier.horizontalScroll(rememberScrollState()),
                                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    customImageUris.forEachIndexed { i, uri ->
                                        val isSelected = i == selectedCustomImageIndex
                                        Card(
                                            modifier = Modifier
                                                .size(60.dp)
                                                .border(
                                                    1.5.dp,
                                                    if (isSelected) NeonCyan else Color.Transparent,
                                                    RoundedCornerShape(6.dp)
                                                )
                                                .clickable { selectedCustomImageIndex = i },
                                            shape = RoundedCornerShape(6.dp)
                                        ) {
                                            AsyncImage(
                                                model = uri.toString(),
                                                contentDescription = "Batch item",
                                                contentScale = ContentScale.Crop,
                                                modifier = Modifier.fillMaxSize()
                                            )
                                        }
                                    }

                                    // Add button
                                    Box(
                                        modifier = Modifier
                                            .size(60.dp)
                                            .background(Color(0xFF231E35), RoundedCornerShape(6.dp))
                                            .border(1.dp, Color.Gray, RoundedCornerShape(6.dp))
                                            .clickable { launchGallery() },
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Icon(imageVector = Icons.Filled.Add, contentDescription = "Add More", tint = Color.LightGray)
                                    }
                                }
                            }
                        }
                    }
                }
            }

            // -------------------------------------------------------------
            // DYNAMIC SIGNAL TUNING SUITE
            // -------------------------------------------------------------
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF090812)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(14.dp)) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Icon(imageVector = Icons.Filled.Tune, contentDescription = "Tuning Core", tint = NeonPurple, modifier = Modifier.size(16.dp))
                        Text(
                            text = "AI System Core Parameters",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }

                    // 1. Output Upscale multiplier factor (2x, 4x, 8x)
                    Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                        Text(
                            text = "Upscale Factor Target Ratio",
                            color = Color.LightGray,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )

                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF040409), RoundedCornerShape(10.dp))
                                .padding(4.dp),
                            horizontalArrangement = Arrangement.spacedBy(6.dp)
                        ) {
                            listOf("2x", "4x", "8x").forEach { ratio ->
                                val isSelected = ratio == upscaleFactor
                                Button(
                                    onClick = { upscaleFactor = ratio },
                                    modifier = Modifier.weight(1f).height(34.dp),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = if (isSelected) NeonPurple else Color.Transparent
                                    ),
                                    shape = RoundedCornerShape(6.dp),
                                    contentPadding = PaddingValues()
                                ) {
                                    Text(
                                        text = ratio + if (ratio == "8x") " (Ultra HD)" else " Screen",
                                        color = if (isSelected) Color.White else Color.Gray,
                                        fontSize = 11.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                        }
                    }

                    Divider(color = Color(0x19FFFFFF))

                    // 2. Feature toggles switches suite
                    Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        // HD Enhancement
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text("Super Resolution AI", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                Text("Dramatically upscales and clarifies base pixel density", color = Color.Gray, fontSize = 10.sp)
                            }
                            Switch(
                                checked = hdEnhancement,
                                onCheckedChange = { hdEnhancement = it },
                                colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan, checkedTrackColor = Color(0xFF133C3B))
                            )
                        }

                        // Blur Removal
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text("Blur & Edge Sharpening", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                Text("Fixes focal errors and lens motion shake", color = Color.Gray, fontSize = 10.sp)
                            }
                            Switch(
                                checked = blurRemoval,
                                onCheckedChange = { blurRemoval = it },
                                colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan, checkedTrackColor = Color(0xFF133C3B))
                            )
                        }

                        // Noise Reduction
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text("High-ISO Noise Reduction", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                Text("De-grains dark night-time or old vintage scans", color = Color.Gray, fontSize = 10.sp)
                            }
                            Switch(
                                checked = noiseReduction,
                                onCheckedChange = { noiseReduction = it },
                                colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan, checkedTrackColor = Color(0xFF133C3B))
                            )
                        }

                        // Color Correction
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text("HDR Aesthetic Correction", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                Text("Restores pale skin-tones and improves dynamic ranges", color = Color.Gray, fontSize = 10.sp)
                            }
                            Switch(
                                checked = colorCorrection,
                                onCheckedChange = { colorCorrection = it },
                                colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan, checkedTrackColor = Color(0xFF133C3B))
                            )
                        }

                        // Face Restoration
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text("Neural Face Restoration", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                Text("Rebuilds details for blurred out-of-focus portraits", color = Color.Gray, fontSize = 10.sp)
                            }
                            Switch(
                                checked = faceRestoration,
                                onCheckedChange = { faceRestoration = it },
                                colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan, checkedTrackColor = Color(0xFF133C3B))
                            )
                        }
                    }
                }
            }

            // Expandable Manual Precision Calibration Suite
            var showManualSuite by remember { mutableStateOf(false) }

            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0C0B18)),
                border = BorderStroke(1.dp, if (showManualSuite) NeonCyan.copy(alpha = 0.5f) else Color.DarkGray.copy(alpha = 0.5f)),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp)) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable { showManualSuite = !showManualSuite },
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Filled.Tune,
                                contentDescription = "Manual Tune",
                                tint = NeonCyan,
                                modifier = Modifier.size(16.dp)
                            )
                            Column {
                                Text(
                                    text = "Manual Precision Calibration Suite",
                                    color = Color.White,
                                    fontSize = 12.5.sp,
                                    fontWeight = FontWeight.Bold
                                )
                                Text(
                                    text = "Fine-tune sharpness, saturation, exposure & denoising",
                                    color = Color.Gray,
                                    fontSize = 11.sp
                                )
                            }
                        }
                        Icon(
                            imageVector = Icons.Filled.ArrowDropDown,
                            contentDescription = "Expand",
                            tint = Color.Gray,
                            modifier = Modifier
                                .size(18.dp)
                                .graphicsLayer(rotationZ = if (showManualSuite) 180f else 0f)
                        )
                    }

                    if (showManualSuite) {
                        Spacer(modifier = Modifier.height(14.dp))
                        Divider(color = Color(0x19FFFFFF), modifier = Modifier.padding(bottom = 12.dp))

                        // Slider 1: Micro-Sharpness & Edge Clarity
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(13.dp))
                                    Text("Micro-Sharpness & Edges", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                }
                                Text("${sharpnessSlider.toInt()}%", color = NeonCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = sharpnessSlider,
                                onValueChange = { sharpnessSlider = it },
                                valueRange = 0f..100f,
                                colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray)
                            )
                        }

                        Spacer(modifier = Modifier.height(8.dp))

                        // Slider 2: Vibrant saturation
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Icon(imageVector = Icons.Filled.Palette, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(13.dp))
                                    Text("Dynamic HDR Vibrancy", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                }
                                Text("${vibrancySlider.toInt()}%", color = NeonCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = vibrancySlider,
                                onValueChange = { vibrancySlider = it },
                                valueRange = 0f..100f,
                                colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray)
                            )
                        }

                        Spacer(modifier = Modifier.height(8.dp))

                        // Slider 3: Dynamic exposure
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Icon(imageVector = Icons.Filled.Star, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(13.dp))
                                    Text("Luminance Exposure Boost", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                }
                                val offsetText = if (exposureSlider >= 0) "+${exposureSlider.toInt()}" else "${exposureSlider.toInt()}"
                                Text(offsetText, color = NeonCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = exposureSlider,
                                onValueChange = { exposureSlider = it },
                                valueRange = -50f..50f,
                                colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray)
                            )
                        }

                        Spacer(modifier = Modifier.height(8.dp))

                        // Slider 4: Denoising Intensity
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Icon(imageVector = Icons.Filled.Settings, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(13.dp))
                                    Text("High-ISO De-graining Ratio", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                }
                                Text("${denoiseSlider.toInt()}%", color = NeonCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = denoiseSlider,
                                onValueChange = { denoiseSlider = it },
                                valueRange = 0f..100f,
                                colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray)
                            )
                        }

                        Spacer(modifier = Modifier.height(8.dp))

                        // Slider 5: Face Fusion Smoothness
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Icon(imageVector = Icons.Filled.Face, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(13.dp))
                                    Text("Portrait Neural Smoothing", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                }
                                Text("${faceFusionSlider.toInt()}%", color = NeonCyan, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = faceFusionSlider,
                                onValueChange = { faceFusionSlider = it },
                                valueRange = 0f..100f,
                                colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray)
                            )
                        }
                    }
                }
            }

            // CORE LAUNCH BUTTON TRIPPED
            val isCustomActiveButEmpty = activeTab == "custom" && customImageUris.isEmpty()

            Button(
                onClick = {
                    if (!isCustomActiveButEmpty) {
                        processState = "processing"
                        processProgress = 0f
                        activeProgressStep = "Accessing secure reconstruction registers..."

                        coroutineScope.launch {
                            // Run progress simulation over 3800ms
                            val simulatedDuration = 3800L
                            val totalIncrementalSteps = 100
                            val delayMs = simulatedDuration / totalIncrementalSteps

                            for (i in 0..totalIncrementalSteps) {
                                processProgress = i / 100f
                                activeProgressStep = when {
                                    i < 15 -> "Connecting neural model channels..."
                                    i < 35 -> "Running blind deconvolution arrays..."
                                    i < 55 -> "Eliminating pixel mosaic frequencies..."
                                    i < 75 -> "Building virtual high res canvas matrix..."
                                    else -> "Fusing restored skin colors & mapping HDR..."
                                }
                                delay(delayMs)
                            }

                            // Commit save action history records
                            val fileNamesStr = if (activeTab == "presets") {
                                presets[selectedPresetIndex].title
                            } else {
                                customImageUris.map { it.lastPathSegment ?: "custom_file.png" }.joinToString(", ")
                            }

                            val settingsComboStr = listOfNotNull(
                                if (hdEnhancement) "HD" else null,
                                if (blurRemoval) "Sharpen" else null,
                                if (noiseReduction) "Denoise" else null,
                                if (colorCorrection) "HDR-Color" else null,
                                if (faceRestoration) "NeuralFace" else null
                            ).joinToString(",")

                            viewModel.recordImageEnhancement(
                                inputImageNames = fileNamesStr,
                                upscaleFactor = upscaleFactor,
                                settingsString = settingsComboStr,
                                enhancedImageUrls = activeAfterUrl
                            )

                            processState = "success"
                            Toast.makeText(context, "AI Image Restoration Complete!", Toast.LENGTH_SHORT).show()
                        }
                    }
                },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(50.dp)
                    .background(
                        if (isCustomActiveButEmpty) Brush.linearGradient(listOf(Color.Transparent, Color.Transparent)) else Brush.linearGradient(listOf(NeonCyan, NeonPurple)),
                        RoundedCornerShape(12.dp)
                    )
                    .testTag("start_enhancement_button"),
                colors = ButtonDefaults.buttonColors(
                    containerColor = if (isCustomActiveButEmpty) Color(0xFF14142B) else Color.Transparent
                ),
                enabled = !isCustomActiveButEmpty,
                shape = RoundedCornerShape(12.dp)
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = "Enhance icon", tint = if (isCustomActiveButEmpty) Color.Gray else PureBlack)
                    Text(
                        text = if (isCustomActiveButEmpty) "UPLOAD AN IMAGE TO BEGIN" else if (customImageUris.size > 1) "ENHANCE BATCH IMAGES (${customImageUris.size})" else "START AI RECONSTRUCTION",
                        color = if (isCustomActiveButEmpty) Color.Gray else PureBlack,
                        fontSize = 12.5.sp,
                        fontWeight = FontWeight.Black,
                        letterSpacing = 1.sp
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // HISTORY MANAGEMENT FOOTER
        // -------------------------------------------------------------
        if (enhancerHistory.isNotEmpty()) {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.padding(top = 10.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "Image Enhancer History",
                        color = Color.White,
                        fontWeight = FontWeight.Bold,
                        fontSize = 13.sp
                    )
                    Text(
                        text = "Clear All",
                        color = Color.DarkGray,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold,
                        modifier = Modifier.clickable { viewModel.clearAllHistory() }
                    )
                }

                Row(
                    modifier = Modifier.horizontalScroll(rememberScrollState()),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    enhancerHistory.forEach { item ->
                        // Attempt to extract enhanced output image URL
                        val parts = item.inputPrompt.split(" | ")
                        var itemUpscale = "4x"
                        var itemSettings = ""
                        parts.forEach { part ->
                            if (part.startsWith("Upscale: ")) itemUpscale = part.replace("Upscale: ", "")
                            if (part.startsWith("Settings: ")) itemSettings = part.replace("Settings: ", "")
                        }
                        val enhancedUrl = item.outputText.lines()
                            .find { it.startsWith("https://") }
                            ?: "https://picsum.photos/300/300?sig=${item.id}"

                        Card(
                            modifier = Modifier
                                .width(120.dp)
                                .clickable {
                                    // Restore states
                                    upscaleFactor = itemUpscale
                                    hdEnhancement = itemSettings.contains("HD")
                                    blurRemoval = itemSettings.contains("Sharpen")
                                    noiseReduction = itemSettings.contains("Denoise")
                                    colorCorrection = itemSettings.contains("HDR-Color")
                                    faceRestoration = itemSettings.contains("NeuralFace")
                                    
                                    // Set to SUCCESS and display in slide reveal sandbox
                                    activeTab = "presets"
                                    selectedPresetIndex = presets.indexOfFirst { it.afterUrl == enhancedUrl }.coerceIn(0, presets.size - 1)
                                    processState = "success"
                                    sliderFraction = 0.5f
                                    Toast.makeText(context, "Loaded task ${item.id} from history!", Toast.LENGTH_SHORT).show()
                                },
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF06060F)),
                            shape = RoundedCornerShape(8.dp),
                            border = BorderStroke(0.5.dp, Color.DarkGray)
                        ) {
                            Column {
                                Box(
                                    modifier = Modifier.fillMaxWidth().height(80.dp)
                                ) {
                                    AsyncImage(
                                        model = enhancedUrl,
                                        contentDescription = "Restored Thumbnail",
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                }
                                Text(
                                    text = "Restoration #${item.id}",
                                    color = Color.White,
                                    fontSize = 9.5.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.padding(start = 6.dp, end = 6.dp, top = 4.dp)
                                )
                                Text(
                                    text = "Scale: $itemUpscale ($itemSettings)",
                                    color = Color.Gray,
                                    fontSize = 8.sp,
                                    modifier = Modifier.padding(start = 6.dp, end = 6.dp, bottom = 6.dp),
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis
                                )
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(30.dp))
    }
}

// ---------------------------------------------------------------------
// AI AVATAR GENERATOR WORKSPACE
// ---------------------------------------------------------------------

data class AvatarStyleInfo(
    val id: String,
    val title: String,
    val description: String,
    val keyword: String,
    val sampleImages: List<String>
)

data class SelfiePreset(
    val title: String,
    val url: String
)

@Composable
fun AvatarGeneratorWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val history by viewModel.history.collectAsState()
    val userStats by viewModel.userStats.collectAsState()

    // ---------------------------------------------------------------------
    // PREDEFINED OPTION DATASETS
    // ---------------------------------------------------------------------
    val stylePresets = remember {
        listOf(
            AvatarStyleInfo("realistic", "Realistic Portrait", "Photorealistic portrait", "Ultra realistic photorealistic lighting", listOf("photo-1544005313-94ddf0286df2", "photo-1506794778202-cad84cf45f1d")),
            AvatarStyleInfo("3d_render", "3D Game Model", "Highly polished gaming mesh", "CGI game protagonist render", listOf("photo-1535713875002-d1d0cf377fde", "photo-1535713875002-d1d0cf377fde")),
            AvatarStyleInfo("anime", "Anime / Manga", "Clean manga cel-shaded art", "Japanese anime illustration detail", listOf("photo-1607604276583-eef5d076aa5f", "photo-1578632767115-351597cf2477")),
            AvatarStyleInfo("cyberpunk", "Cyberpunk Rebel", "Fluorescent futuristic neon punk", "Cyberpunk neon lights style", listOf("photo-1511512578047-dfb367046420", "photo-1618005182384-a83a8bd57fbe")),
            AvatarStyleInfo("pixar", "Pixar Animation", "Cute cartoon animated look", "Pixar disney animated film character face", listOf("photo-1535713875002-d1d0cf377fde", "photo-1494790108377-be9c29b29330")),
            AvatarStyleInfo("chibi", "Cute Chibi Layout", "Tiny adorable SD anime chibi", "Extremely cute chibi keyart detail", listOf("photo-1607604276583-eef5d076aa5f", "photo-1578632767115-351597cf2477"))
        )
    }

    val selfiePresets = remember {
        listOf(
            SelfiePreset("Emma", "https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=400&fit=crop"),
            SelfiePreset("David", "https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=400&fit=crop"),
            SelfiePreset("Sophia", "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?q=80&w=400&fit=crop")
        )
    }

    // ---------------------------------------------------------------------
    // STATE DECLARATIONS: AVATAR DESIGN ELEMENTS
    // ---------------------------------------------------------------------
    var selectedTabFolder by remember { mutableStateOf(0) } // 0: Identity, 1: Hair & Eyes, 2: Apparel, 3: Scene & Pose, 4: Speech & Video
    var socialShareSheetActive by remember { mutableStateOf(false) }
    
    // FOLDER 0: Identity States
    var genderSelect by remember { mutableStateOf("Female") }
    var ageSelect by remember { mutableStateOf("Adult") }
    var faceShape by remember { mutableStateOf("Oval") }
    var faceWidthAdjust by remember { mutableStateOf(1.0f) }
    var jawlineAdjust by remember { mutableStateOf(1.00f) }
    var skinToneSelected by remember { mutableStateOf("Warm Sand") }
    var skinDetailsFreckles by remember { mutableStateOf(false) }
    var skinDetailsBeautyMarks by remember { mutableStateOf(false) }
    var skinDetailsCyberlines by remember { mutableStateOf(false) }

    // FOLDER 1: Hair, Eyes & Shapes
    var hairstyleSelected by remember { mutableStateOf("Curly Wave") }
    var hairLengthSlider by remember { mutableStateOf(35f) }
    var hairColorSelected by remember { mutableStateOf("Golden Yellow") }
    var eyeShapeSelected by remember { mutableStateOf("Almond") }
    var eyeSizeAdjust by remember { mutableStateOf(1.0f) }
    var eyeColorSelected by remember { mutableStateOf("Ocean Blue") }
    var eyebrowStyleSelected by remember { mutableStateOf("Arched Classic") }

    // FOLDER 2: Apparel & Rigging
    var bodyTypeSelected by remember { mutableStateOf("Athletic") }
    var heightSlider by remember { mutableStateOf(172f) }
    var bodyWidthSlider by remember { mutableStateOf(1.0f) }
    var outfitSelected by remember { mutableStateOf("Cybernetic Armor") }
    var accessoryGlasses by remember { mutableStateOf(false) }
    var accessoryHat by remember { mutableStateOf(false) }
    var accessorySunglasses by remember { mutableStateOf(false) }
    var accessoryEarrings by remember { mutableStateOf(true) }
    var accessoryNecklace by remember { mutableStateOf(false) }
    var accessoryHeadphones by remember { mutableStateOf(true) }

    // FOLDER 3: Backdrop, Pose & Express
    var bgEnvironmentSelected by remember { mutableStateOf("Cyber Grid Neon") }
    var poseSelected by remember { mutableStateOf("Thinking Pose") }
    var expressionSelected by remember { mutableStateOf("Confident") }

    // FOLDER 4: Voice Speech Script & Lip-Sync
    var ttsScriptText by remember { mutableStateOf("Welcome to the next generation of AI Custom Avatars! Real-time lip-synchronization and full-render animation pipeline active.") }
    var voiceLanguageSelect by remember { mutableStateOf("English UK Studio") }
    var lipSyncTalkingPlaying by remember { mutableStateOf(false) }

    // GENERAL CONFIG ENGINE
    var selectedAestheticStyleIndex by remember { mutableStateOf(0) }
    var customTextPromptTag by remember { mutableStateOf("") }
    var outputQuantityCount by remember { mutableStateOf(4) }
    var isHdGenerationMode by remember { mutableStateOf(true) }
    var offlineModeFail by remember { mutableStateOf(false) }

    // PREVIEW VIEWPORTS CONTROLLER
    var orbitAngleRotation by remember { mutableStateOf(0f) }
    var isAutoOrbitScanning by remember { mutableStateOf(false) }
    var zoomFactorMagnify by remember { mutableStateOf(1.0f) }
    var activeHolographicScanOverlay by remember { mutableStateOf(true) }

    // ENGINE PROCESS STATE
    var processState by remember { mutableStateOf("idle") }
    var processProgress by remember { mutableStateOf(0f) }
    val aiEngineLogLines = remember { mutableStateListOf<String>() }
    var activeResultPreviewIndex by remember { mutableStateOf(0) }

    // MONETIZATION TIER & DIALOGS
    var premiumUpgradePromptActive by remember { mutableStateOf(false) }
    var securityAuthPromptActive by remember { mutableStateOf(false) }
    var authEmailAddress by remember { mutableStateOf("") }
    var authPassphraseText by remember { mutableStateOf("") }
    var rewardedAdPlayingState by remember { mutableStateOf(false) }
    var adTimerCountdown by remember { mutableStateOf(5) }

    val loggedInState = userStats?.isLoggedIn ?: false
    val activeEmail = userStats?.email ?: "anonymous@clipai.io"
    val isPremiumPlan = (userStats?.subscriptionPlan ?: "Free") != "Free"
    val currentAvailableCredits = ((userStats?.totalCredits ?: 50) - (userStats?.creditsUsed ?: 0)).coerceAtLeast(0)
    val avatarHistory = history.filter { it.toolName == "AI Avatar Generator" }

    // Auto update rotating scan when activated
    LaunchedEffect(isAutoOrbitScanning) {
        if (isAutoOrbitScanning) {
            while (isAutoOrbitScanning) {
                delay(30L)
                orbitAngleRotation = (orbitAngleRotation + 2.5f) % 360f
            }
        }
    }

    // Dynamic prompt mapping helper to render incredibly context-matched portraits!
    val activeOutputUrl = remember(
        genderSelect,
        ageSelect,
        stylePresets,
        selectedAestheticStyleIndex,
        outfitSelected,
        bgEnvironmentSelected,
        activeResultPreviewIndex
    ) {
        val styleKey = stylePresets.getOrNull(selectedAestheticStyleIndex)?.id ?: "realistic"
        val seedPhotoId = when {
            styleKey == "anime" || styleKey == "chibi" -> {
                if (genderSelect == "Male") "photo-1578632767115-351597cf2477" else "photo-1607604276583-eef5d076aa5f"
            }
            styleKey == "cyberpunk" -> {
                if (genderSelect == "Male") "photo-1618005182384-a83a8bd57fbe" else "photo-1511512578047-dfb367046420"
            }
            styleKey == "pixar" || styleKey == "3d_render" -> {
                "photo-1535713875002-d1d0cf377fde"
            }
            else -> { // realistic portrait styles
                if (genderSelect == "Male") {
                    if (ageSelect == "Senior") "photo-1506794778202-cad84cf45f1d" else "photo-1500648767791-00dcc994a43e"
                } else {
                    if (ageSelect == "Senior") "photo-1544005313-94ddf0286df2" else "photo-1494790108377-be9c29b29330"
                }
            }
        }
        "https://images.unsplash.com/$seedPhotoId?q=80&w=600&fit=crop"
    }

    // Collect array of variants
    val resultVariantList = remember(activeOutputUrl) {
        listOf(
            activeOutputUrl,
            activeOutputUrl.replace("q=80", "q=85&sat=-100"), // variant black & white
            activeOutputUrl.replace("w=600", "w=600&blur=2"),  // variant dream focus
            activeOutputUrl.replace("q=80", "q=82&hue=90")     // variant color tone shift
        )
    }

    val runAvatarGeneration = {
        coroutineScope.launch {
            if (offlineModeFail) {
                processState = "error"
                Toast.makeText(context, "Network Offline! Cannot connect to SDXL custom generation cluster.", Toast.LENGTH_LONG).show()
                return@launch
            }
            if (!isPremiumPlan && currentAvailableCredits < 1) {
                Toast.makeText(context, "Insufficient rendering tokens! watch sponsored ad to earn credits.", Toast.LENGTH_LONG).show()
                premiumUpgradePromptActive = true
                return@launch
            }

            processState = "processing"
            processProgress = 0f
            aiEngineLogLines.clear()
            activeResultPreviewIndex = 0

            val logs = listOf(
                "VERIFYING SESSION KEY...",
                "LOADING CONTROLNET FACE DENSITY WEIGHTS...",
                "CONFIGURING FACE MESH STRUCT [${faceShape.uppercase()}] Width=${faceWidthAdjust}f",
                "SETTING SKIN TONE SWATCH TO [$skinToneSelected]",
                "HAIR SYNTHESIS: Style=[$hairstyleSelected], Color=[$hairColorSelected], Length=${hairLengthSlider.toInt()}cm",
                "APPLYING APPAREL GRID TO [$outfitSelected]",
                "COMPILATION PASS AT ${(heightSlider).toInt()}cm AT HIGH STABILITY",
                "DIFFUSION NOISE RESOLVING PASS...",
                "FINALIZING TENSOR METRICS...",
                "TRANSMITTING 4K PNG ASSETS TO MOBILE CANVAS..."
            )

            for (i in logs.indices) {
                processProgress = (i + 1).toFloat() / logs.size
                aiEngineLogLines.add(logs[i])
                delay(if (isPremiumPlan) 450L else 750L)
            }

            // Save in creation logs history
            viewModel.recordAvatarGeneration(
                inputImageName = "CustomRig_${genderSelect}_${ageSelect}.png",
                style = stylePresets.getOrNull(selectedAestheticStyleIndex)?.title ?: "Custom Rig",
                count = outputQuantityCount,
                isHd = isHdGenerationMode,
                outputUrls = resultVariantList.take(outputQuantityCount).joinToString("\n")
            )

            processState = "success"
            Toast.makeText(context, "✦ Premium Customized AI Avatar Generated!", Toast.LENGTH_SHORT).show()
        }
    }

    Column(
        modifier = modifier.fillMaxWidth().verticalScroll(rememberScrollState()).padding(12.dp),
        verticalArrangement = Arrangement.spacedBy(14.dp)
    ) {

        // --- SECTION 1: HEADER & IDENTITY STATUS ---
        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF0F081C)),
            border = BorderStroke(1.dp, NeonPurple.copy(alpha = 0.5f))
        ) {
            Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                        Box(
                            modifier = Modifier
                                .size(32.dp)
                                .background(NeonPurple.copy(alpha = 0.2f), CircleShape),
                            contentAlignment = Alignment.Center
                        ) {
                            Icon(
                                imageVector = Icons.Default.Face,
                                contentDescription = "Face Profile",
                                tint = NeonPurple,
                                modifier = Modifier.size(20.dp)
                            )
                        }
                        Column {
                            Text(
                                text = if (loggedInState) activeEmail else "Active Guest Rig",
                                color = Color.White,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold
                            )
                            Text(
                                text = "${if (isPremiumPlan) "PREMIUM LIFETIME UNLOCKED" else "FREE RENDERING DESIGNER"} • $currentAvailableCredits credits",
                                color = Color.LightGray,
                                fontSize = 9.sp
                            )
                        }
                    }
                    Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        IconButton(onClick = { premiumUpgradePromptActive = true }) {
                            Icon(Icons.Filled.Star, "Pro checkout", tint = Color(0xFFFFD700))
                        }
                        IconButton(onClick = { securityAuthPromptActive = true }) {
                            Icon(Icons.Default.Settings, "Auth config", tint = Color.LightGray)
                        }
                    }
                }

                if (!isPremiumPlan) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color.White.copy(alpha = 0.04f), RoundedCornerShape(8.dp))
                            .clickable {
                                coroutineScope.launch {
                                    rewardedAdPlayingState = true
                                    adTimerCountdown = 5
                                    while (adTimerCountdown > 0) {
                                        delay(1000)
                                        adTimerCountdown--
                                    }
                                    rewardedAdPlayingState = false
                                    // Watch ad grants 15 credits locally via VM record
                                    viewModel.recordAvatarGeneration(
                                        inputImageName = "SponsorAdRef.png",
                                        style = "Ad Incentive",
                                        count = 0,
                                        isHd = false,
                                        outputUrls = "AD_TOKEN_GRANTED"
                                    )
                                    Toast
                                        .makeText(context, "+15 Render Credits Granted!", Toast.LENGTH_SHORT)
                                        .show()
                                }
                            }
                            .padding(10.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                            Box(
                                modifier = Modifier
                                    .size(6.dp)
                                    .background(Color.Green, CircleShape)
                            )
                            Text("Earn Instant Credits", color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                        }
                        Text("Watch 5s Video Ad (+15 credits) ➔", color = NeonPurple, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }
        }

        // --- SECTION 2: 3D-INTEGRATED VISUAL VIEWPORT SANDBOX ---
        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF07040F)),
            border = BorderStroke(1.dp, Color.DarkGray.copy(alpha = 0.5f))
        ) {
            Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "Visual Viewport Frame",
                        color = Color.White,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Black
                    )
                    Box(
                        modifier = Modifier
                            .background(NeonPurple.copy(alpha = 0.15f), RoundedCornerShape(6.dp))
                            .padding(horizontal = 6.dp, vertical = 2.dp)
                    ) {
                        Text(
                            text = "LIVE DESIGNER RIG",
                            color = NeonPurple,
                            fontSize = 8.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }

                // Main Holographic Viewport Canvas
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(260.dp)
                        .clip(RoundedCornerShape(10.dp))
                        .background(Color.Black)
                        .border(1.dp, NeonPurple.copy(alpha = 0.3f), RoundedCornerShape(10.dp)),
                    contentAlignment = Alignment.Center
                ) {
                    val activeDisplayUrl = if (processState == "success") {
                        resultVariantList.getOrNull(activeResultPreviewIndex) ?: activeOutputUrl
                    } else {
                        activeOutputUrl
                    }

                    // Simulated 3D Angle Multiplier
                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .graphicsLayer(
                                rotationZ = if (isAutoOrbitScanning) orbitAngleRotation else 0f,
                                scaleX = zoomFactorMagnify,
                                scaleY = zoomFactorMagnify
                            )
                    ) {
                        AsyncImage(
                            model = activeDisplayUrl,
                            contentDescription = "Avatar Synthesis Output",
                            contentScale = ContentScale.Crop,
                            modifier = Modifier.fillMaxSize()
                        )
                    }

                    // Holographic Grid lines / scanning box
                    if (activeHolographicScanOverlay) {
                        Canvas(modifier = Modifier.fillMaxSize()) {
                            val lineGap = 24.dp.toPx()
                            var x = 0f
                            while (x < size.width) {
                                drawLine(
                                    color = NeonPurple.copy(alpha = 0.08f),
                                    start = Offset(x, 0f),
                                    end = Offset(x, size.height),
                                    strokeWidth = 1f
                                )
                                x += lineGap
                            }
                            var y = 0f
                            while (y < size.height) {
                                drawLine(
                                    color = NeonPurple.copy(alpha = 0.08f),
                                    start = Offset(0f, y),
                                    end = Offset(size.width, y),
                                    strokeWidth = 1f
                                )
                                y += lineGap
                            }
                        }

                        // Framing box
                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .padding(24.dp)
                                .border(0.5.dp, NeonPurple.copy(alpha = 0.2f), RoundedCornerShape(4.dp))
                        )
                    }

                    // Talking lip sync vocal wave bars if activated
                    if (lipSyncTalkingPlaying) {
                        Box(
                            modifier = Modifier
                                .align(Alignment.BottomCenter)
                                .fillMaxWidth()
                                .background(Color.Black.copy(alpha = 0.6f))
                                .padding(8.dp)
                        ) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally, modifier = Modifier.fillMaxWidth()) {
                                Text("Speech Modeling Audio Playback Active...", color = Color.Green, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                                Spacer(modifier = Modifier.height(4.dp))
                                Row(
                                    horizontalArrangement = Arrangement.spacedBy(4.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    for (barIndex in 0..6) {
                                        val waveScale = remember { (10..40).random() }
                                        Box(
                                            modifier = Modifier
                                                .size(3.dp, waveScale.dp)
                                                .background(NeonPurple, RoundedCornerShape(2.dp))
                                        )
                                    }
                                }
                            }
                        }
                    }

                    // Tag Overlay
                    Box(
                        modifier = Modifier
                            .align(Alignment.TopEnd)
                            .padding(10.dp)
                            .background(Color.Black.copy(0.7f), RoundedCornerShape(4.dp))
                            .padding(horizontal = 6.dp, vertical = 2.dp)
                    ) {
                        Text(
                            text = "${genderSelect.uppercase()} • ${ageSelect.uppercase()} • ${expressionSelected.uppercase()}",
                            color = Color.LightGray,
                            fontSize = 8.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }

                // Viewport Controls Grid
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    // Auto Orbit Scanner
                    Row(
                        modifier = Modifier
                            .weight(1f)
                            .background(Color.White.copy(alpha = 0.03f), RoundedCornerShape(6.dp))
                            .clickable { isAutoOrbitScanning = !isAutoOrbitScanning }
                            .padding(6.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.Center
                    ) {
                        Checkbox(
                            checked = isAutoOrbitScanning,
                            onCheckedChange = { isAutoOrbitScanning = it },
                            modifier = Modifier.scale(0.7f)
                        )
                        Spacer(modifier = Modifier.width(2.dp))
                        Text(
                            text = "Orbit Auto-Scan",
                            color = Color.White,
                            fontSize = 9.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }

                    // Grid toggles
                    Row(
                        modifier = Modifier
                            .weight(1f)
                            .background(Color.White.copy(alpha = 0.03f), RoundedCornerShape(6.dp))
                            .clickable { activeHolographicScanOverlay = !activeHolographicScanOverlay }
                            .padding(6.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.Center
                    ) {
                        Checkbox(
                            checked = activeHolographicScanOverlay,
                            onCheckedChange = { activeHolographicScanOverlay = it },
                            modifier = Modifier.scale(0.7f)
                        )
                        Spacer(modifier = Modifier.width(2.dp))
                        Text(
                            text = "Holo Grid Mesh",
                            color = Color.White,
                            fontSize = 9.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }

                // Zoom Factor Slider
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Text("Magnify Lens Preview", color = Color.Gray, fontSize = 9.sp)
                    Slider(
                        value = zoomFactorMagnify,
                        onValueChange = { zoomFactorMagnify = it },
                        valueRange = 0.8f..1.6f,
                        colors = SliderDefaults.colors(thumbColor = NeonPurple, activeTrackColor = NeonPurple),
                        modifier = Modifier.weight(1f)
                    )
                    Text(String.format("%.1fx", zoomFactorMagnify), color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                }
            }
        }

        // --- SECTION 3: TABBED CUSTOMIZATION MATRIX PANEL ---
        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
            border = BorderStroke(0.5.dp, Color.DarkGray)
        ) {
            Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                // Header of Tabs
                Text(
                    text = "Customization Engine Matrix",
                    color = Color.White,
                    fontSize = 11.5.sp,
                    fontWeight = FontWeight.Black
                )

                ScrollableTabRow(
                    selectedTabIndex = selectedTabFolder,
                    containerColor = Color.Transparent,
                    contentColor = NeonPurple,
                    edgePadding = 0.dp,
                    indicator = { tabPositions ->
                        Box(
                            modifier = Modifier
                                .tabIndicatorOffset(tabPositions[selectedTabFolder])
                                .height(2.5.dp)
                                .background(NeonPurple)
                        )
                    }
                ) {
                    listOf("Identity", "Hair & Eyes", "Physique", "Backdrop", "Speech Engine").forEachIndexed { idx, title ->
                        Tab(
                            selected = selectedTabFolder == idx,
                            onClick = { selectedTabFolder = idx },
                            text = { Text(title, fontSize = 9.sp, fontWeight = FontWeight.Bold, color = if (selectedTabFolder == idx) Color.White else Color.Gray) }
                        )
                    }
                }

                // --- TAB CONTROLLER VIEWPORTS ---
                when (selectedTabFolder) {
                    0 -> { // Identity Tab
                        Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                            // Row 1: Gender Choose
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                listOf("Female", "Male").forEach { gender ->
                                    val isSelected = genderSelect == gender
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .background(if (isSelected) NeonPurple.copy(alpha = 0.2f) else Color.White.copy(0.01f), RoundedCornerShape(6.dp))
                                            .border(1.dp, if (isSelected) NeonPurple else Color.DarkGray, RoundedCornerShape(6.dp))
                                            .clickable { genderSelect = gender }
                                            .padding(10.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(gender, color = if (isSelected) Color.White else Color.Gray, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }

                            // Row 2: Age Choose
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                listOf("Teen", "Adult", "Senior").forEach { age ->
                                    val isSelected = ageSelect == age
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .background(if (isSelected) NeonPurple.copy(alpha = 0.2f) else Color.White.copy(0.01f), RoundedCornerShape(6.dp))
                                            .border(1.dp, if (isSelected) NeonPurple else Color.DarkGray, RoundedCornerShape(6.dp))
                                            .clickable { ageSelect = age }
                                            .padding(10.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(age, color = if (isSelected) Color.White else Color.Gray, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }

                            // Row 3: Face Shape Dynamic DropGrid
                            Text("Face Shape Contour", color = Color.LightGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Oval", "Round", "Square", "Heart", "Diamond", "Long").forEach { shape ->
                                    val isSelected = faceShape == shape
                                    Box(
                                        modifier = Modifier
                                            .background(if (isSelected) NeonPurple else Color.White.copy(0.03f), RoundedCornerShape(4.dp))
                                            .clickable { faceShape = shape }
                                            .padding(horizontal = 10.dp, vertical = 6.dp)
                                    ) {
                                        Text(shape, color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }

                            // Sliders for Width / Jawline
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Text("Face Scale Width", color = Color.Gray, fontSize = 9.sp, modifier = Modifier.width(90.dp))
                                Slider(
                                    value = faceWidthAdjust,
                                    onValueChange = { faceWidthAdjust = it },
                                    valueRange = 0.5f..1.5f,
                                    colors = SliderDefaults.colors(thumbColor = NeonPurple, activeTrackColor = NeonPurple),
                                    modifier = Modifier.weight(1f)
                                )
                                Text(String.format("%.2f", faceWidthAdjust), color = Color.White, fontSize = 9.sp, modifier = Modifier.width(30.dp))
                            }

                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Text("Jawline Define Scale", color = Color.Gray, fontSize = 9.sp, modifier = Modifier.width(90.dp))
                                Slider(
                                    value = jawlineAdjust,
                                    onValueChange = { jawlineAdjust = it },
                                    valueRange = 0.5f..1.5f,
                                    colors = SliderDefaults.colors(thumbColor = NeonPurple, activeTrackColor = NeonPurple),
                                    modifier = Modifier.weight(1f)
                                )
                                Text(String.format("%.2f", jawlineAdjust), color = Color.White, fontSize = 9.sp, modifier = Modifier.width(30.dp))
                            }

                            // Skin tone swatch circle selection
                            Text("Selective Skin Swatch", color = Color.LightGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                listOf("Pale Ivory", "Warm Sand", "Honey Bronze", "Rich Cocoa").forEach { tone ->
                                    val isSel = skinToneSelected == tone
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .background(if (isSel) NeonPurple.copy(alpha = 0.15f) else Color.Transparent, RoundedCornerShape(4.dp))
                                            .border(1.dp, if (isSel) NeonPurple else Color.DarkGray, RoundedCornerShape(4.dp))
                                            .clickable { skinToneSelected = tone }
                                            .padding(6.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(tone, color = Color.LightGray, fontSize = 9.sp, textAlign = TextAlign.Center)
                                    }
                                }
                            }

                            // Skin detail elements
                            Row(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.weight(1f)) {
                                    Checkbox(checked = skinDetailsFreckles, onCheckedChange = { skinDetailsFreckles = it })
                                    Text("Freckles", color = Color.Gray, fontSize = 9.sp)
                                }
                                Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.weight(1f)) {
                                    Checkbox(checked = skinDetailsBeautyMarks, onCheckedChange = { skinDetailsBeautyMarks = it })
                                    Text("Beauty Spot", color = Color.Gray, fontSize = 9.sp)
                                }
                                Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.weight(1f)) {
                                    Checkbox(checked = skinDetailsCyberlines, onCheckedChange = { skinDetailsCyberlines = it })
                                    Text("Cybermesh", color = Color.Gray, fontSize = 9.sp)
                                }
                            }
                        }
                    }

                    1 -> { // Hair & Eyes Tab
                        Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                            Text("Hair Rig Configuration", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Curly Wave", "Classic Straight", "Spiky Punk", "Long Braid", "Pixie Style", "Bald Cut").forEach { hs ->
                                    val isSel = hairstyleSelected == hs
                                    Box(
                                        modifier = Modifier
                                            .background(if (isSel) NeonPurple else Color.White.copy(0.02f), RoundedCornerShape(4.dp))
                                            .clickable { hairstyleSelected = hs }
                                            .padding(8.dp)
                                    ) {
                                        Text(hs, color = Color.White, fontSize = 9.5.sp)
                                    }
                                }
                            }

                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Text("Hair Length", color = Color.Gray, fontSize = 9.sp, modifier = Modifier.width(70.dp))
                                Slider(
                                    value = hairLengthSlider,
                                    onValueChange = { hairLengthSlider = it },
                                    valueRange = 0f..100f,
                                    colors = SliderDefaults.colors(thumbColor = NeonPurple),
                                    modifier = Modifier.weight(1f)
                                )
                                Text("${hairLengthSlider.toInt()} cm", color = Color.White, fontSize = 9.sp)
                            }

                            Text("Hair Swatch Color", color = Color.LightGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Silver Gray", "Golden Yellow", "Auburn Red", "Midnight Black", "Neon Pink").forEach { hc ->
                                    val isSel = hairColorSelected == hc
                                    Box(
                                        modifier = Modifier
                                            .background(if (isSel) NeonPurple.copy(alpha = 0.2f) else Color.Transparent, RoundedCornerShape(4.dp))
                                            .border(1.dp, if (isSel) NeonPurple else Color.DarkGray, RoundedCornerShape(4.dp))
                                            .clickable { hairColorSelected = hc }
                                            .padding(6.dp)
                                    ) {
                                        Text(hc, color = Color.LightGray, fontSize = 9.sp)
                                    }
                                }
                            }

                            // Eyes options
                            HorizontalDivider(color = Color.DarkGray, thickness = 0.5.dp)
                            Text("Iris Eye & Eyebrows Structure", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Almond", "Phoenix Shape", "Cat-Eye Glamour", "Manga Large").forEach { es ->
                                    val isSel = eyeShapeSelected == es
                                    Box(
                                        modifier = Modifier
                                            .background(if (isSel) NeonPurple else Color.White.copy(0.02f), RoundedCornerShape(4.dp))
                                            .clickable { eyeShapeSelected = es }
                                            .padding(8.dp)
                                    ) {
                                        Text(es, color = Color.White, fontSize = 9.sp)
                                    }
                                }
                            }

                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Text("Eye Pupil Size", color = Color.Gray, fontSize = 9.sp, modifier = Modifier.width(70.dp))
                                Slider(
                                    value = eyeSizeAdjust,
                                    onValueChange = { eyeSizeAdjust = it },
                                    valueRange = 0.8f..1.4f,
                                    colors = SliderDefaults.colors(thumbColor = NeonPurple),
                                    modifier = Modifier.weight(1f)
                                )
                                Text(String.format("%.2f", eyeSizeAdjust), color = Color.White, fontSize = 9.sp)
                            }

                            Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Ocean Blue", "Emerald Green", "Glowing Violet", "Amber Gold", "Deep Obsidian").forEach { ec ->
                                        val isSel = eyeColorSelected == ec
                                        Box(
                                            modifier = Modifier
                                                .background(if (isSel) NeonPurple.copy(alpha = 0.2f) else Color.Transparent, RoundedCornerShape(4.dp))
                                                .border(1.dp, if (isSel) NeonPurple else Color.DarkGray, RoundedCornerShape(4.dp))
                                                .clickable { eyeColorSelected = ec }
                                                .padding(6.dp)
                                        ) {
                                            Text(ec, color = Color.LightGray, fontSize = 9.sp)
                                        }
                                    }
                            }
                        }
                    }

                    2 -> { // Physique Tab
                        Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                            Text("Body Core Build Type", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Slim", "Athletic", "Average", "Muscular", "Heavy").forEach { bt ->
                                    val isSel = bodyTypeSelected == bt
                                    Box(
                                        modifier = Modifier
                                            .background(if (isSel) NeonPurple else Color.White.copy(0.02f), RoundedCornerShape(4.dp))
                                            .clickable { bodyTypeSelected = bt }
                                            .padding(8.dp)
                                    ) {
                                        Text(bt, color = Color.White, fontSize = 9.5.sp)
                                    }
                                }
                            }

                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Text("Rig Height", color = Color.Gray, fontSize = 9.sp, modifier = Modifier.width(70.dp))
                                Slider(
                                    value = heightSlider,
                                    onValueChange = { heightSlider = it },
                                    valueRange = 140f..210f,
                                    colors = SliderDefaults.colors(thumbColor = NeonPurple),
                                    modifier = Modifier.weight(1f)
                                )
                                Text("${heightSlider.toInt()} cm", color = Color.White, fontSize = 9.sp)
                            }

                            // Outfit Theme Rig
                            Text("Rig Apparel Outfit Item", color = Color.LightGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Cybernetic Armor", "Casual Chic Hoodie", "Traditional Royalty", "Sci-Fi Spacer Suit", "Vintage Leather Rider").forEach { ot ->
                                    val isSel = outfitSelected == ot
                                    Box(
                                        modifier = Modifier
                                            .background(if (isSel) NeonPurple else Color.White.copy(0.02f), RoundedCornerShape(4.dp))
                                            .clickable { outfitSelected = ot }
                                            .padding(8.dp)
                                    ) {
                                        Text(ot, color = Color.White, fontSize = 9.sp)
                                    }
                                }
                            }

                            // Accessory switches
                            Text("Physique Frame Accessories", color = Color.LightGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.fillMaxWidth().horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Checkbox(checked = accessoryGlasses, onCheckedChange = { accessoryGlasses = it })
                                    Text("Spectacles", color = Color.Gray, fontSize = 9.sp)
                                }
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Checkbox(checked = accessoryHat, onCheckedChange = { accessoryHat = it })
                                    Text("Tactical Hat", color = Color.Gray, fontSize = 9.sp)
                                }
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Checkbox(checked = accessorySunglasses, onCheckedChange = { accessorySunglasses = it })
                                    Text("Reflective Sunglasses", color = Color.Gray, fontSize = 9.sp)
                                }
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Checkbox(checked = accessoryEarrings, onCheckedChange = { accessoryEarrings = it })
                                    Text("Earrings", color = Color.Gray, fontSize = 9.sp)
                                }
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Checkbox(checked = accessoryHeadphones, onCheckedChange = { accessoryHeadphones = it })
                                    Text("Earphones", color = Color.Gray, fontSize = 9.sp)
                                }
                            }
                        }
                    }

                    3 -> { // Backdrop Tab
                        Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                            Text("Backdrop Environmental Backdrop", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Cyber Grid Neon", "Scenic Cozy Studio", "Majestic Alpine Summit", "Deep Andromeda Void", "Retro Sunset Beach").forEach { bg ->
                                    val isSel = bgEnvironmentSelected == bg
                                    Box(
                                        modifier = Modifier
                                            .background(if (isSel) NeonPurple else Color.White.copy(0.02f), RoundedCornerShape(4.dp))
                                            .clickable { bgEnvironmentSelected = bg }
                                            .padding(8.dp)
                                    ) {
                                        Text(bg, color = Color.White, fontSize = 9.5.sp)
                                    }
                                }
                            }

                            Text("Mesh Pose & Rig Expression", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Text("Skeletal Rig Pose", color = Color.Gray, fontSize = 8.sp)
                                    Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                        listOf("Thinking Pose", "Hero Stance Action", "Corporate Portrait").forEach { ps ->
                                            Box(
                                                modifier = Modifier
                                                    .background(if (poseSelected == ps) NeonPurple else Color.White.copy(0.01f), RoundedCornerShape(4.dp))
                                                    .border(0.5.dp, Color.DarkGray, RoundedCornerShape(4.dp))
                                                    .clickable { poseSelected = ps }
                                                    .padding(6.dp)
                                            ) {
                                                Text(ps, color = Color.White, fontSize = 8.sp)
                                            }
                                        }
                                    }
                                }
                            }

                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Text("Face Microexpression", color = Color.Gray, fontSize = 8.sp)
                                    Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                        listOf("Confident", "Smiling Charm", "Neutral Slate", "Fierce focus").forEach { es ->
                                            Box(
                                                modifier = Modifier
                                                    .background(if (expressionSelected == es) NeonPurple else Color.White.copy(0.01f), RoundedCornerShape(4.dp))
                                                    .border(0.5.dp, Color.DarkGray, RoundedCornerShape(4.dp))
                                                    .clickable { expressionSelected = es }
                                                    .padding(6.dp)
                                            ) {
                                                Text(es, color = Color.White, fontSize = 8.sp)
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }

                    4 -> { // Speech Engine Tab
                        Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                            Text("Voice Speech Lip-Sync Script", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            OutlinedTextField(
                                value = ttsScriptText,
                                onValueChange = { ttsScriptText = it },
                                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(80.dp),
                                placeholder = { Text("Write speech scripts for your synthesized avatar...", color = Color.Gray, fontSize = 10.sp) }
                            )

                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text("Phoneme Voice Vocal Engine", color = Color.Gray, fontSize = 9.sp)
                                Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    listOf("English UK Studio", "US Accent Pro", "Vocaloid Synth").forEach { lang ->
                                        Box(
                                            modifier = Modifier
                                                .background(if (voiceLanguageSelect == lang) NeonPurple else Color.White.copy(0.02f), RoundedCornerShape(4.dp))
                                                .clickable { voiceLanguageSelect = lang }
                                                .padding(6.dp)
                                        ) {
                                            Text(lang, color = Color.White, fontSize = 8.5.sp)
                                        }
                                    }
                                }
                            }

                            // Talk Switch
                            Button(
                                onClick = { lipSyncTalkingPlaying = !lipSyncTalkingPlaying },
                                colors = ButtonDefaults.buttonColors(containerColor = if (lipSyncTalkingPlaying) Color.Red else NeonPurple),
                                shape = RoundedCornerShape(8.dp),
                                modifier = Modifier.fillMaxWidth()
