                                        tint = Color.White,
                                        modifier = Modifier.size(16.dp)
                                    )
                                    Text(
                                        text = if (lipSyncTalkingPlaying) "MUTE LIP SYNC AUDIO DEMO" else "SIMULATE TALKING MODEL MODE (LIP-SYNC)",
                                        color = Color.White,
                                        fontSize = 10.sp,
                                        fontWeight = FontWeight.Bold
