        // --- SECTION 4: AESTHETIC GENERATION STYLES CATALOG ---
        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF0C0714)),
            border = BorderStroke(0.5.dp, Color.DarkGray)
        ) {
            Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                Text("Selective Rendering Styles Layout", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                Row(
                    modifier = Modifier.fillMaxWidth().horizontalScroll(rememberScrollState()),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    stylePresets.forEachIndexed { i, style ->
                        val isSel = selectedAestheticStyleIndex == i
                        Card(
                            colors = CardDefaults.cardColors(containerColor = if (isSel) Color(0xFF1E0E35) else Color.Transparent),
                            border = BorderStroke(if (isSel) 1.5.dp else 0.5.dp, if (isSel) NeonPurple else Color.DarkGray),
                            modifier = Modifier
                                .width(115.dp)
                                .clickable { selectedAestheticStyleIndex = i }
                        ) {
                            Column {
                                Box(modifier = Modifier.fillMaxWidth().height(60.dp)) {
                                    AsyncImage(
                                        model = "https://images.unsplash.com/" + style.sampleImages.first() + "?q=80&w=200&fit=crop",
                                        contentDescription = "Preset image indicator",
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                }
                                Text(
                                    text = style.title,
                                    color = Color.White,
                                    fontSize = 9.5.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.padding(4.dp),
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis
                                )
                            }
                        }
                    }
                }
            }
        }

        // --- SECTION 5: GENERATION CAPACITY BAR & BATCHES ---
        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF0C0714)),
            border = BorderStroke(0.5.dp, Color.DarkGray)
