            Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column {
                        Text("Rig Render Output Size", color = Color.White, fontSize = 11.5.sp, fontWeight = FontWeight.Bold)
                        Text("Choose total variant assets to synthesize", color = Color.Gray, fontSize = 9.sp)
                    }
                    Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                        listOf(1, 2, 3, 4).forEach { size ->
                            val isSel = outputQuantityCount == size
                            Box(
                                modifier = Modifier
                                    .size(28.dp)
                                    .background(if (isSel) NeonPurple else Color.White.copy(0.04f), RoundedCornerShape(4.dp))
                                    .clickable { outputQuantityCount = size }
                                    .padding(4.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Text(
                                    text = "$size",
                                    color = Color.White,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }

                HorizontalDivider(color = Color.DarkGray, thickness = 0.5.dp)

                // Extra controls and features
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Text("Ultra HD Coreupscale", color = Color.LightGray, fontSize = 10.sp)
                        Switch(
                            checked = isHdGenerationMode,
                            onCheckedChange = { isHdGenerationMode = it },
                            modifier = Modifier.scale(0.6f)
                        )
                    }

                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Text("Simulate Offline Mode", color = Color.LightGray, fontSize = 10.sp)
                        Switch(
                            checked = offlineModeFail,
                            onCheckedChange = { offlineModeFail = it },
                            modifier = Modifier.scale(0.6f)
                        )
                    }
                }
            }
        }

        // --- SECTION 6: PROCESSING LOGS AND RENDER VARIATIONS PROGRESS ---
        if (processState == "processing") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0C0715)),
                border = BorderStroke(1.dp, NeonPurple)
            ) {
                Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                            CircularProgressIndicator(color = NeonPurple, modifier = Modifier.size(14.dp), strokeWidth = 1.5.dp)
                            Text("Compiling custom face nodes...", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                        }
                        Text(String.format("%d%%", (processProgress * 100).toInt()), color = NeonPurple, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                    }

                    LinearProgressIndicator(
                        progress = processProgress,
                        color = NeonPurple,
                        trackColor = Color.DarkGray,
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(5.dp)
                            .clip(CircleShape)
                    )

                    // Floating log traces code terminal looks amazing
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color.Black, RoundedCornerShape(6.dp))
                            .border(0.5.dp, Color.DarkGray, RoundedCornerShape(6.dp))
                            .padding(8.dp)
                            .height(95.dp)
                            .verticalScroll(rememberScrollState()),
                        verticalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        aiEngineLogLines.forEach { line ->
                            Text(
                                text = "➧ $line",
                                color = Color.Green,
                                fontSize = 8.sp,
                                fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace
                            )
                        }
                    }
                }
            }
        }

        // --- SECTION 7: SUCCESS REPAIR & SAVE ACTIONS ---
        if (processState == "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0A0711)),
                border = BorderStroke(1.dp, NeonPurple.copy(alpha = 0.5f))
            ) {
