                                    AsyncImage(
                                        model = url,
                                        contentDescription = "batch item choice",
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                    Box(
                                        modifier = Modifier
                                            .align(Alignment.BottomStart)
                                            .background(Color.Black.copy(0.6f))
                                            .padding(2.dp)
                                    ) {
                                        Text("#${idx + 1}", color = Color.White, fontSize = 7.sp)
                                    }
                                }
                            }
                        }
                    }

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Button(
                            onClick = {
                                val currentAsset = resultVariantList.getOrNull(activeResultPreviewIndex) ?: activeOutputUrl
                                viewModel.triggerMockDownload(
                                    com.example.data.CreationEntity(
                                        id = (1000..9999).random(),
                                        toolName = "AI Avatar Generator",
                                        category = "Graphics Tools",
                                        inputPrompt = "Custom Rig: Style=${stylePresets[selectedAestheticStyleIndex].title}, Gender=$genderSelect, Outfit=$outfitSelected",
                                        outputText = currentAsset
                                    )
                                )
                                Toast.makeText(context, "✦ Output Custom Rig Asset saved to Gallery!", Toast.LENGTH_SHORT).show()
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
                            modifier = Modifier.weight(1f)
                        ) {
                            Icon(Icons.Default.Download, "Download draft", tint = Color.White, modifier = Modifier.size(15.dp))
                            Text(" Save to Disk", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        }

                        OutlinedButton(
                            onClick = { socialShareSheetActive = true },
                            border = BorderStroke(1.dp, NeonPurple),
                            modifier = Modifier.weight(1f)
                        ) {
                            Icon(Icons.Default.Share, "Share blueprint layout", tint = NeonPurple, modifier = Modifier.size(15.dp))
                            Text(" Distribute Concept", color = Color.White, fontSize = 10.sp)
                        }
                    }
                }
            }
        }

        // --- SECTION 8: PRIMARY COMPILE ACTION FAB BUTTON ---
        Button(
            onClick = { runAvatarGeneration() },
            colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
            shape = RoundedCornerShape(12.dp),
            modifier = Modifier
