                        visualTransformation = androidx.compose.ui.text.input.PasswordVisualTransformation(),
                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White)
                    )
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        if (authEmailAddress.contains("@")) {
                            viewModel.login(authEmailAddress, "Cloud login token generated securely")
                        }
                        securityAuthPromptActive = false
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple)
                ) {
                    Text("AUTHORIZE BLUEPRINTS")
                }
            },
            containerColor = Color(0xFF0F0E17)
        )
    }

    if (premiumUpgradePromptActive) {
        AlertDialog(
            onDismissRequest = { premiumUpgradePromptActive = false },
            title = { Text("Clip AI Premium Gold Subscription Plan", color = Color.White, fontSize = 14.sp, fontWeight = FontWeight.Bold) },
