                                    viewModel.updateSubscription("Gold Elite Member Pro", 500)
                                    premiumUpgradePromptActive = false
                                    Toast.makeText(context, "Gold Premium Upgrade Granted!", Toast.LENGTH_SHORT).show()
                                }
