                Column(horizontalAlignment = Alignment.CenterHorizontally, modifier = Modifier.fillMaxWidth()) {
                    CircularProgressIndicator(color = NeonPurple)
                    Spacer(modifier = Modifier.height(10.dp))
                    Text("Releasing high-resolution credit tokens in ($adTimerCountdown seconds left)", color = Color.Gray, fontSize = 9.5.sp)
                }
            },
            confirmButton = {},
            containerColor = Color(0xFF0F0E17)
        )
    }

    if (socialShareSheetActive) {
        AlertDialog(
            onDismissRequest = { socialShareSheetActive = false },
            title = { Text("Share Avatar Vector Scheme", color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Bold) },
