                                    socialShareSheetActive = false
                                }
                                .padding(4.dp)
                        ) {
                            Text(dest, fontSize = 10.sp, modifier = Modifier.padding(10.dp))
                        }
                    }
                }
            },
            confirmButton = {},
            containerColor = Color(0xFF0F0E17)
        )
    }
}

