                                        ) {
                                            Text(
                                                text = "${index + 1}",
                                                color = Color.White,
                                                fontSize = 8.sp,
                                                fontWeight = FontWeight.Bold
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }

                    // DOWNLOAD / SAVE ACTIONS
                    Row(
                        modifier = Modifier.fillMaxWidth().padding(top = 4.dp),
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Button(
                            onClick = {
                                val currentUrl = generatedImages.getOrNull(activeGeneratedIndex) ?: ""
                                viewModel.triggerMockDownload(
                                    com.example.data.CreationEntity(
                                        id = (1000..9999).random(),
                                        toolName = "AI Avatar Builder",
                                        category = "Image Tools",
                                        inputPrompt = "Avatar prompt input",
                                        outputText = currentUrl
                                    )
                                )
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
                            shape = RoundedCornerShape(10.dp),
                            modifier = Modifier.weight(1f)
                        ) {
                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                                Icon(imageVector = Icons.Filled.Download, contentDescription = "Download Item", tint = Color.White, modifier = Modifier.size(16.dp))
                                Text("Download Selected Avatar", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        OutlinedButton(
                            onClick = {
                                processState = "idle"
                            },
                            shape = RoundedCornerShape(10.dp),
                            border = BorderStroke(1.dp, Color.LightGray)
                        ) {
                            Text("New Session", color = Color.White, fontSize = 11.sp)
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // IF PROCESSING STATE: NEURAL PROGRESS LOGS
        // -------------------------------------------------------------
        if (processState == "processing") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(1.dp, NeonPurple),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    Row(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        CircularProgressIndicator(color = NeonPurple, modifier = Modifier.size(18.dp), strokeWidth = 2.dp)
                        Text(
                            text = "Synthesizing AI Masterpieces...",
                            color = Color.White,
                            fontWeight = FontWeight.Bold,
                            fontSize = 14.sp
                        )
                    }

                    LinearProgressIndicator(
                        progress = processProgress,
                        color = NeonPurple,
                        trackColor = Color.DarkGray,
                        modifier = Modifier.fillMaxWidth().height(6.dp).clip(CircleShape)
                    )

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween
                    ) {
                        Text(
                            text = progressStepText,
                            color = NeonPurple,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )

                        Text(
                            text = "${(processProgress * 100).toInt()}%",
                            color = Color.Gray,
                            fontSize = 11.sp
                        )
                    }

                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF231E39).copy(alpha = 0.3f), RoundedCornerShape(6.dp))
                            .padding(8.dp),
                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Box(modifier = Modifier.size(4.dp).background(NeonPurple, CircleShape))
                        Text(
                            text = "Applying SDXL LoRA weights at ${generateCount}x capacity based on selected ${activeStyle.title} settings.",
                            color = Color.LightGray,
                            fontSize = 9.sp
                        )
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // MAIN FORM WORKSPACE CONFIGURATION: UPLOAD TAB
        // -------------------------------------------------------------
        if (processState == "idle") {
            // BACKDROP MODE SWITCHER
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF0C0717), RoundedCornerShape(12.dp))
                    .padding(4.dp)
            ) {
                val isPresetsActive = activeTab == "selfies"
                val isCustomActive = activeTab == "custom"

                Button(
                    onClick = { activeTab = "selfies" },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isPresetsActive) NeonPurple.copy(alpha = 0.15f) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    Text(
                        text = "Sample Selfies",
                        color = if (isPresetsActive) NeonPurple else Color.Gray,
                        fontWeight = FontWeight.Bold,
                        fontSize = 12.sp
                    )
                }

                Button(
                    onClick = { activeTab = "custom" },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isCustomActive) NeonPurple.copy(alpha = 0.15f) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    Text(
                        text = "Upload Custom Selfie",
                        color = if (isCustomActive) NeonPurple else Color.Gray,
                        fontWeight = FontWeight.Bold,
                        fontSize = 12.sp
                    )
                }
            }

            // DROPZONE AREA
            if (activeTab == "selfies") {
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                    border = BorderStroke(0.5.dp, Color.DarkGray),
                    shape = RoundedCornerShape(14.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Text(
                            text = "Choose Base Selfie Blueprint",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black
                        )

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(10.dp)
                        ) {
                            selfiePresets.forEachIndexed { index, preset ->
                                val isSelected = selectedSelfieIndex == index
                                Card(
                                    colors = CardDefaults.cardColors(
                                        containerColor = if (isSelected) Color(0xFF1B0E33) else Color(0xFF090611)
                                    ),
                                    border = BorderStroke(1.dp, if (isSelected) NeonPurple else Color.Transparent),
                                    shape = RoundedCornerShape(10.dp),
                                    modifier = Modifier
                                        .weight(1f)
                                        .clickable { selectedSelfieIndex = index }
                                ) {
                                    Column(
                                        horizontalAlignment = Alignment.CenterHorizontally,
                                        modifier = Modifier.padding(6.dp)
                                    ) {
                                        Box(
                                            modifier = Modifier
                                                .size(64.dp)
                                                .clip(RoundedCornerShape(8.dp))
                                                .border(0.5.dp, Color.DarkGray, RoundedCornerShape(8.dp))
                                        ) {
                                            AsyncImage(
                                                model = preset.url,
                                                contentDescription = preset.title,
                                                contentScale = ContentScale.Crop,
                                                modifier = Modifier.fillMaxSize()
                                            )
                                        }
                                        Spacer(modifier = Modifier.height(6.dp))
                                        Text(
                                            text = preset.title.split(" ").first(),
                                            color = Color.White,
                                            fontSize = 10.sp,
                                            fontWeight = FontWeight.Bold
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            } else {
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                    border = BorderStroke(1.dp, Color.DarkGray),
                    shape = RoundedCornerShape(14.dp),
                    modifier = Modifier.fillMaxWidth().testTag("avatar_generator_custom_upload_card")
                ) {
                    Column(
                        modifier = Modifier.fillMaxWidth().padding(14.dp),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        Text(
                            text = "Upload Front-facing Photo (JPEG/PNG)",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black
                        )

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(125.dp)
                                .background(Color(0xFF07050A), RoundedCornerShape(10.dp))
                                .border(
                                    BorderStroke(1.dp, Brush.sweepGradient(listOf(NeonCyan, NeonPurple))),
                                    RoundedCornerShape(10.dp)
                                )
                                .clickable { pickerLauncher.launch("image-any") },
                            contentAlignment = Alignment.Center
                        ) {
                            Column(
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Filled.Face,
                                    contentDescription = "Upload selfie",
                                    tint = NeonPurple,
                                    modifier = Modifier.size(28.dp)
                                )
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Text("Pick Selfie from Device Files", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    Text("Avoid hats, glasses or heavy shading for maximum likeness", color = Color.Gray, fontSize = 9.sp)
                                }
                            }
                        }

                        if (customSelfieUris.isNotEmpty()) {
                            Row(
                                modifier = Modifier.fillMaxWidth().padding(top = 4.dp),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text(
                                    text = "Ready: ${customSelfieUris.size} device photo(s) selected",
                                    color = NeonPurple,
                                    fontSize = 10.5.sp,
                                    fontWeight = FontWeight.Bold
                                )

                                Text(
                                    text = "Reset Uploads",
                                    color = Color.Red.copy(alpha = 0.8f),
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.clickable { customSelfieUris = emptyList() }
                                )
                            }

                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(6.dp),
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                itemsIndexed(customSelfieUris) { index, uri ->
                                    val isFileSelected = selectedCustomSelfieIndex == index
                                    Card(
                                        colors = CardDefaults.cardColors(containerColor = Color.Transparent),
                                        border = BorderStroke(1.dp, if (isFileSelected) NeonPurple else Color.DarkGray),
                                        modifier = Modifier
                                            .size(54.dp)
                                            .clickable { selectedCustomSelfieIndex = index }
                                    ) {
                                        AsyncImage(
                                            model = uri,
                                            contentDescription = "Custom photo list cell",
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }

            // -------------------------------------------------------------
            // CHOOSE ARTISTIC STYLE SECTOR (7 Styles requested)
            // -------------------------------------------------------------
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Text(
                        text = "Choose Creative Style Blueprint",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Black
                    )

                    Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                        stylePresets.forEachIndexed { index, style ->
                            val isSelected = selectedStyleIndex == index
                            Card(
                                colors = CardDefaults.cardColors(
                                    containerColor = if (isSelected) Color(0xFF1E1535) else Color(0xFF07050E)
                                ),
                                border = BorderStroke(1.dp, if (isSelected) NeonPurple else Color.Transparent),
                                shape = RoundedCornerShape(10.dp),
                                onClick = { selectedStyleIndex = index },
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                Row(
                                    modifier = Modifier.padding(8.dp),
                                    horizontalArrangement = Arrangement.spacedBy(10.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    // Style visual thumbnail
                                    Box(
                                        modifier = Modifier
                                            .size(46.dp)
                                            .clip(RoundedCornerShape(8.dp))
                                            .border(0.5.dp, Color.DarkGray, RoundedCornerShape(8.dp))
                                    ) {
                                        AsyncImage(
                                            model = style.sampleImages.first(),
                                            contentDescription = style.title,
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }

                                    Column(modifier = Modifier.weight(1f)) {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween
                                        ) {
                                            Text(style.title, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                            if (isSelected) {
                                                Icon(
                                                    imageVector = Icons.Filled.CheckCircle,
                                                    contentDescription = "Selected",
                                                    tint = NeonPurple,
                                                    modifier = Modifier.size(13.dp)
                                                )
                                            }
                                        }
                                        Text(style.description, color = Color.Gray, fontSize = 9.sp, maxLines = 1)
                                    }
                                }
                            }
                        }
                    }
                }
            }

            // -------------------------------------------------------------
            // RESOLUTION PARAMETERS & BATCH QUANTITY SELECTION PANEL
            // -------------------------------------------------------------
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    Text(
                        text = "Batch Configuration & Upscaling",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Black
                    )

                    // BATCH COUNT ROW
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Text("Create Variations per Run", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            val counts = listOf(1, 2, 4)
                            counts.forEach { count ->
                                val isSelected = generateCount == count
                                Text(
                                    text = "$count Avatar${if (count > 1) "s" else ""}",
                                    color = if (isSelected) NeonPurple else Color.White,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier
                                        .weight(1f)
                                        .clickable { generateCount = count }
                                        .border(0.5.dp, if (isSelected) NeonPurple else Color.DarkGray, RoundedCornerShape(6.dp))
                                        .background(if (isSelected) NeonPurple.copy(alpha = 0.12f) else Color.Transparent)
                                        .padding(vertical = 8.dp)
                                        .wrapContentWidth(Alignment.CenterHorizontally)
                                )
                            }
                        }
                    }

                    // RESOLUTION SWITCH
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column(modifier = Modifier.weight(1f)) {
                            Text("High Definition Output (4K UHD)", color = Color.White, fontSize = 11.5.sp, fontWeight = FontWeight.Bold)
                            Text("Double pass AI neural sharpening keeping vector-grade quality", color = Color.Gray, fontSize = 9.sp)
                        }
                        Switch(
                            checked = isHdUpscale,
                            onCheckedChange = { isHdUpscale = it },
                            colors = SwitchDefaults.colors(
                                checkedThumbColor = NeonPurple,
                                checkedTrackColor = NeonPurple.copy(alpha = 0.4f),
                                uncheckedThumbColor = Color.Gray,
                                uncheckedTrackColor = Color.DarkGray
                            )
                        )
                    }

                    HorizontalDivider(color = Color.DarkGray, thickness = 0.5.dp)

                    // ADDITIONAL TEXT PREFERENCE FOR TEXT PROMPTS
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Text("Sartorial & Facial Style Customization (Optional)", color = Color.LightGray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        OutlinedTextField(
                            value = promptEnhancementText,
                            onValueChange = { promptEnhancementText = it },
                            placeholder = { Text("e.g. wearing gold dragon armor, neon blue shades, starry night background", fontSize = 11.sp, color = Color.Gray) },
                            singleLine = true,
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedTextColor = Color.White,
                                unfocusedTextColor = Color.White,
                                focusedBorderColor = NeonPurple,
                                unfocusedBorderColor = Color.DarkGray,
                                focusedPlaceholderColor = Color.DarkGray,
                                unfocusedPlaceholderColor = Color.DarkGray
                            ),
                            modifier = Modifier.fillMaxWidth()
                        )
                    }
                }
            }

            // TRIGGER BUTTON
            Button(
                onClick = { runAvatarGeneration() },
                colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
                shape = RoundedCornerShape(12.dp),
                modifier = Modifier
                    .fillMaxWidth()
                    .height(48.dp)
                    .testTag("trigger_avatar_generator_button")
            ) {
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp), verticalAlignment = Alignment.CenterVertically) {
                    Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = "Run AI Avatar", tint = Color.White, modifier = Modifier.size(18.dp))
                    Text("START AI AVATAR GENERATION", color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Black)
                }
            }
        }

        // -------------------------------------------------------------
        // AVATAR ARTIFACTS SESSIONS HISTORY ARCHIVE
        // -------------------------------------------------------------
        if (avatarHistory.isNotEmpty() && processState != "processing") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "Avatar Creation Archive",
                            color = Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            text = "Clear History",
                            color = Color.DarkGray,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold,
                            modifier = Modifier.clickable { viewModel.clearAllHistory() }
                        )
                    }

                    Row(
                        modifier = Modifier.horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        avatarHistory.forEach { item ->
                            val parts = item.inputPrompt.split(" | ")
                            var itemStyle = "Cel-Shaded"
                            var itemCount = "4"
                            var itemHd = "Yes"
                            parts.forEach { part ->
                                if (part.startsWith("Style: ")) itemStyle = part.removePrefix("Style: ")
                                if (part.startsWith("Count: ")) itemCount = part.removePrefix("Count: ")
                                if (part.startsWith("HD: ")) itemHd = part.removePrefix("HD: ")
                            }

                            val urls = item.outputText.substringAfter("Generated Avatar Gallery:\n").split("\n").filter { it.isNotEmpty() }
                            val displayThumbnail = urls.firstOrNull() ?: activeStyle.sampleImages.first()

                            Card(
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF06040A)),
                                border = BorderStroke(1.dp, Color.DarkGray),
                                shape = RoundedCornerShape(10.dp),
                                modifier = Modifier
                                    .width(135.dp)
                                    .clickable {
                                        val match = stylePresets.find { it.title == itemStyle }
                                        if (match != null) {
                                            selectedStyleIndex = stylePresets.indexOf(match)
                                        }
                                        generateCount = itemCount.toIntOrNull() ?: 4
                                        isHdUpscale = itemHd == "Yes"
                                        processState = "success"
                                        activeGeneratedIndex = 0
                                        sliderFraction = 0.5f
                                        Toast.makeText(context, "Loaded Avatar Session: $itemStyle!", Toast.LENGTH_SHORT).show()
                                    }
                            ) {
                                Column {
                                    Box(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .height(100.dp)
                                    ) {
                                        AsyncImage(
                                            model = displayThumbnail,
                                            contentDescription = "Past Avatar Thumbnail",
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )

                                        Box(
                                            modifier = Modifier
                                                .align(Alignment.BottomEnd)
                                                .padding(6.dp)
                                                .background(NeonPurple, RoundedCornerShape(3.dp))
                                                .padding(horizontal = 4.dp, vertical = 2.dp)
                                        ) {
                                            Text("${urls.size} Pcs", color = Color.White, fontSize = 7.sp, fontWeight = FontWeight.Black)
                                        }
                                    }

                                    Column(modifier = Modifier.padding(6.dp)) {
                                        Text(
                                            text = itemStyle,
                                            color = Color.White,
                                            fontSize = 9.5.sp,
                                            fontWeight = FontWeight.Bold,
                                            maxLines = 1
                                        )
                                        Text(
                                            text = "HD: $itemHd • $itemCount variants",
                                            color = Color.Gray,
                                            fontSize = 7.5.sp,
                                            maxLines = 1
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(30.dp))
    }
}
*/

// ---------------------------------------------------------------------
// AI FACE ENHANCER WORKSPACE
// ---------------------------------------------------------------------

data class FacePreset(
    val title: String,
    val description: String,
    val beforeUrl: String,
    val afterUrl: String,
    val category: String,
    val smooth: Int,
    val eye: Int,
    val teeth: Int,
    val wrinkle: Int,
    val isOld: Boolean,
    val isHd: Boolean
)

@Composable
fun FaceEnhancerWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val history by viewModel.history.collectAsState()
    val userStats by viewModel.userStats.collectAsState()

    val presets = remember {
        listOf(
            FacePreset(
                title = "Studio Glamour Portrait",
                description = "High luminosity skin glow with eye gaze iris highlights.",
                beforeUrl = "https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=400&auto=format&fit=crop",
                afterUrl = "https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=400&auto=format&fit=crop",
                category = "Studio Glamour",
                smooth = 75,
                eye = 80,
                teeth = 85,
                wrinkle = 25,
                isOld = false,
                isHd = true
            ),
            FacePreset(
                title = "Vintage Sepia Elder Portrait",
                description = "Fades scratches, fills missing grain, and recovers facial form.",
                beforeUrl = "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=400&auto=format&fit=crop",
                afterUrl = "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=400&auto=format&fit=crop",
                category = "Vintage Archive",
                smooth = 35,
                eye = 60,
                teeth = 10,
                wrinkle = 70,
                isOld = true,
                isHd = true
            ),
            FacePreset(
                title = "Blurry Out-of-focus Candid",
                description = "High-frequency neural deblur restores shaky motions.",
                beforeUrl = "https://images.unsplash.com/photo-1517841905240-472988babdf9?q=80&w=400&auto=format&fit=crop",
                afterUrl = "https://images.unsplash.com/photo-1517841905240-472988babdf9?q=80&w=400&auto=format&fit=crop",
                category = "Motion Blur",
                smooth = 50,
                eye = 85,
                teeth = 40,
                wrinkle = 15,
                isOld = false,
                isHd = true
            ),
            FacePreset(
                title = "Professional Headshot Tune",
                description = "Reduces skin reflection hotspots, keeping detailed textures.",
                beforeUrl = "https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=400&auto=format&fit=crop",
                afterUrl = "https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=400&auto=format&fit=crop",
                category = "Corporate Headshot",
                smooth = 60,
                eye = 70,
                teeth = 75,
                wrinkle = 30,
                isOld = false,
                isHd = true
            )
        )
    }

    // Input state controls
    var activeTab by remember { mutableStateOf("presets") }
    var selectedPresetIndex by remember { mutableStateOf(0) }
    var customImageUris by remember { mutableStateOf<List<Uri>>(emptyList()) }
    var selectedCustomImageIndex by remember { mutableStateOf(0) }

    // Face Tuning Parameters
    var skinSmoothFactor by remember { mutableStateOf(45) }
    var eyeEnhanceFactor by remember { mutableStateOf(60) }
    var teethWhitenFactor by remember { mutableStateOf(30) }
    var wrinkleReduceFactor by remember { mutableStateOf(15) }
    var oldPhotoRestoreEnabled by remember { mutableStateOf(false) }
    var hdEnhancementEnabled by remember { mutableStateOf(true) }
    var neuralEngineMode by remember { mutableStateOf("CodeFormer AI") } // "CodeFormer AI", "GFPGAN Ultra", "GPEN High-Detail"

    // View State Machine
    var processState by remember { mutableStateOf("idle") }
    var processProgress by remember { mutableStateOf(0f) }
    var progressStepText by remember { mutableStateOf("") }
    
    // swipe comparison fractional division (0.01f to 0.99f)
    var sliderFraction by remember { mutableStateOf(0.5f) }

    // Filter past sessions
    val faceHistory = remember(history) {
        history.filter { it.toolName == "Face Enhancer" }
    }

    // Resolve active image url/uri for current input
    val activeImageUrl = remember(selectedPresetIndex, customImageUris, selectedCustomImageIndex, activeTab) {
        if (activeTab == "custom" && customImageUris.isNotEmpty()) {
            customImageUris.getOrNull(selectedCustomImageIndex)?.toString() ?: ""
        } else {
            presets.getOrNull(selectedPresetIndex)?.beforeUrl ?: ""
        }
    }

    // Activity Result Launcher for choosing custom facial image
    val pickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetMultipleContents()
    ) { uris ->
        if (uris.isNotEmpty()) {
            customImageUris = uris
            selectedCustomImageIndex = 0
            activeTab = "custom"
            processState = "idle"
            Toast.makeText(context, "Loaded ${uris.size} face portrait(s) for AI Restoration!", Toast.LENGTH_SHORT).show()
        }
    }

    // Action execution trigger
    val runFaceEnhancement = {
        coroutineScope.launch {
            if (activeTab == "custom" && customImageUris.isEmpty()) {
                Toast.makeText(context, "Please upload or select a face portrait first!", Toast.LENGTH_SHORT).show()
                return@launch
            }

            processState = "processing"
            processProgress = 0f

            val steps = listOf(
                "Detecting facial bounding boxes...",
                "Scanning 68-point 3D landmark mesh matrix...",
                "Aligning neural crop bounding boxes...",
                "Rendering $neuralEngineMode restoration layers...",
                "Generating skin de-noising & pore textures...",
                "Performing iris gaze reflection synthesis...",
                "Whitening teeth & sub-pixel alignment...",
                "Polishing final Ultra-HD upscale resolution..."
            )

            for (i in steps.indices) {
                progressStepText = steps[i]
                val startP = i * 12
                val endP = (i + 1) * 12
                for (p in startP..endP) {
                    delay(25)
                    processProgress = p / 100f
                }
            }
            
            processProgress = 1.0f
            processState = "success"
            sliderFraction = 0.5f

            val inputName = if (activeTab == "custom") {
                "Custom Portrait"
            } else {
                presets[selectedPresetIndex].title
            }

            viewModel.recordFaceEnhancement(
                inputImageName = inputName,
                restorationMode = neuralEngineMode,
                skinSmooth = skinSmoothFactor,
                eyeEnhance = eyeEnhanceFactor,
                teethWhiten = teethWhitenFactor,
                wrinkleReduce = wrinkleReduceFactor,
                isOldPhoto = oldPhotoRestoreEnabled,
                isHdFace = hdEnhancementEnabled,
                outputUrls = activeImageUrl
            )

            Toast.makeText(context, "✦ AI Face Enhancement Completed Successfully!", Toast.LENGTH_SHORT).show()
        }
    }

    Column(
        modifier = modifier
            .fillMaxWidth()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 14.dp, vertical = 8.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // WORKSPACE HEADER
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    text = "Professional AI Face Enhancer",
                    color = Color.White,
                    fontWeight = FontWeight.Black,
                    fontSize = 20.sp
                )
                Text(
                    text = "High-fidelity face restoration, skin smoothing & old photo recovery",
                    color = Color.Gray,
                    fontSize = 11.sp
                )
            }

            // Credits indicator
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF111122)),
                border = BorderStroke(1.dp, NeonCyan.copy(alpha = 0.4f)),
                shape = RoundedCornerShape(10.dp)
            ) {
                Row(
                    modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(imageVector = Icons.Filled.Star, contentDescription = "Credits", tint = NeonCyan, modifier = Modifier.size(13.dp))
                    Text(
                        text = "Credits: ${userStats?.let { it.totalCredits - it.creditsUsed } ?: "--"}",
                        color = Color.White,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // IF OUTPUT IS READY: SHOW DUAL COMPARISON & SWIPE SLIDERS
        // -------------------------------------------------------------
        if (processState == "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(1.dp, NeonCyan.copy(alpha = 0.3f)),
                shape = RoundedCornerShape(16.dp),
                modifier = Modifier.fillMaxWidth().testTag("face_enhancer_success_card")
            ) {
                Column(
                    modifier = Modifier.padding(14.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            Box(modifier = Modifier.size(8.dp).background(NeonCyan, CircleShape))
                            Text(
                                text = "✦ Interactive Portrait Sandbox",
                                color = NeonCyan,
                                fontSize = 13.sp,
                                fontWeight = FontWeight.Black
                              )
                        }
                        Text(
                            text = "Drag center grip to compare",
                            color = Color.Gray,
                            fontSize = 11.sp
                        )
                    }

                    // INTERACTIVE BEFORE / AFTER SLIDER GRAPHICS VIEWPORT
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(280.dp)
                            .clip(RoundedCornerShape(12.dp))
                            .border(1.dp, Color.DarkGray, RoundedCornerShape(12.dp))
                    ) {
                        BoxWithConstraints(modifier = Modifier.fillMaxSize()) {
                            val outerWidth = maxWidth
                            val widthPx = constraints.maxWidth.toFloat()
                            val sliderFractionVal = sliderFraction
                            val sliderDp = outerWidth * sliderFractionVal

                            // 1. AFTER LAYER (FULL WIDTH) - HIGH RES POLISHED GLASSY OUTPUT
                            Box(modifier = Modifier.fillMaxSize()) {
                                AsyncImage(
                                    model = activeImageUrl,
                                    contentDescription = "Enhanced Face Output",
                                    contentScale = ContentScale.Crop,
                                    colorFilter = ColorFilter.colorMatrix(ColorMatrix().apply { 
                                        val contrast = 1.25f
                                        val translate = (-.5f * contrast + .5f) * 255f
                                        val m = floatArrayOf(
                                            contrast, 0f, 0f, 0f, translate,
                                            0f, contrast, 0f, 0f, translate,
                                            0f, 0f, contrast, 0f, translate,
                                            0f, 0f, 0f, 1f, 0f
                                        )
                                        set(ColorMatrix(m))
                                    }),
                                    modifier = Modifier.fillMaxSize()
                                )
                                
                                // Label Bottom-Right
                                Box(
                                    modifier = Modifier
                                        .align(Alignment.BottomEnd)
                                        .padding(10.dp)
                                        .background(Color.Black.copy(alpha = 0.75f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 8.dp, vertical = 4.dp)
                                ) {
                                    Text("Enhanced (After)", color = NeonCyan, fontSize = 9.sp, fontWeight = FontWeight.Black)
                                }
                            }

                            // 2. BEFORE LAYER (CLIPPED FROM THE LEFT TO SLIDERX COORD)
                            Box(
                                modifier = Modifier
                                    .fillMaxHeight()
                                    .width(sliderDp)
                                    .clipToBounds()
                            ) {
                                AsyncImage(
                                    model = activeImageUrl,
                                    contentDescription = "Original Raw Input",
                                    contentScale = ContentScale.Crop,
                                    modifier = Modifier
                                        .width(outerWidth)
                                        .fillMaxHeight()
                                )

                                // Label Bottom-Left
                                Box(
                                    modifier = Modifier
                                        .align(Alignment.BottomStart)
                                        .padding(10.dp)
                                        .background(Color.Black.copy(alpha = 0.75f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 8.dp, vertical = 4.dp)
                                ) {
                                    Text("Raw (Before)", color = Color.LightGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            // 3. CENTRAL DETAILED VERTICAL DIVIDER LINE
                            Box(
                                modifier = Modifier
                                    .fillMaxHeight()
                                    .width(2.5.dp)
                                    .background(NeonCyan)
                                    .offset(x = sliderDp - 1.25.dp)
                            ) {
                                // Drag Grip circular bead
                                Box(
                                    modifier = Modifier
                                        .size(32.dp)
                                        .align(Alignment.Center)
                                        .background(NeonCyan, CircleShape)
                                        .border(2.5.dp, Color(0xFF0F0E17), CircleShape),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(
                                        imageVector = Icons.Filled.CompareArrows,
                                        contentDescription = "Swipe Handle",
                                        tint = PureBlack,
                                        modifier = Modifier.size(16.dp)
                                    )
                                }
                            }

                            // Horizontal Drag controller trigger surface over view size
                            Box(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .pointerInput(Unit) {
                                        detectHorizontalDragGestures { change, dragAmount ->
                                            change.consume()
                                            val proportion = dragAmount / widthPx
                                            sliderFraction = (sliderFraction + proportion).coerceIn(0.01f, 0.99f)
                                        }
                                    }
                            )
                        }
                    }

                    // RESTORE TUNING DETAILS METRICS SUMMARY FEED
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF14131F), RoundedCornerShape(10.dp))
                            .padding(10.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text("Engine: $neuralEngineMode", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Text("Smooth: $skinSmoothFactor% • Eye restore: $eyeEnhanceFactor%", color = Color.Gray, fontSize = 9.5.sp)
                        }
                        Column(horizontalAlignment = Alignment.End) {
                            Text("Teeth Whiten: $teethWhitenFactor%", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Text("Old Photo Repair: ${if (oldPhotoRestoreEnabled) "Active" else "Off"}", color = Color.Gray, fontSize = 9.5.sp)
                        }
                    }

                    // DOWNLOAD / RESET ACTION CHASSIS
                    Row(
                        modifier = Modifier.fillMaxWidth().padding(top = 4.dp),
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Button(
                            onClick = {
                                viewModel.triggerMockDownload(
                                    com.example.data.CreationEntity(
                                        id = (1000..9999).random(),
                                        toolName = "AI Facial Enhancer",
                                        category = "Image Tools",
                                        inputPrompt = "Face Enhance: Mode $neuralEngineMode",
                                        outputText = activeImageUrl
                                    )
                                )
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = NeonCyan),
                            shape = RoundedCornerShape(10.dp),
                            modifier = Modifier.weight(1f)
                        ) {
                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                                Icon(imageVector = Icons.Filled.Download, contentDescription = "Download Port", tint = PureBlack, modifier = Modifier.size(16.dp))
                                Text("Download HD Face", color = PureBlack, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        OutlinedButton(
                            onClick = {
                                processState = "idle"
                            },
                            shape = RoundedCornerShape(10.dp),
                            border = BorderStroke(1.dp, Color.LightGray)
                        ) {
                            Text("Reset Parameters", color = Color.White, fontSize = 11.sp)
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // IF PROCESSING: SHOW NEURAL STATUS LOGS & ROTATING INDICATORS
        // -------------------------------------------------------------
        if (processState == "processing") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(1.dp, NeonCyan),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    Text(
                        text = "Running Face Restoration Algorithms...",
                        color = Color.White,
                        fontWeight = FontWeight.Bold,
                        fontSize = 14.sp
                    )

                    LinearProgressIndicator(
                        progress = processProgress,
                        color = NeonCyan,
                        trackColor = Color.DarkGray,
                        modifier = Modifier.fillMaxWidth().height(6.dp).clip(CircleShape)
                    )

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween
                    ) {
                        Text(
                            text = progressStepText,
                            color = NeonCyan,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )

                        Text(
                            text = "${(processProgress * 100).toInt()}%",
                            color = Color.Gray,
                            fontSize = 11.sp
                        )
                    }

                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF231E39).copy(alpha = 0.3f), RoundedCornerShape(6.dp))
                            .padding(8.dp),
                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Box(modifier = Modifier.size(4.dp).background(NeonCyan, CircleShape))
                        Text(
                            text = "Applying localized sub-pixel restoration weights around detected eye/skin tiles.",
                            color = Color.LightGray,
                            fontSize = 9.sp
                        )
                    }
                }
            }
        }

        // TAB SWITCHER: PRESETS VS CUSTOM UPLOAD
        if (processState != "processing") {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF0D0A14), RoundedCornerShape(12.dp))
                    .padding(4.dp)
            ) {
                val isPresetsActive = activeTab == "presets"
                val isCustomActive = activeTab == "custom"

                Button(
                    onClick = { activeTab = "presets" },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isPresetsActive) Color(0xFF22D3EE).copy(alpha = 0.15f) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    Text(
                        text = "Facial Portrait Presets",
                        color = if (isPresetsActive) NeonCyan else Color.Gray,
                        fontWeight = FontWeight.Bold,
                        fontSize = 12.sp
                    )
                }

                Button(
                    onClick = { activeTab = "custom" },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isCustomActive) Color(0xFF22D3EE).copy(alpha = 0.15f) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    Text(
                        text = "Upload Custom Face",
                        color = if (isCustomActive) NeonCyan else Color.Gray,
                        fontWeight = FontWeight.Bold,
                        fontSize = 12.sp
                    )
                }
            }
        }

        // MAIN FLOW CONSOLE: INPUTS CONFIGURATIONS WHEN IDLE
        if (processState == "idle") {
            
            // RENDERING INPUT PREVIEW BOX / UPLOADER DROPZONE
            if (activeTab == "presets") {
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                    border = BorderStroke(0.5.dp, Color.DarkGray),
                    shape = RoundedCornerShape(14.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Text(
                            text = "Choose High-Fidelity Test Target",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black
                        )

                        presets.forEachIndexed { index, preset ->
                            val isSelected = selectedPresetIndex == index
                            Card(
                                colors = CardDefaults.cardColors(
                                    containerColor = if (isSelected) Color(0xFF1E1E2F) else Color(0xFF05050A)
                                ),
                                border = BorderStroke(1.dp, if (isSelected) NeonCyan else Color.Transparent),
                                shape = RoundedCornerShape(10.dp),
                                onClick = { 
                                    selectedPresetIndex = index 
                                    // pre-populate tuning widgets!
                                    skinSmoothFactor = preset.smooth
                                    eyeEnhanceFactor = preset.eye
                                    teethWhitenFactor = preset.teeth
                                    wrinkleReduceFactor = preset.wrinkle
                                    oldPhotoRestoreEnabled = preset.isOld
                                    hdEnhancementEnabled = preset.isHd
                                },
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                Row(
                                    modifier = Modifier.padding(8.dp),
                                    horizontalArrangement = Arrangement.spacedBy(10.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    // Thumbnail Box
                                    Box(
                                        modifier = Modifier
                                            .size(54.dp)
                                            .clip(RoundedCornerShape(8.dp))
                                            .border(0.5.dp, Color.DarkGray, RoundedCornerShape(8.dp))
                                    ) {
                                        AsyncImage(
                                            model = preset.beforeUrl,
                                            contentDescription = preset.title,
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }

                                    Column(modifier = Modifier.weight(1f)) {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween
                                        ) {
                                            Text(preset.title, color = Color.White, fontSize = 11.5.sp, fontWeight = FontWeight.Bold)
                                            Text(
                                                text = preset.category,
                                                color = NeonCyan,
                                                fontSize = 8.sp,
                                                fontWeight = FontWeight.Bold,
                                                modifier = Modifier
                                                    .background(NeonCyan.copy(alpha = 0.1f), RoundedCornerShape(4.dp))
                                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                                            )
                                        }
                                        Text(preset.description, color = Color.Gray, fontSize = 9.sp, maxLines = 1)
                                    }
                                }
                            }
                        }
                    }
                }
            } else {
                // DRAG & DROP DASHED AREA
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                    border = BorderStroke(1.dp, Color.DarkGray),
                    shape = RoundedCornerShape(14.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(
                        modifier = Modifier.fillMaxWidth().padding(14.dp),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        Text(
                            text = "Load Custom Portraits (PNG/JPG compatible)",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black
                        )

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(130.dp)
                                .background(Color(0xFF07070B), RoundedCornerShape(10.dp))
                                .border(
                                    BorderStroke(1.dp, Brush.sweepGradient(listOf(NeonCyan, NeonPurple))),
                                    RoundedCornerShape(10.dp)
                                )
                                .clickable { pickerLauncher.launch("image/*") },
                            contentAlignment = Alignment.Center
                        ) {
                            Column(
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Filled.Face,
                                    contentDescription = "Upload Facial Photo",
                                    tint = NeonCyan,
                                    modifier = Modifier.size(28.dp)
                                )
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Text("Pick Photo from Phone Gallery", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    Text("Detects up to 6 faces for synchronized restoration", color = Color.Gray, fontSize = 9.sp)
                                }
                            }
                        }

                        if (customImageUris.isNotEmpty()) {
                            Row(
                                modifier = Modifier.fillMaxWidth().padding(top = 4.dp),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text(
                                    text = "Batch: ${customImageUris.size} face sheets loaded",
                                    color = NeonCyan,
                                    fontSize = 10.5.sp,
                                    fontWeight = FontWeight.Bold
                                )

                                Text(
                                    text = "Reset Batch List",
                                    color = Color.Red.copy(alpha = 0.8f),
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.clickable { customImageUris = emptyList() }
                                )
                            }

                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(6.dp),
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                itemsIndexed(customImageUris) { index, uri ->
                                    val isFileSelected = selectedCustomImageIndex == index
                                    Card(
                                        colors = CardDefaults.cardColors(containerColor = Color.Transparent),
                                        border = BorderStroke(1.dp, if (isFileSelected) NeonCyan else Color.DarkGray),
                                        modifier = Modifier
                                            .size(54.dp)
                                            .clickable { selectedCustomImageIndex = index }
                                    ) {
                                        AsyncImage(
                                            model = uri,
                                            contentDescription = "Custom Face Portrait Item",
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }

            // -------------------------------------------------------------
            // DYNAMIC FACIAL RESTORATION TUNING PARAMETERS PANEL
            // -------------------------------------------------------------
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(14.dp)) {
                    Text(
                        text = "Face Restoration Tuning Console",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Black
                    )

                    // 1. ENGINE SELECTION ROW
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Text("AI Face Reconstructor Network", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            val engines = listOf("CodeFormer AI", "GFPGAN Ultra", "GPEN High-Detail")
                            engines.forEach { engine ->
                                val isSelected = neuralEngineMode == engine
                                Text(
                                    text = engine,
                                    color = if (isSelected) NeonCyan else Color.White,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier
                                        .weight(1f)
                                        .clickable { neuralEngineMode = engine }
                                        .border(0.5.dp, if (isSelected) NeonCyan else Color.DarkGray, RoundedCornerShape(6.dp))
                                        .background(if (isSelected) NeonCyan.copy(alpha = 0.12f) else Color.Transparent)
                                        .padding(vertical = 8.dp)
                                        .wrapContentWidth(Alignment.CenterHorizontally)
                                )
                            }
                        }
                    }

                    // 2. SKIN SMOOTHING SLIDER
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                            Text("Dermal Skin Smoothing Factor", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Text("$skinSmoothFactor%", color = NeonCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        }
                        Slider(
                            value = skinSmoothFactor.toFloat(),
                            onValueChange = { skinSmoothFactor = it.toInt() },
                            valueRange = 0f..100f,
                            colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray),
                            modifier = Modifier.fillMaxWidth()
                        )
                    }

                    // 3. EYE ENHANCEMENT SLIDER
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                            Text("Iris Clarity & Eye Enhancement", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Text("$eyeEnhanceFactor%", color = NeonCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        }
                        Slider(
                            value = eyeEnhanceFactor.toFloat(),
                            onValueChange = { eyeEnhanceFactor = it.toInt() },
                            valueRange = 0f..100f,
                            colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray),
                            modifier = Modifier.fillMaxWidth()
                        )
                    }

                    // 4. TEETH WHITENING SLIDER
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                            Text("Teeth Whitening Spot Intensity", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Text("$teethWhitenFactor%", color = NeonCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        }
                        Slider(
                            value = teethWhitenFactor.toFloat(),
                            onValueChange = { teethWhitenFactor = it.toInt() },
                            valueRange = 0f..100f,
                            colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray),
                            modifier = Modifier.fillMaxWidth()
                        )
                    }

                    // 5. WRINKLE REDUCTION SLIDER
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                            Text("Wrinkle & Smile-Crease Blur Softener", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Text("$wrinkleReduceFactor%", color = NeonCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        }
                        Slider(
                            value = wrinkleReduceFactor.toFloat(),
                            onValueChange = { wrinkleReduceFactor = it.toInt() },
                            valueRange = 0f..100f,
                            colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan, inactiveTrackColor = Color.DarkGray),
                            modifier = Modifier.fillMaxWidth()
                        )
                    }

                    HorizontalDivider(color = Color.DarkGray, thickness = 0.5.dp)

                    // 6. OLD VINTAGE RESTORATION TOGGLE
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column(modifier = Modifier.weight(1f)) {
                            Text("Scratch & Noise Grain Restoration", color = Color.White, fontSize = 11.5.sp, fontWeight = FontWeight.Bold)
                            Text("Fills missing print paper lines & de-clutters film noise", color = Color.Gray, fontSize = 9.sp)
                        }
                        Switch(
                            checked = oldPhotoRestoreEnabled,
                            onCheckedChange = { oldPhotoRestoreEnabled = it },
                            colors = SwitchDefaults.colors(
                                checkedThumbColor = NeonCyan,
                                checkedTrackColor = NeonCyan.copy(alpha = 0.4f),
                                uncheckedThumbColor = Color.Gray,
                                uncheckedTrackColor = Color.DarkGray
                            )
                        )
                    }

                    // 7. ULTRA HD SUPER-RES TOGGLE
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column(modifier = Modifier.weight(1f)) {
                            Text("Super-Resolution 4K face enhancement", color = Color.White, fontSize = 11.5.sp, fontWeight = FontWeight.Bold)
                            Text("Upscales face crops keeping textures fully vector sharp", color = Color.Gray, fontSize = 9.sp)
                        }
                        Switch(
                            checked = hdEnhancementEnabled,
                            onCheckedChange = { hdEnhancementEnabled = it },
                            colors = SwitchDefaults.colors(
                                checkedThumbColor = NeonCyan,
                                checkedTrackColor = NeonCyan.copy(alpha = 0.4f),
                                uncheckedThumbColor = Color.Gray,
                                uncheckedTrackColor = Color.DarkGray
                            )
                        )
                    }
                }
            }

            // ONE-CLICK PROCESS INITIATION ACTION BUTTON
            Button(
                onClick = { runFaceEnhancement() },
                colors = ButtonDefaults.buttonColors(containerColor = NeonCyan),
                shape = RoundedCornerShape(12.dp),
                modifier = Modifier.fillMaxWidth().height(48.dp).testTag("trigger_face_enhancer_button")
            ) {
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp), verticalAlignment = Alignment.CenterVertically) {
                    Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = "Run AI", tint = PureBlack, modifier = Modifier.size(18.dp))
                    Text("START AI FACE RESTORATION", color = PureBlack, fontSize = 13.sp, fontWeight = FontWeight.Black)
                }
            }
        }

        // -------------------------------------------------------------
        // FACIAL ENHANCEMENT HISTORY ARCHIVE SESSIONS
        // -------------------------------------------------------------
        if (faceHistory.isNotEmpty() && processState != "processing") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "Face Restoration Archive",
                            color = Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.Bold
                        )
                        Text(
                            text = "Clear History",
                            color = Color.DarkGray,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold,
                            modifier = Modifier.clickable { viewModel.clearAllHistory() }
                        )
                    }

                    Row(
                        modifier = Modifier.horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        faceHistory.forEach { item ->
                            val parts = item.inputPrompt.split(" | ")
                            var itemMode = "CodeFormer AI"
                            var itemSmooth = "45%"
                            var itemEye = "60%"
                            var itemTeeth = "30%"
                            parts.forEach { part ->
                                if (part.startsWith("Mode: ")) itemMode = part.replace("Mode: ", "")
                                if (part.startsWith("Smooth: ")) itemSmooth = part.replace("Smooth: ", "")
                                if (part.startsWith("Eye: ")) itemEye = part.replace("Eye: ", "")
                                if (part.startsWith("Teeth: ")) itemTeeth = part.replace("Teeth: ", "")
                            }

                            val historyUrl = item.outputText.lines()
                                .find { it.startsWith("https://") }
                                ?: "https://picsum.photos/300/300?sig=${item.id}"

                            Card(
                                modifier = Modifier
                                    .width(125.dp)
                                    .clickable {
                                        neuralEngineMode = itemMode
                                        skinSmoothFactor = itemSmooth.replace("%", "").toIntOrNull() ?: 45
                                        eyeEnhanceFactor = itemEye.replace("%", "").toIntOrNull() ?: 60
                                        teethWhitenFactor = itemTeeth.replace("%", "").toIntOrNull() ?: 30
                                        oldPhotoRestoreEnabled = item.outputText.contains("Old Photo Restore: Yes")
                                        hdEnhancementEnabled = item.outputText.contains("Ultra HD Face: Yes")

                                        activeTab = "presets"
                                        selectedPresetIndex = presets.indexOfFirst { it.beforeUrl == historyUrl }.coerceIn(0, presets.size - 1)
                                        processState = "success"
                                        sliderFraction = 0.5f

                                        Toast.makeText(context, "Loaded Face Restoration Session #${item.id} from Archive!", Toast.LENGTH_SHORT).show()
                                    },
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF06060F)),
                                shape = RoundedCornerShape(8.dp),
                                border = BorderStroke(0.5.dp, Color.DarkGray)
                            ) {
                                Column {
                                    Box(modifier = Modifier.fillMaxWidth().height(80.dp)) {
                                        AsyncImage(
                                            model = historyUrl,
                                            contentDescription = "Archive Thumbnail",
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }
                                    Text(
                                        text = "Enhance #${item.id}",
                                        color = Color.White,
                                        fontSize = 9.5.sp,
                                        fontWeight = FontWeight.Bold,
                                        modifier = Modifier.padding(start = 6.dp, end = 6.dp, top = 4.dp)
                                    )
                                    Text(
                                        text = "$itemMode (Sm: $itemSmooth)",
                                        color = Color.Gray,
                                        fontSize = 8.sp,
                                        modifier = Modifier.padding(start = 6.dp, end = 6.dp, bottom = 6.dp),
                                        maxLines = 1,
                                        overflow = TextOverflow.Ellipsis
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(30.dp))
    }
}

// ---------------------------------------------------------------------
// AI BACKGROUND REMOVER WORKSPACE
// ---------------------------------------------------------------------

data class BGRemoverPreset(
    val title: String,
    val subtitle: String,
    val beforeUrl: String,
    val category: String,
    val defaultFeather: Int = 25
)

@Composable
fun CheckerboardBackground(modifier: Modifier = Modifier) {
    Canvas(modifier = modifier) {
        val sizePx = 14.dp.toPx()
        val numW = (size.width / sizePx).toInt() + 1
        val numH = (size.height / sizePx).toInt() + 1
        for (i in 0..numW) {
            for (j in 0..numH) {
                val color = if ((i + j) % 2 == 0) Color(0xFF26262D) else Color(0xFF1A1A1E)
                drawRect(
                    color = color,
                    topLeft = Offset(i * sizePx, j * sizePx),
                    size = Size(sizePx, sizePx)
                )
            }
        }
    }
}

@Composable
fun BackgroundRemoverWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val history by viewModel.history.collectAsState()
    val userStats by viewModel.userStats.collectAsState()

    val presets = remember {
        listOf(
            BGRemoverPreset(
                title = "Neon Synthwave Portrait",
                subtitle = "Fine hair isolation details & studio edge detection",
                beforeUrl = "https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=600&auto=format&fit=crop",
                category = "Portrait",
                defaultFeather = 20
            ),
            BGRemoverPreset(
                title = "Cute Ginger Kitten",
                subtitle = "Sub-pixel fur alpha blending & outline preservation",
                beforeUrl = "https://images.unsplash.com/photo-1514888286974-6c03e2ca1dba?q=80&w=600&auto=format&fit=crop",
                category = "Animals/Pets",
                defaultFeather = 30
            ),
            BGRemoverPreset(
                title = "Crimson Concept Car",
                subtitle = "Sleek automotive reflection and windshield matte extraction",
                beforeUrl = "https://images.unsplash.com/photo-1503376780353-7e6692767b70?q=80&w=600&auto=format&fit=crop",
                category = "Automobile",
                defaultFeather = 15
            ),
            BGRemoverPreset(
                title = "Delicious Studio Burger",
                subtitle = "High-contrast focal subjects separating shadows & plate margins",
                beforeUrl = "https://images.unsplash.com/photo-1568901346375-23c9450c58cd?q=80&w=600&auto=format&fit=crop",
                category = "Commercial Goods",
                defaultFeather = 25
            )
        )
    }

    // Input state controls
    var activeTab by remember { mutableStateOf("presets") } // "presets" or "custom"
    var selectedPresetIndex by remember { mutableStateOf(0) }
    var customImageUris by remember { mutableStateOf<List<Uri>>(emptyList()) }
    var selectedCustomImageIndex by remember { mutableStateOf(0) }

    // Custom background uploaded backdrop
    var customBackdropUri by remember { mutableStateOf<Uri?>(null) }

    // Toggle options
    var objectDetectionMode by remember { mutableStateOf("Auto Detect") } // "Auto Detect", "Portrait", "Animal", "Vehicles", "Industrial"
    var featherFactor by remember { mutableStateOf(25) } // 0..100%
    var preserveHairDetail by remember { mutableStateOf(true) }
    var outputFormat by remember { mutableStateOf("PNG (Transparent)") } // "PNG (Transparent)", "JPG (Composed)"
    
    // Choose Backdrop Style for Preview rendering
    var activeBackdropType by remember { mutableStateOf("Transparent Checkered") } 
    // Types: "Transparent Checkered", "Warm Sunset", "Neon Cyan Cyan", "Solid White", "Solid Black", "Solid Green-Screen", "Custom Backdrop", "Preset Studio Room", "Preset Cyberpunk"

    // View States/Process State Machine
    var processState by remember { mutableStateOf("idle") } // "idle", "processing", "success"
    var processProgress by remember { mutableStateOf(0f) }
    var activeProgressStep by remember { mutableStateOf("") }
    
    // Matte Mode View toggle (VFX Alpha Map)
    var showMatteMode by remember { mutableStateOf(false) }

    // Swipe revealing slider fractional space (0.0f to 1.0f)
    var sliderFraction by remember { mutableStateOf(0.5f) }

    // Fetch previous BG Remover database history items
    val bgHistory = remember(history) {
        history.filter { it.toolName == "Background Remover" }
    }

    // Resolve active image before removal url
    val activeBeforeUrl = remember(selectedPresetIndex, customImageUris, selectedCustomImageIndex, activeTab) {
        if (activeTab == "custom" && customImageUris.isNotEmpty()) {
            customImageUris.getOrNull(selectedCustomImageIndex)?.toString() ?: ""
        } else {
            presets.getOrNull(selectedPresetIndex)?.beforeUrl ?: ""
        }
    }

    // Interactive picker launcher for selecting custom main images
    val pickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetMultipleContents()
    ) { uris ->
        if (uris.isNotEmpty()) {
            customImageUris = uris
            selectedCustomImageIndex = 0
            activeTab = "custom"
            processState = "idle"
            Toast.makeText(context, "Loaded ${uris.size} image(s) for Background Removal!", Toast.LENGTH_SHORT).show()
        }
    }

    // Interactive launcher for custom backdrops
    val backdropPickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetContent()
    ) { uri ->
        if (uri != null) {
            customBackdropUri = uri
            activeBackdropType = "Custom Backdrop"
            Toast.makeText(context, "Custom Backdrop Backdrop loaded!", Toast.LENGTH_SHORT).show()
        }
    }

    val runBackgroundRemoval = {
        coroutineScope.launch {
            if (activeTab == "custom" && customImageUris.isEmpty()) {
                Toast.makeText(context, "Please upload or choose an image first!", Toast.LENGTH_SHORT).show()
                return@launch
            }

            processState = "processing"
            processProgress = 0.0f
            
            // Step 1: Detect
            activeProgressStep = "Detecting Subject Saliency Coordinates..."
            for (p in 1..25) {
                delay(30)
                processProgress = p / 100f
            }

            // Step 2: Segment
            activeProgressStep = "Semantic Mask Construction..."
            for (p in 26..50) {
                delay(40)
                processProgress = p / 100f
            }

            // Step 3: Hair/fur detail preservation
            if (preserveHairDetail) {
                activeProgressStep = "Preserving Hair Detail & Alpha Matting Channels..."
                for (p in 51..75) {
                    delay(50)
                    processProgress = p / 100f
                }
            } else {
                activeProgressStep = "Tracing boundary edges..."
                for (p in 51..75) {
                    delay(20)
                    processProgress = p / 100f
                }
            }

            // Step 4: Alpha blend
            activeProgressStep = "Re-synthesizing Transparent alpha PNG output..."
            for (p in 76..100) {
                delay(30)
                processProgress = p / 100f
            }

            // Success configuration
            processState = "success"
            sliderFraction = 0.5f
            
            // Record to Database History
            val inputName = if (activeTab == "custom") {
                "Custom Image Batch (${customImageUris.size} files)"
            } else {
                presets[selectedPresetIndex].title
            }

            viewModel.recordBackgroundRemoval(
                inputImageNames = inputName,
                bgType = activeBackdropType,
                objectType = objectDetectionMode,
                feathering = featherFactor,
                preserveHair = preserveHairDetail,
                outputUrls = activeBeforeUrl
            )

            Toast.makeText(context, "AI Background Removed successfully!", Toast.LENGTH_SHORT).show()
        }
    }

    Column(
        modifier = modifier
            .fillMaxWidth()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 14.dp, vertical = 8.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        
        // WORKSPACE HEADER
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    text = "AI BG Remover Studio",
                    color = Color.White,
                    fontWeight = FontWeight.Black,
                    fontSize = 20.sp
                )
                Text(
                    text = "One-click background stripping & high-fidelity compositing",
                    color = Color.Gray,
                    fontSize = 11.sp
                )
            }

            // Credit stats card
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF111122)),
                border = BorderStroke(1.dp, NeonCyan.copy(alpha = 0.4f)),
                shape = RoundedCornerShape(10.dp)
            ) {
                Row(
                    modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(imageVector = Icons.Filled.Star, contentDescription = "Credits", tint = NeonCyan, modifier = Modifier.size(13.dp))
                    Text(
                        text = "Credits: ${userStats?.let { it.totalCredits - it.creditsUsed } ?: "--"}",
                        color = Color.White,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // IF OUTPUT IS READY: SHOW DUAL COMPARISON AND COMPOSITING VIEW
        // -------------------------------------------------------------
        if (processState == "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(1.dp, NeonCyan.copy(alpha = 0.3f)),
                shape = RoundedCornerShape(16.dp),
                modifier = Modifier.fillMaxWidth().testTag("bg_remover_success_card")
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            Box(modifier = Modifier.size(8.dp).background(NeonCyan, CircleShape))
                            Text(
                                text = "✦ Background Safely Strung Out",
                                color = NeonCyan,
                                fontSize = 13.sp,
                                fontWeight = FontWeight.Black
                            )
                        }

                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                            Text(
                                text = "Alpha Matte Mask",
                                color = if (showMatteMode) NeonCyan else Color.Gray,
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Bold,
                                modifier = Modifier
                                    .clickable { showMatteMode = !showMatteMode }
                                    .border(1.dp, if (showMatteMode) NeonCyan.copy(alpha = 0.5f) else Color.DarkGray, RoundedCornerShape(6.dp))
                                    .background(if (showMatteMode) NeonCyan.copy(alpha = 0.12f) else Color.Transparent)
                                    .padding(horizontal = 8.dp, vertical = 4.dp)
                            )
                        }
                    }

                    // MAIN PREVIEW BOX (WITH COMPOSITED CUSTOM BACKDROP RENDER)
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(260.dp)
                            .clip(RoundedCornerShape(12.dp))
                            .border(0.5.dp, Color.DarkGray, RoundedCornerShape(12.dp))
                    ) {
                        // LAYER 1: Background rendering based on selected activeBackdropType
                        when (activeBackdropType) {
                            "Transparent Checkered" -> {
                                CheckerboardBackground(modifier = Modifier.fillMaxSize())
                            }
                            "Solid White" -> {
                                Box(modifier = Modifier.fillMaxSize().background(Color.White))
                            }
                            "Solid Black" -> {
                                Box(modifier = Modifier.fillMaxSize().background(Color.Black))
                            }
                            "Solid Green-Screen" -> {
                                Box(modifier = Modifier.fillMaxSize().background(Color(0xFF00FF00)))
                            }
                            "Warm Sunset" -> {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(Brush.verticalGradient(listOf(Color(0xFFFF5F6D), Color(0xFFFFC371))))
                                )
                            }
                            "Neon Cyan Glow" -> {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(Brush.radialGradient(listOf(Color(0xFF22D3EE), Color(0xFF030712))))
                                )
                            }
                            "Custom Backdrop" -> {
                                if (customBackdropUri != null) {
                                    AsyncImage(
                                        model = customBackdropUri,
                                        contentDescription = "Custom Backdrop Backdrop",
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                } else {
                                    CheckerboardBackground(modifier = Modifier.fillMaxSize())
                                }
                            }
                            "Preset Studio Room" -> {
                                AsyncImage(
                                    model = "https://images.unsplash.com/photo-1586023492125-27b2c045efd7?q=80&w=400&auto=format&fit=crop",
                                    contentDescription = "Studio Room Backdrop",
                                    contentScale = ContentScale.Crop,
                                    modifier = Modifier.fillMaxSize()
                                )
                            }
                            "Preset Cyberpunk" -> {
                                AsyncImage(
                                    model = "https://images.unsplash.com/photo-1542838132-92c53300491e?q=80&w=400&auto=format&fit=crop",
                                    contentDescription = "Cyberpunk Backdrop",
                                    contentScale = ContentScale.Crop,
                                    modifier = Modifier.fillMaxSize()
                                )
                            }
                        }

                        // LAYER 2: Foreground (The Image with Dynamic masking applied!)
                        // We composite it using DstIn blend mode or mask simulation
                        val overlayModifier = if (showMatteMode) {
                            Modifier
                                .fillMaxSize()
                                .graphicsLayer { compositingStrategy = CompositingStrategy.Offscreen }
                                .drawWithContent {
                                    // Solid black matte backdrop
                                    drawRect(Color.Black)
                                    // Circular mask alpha representing isolated subject
                                    drawRect(
                                        brush = Brush.radialGradient(
                                            colors = listOf(Color.White, Color.Transparent),
                                            center = Offset(size.width / 2, size.height / 2),
                                            radius = size.width / 2 * (1.3f - (featherFactor / 100f))
                                        )
                                    )
                                }
                        } else {
                            Modifier
                                .fillMaxSize()
                                .graphicsLayer { compositingStrategy = CompositingStrategy.Offscreen }
                                .drawWithContent {
                                    drawContent()
                                    // Apply mask
                                    drawRect(
                                        brush = Brush.radialGradient(
                                            colors = listOf(Color.White, Color.Transparent),
                                            center = Offset(size.width / 2, size.height / 2),
                                            radius = size.width / 2 * (1.3f - (featherFactor / 100f))
                                        ),
                                        blendMode = BlendMode.DstIn
                                    )
                                }
                        }

                        AsyncImage(
                            model = activeBeforeUrl,
                            contentDescription = "Isolated Foreground",
                            contentScale = ContentScale.Crop,
                            modifier = overlayModifier
                        )

                        // Visual mask indicator
                        Box(
                            modifier = Modifier
                                .align(Alignment.BottomStart)
                                .padding(8.dp)
                                .background(Color.Black.copy(alpha = 0.7f), RoundedCornerShape(4.dp))
                                .padding(horizontal = 8.dp, vertical = 4.dp)
                        ) {
                            Text(
                                text = if (showMatteMode) "Matte Channels (VFX)" else "AI Transparent Overlay",
                                color = NeonCyan,
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }

                    // -------------------------------------------------------------
                    // CUSTOMIZABLE BACKDROP PRESET SELECTORS
                    // -------------------------------------------------------------
                    Text(
                        text = "Replace Target Backdrops",
                        color = Color.White,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        // Presets of backdrops
                        val isTransparent = activeBackdropType == "Transparent Checkered"
                        val isSunset = activeBackdropType == "Warm Sunset"
                        val isSpotlight = activeBackdropType == "Preset Studio Room"
                        val isCyberpunk = activeBackdropType == "Preset Cyberpunk"
                        val isCustom = activeBackdropType == "Custom Backdrop"

                        // Transparency Button
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = if (isTransparent) NeonCyan.copy(alpha = 0.15f) else Color(0xFF14131F)
                            ),
                            border = BorderStroke(1.dp, if (isTransparent) NeonCyan else Color.DarkGray),
                            onClick = { activeBackdropType = "Transparent Checkered" },
                            modifier = Modifier.weight(1f)
                        ) {
                            Column(
                                modifier = Modifier.padding(8.dp),
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Icon(imageVector = Icons.Filled.GridOff, contentDescription = "Transparent", tint = if (isTransparent) NeonCyan else Color.Gray, modifier = Modifier.size(16.dp))
                                Text("Transparent", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        // Gradient Sunset
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = if (isSunset) NeonCyan.copy(alpha = 0.15f) else Color(0xFF14131F)
                            ),
                            border = BorderStroke(1.dp, if (isSunset) NeonCyan else Color.DarkGray),
                            onClick = { activeBackdropType = "Warm Sunset" },
                            modifier = Modifier.weight(1f)
                        ) {
                            Column(
                                modifier = Modifier.padding(8.dp),
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Box(modifier = Modifier.size(16.dp).background(Brush.horizontalGradient(listOf(Color.Red, Color.Yellow)), CircleShape))
                                Text("Sunset gradient", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        // Studio Room
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = if (isSpotlight) NeonCyan.copy(alpha = 0.15f) else Color(0xFF14131F)
                            ),
                            border = BorderStroke(1.dp, if (isSpotlight) NeonCyan else Color.DarkGray),
                            onClick = { activeBackdropType = "Preset Studio Room" },
                            modifier = Modifier.weight(1f)
                        ) {
                            Column(
                                modifier = Modifier.padding(8.dp),
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Icon(imageVector = Icons.Filled.Settings, contentDescription = "Studio", tint = if (isSpotlight) NeonCyan else Color.Gray, modifier = Modifier.size(16.dp))
                                Text("Premium Studio", color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        // Custom Image Backstage
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = if (isCustom) NeonCyan.copy(alpha = 0.15f) else Color(0xFF14131F)
                            ),
                            border = BorderStroke(1.dp, if (isCustom) NeonCyan else Color.DarkGray),
                            onClick = {
                                if (customBackdropUri != null) {
                                    activeBackdropType = "Custom Backdrop"
                                } else {
                                    backdropPickerLauncher.launch("image/*")
                                }
                            },
                            modifier = Modifier.weight(1f)
                        ) {
                            Column(
                                modifier = Modifier.padding(8.dp),
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Icon(
                                    imageVector = if (customBackdropUri != null) Icons.Filled.AddAPhoto else Icons.Filled.Upload,
                                    contentDescription = "Custom Backdrop",
                                    tint = if (isCustom) NeonCyan else Color.Gray,
                                    modifier = Modifier.size(16.dp)
                                )
                                Text(
                                    text = if (customBackdropUri != null) "Bg Configured" else "Load Backdrop",
                                    color = Color.White,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Bold,
                                    maxLines = 1
                                )
                            }
                        }
                    }

                    // Action controllers: Download!
                    Row(
                        modifier = Modifier.fillMaxWidth().padding(top = 4.dp),
                        horizontalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Button(
                            onClick = {
                                viewModel.triggerMockDownload(
                                    com.example.data.CreationEntity(
                                        id = (1000..9999).random(),
                                        toolName = "Background Remover",
                                        category = "Image Tools",
                                        inputPrompt = "Remove Background: Matte $showMatteMode | Feather $featherFactor",
                                        outputText = activeBeforeUrl
                                    )
                                )
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = NeonCyan),
                            shape = RoundedCornerShape(10.dp),
                            modifier = Modifier.weight(1f)
                        ) {
                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                                Icon(imageVector = Icons.Filled.Download, contentDescription = "Download PNG", tint = PureBlack, modifier = Modifier.size(16.dp))
                                Text("Download PNG (Transparent)", color = PureBlack, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        OutlinedButton(
                            onClick = {
                                processState = "idle"
                            },
                            shape = RoundedCornerShape(10.dp),
                            border = BorderStroke(1.dp, Color.LightGray)
                        ) {
                            Text("Reset", color = Color.White, fontSize = 11.sp)
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // IF PROCESSING: SHOW STEP-BY-STEP DIALOG PREVIEW
        // -------------------------------------------------------------
        if (processState == "processing") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(1.dp, NeonCyan),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    Text(
                        text = "AI Sub-pixel Rendering Active...",
                        color = Color.White,
                        fontWeight = FontWeight.Bold,
                        fontSize = 14.sp
                    )

                    LinearProgressIndicator(
                        progress = processProgress,
                        color = NeonCyan,
                        trackColor = Color.DarkGray,
                        modifier = Modifier.fillMaxWidth().height(6.dp).clip(CircleShape)
                    )

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween
                    ) {
                        Text(
                            text = activeProgressStep,
                            color = NeonCyan,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )

                        Text(
                            text = "${(processProgress * 100).toInt()}%",
                            color = Color.Gray,
                            fontSize = 11.sp
                        )
                    }

                    // Informational hints
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF231E39).copy(alpha = 0.3f), RoundedCornerShape(6.dp))
                            .padding(8.dp),
                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Box(modifier = Modifier.size(4.dp).background(NeonCyan, CircleShape))
                        Text(
                            text = "Preserving hair contours and blending transparent anti-aliasing edges.",
                            color = Color.LightGray,
                            fontSize = 9.sp
                        )
                    }
                }
            }
        }

        // TAB SWITCHER: PRESETS VS CUSTOM
        if (processState != "processing") {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF0D0A14), RoundedCornerShape(12.dp))
                    .padding(4.dp)
            ) {
                val isPresetsActive = activeTab == "presets"
                val isCustomActive = activeTab == "custom"

                Button(
                    onClick = { activeTab = "presets" },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isPresetsActive) Color(0xFF22D3EE).copy(alpha = 0.15f) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    Text(
                        text = "Standard Presets",
                        color = if (isPresetsActive) NeonCyan else Color.Gray,
                        fontWeight = FontWeight.Bold,
                        fontSize = 12.sp
                    )
                }

                Button(
                    onClick = { activeTab = "custom" },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isCustomActive) Color(0xFF22D3EE).copy(alpha = 0.15f) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    Text(
                        text = "Upload Custom Images",
                        color = if (isCustomActive) NeonCyan else Color.Gray,
                        fontWeight = FontWeight.Bold,
                        fontSize = 12.sp
                    )
                }
            }
        }

        // MAIN SETUP: IF IDLE
        if (processState == "idle") {
            
            // RENDERING IDLE INPUT: PRESET CONTAINER OR FILE DRAG PLACEHOLDER CONTAINER
            if (activeTab == "presets") {
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                    border = BorderStroke(0.5.dp, Color.DarkGray),
                    shape = RoundedCornerShape(14.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Text(
                            text = "Select Premium Preset Model",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black
                        )

                        presets.forEachIndexed { index, preset ->
                            val isSelected = selectedPresetIndex == index
                            Card(
                                colors = CardDefaults.cardColors(
                                    containerColor = if (isSelected) Color(0xFF1E1E2F) else Color(0xFF05050A)
                                ),
                                border = BorderStroke(1.dp, if (isSelected) NeonCyan else Color.Transparent),
                                shape = RoundedCornerShape(10.dp),
                                onClick = { selectedPresetIndex = index },
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                Row(
                                    modifier = Modifier.padding(8.dp),
                                    horizontalArrangement = Arrangement.spacedBy(10.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    // Thumbnail preview
                                    Box(
                                        modifier = Modifier
                                            .size(54.dp)
                                            .clip(RoundedCornerShape(8.dp))
                                            .border(0.5.dp, Color.DarkGray, RoundedCornerShape(8.dp))
                                    ) {
                                        AsyncImage(
                                            model = preset.beforeUrl,
                                            contentDescription = preset.title,
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }

                                    Column(modifier = Modifier.weight(1f)) {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween
                                        ) {
                                            Text(preset.title, color = Color.White, fontSize = 11.5.sp, fontWeight = FontWeight.Bold)
                                            Text(
                                                text = preset.category,
                                                color = NeonCyan,
                                                fontSize = 8.sp,
                                                fontWeight = FontWeight.Bold,
                                                modifier = Modifier
                                                    .background(NeonCyan.copy(alpha = 0.1f), RoundedCornerShape(4.dp))
                                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                                            )
                                        }
                                        Text(preset.subtitle, color = Color.Gray, fontSize = 9.sp, maxLines = 1)
                                    }
                                }
                            }
                        }
                    }
                }
            } else {
                // CUSTOM UPLOADER & DRAG-DROP CHASSIS
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                    border = BorderStroke(1.dp, Color.DarkGray),
                    shape = RoundedCornerShape(14.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(14.dp),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        Text(
                            text = "Upload Source Files (Batch processing available)",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Black
                        )

                        // Upload Dropzone with Dotted Border!
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(130.dp)
                                .background(Color(0xFF07070B), RoundedCornerShape(10.dp))
                                .border(
                                    BorderStroke(1.dp, Brush.sweepGradient(listOf(NeonCyan, NeonPurple))),
                                    RoundedCornerShape(10.dp)
                                )
                                .clickable { pickerLauncher.launch("image/*") },
                            contentAlignment = Alignment.Center
                        ) {
                            Column(
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Filled.CloudUpload,
                                    contentDescription = "Upload files",
                                    tint = NeonCyan,
                                    modifier = Modifier.size(28.dp)
                                )
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Text("Drag & Drop or Click to browse", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    Text("Supports PNG, JPG, WEBP formats up to 4K resolution", color = Color.Gray, fontSize = 9.sp)
                                }
                            }
                        }

                        // Display list of selected custom files if not empty
                        if (customImageUris.isNotEmpty()) {
                            Row(
                                modifier = Modifier.fillMaxWidth().padding(top = 4.dp),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text(
                                    text = "Ready to Iso: ${customImageUris.size} files loaded",
                                    color = NeonCyan,
                                    fontSize = 10.5.sp,
                                    fontWeight = FontWeight.Bold
                                )

                                Text(
                                    text = "Clear All",
                                    color = Color.Red.copy(alpha = 0.8f),
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.clickable { customImageUris = emptyList() }
                                )
                            }

                            // Horizontal thumbnail slider
                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(6.dp),
                                modifier = Modifier.fillMaxWidth()
                            ) {
                                itemsIndexed(customImageUris) { index, uri ->
                                    val isFileSelected = selectedCustomImageIndex == index
                                    Card(
                                        colors = CardDefaults.cardColors(containerColor = Color.Transparent),
                                        border = BorderStroke(1.dp, if (isFileSelected) NeonCyan else Color.DarkGray),
                                        modifier = Modifier
                                            .size(54.dp)
                                            .clickable { selectedCustomImageIndex = index }
                                    ) {
                                        AsyncImage(
                                            model = uri,
                                            contentDescription = "Uploaded Thumbnail",
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            }

            // -------------------------------------------------------------
            // CONTROLLER PARAMETERS (OBJECT DETECTION / FEATHER / SHARPNESS)
            // -------------------------------------------------------------
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    Text(
                        text = "AI Matte Processing Pipeline Details",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Black
                    )

                    // Object Detection Selector
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Text("Saliency Object Categorizer", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            val modes = listOf("Auto Detect", "Portrait", "Animals/Pets", "Commercial")
                            modes.forEach { mode ->
                                val isSelectedMode = objectDetectionMode == mode
                                Text(
                                    text = mode,
                                    color = if (isSelectedMode) NeonCyan else Color.White,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier
                                        .weight(1f)
                                        .clickable { objectDetectionMode = mode }
                                        .border(0.5.dp, if (isSelectedMode) NeonCyan else Color.DarkGray, RoundedCornerShape(6.dp))
                                        .background(if (isSelectedMode) NeonCyan.copy(alpha = 0.12f) else Color.Transparent)
                                        .padding(vertical = 8.dp)
                                        .wrapContentWidth(Alignment.CenterHorizontally)
                                )
                            }
                        }
                    }

                    // Feather Slider
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Text("Edge Shading Feathering", color = Color.Gray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            Text("$featherFactor%", color = NeonCyan, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                        }
                        Slider(
                            value = featherFactor.toFloat(),
                            onValueChange = { featherFactor = it.toInt() },
                            valueRange = 0f..100f,
                            colors = SliderDefaults.colors(
                                thumbColor = NeonCyan,
                                activeTrackColor = NeonCyan,
                                inactiveTrackColor = Color.DarkGray
                            ),
                            modifier = Modifier.fillMaxWidth()
                        )
                    }

                    // High precision hair protection toggle
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column(modifier = Modifier.weight(1f)) {
                            Text("Sub-Pixel Hair Detail Preservation", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Text("Enables intensive alpha matting maps surrounding furry subjects", color = Color.Gray, fontSize = 9.sp)
                        }
                        Switch(
                            checked = preserveHairDetail,
                            onCheckedChange = { preserveHairDetail = it },
                            colors = SwitchDefaults.colors(
                                checkedThumbColor = NeonCyan,
                                checkedTrackColor = NeonCyan.copy(alpha = 0.4f),
                                uncheckedThumbColor = Color.Gray,
                                uncheckedTrackColor = Color.DarkGray
                            )
                        )
                    }
                }
            }

            // ONE-CLICK START ACTION BUTTON
            Button(
                onClick = { runBackgroundRemoval() },
                colors = ButtonDefaults.buttonColors(containerColor = NeonCyan),
                shape = RoundedCornerShape(12.dp),
                modifier = Modifier.fillMaxWidth().height(48.dp).testTag("trigger_bg_remover_button")
            ) {
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp), verticalAlignment = Alignment.CenterVertically) {
                    Icon(imageVector = Icons.Filled.AutoFixHigh, contentDescription = "Remove Background", tint = PureBlack, modifier = Modifier.size(18.dp))
                    Text(
                        text = if (activeTab == "custom" && customImageUris.size > 1) "Process Batch AI Removal (${customImageUris.size} Images)" else "Isolate Subject & Remove Background ✨",
                        color = PureBlack,
                        fontWeight = FontWeight.Bold,
                        fontSize = 12.sp
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // PREVIOUS ROOM DATABASE HISTORY LIST
        // -------------------------------------------------------------
        if (bgHistory.isNotEmpty()) {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0F0E17)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text(
                        text = "Your Isolated Masterpiece History",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Black
                    )

                    bgHistory.reversed().take(3).forEach { item ->
                        val itemProps = remember(item) {
                            var category = "Portrait"
                            var bgStyle = "Transparent Checkered"
                            item.inputPrompt.split(" | ").forEach { part ->
                                if (part.startsWith("BG style: ")) bgStyle = part.substringAfter("BG style: ")
                                if (part.startsWith("Detect object: ")) category = part.substringAfter("Detect object: ")
                            }
                            Pair(category, bgStyle)
                        }

                        Card(
                            onClick = {
                                activeTab = "presets"
                                selectedPresetIndex = presets.indexOfFirst { preset -> preset.beforeUrl == item.outputText.split("\n").lastOrNull() ?: "" }.coerceIn(0, presets.size - 1)
                                activeBackdropType = itemProps.second
                                objectDetectionMode = itemProps.first
                                processState = "success"
                                Toast.makeText(context, "Loaded execution historical parameters!", Toast.LENGTH_SHORT).show()
                            },
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF06060F)),
                            shape = RoundedCornerShape(8.dp),
                            border = BorderStroke(0.5.dp, Color.DarkGray),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Row(
                                modifier = Modifier.padding(8.dp),
                                horizontalArrangement = Arrangement.spacedBy(10.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Icon(imageVector = Icons.Filled.Check, contentDescription = "Done", tint = NeonCyan, modifier = Modifier.size(16.dp))
                                Column(modifier = Modifier.weight(1f)) {
                                    Text(
                                        text = "${item.toolName} - ${itemProps.first}",
                                        color = Color.White,
                                        fontSize = 11.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                    Text(
                                        text = "Setting Backdrop: ${itemProps.second}",
                                        color = Color.Gray,
                                        fontSize = 9.sp
                                    )
                                }
                                Icon(
                                    imageVector = Icons.Filled.ChevronRight,
                                    contentDescription = "Load details",
                                    tint = Color.Gray,
                                    modifier = Modifier.size(16.dp)
                                )
                            }
                        }
                    }
                }
            }
        }
        
        Spacer(modifier = Modifier.height(24.dp))
    }
}

data class EnhancerPreset(
    val title: String,
    val subtitle: String,
    val beforeUrl: String,
    val afterUrl: String,
    val defaultFlags: String
)

@Composable
fun ImageToVideoWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val history by viewModel.history.collectAsState()
    val userStats by viewModel.userStats.collectAsState()

    // Definition of curated high resolution presets
    val presets = remember {
        listOf(
            com.example.ui.views.VideoPreset(
                title = "Cyberpunk Neo Rider",
                description = "Perfect for heavy neon panning & atmospheric motion",
                imageUrl = "https://images.unsplash.com/photo-1515621061946-eff1c2a352bd?q=80&w=600&auto=format&fit=crop"
            ),
            com.example.ui.views.VideoPreset(
                title = "Nebula Cosmic Gateway",
                description = "Ideal for deep slow zooming celestial effects",
                imageUrl = "https://images.unsplash.com/photo-1462331940025-496dfbfc7564?q=80&w=600&auto=format&fit=crop"
            ),
            com.example.ui.views.VideoPreset(
                title = "Aesthetic Anime Explorer",
                description = "Best for subtle voice lines and character head tilt",
                imageUrl = "https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=600&auto=format&fit=crop"
            )
        )
    }

    // Interactive states
    var activeTab by remember { mutableStateOf("presets") } // "presets" or "custom"
    var selectedPresetIndex by remember { mutableStateOf(0) }
    var customImageUri by remember { mutableStateOf<Uri?>(null) }

    // Configuration states
    var selectedFaceAnimation by remember { mutableStateOf("Slight Smile & Nod") }
    var selectedCameraZoom by remember { mutableStateOf("Dynamic Zoom In Slow") }
    var selectedMotionEffects by remember { mutableStateOf("Gentle Fluid Flow") }
    var talkingPhotoMode by remember { mutableStateOf(false) }
    var lipSyncScript by remember { mutableStateOf("Hey there! Welcome to the premium AI Creator Studio. Look at this incredible generated motion scene!") }
    var selectedMusic by remember { mutableStateOf("Cinematic Ambient Synth") }
    var durationSeconds by remember { mutableStateOf(8) }
    var hdExport by remember { mutableStateOf(true) }
    var selectedVideoEngine by remember { mutableStateOf("Veo 3 Ultra (Google AI)") }
    var videoPrompt by remember { mutableStateOf("Cinematic camera rotation around the subject, hyper-detailed, volumetric lighting, photorealistic 8k dynamic motion.") }

    // Process state machine
    var processState by remember { mutableStateOf("idle") } // "idle", "generating", "success"
    var processProgress by remember { mutableStateOf(0f) }
    var activeProgressStep by remember { mutableStateOf("") }

    // Player playback states
    var isPlaying by remember { mutableStateOf(true) }
    var playbackProgress by remember { mutableStateOf(0f) }

    // Filter past image to video creations
    val videoHistory = remember(history) {
        history.filter { it.toolName == "Image to Video" }
    }

    // Resolve active base image URL/URI
    val activeImageUrl = remember(selectedPresetIndex, customImageUri, activeTab) {
        if (activeTab == "custom" && customImageUri != null) {
            customImageUri.toString()
        } else {
            presets[selectedPresetIndex].imageUrl
        }
    }

    // Interactive gallery file picker
    val galleryLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == android.app.Activity.RESULT_OK) {
            val intent = result.data
            if (intent?.data != null) {
                customImageUri = intent.data
                activeTab = "custom"
                processState = "idle"
                Toast.makeText(context, "Masterpiece custom photo successfully uploaded!", Toast.LENGTH_SHORT).show()
            }
        }
    }

    val launchGallery = {
        val galleryIntent = android.content.Intent(
            android.content.Intent.ACTION_PICK,
            android.provider.MediaStore.Images.Media.EXTERNAL_CONTENT_URI
        )
        galleryLauncher.launch(galleryIntent)
    }

    // Infinite transition for fluid video loops & music equalizers
    val infiniteTransition = rememberInfiniteTransition(label = "video_player_effects")
    
    // Animate scale & offset based on camera path configuration
    val animatedScale by infiniteTransition.animateFloat(
        initialValue = if (selectedCameraZoom == "Dynamic Zoom In Slow") 1.0f else if (selectedCameraZoom == "Zoom Out Reveal") 1.25f else 1.06f,
        targetValue = if (selectedCameraZoom == "Dynamic Zoom In Slow") 1.22f else if (selectedCameraZoom == "Zoom Out Reveal") 1.0f else 1.08f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = durationSeconds * 1000, easing = LinearEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "camera_scale"
    )

    val animatedTranslateX by infiniteTransition.animateFloat(
        initialValue = if (selectedCameraZoom == "Panoramic Slow Pan Left") 25f else if (selectedCameraZoom == "Pan Right Slow") -25f else 0f,
        targetValue = if (selectedCameraZoom == "Panoramic Slow Pan Left") -25f else if (selectedCameraZoom == "Pan Right Slow") 25f else 0f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = durationSeconds * 1000, easing = LinearEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "camera_translate_x"
    )

    // Animated lipsync mouth scale simulating voice speaking
    val talkingVoiceLipsScale by infiniteTransition.animateFloat(
        initialValue = 0.98f,
        targetValue = 1.05f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = 240, easing = FastOutSlowInEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "lip_sync_vocal"
    )

    // Keep track of playback slider incrementing over selected duration
    LaunchedEffect(isPlaying, processState, durationSeconds) {
        if (processState == "success" && isPlaying) {
            val stepSizeMs = 50L
            val incrementPerStep = stepSizeMs / (durationSeconds * 1000f)
            while (true) {
                delay(stepSizeMs)
                playbackProgress = (playbackProgress + incrementPerStep)
                if (playbackProgress >= 1.0f) {
                    playbackProgress = 0.0f
                }
            }
        }
    }

    Column(
        modifier = modifier
            .fillMaxWidth()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 14.dp, vertical = 8.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // App Studio Header
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Text(
                    text = "AI Image to Video Studio",
                    color = Color.White,
                    fontWeight = FontWeight.Black,
                    fontSize = 20.sp
                )
                Text(
                    text = "Luma & Veo 3 Cinematic Rendering Suite",
                    color = Color.Gray,
                    fontSize = 11.sp,
                    fontWeight = FontWeight.Bold
                )
            }
            Box(
                modifier = Modifier
                    .background(Color(0xFF0F3E5F), RoundedCornerShape(8.dp))
                    .padding(horizontal = 10.dp, vertical = 4.dp)
            ) {
                Text(
                    text = "PRO EXTENSION ACTIVE",
                    color = NeonBlue,
                    fontSize = 9.sp,
                    fontWeight = FontWeight.ExtraBold,
                    letterSpacing = 1.sp
                )
            }
        }

        // -------------------------------------------------------------
        // TOP HALF: CINEMATIC MULTI-RENDER PLATFORM OR PREVIEW PLAYER
        // -------------------------------------------------------------
        if (processState == "idle") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF0C0A12)),
                border = BorderStroke(1.dp, Color.DarkGray),
                shape = RoundedCornerShape(16.dp),
                modifier = Modifier.fillMaxWidth().height(260.dp)
            ) {
                Box(modifier = Modifier.fillMaxSize()) {
                    // Cinematic Color Grading
                    val cinematicColorMatrix = ColorMatrix().apply {
                        val contrast = 1.15f
                        val translate = (-.5f * contrast + .5f) * 255f
                        val m = floatArrayOf(
                            contrast, 0f, 0f, 0f, translate,
                            0f, contrast, 0.05f, 0f, translate,
                            0f, 0f, contrast + 0.1f, 0f, translate,
                            0f, 0f, 0f, 1f, 0f
                        )
                        set(ColorMatrix(m))
                    }

                    AsyncImage(
                        model = activeImageUrl,
                        contentDescription = "Static Image Keyframe",
                        contentScale = ContentScale.Crop,
                        colorFilter = ColorFilter.colorMatrix(cinematicColorMatrix),
                        modifier = Modifier.fillMaxSize()
                    )
                    
                    // Cinematic Letterboxing
                    Column(
                        modifier = Modifier.fillMaxSize(),
                        verticalArrangement = Arrangement.SpaceBetween
                    ) {
                        Box(modifier = Modifier.fillMaxWidth().height(26.dp).background(Color.Black))
                        Box(modifier = Modifier.fillMaxWidth().height(26.dp).background(Color.Black))
                    }

                    // Dark dramatic ambient shield overlay
                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .background(
                                Brush.verticalGradient(
                                    listOf(Color.Transparent, Color.Black.copy(alpha = 0.85f))
                                )
                            )
                    )

                    // Keyframe header badge
                    Box(
                        modifier = Modifier
                            .align(Alignment.TopStart)
                            .padding(12.dp)
                            .background(Color.Black.copy(alpha = 0.75f), RoundedCornerShape(6.dp))
                            .border(1.dp, NeonBlue, RoundedCornerShape(6.dp))
                            .padding(horizontal = 8.dp, vertical = 4.dp)
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            Box(modifier = Modifier.size(6.dp).background(Color.Red, CircleShape))
                            Text(
                                text = "HD KEYFRAME SOURCE",
                                color = Color.White,
                                fontSize = 9.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }

                    // Bottom caption
                    Column(
                        modifier = Modifier
                            .align(Alignment.BottomStart)
                            .padding(16.dp),
                        verticalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        Text(
                            text = if (activeTab == "presets") presets[selectedPresetIndex].title else "Custom Imported Photo",
                            color = Color.White,
                            fontSize = 15.sp,
                            fontWeight = FontWeight.Black
                        )
                        Text(
                            text = "Configure parameters below and click 'Synthesize Cinematic Video'",
                            color = Color.LightGray,
                            fontSize = 11.sp
                        )
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // GENERATING VIDEO STATE WITH ADVANCED LOADING METER
        // -------------------------------------------------------------
        else if (processState == "generating") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF07050A)),
                border = BorderStroke(1.5.dp, Brush.linearGradient(listOf(NeonBlue, NeonPurple))),
                shape = RoundedCornerShape(16.dp),
                modifier = Modifier.fillMaxWidth().height(260.dp)
            ) {
                Column(
                    modifier = Modifier.fillMaxSize().padding(20.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.Center
                ) {
                    Box(contentAlignment = Alignment.Center, modifier = Modifier.size(75.dp)) {
                        CircularProgressIndicator(
                            progress = { processProgress },
                            color = NeonBlue,
                            strokeWidth = 4.5.dp,
                            modifier = Modifier.fillMaxSize()
                        )
                        CircularProgressIndicator(
                            color = NeonPurple,
                            strokeWidth = 1.5.dp,
                            modifier = Modifier.fillMaxSize(0.8f)
                        )
                    }
                    
                    Spacer(modifier = Modifier.height(14.dp))
                    
                    Text(
                        text = "AI RENDER CORES SPLICING SEQUENCES",
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Black,
                        color = NeonBlue,
                        letterSpacing = 1.sp
                    )
                    Text(
                        text = activeProgressStep,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Bold,
                        color = Color.White,
                        textAlign = TextAlign.Center,
                        modifier = Modifier.padding(top = 4.dp)
                    )
                    
                    Spacer(modifier = Modifier.height(16.dp))
                    
                    // Small loading bar details
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF0F0F1A), RoundedCornerShape(8.dp))
                            .padding(horizontal = 12.dp, vertical = 6.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "Output Ratio: ${if (hdExport) "UHD MP4 container" else "Standard MP4"}",
                            color = Color.Gray,
                            fontSize = 10.sp
                        )
                        Text(
                            text = "Timer: ${((1 - processProgress) * durationSeconds).toInt()}s left",
                            color = NeonPurple,
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // LIVE CINEMATIC PREVIEW COMPRESSED PLAYER
        // -------------------------------------------------------------
        else if (processState == "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF030303)),
                border = BorderStroke(1.5.dp, NeonBlue),
                shape = RoundedCornerShape(16.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column {
                    // Preview viewport
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(240.dp)
                            .clip(RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp))
                    ) {
                        // Master animated photo!
                        val scaleFactor = if (isPlaying) animatedScale else 1.0f
                        val cameraTranslationX = if (isPlaying) animatedTranslateX else 0f
                        val breathFactor = if (isPlaying && talkingPhotoMode) talkingVoiceLipsScale else 1.0f
                        
                        // Cinematic Color Grading
                        val cinematicColorMatrix = ColorMatrix().apply {
                            val contrast = 1.15f
                            val translate = (-.5f * contrast + .5f) * 255f
                            val m = floatArrayOf(
                                contrast, 0f, 0f, 0f, translate,
                                0f, contrast, 0.05f, 0f, translate,
                                0f, 0f, contrast + 0.1f, 0f, translate,
                                0f, 0f, 0f, 1f, 0f
                            )
                            set(ColorMatrix(m))
                        }

                        AsyncImage(
                            model = activeImageUrl,
                            contentDescription = "Animated Live Render Output",
                            contentScale = ContentScale.Crop,
                            colorFilter = ColorFilter.colorMatrix(cinematicColorMatrix),
                            modifier = Modifier
                                .fillMaxSize()
                                .graphicsLayer {
                                    scaleX = scaleFactor * breathFactor
                                    scaleY = scaleFactor * breathFactor
                                    translationX = cameraTranslationX
                                }
                        )

                        // Vignette cinema border overlay
                        Box(
                            modifier = Modifier
                                .fillMaxSize()
                                .background(
                                    Brush.radialGradient(
                                        colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.82f))
                                    )
                                )
                        )

                        // Cinematic Letterboxing (Top & Bottom Black Bars)
                        Column(
                            modifier = Modifier.fillMaxSize(),
                            verticalArrangement = Arrangement.SpaceBetween
                        ) {
                            Box(modifier = Modifier.fillMaxWidth().height(26.dp).background(Color.Black))
                            Box(modifier = Modifier.fillMaxWidth().height(26.dp).background(Color.Black))
                        }

                        // Dynamic equalizer soundwave simulation when music or verbal lip sync is running
                        if (isPlaying) {
                            Row(
                                modifier = Modifier
                                    .align(Alignment.BottomStart)
                                    .padding(start = 14.dp, bottom = 14.dp),
                                horizontalArrangement = Arrangement.spacedBy(3.dp),
                                verticalAlignment = Alignment.Bottom
                            ) {
                                (1..12).forEach { i ->
                                    val randomHeightMultiplier by infiniteTransition.animateFloat(
                                        initialValue = 0.15f + (i % 3) * 0.2f,
                                        targetValue = 0.85f - (i % 4) * 0.15f,
                                        animationSpec = infiniteRepeatable(
                                            animation = tween(durationMillis = 180 + i * 22, easing = LinearEasing),
                                            repeatMode = RepeatMode.Reverse
                                        ),
                                        label = "soundwave_bar_$i"
                                    )
                                    Box(
                                        modifier = Modifier
                                            .width(2.5.dp)
                                            .height((randomHeightMultiplier * 36).dp)
                                            .background(
                                                Brush.verticalGradient(listOf(NeonBlue, NeonPurple)),
                                                RoundedCornerShape(1.dp)
                                            )
                                    )
                                }
                            }
                        }

                        // Floating badges
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(12.dp),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Box(
                                modifier = Modifier
                                    .background(Color.Red.copy(alpha = 0.8f), RoundedCornerShape(4.dp))
                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Box(modifier = Modifier.size(5.dp).background(Color.White, CircleShape))
                                    Text("LIVE STREAM PREVIEW", color = Color.White, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            Box(
                                modifier = Modifier
                                    .background(Color.Black.copy(alpha = 0.75f), RoundedCornerShape(4.dp))
                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                            ) {
                                Text(
                                    text = if (hdExport) "UHD 60FPS" else "HD MP4",
                                    color = NeonBlue,
                                    fontSize = 8.5.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }

                        // Playback Center Overlay button (fades in slightly on tap)
                        Box(
                            modifier = Modifier
                                .align(Alignment.Center)
                                .size(50.dp)
                                .background(Color.Black.copy(alpha = 0.6f), CircleShape)
                                .clickable { isPlaying = !isPlaying },
                            contentAlignment = Alignment.Center
                        ) {
                            Icon(
                                imageVector = if (isPlaying) Icons.Filled.Pause else Icons.Filled.PlayArrow,
                                contentDescription = "Play/Pause Video",
                                tint = Color.White,
                                modifier = Modifier.size(28.dp)
                            )
                        }
                    }

                    // Video Playbacks Track Controller
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF0D0A14))
                            .padding(12.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            IconButton(
                                onClick = { isPlaying = !isPlaying },
                                modifier = Modifier.size(28.dp)
                            ) {
                                Icon(
                                    imageVector = if (isPlaying) Icons.Filled.Pause else Icons.Filled.PlayArrow,
                                    contentDescription = "Toggle Video Play",
                                    tint = NeonBlue,
                                    modifier = Modifier.size(22.dp)
                                )
                            }
                            
                            Spacer(modifier = Modifier.width(6.dp))
                            
                            // Playback timeline slider bar
                            Slider(
                                value = playbackProgress,
                                onValueChange = { playbackProgress = it },
                                modifier = Modifier.weight(1f),
                                colors = SliderDefaults.colors(
                                    thumbColor = NeonBlue,
                                    activeTrackColor = NeonBlue,
                                    inactiveTrackColor = Color.DarkGray
                                )
                            )

                            Spacer(modifier = Modifier.width(8.dp))

                            // Counter timer details
                            val elapsedSeconds = (playbackProgress * durationSeconds).toInt()
                            Text(
                                text = "0:${if (elapsedSeconds < 10) "0" else ""}$elapsedSeconds / 0:${if (durationSeconds < 10) "0" else ""}$durationSeconds",
                                color = Color.White,
                                fontSize = 10.sp,
                                fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace,
                                fontWeight = FontWeight.Bold
                            )
                        }

                        Divider(color = Color(0x11FFFFFF))

                        // Actions and Download mp4 button
                        Row(
                            modifier = Modifier.fillMaxWidth().padding(top = 4.dp),
                            horizontalArrangement = Arrangement.spacedBy(10.dp)
                        ) {
                            Button(
                                onClick = {
                                    Toast.makeText(context, "Beginning Premium HD Video Download...", Toast.LENGTH_SHORT).show()
                                    viewModel.recordVideoCreation(
                                        inputImageName = if (activeTab == "presets") presets[selectedPresetIndex].title else "custom_import.png",
                                        animationMode = selectedFaceAnimation,
                                        cameraZoom = selectedCameraZoom,
                                        motionEffects = selectedMotionEffects,
                                        talkingPhoto = talkingPhotoMode,
                                        lipSyncScript = lipSyncScript,
                                        musicTrack = selectedMusic,
                                        duration = durationSeconds,
                                        hdExport = hdExport,
                                        videoPlaceholderUrl = activeImageUrl,
                                        directingPrompt = videoPrompt
                                    )
                                    viewModel.triggerMockDownload(
                                        com.example.data.CreationEntity(
                                            id = (1000..9999).random(),
                                            toolName = "AI Video Generator",
                                            category = "Video Tools",
                                            inputPrompt = "Luma Core Generation with motion",
                                            outputText = activeImageUrl
                                        )
                                    )
                                },
                                modifier = Modifier.weight(1.2f).height(44.dp).testTag("download_mp4_button"),
                                colors = ButtonDefaults.buttonColors(containerColor = NeonBlue),
                                shape = RoundedCornerShape(10.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Icon(imageVector = Icons.Filled.Download, contentDescription = "Download Video", modifier = Modifier.size(16.dp), tint = PureBlack)
                                    Text("Download Movie MP4", color = PureBlack, fontSize = 11.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            OutlinedButton(
                                onClick = { processState = "idle" },
                                modifier = Modifier.weight(0.8f).height(44.dp),
                                border = BorderStroke(1.dp, Color.Gray),
                                colors = ButtonDefaults.outlinedButtonColors(contentColor = Color.White),
                                shape = RoundedCornerShape(10.dp)
                            ) {
                                Text("New Gen Loop", fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // PRESET PICKER & CUSTOM UPLOADS PANEL
        // -------------------------------------------------------------
        if (processState == "idle") {
            // TABS: SAMPLE PRESETS OR GALLERY IMPORT
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0x1F22D3EE), RoundedCornerShape(10.dp))
                    .padding(3.dp),
                horizontalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                Button(
                    onClick = { activeTab = "presets" },
                    modifier = Modifier.weight(1f).height(38.dp),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (activeTab == "presets") Color(0xFF0D0C15) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    contentPadding = PaddingValues()
                ) {
                    Text(
                        text = "Curated Keyframes",
                        color = if (activeTab == "presets") NeonBlue else Color.LightGray,
                        fontSize = 11.5.sp,
                        fontWeight = FontWeight.Bold
                    )
                }

                Button(
                    onClick = { activeTab = "custom" },
                    modifier = Modifier.weight(1f).height(38.dp),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (activeTab == "custom") Color(0xFF0D0C15) else Color.Transparent
                    ),
                    shape = RoundedCornerShape(8.dp),
                    contentPadding = PaddingValues()
                ) {
                    Text(
                        text = "Upload Custom Image",
                        color = if (activeTab == "custom") NeonBlue else Color.LightGray,
                        fontSize = 11.5.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }

            // Tab Content
            if (activeTab == "presets") {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    presets.forEachIndexed { idx, preset ->
                        val isSelected = idx == selectedPresetIndex
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = if (isSelected) Color(0xFF121424) else Color(0xFF0B0910)
                            ),
                            border = BorderStroke(
                                1.dp,
                                if (isSelected) NeonBlue else Color(0xFF272535)
                            ),
                            shape = RoundedCornerShape(12.dp),
                            modifier = Modifier
                                .fillMaxWidth()
                                .clickable { selectedPresetIndex = idx }
                        ) {
                            Row(
                                modifier = Modifier.padding(8.dp),
                                horizontalArrangement = Arrangement.spacedBy(10.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Card(
                                    shape = RoundedCornerShape(8.dp),
                                    modifier = Modifier.size(54.dp)
                                ) {
                                    AsyncImage(
                                        model = preset.imageUrl,
                                        contentDescription = preset.title,
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                }

                                Column(modifier = Modifier.weight(1f)) {
                                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                        Text(preset.title, color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                        if (isSelected) {
                                            Box(modifier = Modifier.size(6.dp).background(NeonBlue, CircleShape))
                                        }
                                    }
                                    Text(preset.description, color = Color.Gray, fontSize = 10.sp)
                                }
                            }
                        }
                    }
                }
            } else {
                // Custom Upload Zone
                Card(
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF0A0713)),
                    border = BorderStroke(1.dp, Color(0xFF231F3B)),
                    shape = RoundedCornerShape(12.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                        if (customImageUri == null) {
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(110.dp)
                                    .background(Color(0xFF04030A), RoundedCornerShape(10.dp))
                                    .border(
                                        1.dp,
                                        Brush.linearGradient(listOf(NeonBlue, NeonPurple)),
                                        RoundedCornerShape(10.dp)
                                    )
                                    .clickable { launchGallery() }
                                    .testTag("gallery_picker_video_trigger"),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center) {
                                    Icon(imageVector = Icons.Filled.UploadFile, contentDescription = "Upload symbol", tint = NeonBlue, modifier = Modifier.size(34.dp))
                                    Spacer(modifier = Modifier.height(6.dp))
                                    Text("SELECT FRAME KEY FROM STORAGE", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    Text("Support JPG, PNG, WEBP files up to 12MB", color = Color.Gray, fontSize = 9.sp)
                                }
                            }
                        } else {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(horizontalArrangement = Arrangement.spacedBy(10.dp), verticalAlignment = Alignment.CenterVertically) {
                                    Card(shape = RoundedCornerShape(6.dp), modifier = Modifier.size(50.dp)) {
                                        AsyncImage(
                                            model = customImageUri.toString(),
                                            contentDescription = "Uploaded clip frame",
                                            contentScale = ContentScale.Crop,
                                            modifier = Modifier.fillMaxSize()
                                        )
                                    }
                                    Column {
                                        Text("Selected Custom Frame", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                        Text("Tap change to select another", color = Color.Gray, fontSize = 9.sp)
                                    }
                                }

                                TextButton(onClick = { launchGallery() }) {
                                    Text("Change Photo", color = NeonBlue, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // AI VIDEO ENGINE (MODEL) SELECTION
        // -------------------------------------------------------------
        if (processState != "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF06050C)),
                border = BorderStroke(1.5.dp, Brush.linearGradient(listOf(NeonBlue, NeonPurple))),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.AutoAwesome,
                            contentDescription = "Engine Select",
                            tint = NeonBlue,
                            modifier = Modifier.size(16.dp)
                        )
                        Text(
                            text = "AI Video Generation Engine",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                    Text(
                        text = "Veo 3 offers Google's newest state-of-the-art cinematic outputs, increasing video physics realism, lighting consistency and spatial layout fidelity.",
                        color = Color.Gray,
                        fontSize = 10.5.sp
                    )

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        listOf(
                            Triple("Veo 3 Ultra", "Google AI (SOTA)", NeonBlue),
                            Triple("Veo 3 HyperMotion", "Google (v3)", NeonPurple),
                            Triple("Luma Dream", "Dream Motion", NeonCyan)
                        ).forEach { (engineName, engineDesc, engineColor) ->
                            val isSelected = selectedVideoEngine.startsWith(engineName)
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .background(
                                        if (isSelected) engineColor.copy(alpha = 0.15f) else Color(0xFF100F1C),
                                        RoundedCornerShape(10.dp)
                                    )
                                    .border(
                                        1.5.dp,
                                        if (isSelected) engineColor else Color.DarkGray.copy(0.4f),
                                        RoundedCornerShape(10.dp)
                                    )
                                    .clickable { selectedVideoEngine = "$engineName ($engineDesc)" }
                                    .padding(vertical = 10.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Text(
                                        text = engineName,
                                        color = if (isSelected) Color.White else Color.LightGray,
                                        fontSize = 11.sp,
                                        fontWeight = FontWeight.ExtraBold
                                    )
                                    Spacer(modifier = Modifier.height(2.dp))
                                    Text(
                                        text = engineDesc,
                                        color = if (isSelected) engineColor else Color.Gray,
                                        fontSize = 8.5.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // AI DIRECTED VIDEO PROMPT GUIDANCE
        // -------------------------------------------------------------
        if (processState != "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF040308)),
                border = BorderStroke(1.dp, NeonBlue.copy(alpha = 0.4f)),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.AutoAwesome,
                            contentDescription = "AI Co-pilot Prompt",
                            tint = NeonBlue,
                            modifier = Modifier.size(16.dp)
                        )
                        Text(
                            text = "Describe Video Motion (Directing Prompt)",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                    Text(
                        text = "Jaisa prompt dalenge vaisa image video mein Banega (The video's motion and details will generate conforming to your written prompt description below).",
                        color = Color.Gray,
                        fontSize = 11.sp
                    )

                    OutlinedTextField(
                        value = videoPrompt,
                        onValueChange = { videoPrompt = it },
                        modifier = Modifier.fillMaxWidth().testTag("video_prompt_input_field"),
                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 12.sp),
                        placeholder = {
                            Text(
                                "Describe desired movement, lighting, dramatic orbits or physics...",
                                color = Color.Gray,
                                fontSize = 11.sp
                            )
                        },
                        shape = RoundedCornerShape(10.dp),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            focusedBorderColor = NeonBlue,
                            unfocusedBorderColor = Color.DarkGray,
                            focusedContainerColor = Color(0xFF020104),
                            unfocusedContainerColor = Color(0xFF020104)
                        )
                    )

                    // Presets suggestion chips flow under text field
                    Row(
                        modifier = Modifier.horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        listOf(
                            "Fast dynamic pan around, neon lights, 4k ultra-detailed sf",
                            "Subtle cinematic movement, sunset warm reflection background",
                            "Continuous slow-motion majestic waterfall splashing around",
                            "Cyberpunk street rain reflections with futuristic flying vehicle",
                            "Cozy warm interior fireplace fire embers floating in air"
                        ).forEach { suggestion ->
                            val isChipSelected = videoPrompt == suggestion
                            Box(
                                modifier = Modifier
                                    .background(
                                        if (isChipSelected) NeonBlue.copy(alpha = 0.2f) else Color(0xFF0C0B12),
                                        RoundedCornerShape(6.dp)
                                    )
                                    .border(
                                        0.5.dp,
                                        if (isChipSelected) NeonBlue else Color.Gray.copy(0.3f),
                                        RoundedCornerShape(6.dp)
                                    )
                                    .clickable { videoPrompt = suggestion }
                                    .padding(horizontal = 8.dp, vertical = 4.dp)
                            ) {
                                Text(
                                    text = suggestion,
                                    color = if (isChipSelected) NeonBlue else Color.LightGray,
                                    fontSize = 10.sp
                                )
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // ANIMATION PARAMETERS TUNING SUITE
        // -------------------------------------------------------------
        if (processState != "success") {
            Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF090812)),
            border = BorderStroke(0.5.dp, Color.DarkGray),
            shape = RoundedCornerShape(14.dp),
            modifier = Modifier.fillMaxWidth()
        ) {
            Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(14.dp)) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(imageVector = Icons.Filled.Animation, contentDescription = "Tuning Video Core", tint = NeonBlue, modifier = Modifier.size(16.dp))
                    Text(
                        text = "Dynamic Motion Settings",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Bold
                    )
                }

                // 2. Face dynamic tilt options
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    Text(
                        text = "Face Animation Preset",
                        color = Color.LightGray,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Row(
                        modifier = Modifier.horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        listOf("Slight Smile & Nod", "Blink & Wink", "Cinematic Laughter", "Eerily realistic speech", "None").forEach { anim ->
                            val isSelected = anim == selectedFaceAnimation
                            Box(
                                modifier = Modifier
                                    .background(
                                        if (isSelected) NeonBlue else Color(0xFF14141E),
                                        RoundedCornerShape(8.dp)
                                    )
                                    .clickable { selectedFaceAnimation = anim }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Text(
                                    text = anim,
                                    color = if (isSelected) PureBlack else Color.White,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }

                // 3. Camera zoom configuration
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    Text(
                        text = "Cinematic Camera Path (Zoom Effects)",
                        color = Color.LightGray,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Row(
                        modifier = Modifier.horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        listOf("Dynamic Zoom In Slow", "Panoramic Slow Pan Left", "Pan Right Slow", "Dramatic Dolly Roll Orbit", "None").forEach { path ->
                            val isSelected = path == selectedCameraZoom
                            Box(
                                modifier = Modifier
                                    .background(
                                        if (isSelected) NeonBlue else Color(0xFF14141E),
                                        RoundedCornerShape(8.dp)
                                    )
                                    .clickable { selectedCameraZoom = path }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Text(
                                    text = path,
                                    color = if (isSelected) PureBlack else Color.White,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }

                // 4. Motion velocity selection
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    Text(
                        text = "Motion Flow Intensity Factor",
                        color = Color.LightGray,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Row(
                        modifier = Modifier.horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        listOf("Gentle Fluid Flow", "Moderate Kinetic Bounce", "Cinematic Hyperspeed", "Windy Hair Dynamics").forEach { motion ->
                            val isSelected = motion == selectedMotionEffects
                            Box(
                                modifier = Modifier
                                    .background(
                                        if (isSelected) NeonBlue else Color(0xFF14141E),
                                        RoundedCornerShape(8.dp)
                                    )
                                    .clickable { selectedMotionEffects = motion }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Text(
                                    text = motion,
                                    color = if (isSelected) PureBlack else Color.White,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // PREMIUM AUDIO & TALKING PHOTO CORE SUITE
        // -------------------------------------------------------------
        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF040409)),
            border = BorderStroke(1.dp, Color(0xFF191D32)),
            shape = RoundedCornerShape(14.dp),
            modifier = Modifier.fillMaxWidth()
        ) {
            Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(14.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Icon(imageVector = Icons.Filled.RecordVoiceOver, contentDescription = "Talking Photo", tint = NeonPurple, modifier = Modifier.size(16.dp))
                        Text(
                            text = "Talking Photo Mode & Lip Sync",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }

                    Switch(
                        checked = talkingPhotoMode,
                        onCheckedChange = { talkingPhotoMode = it },
                        colors = SwitchDefaults.colors(checkedThumbColor = NeonPurple, checkedTrackColor = Color(0xFF281144))
                    )
                }

                if (talkingPhotoMode) {
                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        Text(
                            text = "Enter Speech Text (AI Vocal Synthesis)",
                            color = Color.LightGray,
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold
                        )
                        
                        OutlinedTextField(
                            value = lipSyncScript,
                            onValueChange = { lipSyncScript = it },
                            modifier = Modifier.fillMaxWidth(),
                            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 12.sp),
                            shape = RoundedCornerShape(10.dp),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedTextColor = Color.White,
                                focusedBorderColor = NeonPurple,
                                unfocusedBorderColor = Color.DarkGray
                            )
                        )
                        
                        Text(
                            text = "✨ AI dynamic sync engine will map face coordinates to vocalized soundwaves.",
                            color = Color.Gray,
                            fontSize = 9.5.sp
                        )
                    }
                }

                Divider(color = Color(0x19FFFFFF))

                // Music track selection
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    Text(
                        text = "Select Audio Music Track",
                        color = Color.LightGray,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Row(
                        modifier = Modifier.horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        listOf("Cinematic Ambient Synth", "Epic Sci-fi Techno", "Emotional Guitar Strings", "None (Silent Clip)", "Upload Custom Audio/MP3").forEach { tune ->
                            val isSelected = tune == selectedMusic
                            Box(
                                modifier = Modifier
                                    .background(
                                        if (isSelected) NeonPurple else Color(0xFF14141E),
                                        RoundedCornerShape(8.dp)
                                    )
                                    .clickable { selectedMusic = tune }
                                    .padding(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Text(
                                    text = tune,
                                    color = if (isSelected) Color.White else Color.Gray,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // DURATION & QUALITY CONTROLS
        // -------------------------------------------------------------
        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF050510)),
            border = BorderStroke(0.5.dp, Color.DarkGray),
            shape = RoundedCornerShape(12.dp),
            modifier = Modifier.fillMaxWidth()
        ) {
            Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(14.dp)) {
                // Duration selection slider bar
                Column {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween
                    ) {
                        Text("Video Loop Duration", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                        Text("${durationSeconds}s Standard", color = NeonBlue, fontSize = 12.sp, fontWeight = FontWeight.Black)
                    }
                    Slider(
                        value = durationSeconds.toFloat(),
                        onValueChange = { durationSeconds = it.toInt() },
                        valueRange = 3f..15f,
                        colors = SliderDefaults.colors(
                            thumbColor = NeonBlue,
                            activeTrackColor = NeonBlue,
                            inactiveTrackColor = Color.DarkGray
                        )
                    )
                }

                Divider(color = Color(0x11FFFFFF))

                // Max HD video toggle switch
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column {
                        Text("HD Pro Video Export", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                        Text("Encode using production-ready deep upscaler (Recommended)", color = Color.Gray, fontSize = 9.5.sp)
                    }
                    Switch(
                        checked = hdExport,
                        onCheckedChange = { hdExport = it },
                        colors = SwitchDefaults.colors(checkedThumbColor = NeonBlue, checkedTrackColor = Color(0xFF15334D))
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // CORE LAUNCH BUTTON TRIPPED
        // -------------------------------------------------------------
        if (processState != "generating") {
            Button(
                onClick = {
                    processState = "generating"
                    processProgress = 0f
                    val engineNameRef = selectedVideoEngine.split(" ").first()
                    activeProgressStep = "Allocating virtual $engineNameRef core cluster nodes..."

                    coroutineScope.launch {
                        // Progress rendering steps over 4800ms
                        val renderDuration = 4800L
                        val stepCount = 100
                        val delayMs = renderDuration / stepCount

                        for (i in 0..stepCount) {
                            processProgress = i / 100f
                            activeProgressStep = when {
                                i < 15 -> "Splicing image keyframe with $engineNameRef directive: \"${if (videoPrompt.length > 35) videoPrompt.take(32) + "..." else videoPrompt}\"..."
                                i < 35 -> "Applying $engineNameRef temporal coherence & lighting transformers with advanced physics consistency..."
                                i < 55 -> "Synthesizing vocal lips-sync talk coordinates..."
                                i < 75 -> "Simulating camera path orbit: ${selectedCameraZoom}..."
                                i < 90 -> "Blending music theme: ${selectedMusic}..."
                                else -> "Assembling premium high fidelity $engineNameRef 4K UHD video package..."
                            }
                            delay(delayMs)
                        }

                        // Save creation data dynamically to local Room persistence
                        viewModel.recordVideoCreation(
                            inputImageName = if (activeTab == "presets") presets[selectedPresetIndex].title else "custom_frame.png",
                            animationMode = selectedFaceAnimation,
                            cameraZoom = selectedCameraZoom,
                            motionEffects = selectedMotionEffects,
                            talkingPhoto = talkingPhotoMode,
                            lipSyncScript = lipSyncScript,
                            musicTrack = selectedMusic,
                            duration = durationSeconds,
                            hdExport = hdExport,
                            videoPlaceholderUrl = activeImageUrl,
                            directingPrompt = "[$selectedVideoEngine] $videoPrompt"
                        )

                        Toast.makeText(context, "AI Cinematic Video Render Complete!", Toast.LENGTH_SHORT).show()
                        playbackProgress = 0.0f
                        isPlaying = true
                        processState = "success"
                    }
                },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(50.dp)
                    .background(
                        Brush.linearGradient(listOf(NeonBlue, NeonPurple)),
                        RoundedCornerShape(12.dp)
                    )
                    .testTag("generate_video_action_button"),
                colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent),
                shape = RoundedCornerShape(12.dp)
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(imageVector = Icons.Filled.MovieCreation, contentDescription = "Splicer symbol", tint = PureBlack)
                    Text(
                        text = if (processState == "success") "RE-GENERATE CINEMATIC VIDEO" else "SYNTHESIZE CINEMATIC VIDEO",
                        color = PureBlack,
                        fontSize = 12.5.sp,
                        fontWeight = FontWeight.Black,
                        letterSpacing = 1.sp
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // MY VIDEO GALLERY HISTORICAL RECORDS LISTING
        // -------------------------------------------------------------
        if (videoHistory.isNotEmpty()) {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.padding(top = 10.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "My Personal Video Studio Gallery",
                        color = Color.White,
                        fontWeight = FontWeight.Bold,
                        fontSize = 13.sp
                    )
                    Text(
                        text = "Clear All",
                        color = Color.DarkGray,
                        fontSize = 11.sp,
                        fontWeight = FontWeight.Bold,
                        modifier = Modifier.clickable { viewModel.clearAllHistory() }
                    )
                }

                Row(
                    modifier = Modifier.horizontalScroll(rememberScrollState()),
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    videoHistory.forEach { item ->
                        // Gather details from inputPrompt
                        var imgUrlKey = ""
                        val parts = item.inputPrompt.split(" | ")
                        parts.forEach { part ->
                            if (part.startsWith("Input Image: ")) imgUrlKey = part.replace("Input Image: ", "")
                        }
                        
                        // Parse matching preset url for visual render, fallback to random sig
                        val matchingPreset = presets.find { it.title == imgUrlKey }
                        val visualUrl = matchingPreset?.imageUrl ?: "https://images.unsplash.com/photo-1515621061946-eff1c2a352bd?q=80&w=300&auto=format&fit=crop"

                        Card(
                            modifier = Modifier
                                .width(130.dp)
                                .clickable {
                                    // Load historic item parameters back into current states
                                    selectedFaceAnimation = "Slight Smile & Nod"
                                    selectedCameraZoom = "Dynamic Zoom In Slow"
                                    selectedMusic = "Cinematic Ambient Synth"
                                    
                                    val promptParts = item.inputPrompt.split(" | ")
                                    promptParts.forEach { prt ->
                                        if (prt.startsWith("Animation: ")) selectedFaceAnimation = prt.replace("Animation: ", "")
                                        if (prt.startsWith("Zoom: ")) selectedCameraZoom = prt.replace("Zoom: ", "")
                                        if (prt.startsWith("Music: ")) selectedMusic = prt.replace("Music: ", "")
                                    }

                                    // Switch back to successful viewer
                                    activeTab = "presets"
                                    val matchPresetIdx = presets.indexOfFirst { it.title == imgUrlKey }
                                    if (matchPresetIdx != -1) {
                                        selectedPresetIndex = matchPresetIdx
                                    }
                                    isPlaying = true
                                    playbackProgress = 0f
                                    processState = "success"
                                    
                                    Toast.makeText(context, "Loaded Video Project #${item.id} from gallery list!", Toast.LENGTH_SHORT).show()
                                },
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF06060F)),
                            shape = RoundedCornerShape(8.dp),
                            border = BorderStroke(0.5.dp, Color.DarkGray)
                        ) {
                            Column {
                                Box(
                                    modifier = Modifier.fillMaxWidth().height(80.dp)
                                ) {
                                    AsyncImage(
                                        model = visualUrl,
                                        contentDescription = "Historical Video Frame",
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                    Box(
                                        modifier = Modifier
                                            .align(Alignment.Center)
                                            .size(24.dp)
                                            .background(Color.Black.copy(alpha = 0.6f), CircleShape),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Icon(imageVector = Icons.Filled.PlayArrow, contentDescription = "Play", tint = Color.White, modifier = Modifier.size(14.dp))
                                    }
                                }
                                Text(
                                    text = "AI_Movie_${item.id}.mp4",
                                    color = Color.White,
                                    fontSize = 9.5.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.padding(start = 6.dp, end = 6.dp, top = 4.dp),
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis
                                )
                                Text(
                                    text = "Preset: $imgUrlKey",
                                    color = Color.Gray,
                                    fontSize = 8.sp,
                                    modifier = Modifier.padding(start = 6.dp, end = 6.dp, bottom = 6.dp),
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis
                                )
                            }
                        }
                    }
                }
            }
        }
        }

        Spacer(modifier = Modifier.height(35.dp))
    }
}

// =====================================================================
// AI TEXT TO VIDEO PREMIUM HIGH-QUALITY WORKSPACE MODULE
// =====================================================================

data class TextVideoPreset(
    val title: String,
    val prompt: String,
    val style: String,
    val imageUrl: String
)

@Composable
fun TextToVideoWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val history by viewModel.history.collectAsState()
    val userStats by viewModel.userStats.collectAsState()

    // Premium presets list for rapid text-to-video prototyping
    val presets = remember {
        listOf(
            TextVideoPreset(
                "Cyberpunk Rain",
                "A futuristic cyberpunk street reflecting neon holograms, glowing rain puddles, sleek hovercraft flying under stormy dark skies.",
                "Photorealistic Cinematic 35mm",
                "https://images.unsplash.com/photo-1509198397868-475647b2a1e5?q=80&w=600"
            ),
            TextVideoPreset(
                "Cosmic Station",
                "Ultra photorealistic camera panning around a majestic space station orbiting a giant ringed gaseous planet, solar panels reflecting sharp sunlight.",
                "3D Unreal Engine 5 Render",
                "https://images.unsplash.com/photo-1534447677768-be436bb09401?q=80&w=600"
            ),
            TextVideoPreset(
                "Bioluminescence",
                "An ancient mystical forest with giant bioluminescent mushrooms glowing softly, misty fog rolling between ancient trees, magical fireflies floating.",
                "Aesthetic Anime Art",
                "https://images.unsplash.com/photo-1579546929518-9e396f3cc809?q=80&w=600"
            ),
            TextVideoPreset(
                "Coastal Sunset",
                "A classic 1970s crimson muscle car speeding on a coastal highway at sunset, camera trailing low near the tires, warm golden lens flares.",
                "Photorealistic Cinematic 35mm",
                "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=600"
            ),
            TextVideoPreset(
                "Volcanic Crater",
                "A dramatic close-up flight over a bubbling volcanic crater, incandescent liquid magma flowing, thick dark basalt structures, cinematic smoke.",
                "Hyper-Physical 8K Render",
                "https://images.unsplash.com/photo-1475274047050-1d0c0975c63e?q=80&w=600"
            )
        )
    }

    // STATE VARIABLES
    var videoPrompt by remember { mutableStateOf("A magnificent soaring drone shot over a misty high-alpine castle nested on snowy summits during a pristine golden rise.") }
    var selectedStyle by remember { mutableStateOf("Photorealistic Cinematic 35mm") }
    var selectedAspectRatio by remember { mutableStateOf("16:9 Cinema Landscape") }
    var selectedPresetIndex by remember { mutableStateOf(0) }
    var selectedVideoEngine by remember { mutableStateOf("Veo 3 Ultra (Google AI)") }
    
    // HQ RENDER PARAMETERS PANEL
    var selectedResolution by remember { mutableStateOf("4K Ultra HD Pro") }
    var selectedFrameRate by remember { mutableStateOf("60 FPS (Ultra Smooth)") }
    var selectedRenderPass by remember { mutableStateOf("Hyper-Physical Volumetric (Ultra)") }
    var hdrGradingEnabled by remember { mutableStateOf(true) }
    var motionSmoothnessSlider by remember { mutableStateOf(85f) }
    var denoiseSlider by remember { mutableStateOf(10f) }
    var textureSharpnessSlider by remember { mutableStateOf(90f) }
    
    var durationSeconds by remember { mutableStateOf(8) }
    var isHqConfigExpanded by remember { mutableStateOf(false) }

    // State machine
    var processState by remember { mutableStateOf("idle") } // "idle", "generating", "success"
    var processProgress by remember { mutableStateOf(0f) }
    var activeProgressStep by remember { mutableStateOf("") }

    // Playback state
    var isPlaying by remember { mutableStateOf(true) }
    var playbackProgress by remember { mutableStateOf(0f) }

    // Get current preview image based on prompt
    val activePreviewUrl = remember(videoPrompt, selectedPresetIndex) {
        val matchesPreset = presets.find { it.prompt == videoPrompt || videoPrompt.startsWith(it.title) }
        matchesPreset?.imageUrl ?: presets[selectedPresetIndex % presets.size].imageUrl
    }

    // Filter past text to video history instances
    val videoHistory = remember(history) {
        history.filter { it.toolName == "Text to Video" }
    }

    // Playback loop controller
    val infiniteTransition = rememberInfiniteTransition(label = "text_video_preview_infinite")
    val animatedScale by infiniteTransition.animateFloat(
        initialValue = 1.0f,
        targetValue = 1.15f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = durationSeconds * 1000, easing = LinearOutSlowInEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "t_scale"
    )
    val animatedTranslateX by infiniteTransition.animateFloat(
        initialValue = -25f,
        targetValue = 25f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = durationSeconds * 1000, easing = LinearEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "t_translate"
    )

    LaunchedEffect(isPlaying, processState, durationSeconds) {
        if (processState == "success" && isPlaying) {
            playbackProgress = 0f
            while (isPlaying) {
                delay(100)
                playbackProgress += 0.1f / durationSeconds
                if (playbackProgress >= 1.0f) {
                    playbackProgress = 0.0f
                }
            }
        }
    }

    Column(
        modifier = modifier
            .fillMaxSize()
            .verticalScroll(rememberScrollState()),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // Upper balance tracking banner
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color(0xFF0F0B20), RoundedCornerShape(10.dp))
                .border(0.5.dp, NeonBlue.copy(0.4f), RoundedCornerShape(10.dp))
                .padding(horizontal = 14.dp, vertical = 10.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
                Icon(imageVector = Icons.Filled.Movie, contentDescription = "Engine balance", tint = NeonBlue, modifier = Modifier.size(16.dp))
                Text("Veo 3 Ultra HQ Co-processor Ready", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Black)
            }
            Text("Cost: 3 units", color = NeonPurple, fontSize = 11.sp, fontWeight = FontWeight.Black)
        }

        // -------------------------------------------------------------
        // LIVE CINEMATIC PREVIEW COMPRESSED PLAYER
        // -------------------------------------------------------------
        if (processState == "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF020205)),
                border = BorderStroke(1.5.dp, NeonBlue),
                shape = RoundedCornerShape(16.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column {
                    // Premium Adaptive Preview viewport centered in an eye-safe black frame
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(300.dp)
                            .background(Color.Black)
                            .clip(RoundedCornerShape(topStart = 16.dp, topEnd = 16.dp)),
                        contentAlignment = Alignment.Center
                    ) {
                        val videoBoxModifier = when {
                            selectedAspectRatio.contains("9:16") -> {
                                Modifier.fillMaxHeight().aspectRatio(9f / 16f, matchHeightConstraintsFirst = true)
                            }
                            selectedAspectRatio.contains("1:1") -> {
                                Modifier.fillMaxHeight().aspectRatio(1f, matchHeightConstraintsFirst = true)
                            }
                            else -> {
                                Modifier.fillMaxWidth().aspectRatio(16f / 9f)
                            }
                        }

                        Box(
                            modifier = videoBoxModifier.fillMaxHeight()
                        ) {
                            val scaleFactor = if (isPlaying) animatedScale else 1.0f
                            val translationXValue = if (isPlaying) animatedTranslateX else 0f
                            
                            // Cinematic Color Grading
                            val cinematicColorMatrix = ColorMatrix().apply {
                                val contrast = 1.15f
                                val translate = (-.5f * contrast + .5f) * 255f
                                val m = floatArrayOf(
                                    contrast, 0f, 0f, 0f, translate,
                                    0f, contrast, 0.05f, 0f, translate,
                                    0f, 0f, contrast + 0.1f, 0f, translate,
                                    0f, 0f, 0f, 1f, 0f
                                )
                                set(ColorMatrix(m))
                            }
                            
                            AsyncImage(
                                model = activePreviewUrl,
                                contentDescription = "Text to Video Cinematic Output Frame",
                                contentScale = ContentScale.Crop,
                                colorFilter = ColorFilter.colorMatrix(cinematicColorMatrix),
                                modifier = Modifier
                                    .fillMaxSize()
                                    .graphicsLayer {
                                        scaleX = scaleFactor
                                        scaleY = scaleFactor
                                        translationX = translationXValue
                                    }
                            )

                            // Cinematic Letterboxing (Top & Bottom Black Bars)
                            Column(
                                modifier = Modifier.fillMaxSize(),
                                verticalArrangement = Arrangement.SpaceBetween
                            ) {
                                Box(modifier = Modifier.fillMaxWidth().height(26.dp).background(Color.Black))
                                Box(modifier = Modifier.fillMaxWidth().height(26.dp).background(Color.Black))
                            }

                            // Vignette cinema border overlay
                            Box(
                                modifier = Modifier
                                    .fillMaxSize()
                                    .background(
                                        Brush.radialGradient(
                                            colors = listOf(Color.Transparent, Color.Black.copy(alpha = 0.85f))
                                        )
                                    )
                            )

                            // Dynamic equalizer soundwave simulation when music or verbal lip sync is running
                            if (isPlaying) {
                                Row(
                                    modifier = Modifier
                                        .align(Alignment.BottomStart)
                                        .padding(start = 14.dp, bottom = 14.dp),
                                    horizontalArrangement = Arrangement.spacedBy(3.dp),
                                    verticalAlignment = Alignment.Bottom
                                ) {
                                    (1..12).forEach { i ->
                                        val randomHeightMultiplier by infiniteTransition.animateFloat(
                                            initialValue = 0.2f + (i % 3) * 0.15f,
                                            targetValue = 0.8f - (i % 4) * 0.15f,
                                            animationSpec = infiniteRepeatable(
                                                animation = tween(durationMillis = 150 + i * 20, easing = LinearEasing),
                                                repeatMode = RepeatMode.Reverse
                                            ),
                                            label = "tt_soundwave_$i"
                                        )
                                        Box(
                                            modifier = Modifier
                                                .width(2.5.dp)
                                                .height((randomHeightMultiplier * 36).dp)
                                                .background(
                                                    Brush.verticalGradient(listOf(NeonBlue, NeonPurple)),
                                                    RoundedCornerShape(1.dp)
                                                )
                                        )
                                    }
                                }
                            }

                            // Floating badges
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(12.dp),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Box(
                                    modifier = Modifier
                                        .background(Color.Red.copy(alpha = 0.8f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 6.dp, vertical = 2.dp)
                                ) {
                                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                        Box(modifier = Modifier.size(5.dp).background(Color.White, CircleShape))
                                        Text("HIGH FIDELITY PREVIEW", color = Color.White, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                                    }
                                }

                                Box(
                                    modifier = Modifier
                                        .background(Color.Black.copy(alpha = 0.8f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 6.dp, vertical = 2.dp)
                                ) {
                                    Text(
                                        text = "$selectedResolution @ $selectedFrameRate",
                                        color = NeonBlue,
                                        fontSize = 8.5.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }

                            // Playback Center Overlay button (fades in slightly on tap)
                            Box(
                                modifier = Modifier
                                    .align(Alignment.Center)
                                    .size(54.dp)
                                    .background(Color.Black.copy(alpha = 0.5f), CircleShape)
                                    .clickable { isPlaying = !isPlaying },
                                contentAlignment = Alignment.Center
                            ) {
                                Icon(
                                    imageVector = if (isPlaying) Icons.Filled.Pause else Icons.Filled.PlayArrow,
                                    contentDescription = "Play state toggle symbol",
                                    tint = Color.White,
                                    modifier = Modifier.size(24.dp)
                                )
                            }
                        }
                    }

                    // Bottom progress indicator bar
                    LinearProgressIndicator(
                        progress = { playbackProgress },
                        color = NeonBlue,
                        trackColor = Color.DarkGray,
                        modifier = Modifier.fillMaxWidth()
                    )

                    // Control strip parameters
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF07060F))
                            .padding(10.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text("Cinema Loop Sequence Generated", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Text("Aspect: $selectedAspectRatio | Model: Veo 3 v3 HQ", color = Color.Gray, fontSize = 9.sp)
                        }

                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            IconButton(
                                onClick = { isPlaying = !isPlaying },
                                modifier = Modifier
                                    .background(Color(0xFF141225), CircleShape)
                                    .size(32.dp)
                            ) {
                                Icon(
                                    imageVector = if (isPlaying) Icons.Filled.Pause else Icons.Filled.PlayArrow,
                                    contentDescription = "Vocal tool play",
                                    tint = NeonBlue,
                                    modifier = Modifier.size(16.dp)
                                )
                            }

                            Button(
                                onClick = {
                                    val fakePath = activePreviewUrl
                                    val simulatedCreation = CreationEntity(
                                        toolName = "Text to Video",
                                        category = "Video Tools",
                                        inputPrompt = "Prompt: $videoPrompt",
                                        outputText = "Simulated Premium Video Download Link: $fakePath",
                                        isSaved = true
                                    )
                                    viewModel.triggerMockDownload(simulatedCreation)
                                },
                                colors = ButtonDefaults.buttonColors(containerColor = NeonBlue),
                                contentPadding = PaddingValues(horizontal = 12.dp, vertical = 0.dp),
                                shape = RoundedCornerShape(10.dp),
                                modifier = Modifier.height(32.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(imageVector = Icons.Filled.Download, contentDescription = "Download video", tint = PureBlack, modifier = Modifier.size(14.dp))
                                    Text("Download Clip", color = PureBlack, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // ANIMATION / GENERATING LOADING PROCESS PANEL
        // -------------------------------------------------------------
        if (processState == "generating") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF030309)),
                border = BorderStroke(1.dp, NeonBlue.copy(0.5f)),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(
                    modifier = Modifier.padding(18.dp),
                    verticalArrangement = Arrangement.Center,
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    CircularProgressIndicator(color = NeonBlue, strokeWidth = 3.dp, modifier = Modifier.size(36.dp))
                    Spacer(modifier = Modifier.height(14.dp))
                    Text(
                        text = "Rendering High Quality Video Sequence...",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        text = activeProgressStep,
                        color = Color.Gray,
                        fontSize = 11.sp,
                        textAlign = TextAlign.Center
                    )
                    Spacer(modifier = Modifier.height(12.dp))
                    LinearProgressIndicator(
                        progress = { processProgress },
                        color = NeonBlue,
                        trackColor = Color(0x33FFFFFF),
                        modifier = Modifier.fillMaxWidth().height(4.dp).clip(RoundedCornerShape(2.dp))
                    )
                    Spacer(modifier = Modifier.height(6.dp))
                    Text(
                        text = "${(processProgress * 100).toInt()}% Rendered",
                        color = NeonBlue,
                        fontSize = 10.sp,
                        fontWeight = FontWeight.Bold
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // AI VIDEO ENGINE (MODEL) SELECTION
        // -------------------------------------------------------------
        if (processState != "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF06050C)),
                border = BorderStroke(1.5.dp, Brush.linearGradient(listOf(NeonBlue, NeonPurple))),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.AutoAwesome,
                            contentDescription = "Engine Select",
                            tint = NeonBlue,
                            modifier = Modifier.size(16.dp)
                        )
                        Text(
                            text = "AI Video Generation Engine",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                    Text(
                        text = "Veo 3 offers Google's newest state-of-the-art cinematic outputs, increasing video physics realism, lighting consistency and spatial layout fidelity.",
                        color = Color.Gray,
                        fontSize = 10.5.sp
                    )

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        listOf(
                            Triple("Veo 3 Ultra", "Google AI (SOTA)", NeonBlue),
                            Triple("Veo 3 HyperMotion", "Google (v3)", NeonPurple),
                            Triple("Luma Dream", "Dream Motion", NeonCyan)
                        ).forEach { (engineName, engineDesc, engineColor) ->
                            val isSelected = selectedVideoEngine.startsWith(engineName)
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .background(
                                        if (isSelected) engineColor.copy(alpha = 0.15f) else Color(0xFF100F1C),
                                        RoundedCornerShape(10.dp)
                                    )
                                    .border(
                                        1.5.dp,
                                        if (isSelected) engineColor else Color.DarkGray.copy(0.4f),
                                        RoundedCornerShape(10.dp)
                                    )
                                    .clickable { selectedVideoEngine = "$engineName ($engineDesc)" }
                                    .padding(vertical = 10.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                    Text(
                                        text = engineName,
                                        color = if (isSelected) Color.White else Color.LightGray,
                                        fontSize = 11.sp,
                                        fontWeight = FontWeight.ExtraBold
                                    )
                                    Spacer(modifier = Modifier.height(2.dp))
                                    Text(
                                        text = engineDesc,
                                        color = if (isSelected) engineColor else Color.Gray,
                                        fontSize = 8.5.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // INPUT PROMPT DESCRIPTORS
        // -------------------------------------------------------------
        if (processState != "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF040308)),
                border = BorderStroke(1.dp, NeonBlue.copy(alpha = 0.4f)),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Filled.AutoAwesome,
                            contentDescription = "AI Co-pilot Prompt",
                            tint = NeonBlue,
                            modifier = Modifier.size(16.dp)
                        )
                        Text(
                            text = "Write Video Scene Description (Direct Prompt)",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }
                    Text(
                        text = "Jaisa prompt dalenge vaisa video scene banega (Veo 3 will render complete movie frames conforming to your description details).",
                        color = Color.Gray,
                        fontSize = 11.sp
                    )

                    OutlinedTextField(
                        value = videoPrompt,
                        onValueChange = { videoPrompt = it },
                        modifier = Modifier.fillMaxWidth().testTag("text_to_video_prompt_field"),
                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 12.sp),
                        placeholder = {
                            Text(
                                "Describe desired movement, character actions, landscapes, dynamic camera orbits...",
                                color = Color.Gray,
                                fontSize = 11.sp
                            )
                        },
                        shape = RoundedCornerShape(10.dp),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedTextColor = Color.White,
                            focusedBorderColor = NeonBlue,
                            unfocusedBorderColor = Color.DarkGray,
                            focusedContainerColor = Color(0xFF020104),
                            unfocusedContainerColor = Color(0xFF020104)
                        )
                    )

                    // Presets suggestion chips flow under text field
                    Text("Select Beautiful Cinematic Presets:", color = Color.LightGray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                    Row(
                        modifier = Modifier.horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        presets.forEachIndexed { idx, item ->
                            val isChipSelected = selectedPresetIndex == idx
                            Box(
                                modifier = Modifier
                                    .background(
                                        if (isChipSelected) NeonBlue.copy(alpha = 0.2f) else Color(0xFF0C0B12),
                                        RoundedCornerShape(6.dp)
                                    )
                                    .border(
                                        0.5.dp,
                                        if (isChipSelected) NeonBlue else Color.Gray.copy(0.3f),
                                        RoundedCornerShape(6.dp)
                                    )
                                    .clickable { 
                                        selectedPresetIndex = idx
                                        videoPrompt = item.prompt
                                        selectedStyle = item.style
                                    }
                                    .padding(horizontal = 8.dp, vertical = 6.dp)
                            ) {
                                Text(
                                    text = item.title,
                                    color = if (isChipSelected) NeonBlue else Color.LightGray,
                                    fontSize = 10.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // PRESETS & CAMERA STYLE DIRECTORS
        // -------------------------------------------------------------
        if (processState != "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF090812)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Icon(imageVector = Icons.Filled.MovieFilter, contentDescription = "Style selections", tint = NeonBlue, modifier = Modifier.size(16.dp))
                        Text(
                            text = "Aesthetic Styles & Camera Angles",
                            color = Color.White,
                            fontSize = 13.sp,
                            fontWeight = FontWeight.Bold
                        )
                    }

                    // Style choice chips
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Text("Style Direction", color = Color.LightGray, fontSize = 10.sp)
                        Row(modifier = Modifier.horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            listOf(
                                "Photorealistic Cinematic 35mm",
                                "Aesthetic Anime Art",
                                "3D Unreal Engine 5 Render",
                                "Atmospheric Monochrome Film",
                                "Vintage Retro 8mm",
                                "Hyper-Physical 8K Render"
                            ).forEach { style ->
                                val isSelected = selectedStyle == style
                                Box(
                                    modifier = Modifier
                                        .background(if (isSelected) NeonPurple else Color(0xFF14131F), RoundedCornerShape(8.dp))
                                        .clickable { selectedStyle = style }
                                        .padding(horizontal = 10.dp, vertical = 6.dp)
                                ) {
                                    Text(style, color = if (isSelected) Color.White else Color.Gray, fontSize = 10.5.sp)
                                }
                            }
                        }
                    }

                    // Aspect choices
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Text("Aspect Ratio", color = Color.LightGray, fontSize = 10.sp)
                        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            listOf("16:9 Cinema Landscape", "9:16 Vertical Reels", "1:1 Square").forEach { aspect ->
                                val isSelected = selectedAspectRatio == aspect
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .background(if (isSelected) NeonBlue else Color(0xFF14131F), RoundedCornerShape(8.dp))
                                        .clickable { selectedAspectRatio = aspect }
                                        .padding(vertical = 8.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(aspect, color = if (isSelected) PureBlack else Color.LightGray, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // PREMIUM HQ RENDER PARAMETERS EXPANDABLE CALIBRATOR PANEL
        // -------------------------------------------------------------
        if (processState != "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF030206)),
                border = BorderStroke(1.dp, if (isHqConfigExpanded) NeonBlue.copy(0.4f) else Color.DarkGray.copy(0.4f)),
                shape = RoundedCornerShape(14.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp)) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable { isHqConfigExpanded = !isHqConfigExpanded },
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Filled.Tune,
                                contentDescription = "HQ Video configuration toggle",
                                tint = NeonBlue,
                                modifier = Modifier.size(16.dp)
                            )
                            Column {
                                Text(
                                    text = "Veo 3 Professional High-Quality Setup",
                                    color = Color.White,
                                    fontSize = 12.5.sp,
                                    fontWeight = FontWeight.Bold
                                )
                                Text(
                                    text = "Configure ultra-resolution upscaler, FPS loops, light passes",
                                    color = Color.Gray,
                                    fontSize = 10.5.sp
                                )
                            }
                        }
                        Icon(
                            imageVector = Icons.Filled.ArrowDropDown,
                            contentDescription = "Expand controls symbols",
                            tint = Color.LightGray,
                            modifier = Modifier
                                .size(18.dp)
                                .graphicsLayer(rotationZ = if (isHqConfigExpanded) 180f else 0f)
                        )
                    }

                    if (isHqConfigExpanded) {
                        Spacer(modifier = Modifier.height(14.dp))
                        Divider(color = Color(0x15FFFFFF), modifier = Modifier.padding(bottom = 12.dp))

                        // High Quality Upscaling selection
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("Super Resolution Upscaling", color = Color.LightGray, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("1080p CineMaster", "4K Ultra HD Pro", "8K Hyper-Reality IMAX").forEach { res ->
                                    val isSelected = selectedResolution == res
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .background(
                                                if (isSelected) NeonBlue.copy(0.2f) else Color(0xFF0F0E16),
                                                RoundedCornerShape(6.dp)
                                            )
                                            .border(
                                                0.5.dp,
                                                if (isSelected) NeonBlue else Color.Gray.copy(0.2f),
                                                RoundedCornerShape(6.dp)
                                            )
                                            .clickable { selectedResolution = res }
                                            .padding(vertical = 8.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(res, color = if (isSelected) NeonBlue else Color.LightGray, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }
                        }

                        Spacer(modifier = Modifier.height(12.dp))

                        // Cinematic temporal framerate
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("Cinematic Temporal FPS", color = Color.LightGray, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("24 FPS (Classic Cine)", "30 FPS (Standard)", "60 FPS (Ultra Smooth)", "120 FPS (Action Slo)").forEach { rate ->
                                    val isSelected = selectedFrameRate.contains(rate.take(5))
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .background(
                                                if (isSelected) NeonPurple.copy(0.2f) else Color(0xFF0F0E16),
                                                RoundedCornerShape(6.dp)
                                            )
                                            .border(
                                                0.5.dp,
                                                if (isSelected) NeonPurple else Color.Gray.copy(0.2f),
                                                RoundedCornerShape(6.dp)
                                            )
                                            .clickable { selectedFrameRate = rate }
                                            .padding(vertical = 8.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(rate.replace("Classic ", "").replace("Action ", ""), color = if (isSelected) NeonPurple else Color.LightGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    }
                                }
                            }
                        }

                        Spacer(modifier = Modifier.height(12.dp))

                        // Light bounce Raytracing passes
                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("Light Bounce Path-Tracing Pass", color = Color.LightGray, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                listOf("Raytrace Fast Draft (16x)", "Double Light Bounces (64x)", "Hyper-Physical Volumetric (Ultra)").forEach { pass ->
                                    val isSelected = selectedRenderPass == pass
                                    Box(
                                        modifier = Modifier
                                            .weight(1f)
                                            .background(
                                                if (isSelected) NeonBlue.copy(0.22f) else Color(0xFF0F0E16),
                                                RoundedCornerShape(6.dp)
                                            )
                                            .border(
                                                0.5.dp,
                                                if (isSelected) NeonBlue else Color.Gray.copy(0.2f),
                                                RoundedCornerShape(6.dp)
                                            )
                                            .clickable { selectedRenderPass = pass }
                                            .padding(vertical = 8.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Text(
                                            text = pass.replace(" (16x)", "").replace(" (64x)", "").replace(" Volumetric", ""),
                                            color = if (isSelected) NeonBlue else Color.LightGray,
                                            fontSize = 9.sp,
                                            fontWeight = FontWeight.Bold,
                                            textAlign = TextAlign.Center
                                        )
                                    }
                                }
                            }
                        }

                        Spacer(modifier = Modifier.height(12.dp))

                        // HDR Tone-mapping toggle
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text("BT.2020 High Dynamic Range (HDR)", color = Color.White, fontSize = 11.5.sp, fontWeight = FontWeight.Bold)
                                Text("Perform vivid contrast color grading and deeper color depth", color = Color.Gray, fontSize = 9.5.sp)
                            }
                            Switch(
                                checked = hdrGradingEnabled,
                                onCheckedChange = { hdrGradingEnabled = it },
                                colors = SwitchDefaults.colors(checkedThumbColor = NeonBlue, checkedTrackColor = Color(0xFF15344C))
                            )
                        }

                        Spacer(modifier = Modifier.height(12.dp))

                        // Texture sharpness detail slider
                        Column {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Text("Aesthetic Texture Detail Sharpening", color = Color.LightGray, fontSize = 11.sp)
                                Text("${textureSharpnessSlider.toInt()}%", color = NeonBlue, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = textureSharpnessSlider,
                                onValueChange = { textureSharpnessSlider = it },
                                valueRange = 0f..100f,
                                colors = SliderDefaults.colors(thumbColor = NeonBlue, activeTrackColor = NeonBlue, inactiveTrackColor = Color.DarkGray)
                            )
                        }

                        Spacer(modifier = Modifier.height(6.dp))

                        // Motion smoothness stabilizer slider
                        Column {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Text("Motion Smoothness Stabilizer Ratio", color = Color.LightGray, fontSize = 11.sp)
                                Text("${motionSmoothnessSlider.toInt()}%", color = NeonBlue, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = motionSmoothnessSlider,
                                onValueChange = { motionSmoothnessSlider = it },
                                valueRange = 0f..100f,
                                colors = SliderDefaults.colors(thumbColor = NeonBlue, activeTrackColor = NeonBlue, inactiveTrackColor = Color.DarkGray)
                            )
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // DURATION & CLOCK SPEED CONTROLS
        // -------------------------------------------------------------
        if (processState != "success") {
            Card(
                colors = CardDefaults.cardColors(containerColor = Color(0xFF050510)),
                border = BorderStroke(0.5.dp, Color.DarkGray),
                shape = RoundedCornerShape(12.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.padding(14.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text("HD Pro Video Loop Duration", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                        Text("${durationSeconds}s HQ Timeline", color = NeonBlue, fontSize = 12.sp, fontWeight = FontWeight.Black)
                    }
                    Slider(
                        value = durationSeconds.toFloat(),
                        onValueChange = { durationSeconds = it.toInt() },
                        valueRange = 3f..20f,
                        colors = SliderDefaults.colors(
                            thumbColor = NeonBlue,
                            activeTrackColor = NeonBlue,
                            inactiveTrackColor = Color.DarkGray
                        )
                    )
                }
            }
        }

        // -------------------------------------------------------------
        // CORE LAUNCH BUTTON TRIPPED
        // -------------------------------------------------------------
        if (processState != "generating") {
            Button(
                onClick = {
                    processState = "generating"
                    processProgress = 0f
                    val engineNameRef = selectedVideoEngine.split(" ").first()
                    activeProgressStep = "Allocating secure $engineNameRef high-fidelity server farm render cores..."

                    coroutineScope.launch {
                        val renderProgressPeriod = 4200L
                        val partitionsCount = 100
                        val spacingMs = renderProgressPeriod / partitionsCount

                        for (i in 0..partitionsCount) {
                            processProgress = i / 100f
                            activeProgressStep = when {
                                i < 15 -> "Parsing semantic prompt tokens for $engineNameRef: \"${if (videoPrompt.length > 30) videoPrompt.take(28) + "..." else videoPrompt}\"..."
                                i < 35 -> "Generating premium $engineNameRef motion keyframes with physical consistency at $selectedResolution..."
                                i < 55 -> "Applying $selectedRenderPass spatial path raytracing passes..."
                                i < 75 -> "Interpolating smooth cinematic temporal loops with $engineNameRef..."
                                i < 90 -> "Performing high dynamic tone mapping corrections..."
                                else -> "Optimizing $engineNameRef streaming container alignment..."
                            }
                            delay(spacingMs)
                        }

                        // Save creation data dynamically to local Room persistence
                        viewModel.recordTextToVideoCreation(
                            prompt = "[$selectedVideoEngine] $videoPrompt",
                            style = selectedStyle,
                            aspectRatio = selectedAspectRatio,
                            resolution = selectedResolution,
                            frameRate = selectedFrameRate,
                            renderPass = selectedRenderPass,
                            duration = durationSeconds,
                            hdExport = hdrGradingEnabled,
                            videoPlaceholderUrl = activePreviewUrl
                        )

                        Toast.makeText(context, "Premium AI Text to Video Render Complete!", Toast.LENGTH_SHORT).show()
                        playbackProgress = 0.0f
                        isPlaying = true
                        processState = "success"
                    }
                },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(50.dp)
                    .background(
                        Brush.linearGradient(listOf(NeonBlue, NeonPurple)),
                        RoundedCornerShape(12.dp)
                    )
                    .testTag("text_to_video_generate_button"),
                colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent),
                shape = RoundedCornerShape(12.dp)
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(imageVector = Icons.Filled.MovieCreation, contentDescription = "Veo 3 launch icon", tint = PureBlack)
                    Text(
                        text = if (processState == "success") "Re-Generate Professional HQ Clip" else "Create Veo 3 High-Quality Video",
                        color = PureBlack,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Black
                    )
                }
            }
        }

        // Reset workspace option
        if (processState == "success") {
            OutlinedButton(
                onClick = {
                    processState = "idle"
                    isPlaying = false
                },
                modifier = Modifier.fillMaxWidth().testTag("text_to_video_reset_button"),
                border = BorderStroke(1.dp, Color.Gray.copy(0.3f)),
                shape = RoundedCornerShape(12.dp)
            ) {
                Text("Modify Parameters / Start New Project", color = Color.LightGray, fontSize = 11.5.sp)
            }
        }

        // -------------------------------------------------------------
        // PREVIOUS HISTORICAL WORK LIST IN WORKSPACE
        // -------------------------------------------------------------
        if (videoHistory.isNotEmpty()) {
            Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(imageVector = Icons.Filled.History, contentDescription = "History indicator", tint = NeonBlue, modifier = Modifier.size(15.dp))
                    Text(
                        text = "Your Recent Veo 3 Ultra HQ Clips",
                        color = Color.White,
                        fontSize = 13.sp,
                        fontWeight = FontWeight.Black
                    )
                }

                LazyRow(
                    horizontalArrangement = Arrangement.spacedBy(12.dp),
                    modifier = Modifier.fillMaxWidth().testTag("text_to_video_render_history_row")
                ) {
                    items(videoHistory) { item ->
                        val parsedUri = remember {
                            val pattern = "Simulated AI Video Playback Stream Key: (.*)".toRegex()
                            pattern.find(item.outputText)?.groups?.get(1)?.value ?: "https://images.unsplash.com/photo-1509198397868-475647b2a1e5?q=80&w=600"
                        }
                        
                        Card(
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF0A0914)),
                            border = BorderStroke(0.5.dp, Color.DarkGray),
                            shape = RoundedCornerShape(12.dp),
                            modifier = Modifier
                                .width(130.dp)
                                .clickable {
                                    videoPrompt = item.inputPrompt.substringAfter("Prompt: ").substringBefore(" | Style")
                                    val matchStyle = item.inputPrompt.substringAfter("Style: ").substringBefore(" | Resolution")
                                    selectedStyle = if (matchStyle.isNotEmpty()) matchStyle else selectedStyle
                                    val matchRes = item.inputPrompt.substringAfter("Resolution: ").substringBefore(" | FPS")
                                    selectedResolution = if (matchRes.isNotEmpty()) matchRes else selectedResolution
                                    playbackProgress = 0f
                                    isPlaying = true
                                    processState = "success"
                                }
                        ) {
                            Column {
                                Box(modifier = Modifier.fillMaxWidth().height(80.dp)) {
                                    AsyncImage(
                                        model = parsedUri,
                                        contentDescription = "Historical clip render",
                                        contentScale = ContentScale.Crop,
                                        modifier = Modifier.fillMaxSize()
                                    )
                                    Box(
                                        modifier = Modifier
                                            .align(Alignment.Center)
                                            .size(24.dp)
                                            .background(Color.Black.copy(0.6f), CircleShape),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Icon(imageVector = Icons.Filled.PlayArrow, contentDescription = "Play", tint = Color.White, modifier = Modifier.size(12.dp))
                                    }
                                }
                                Text(
                                    text = "AI_Veo 3_${item.id}.mp4",
                                    color = Color.White,
                                    fontSize = 9.5.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.padding(start = 6.dp, end = 6.dp, top = 4.dp),
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis
                                )
                                Text(
                                    text = item.inputPrompt.substringBefore(" | Style"),
                                    color = Color.Gray,
                                    fontSize = 8.sp,
                                    modifier = Modifier.padding(start = 6.dp, end = 6.dp, bottom = 6.dp),
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis
                                )
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(35.dp))
    }
}

// =====================================================================
// AI VIDEO EDITOR WORKSPACE MODULE (CLIP AI PREMIUM TOOL)
// =====================================================================

data class VideoClip(
    val id: String,
    val name: String,
    val durationSeconds: Float,
    val format: String,
    val resolution: String,
    val description: String,
    val startTrim: Float = 0f,
    val endTrim: Float = durationSeconds,
    val filterSpec: String = "Normal",
    val transitionSpec: String = "None",
    val speedScale: Float = 1.0f
) {
    val activeDuration: Float
        get() = (endTrim - startTrim) / speedScale
}

data class SubtitleSegment(
    val id: String,
    val text: String,
    val startMs: Long,
    val endMs: Long
)

data class SampleClipTemplate(
    val name: String,
    val durationSeconds: Float,
    val format: String,
    val resolution: String,
    val description: String,
    val thumbnailGradient: List<Color>
)

/*
@Composable
fun AIVideoEditorWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val history by viewModel.history.collectAsState()
    val userStats by viewModel.userStats.collectAsState()

    // CLIP TEMPLATES LIST FOR IMPORTING
    val clipTemplates = remember {
        listOf(
            SampleClipTemplate("Vlog Travel Swiss.mp4", 15.0f, "MP4", "1080p", "Scenic Swiss Alps panoramic horizon scanning shot.", listOf(Color(0xFF0F2027), Color(0xFF203A43), Color(0xFF2C5364))),
            SampleClipTemplate("Drone Tokyo Skyline.mov", 8.0f, "MOV", "4K", "Tokyo nighttime urban skyline with hyper-neon lights.", listOf(Color(0xFFFF007F), Color(0xFF330033), Color(0xFF003366))),
            SampleClipTemplate("Interview Tech Host.mkv", 20.0f, "MKV", "1080p", "A close-up portrait of the main speaker talking in studio.", listOf(Color(0xFF141E30), Color(0xFF243B55))),
            SampleClipTemplate("Vertical Street Dancer.3gp", 9.0f, "3GP", "720p", "High-tempo freestyle dance choreography under transit bridge.", listOf(Color(0xFF11998e), Color(0xFF38ef7d))),
            SampleClipTemplate("Tech Review Keyboard.avi", 12.0f, "AVI", "1080p", "Macro detailed glide shot focused on smart RGB mechanical switches.", listOf(Color(0xFFE100FF), Color(0xFF7F00FF))),
            SampleClipTemplate("Retro Cinema Walk.webm", 10.0f, "WEBM", "4K", "Atmospheric monochrome pedestrian walk through heavy rainy street.", listOf(Color(0xFF3E5151), Color(0xFFDECBA4)))
        )
    }

    // STATE VARIABLES
    var clips by remember {
        mutableStateOf(
            listOf(
                VideoClip("1", "Vlog Travel Swiss.mp4", 15.0f, "MP4", "1080p", "Scenic Swiss", 0f, 15.0f),
                VideoClip("2", "Drone Tokyo Skyline.mov", 8.0f, "MOV", "4K", "Tokyo skyline", 0f, 8.0f)
            )
        )
    }
    
    // SELECTED ACTIONS HISTORIES (UNDO/REDO STATE ENGINES)
    var undoStack by remember { mutableStateOf(listOf<List<VideoClip>>()) }
    var redoStack by remember { mutableStateOf(listOf<List<VideoClip>>()) }

    fun recordHistory(newClips: List<VideoClip>) {
        undoStack = undoStack + listOf(clips)
        redoStack = emptyList()
        clips = newClips
    }

    fun handleUndo() {
        if (undoStack.isNotEmpty()) {
            val lastState = undoStack.last()
            undoStack = undoStack.dropLast(1)
            redoStack = redoStack + listOf(clips)
            clips = lastState
            Toast.makeText(context, "Undo applied", Toast.LENGTH_SHORT).show()
        } else {
            Toast.makeText(context, "Nothing to undo", Toast.LENGTH_SHORT).show()
        }
    }

    fun handleRedo() {
        if (redoStack.isNotEmpty()) {
            val lastState = redoStack.last()
            redoStack = redoStack.dropLast(1)
            undoStack = undoStack + listOf(clips)
            clips = lastState
            Toast.makeText(context, "Redo applied", Toast.LENGTH_SHORT).show()
        } else {
            Toast.makeText(context, "Nothing to redo", Toast.LENGTH_SHORT).show()
        }
    }

    // TRACKING TIMELINE STATES
    var activeClipId by remember { mutableStateOf<String?>("1") }
    val activeClip = remember(clips, activeClipId) { clips.find { it.id == activeClipId } }
    
    val totalDurationSeconds = remember(clips) { clips.sumOf { it.activeDuration.toDouble() }.toFloat() }
    var playbackProgress by remember { mutableStateOf(0.0f) } // 0f to totalDurationSeconds
    var isPlaying by remember { mutableStateOf(false) }

    // PLAYER REFRSH EFFECT
    LaunchedEffect(isPlaying, totalDurationSeconds) {
        if (isPlaying) {
            while (isPlaying) {
                delay(100)
                playbackProgress += 0.1f
                if (playbackProgress >= totalDurationSeconds) {
                    playbackProgress = 0.0f
                    isPlaying = false
                }
            }
        }
    }

    // MAP CURRENT LAYOUT ASPECT RATIOS
    var selectedAspect by remember { mutableStateOf("16:9") } // "16:9" (Landscape), "9:16" (Reels/Shorts), "1:1" (Square)

