                SubtitleSegment("s1", "Hey guys! Welcome to Clip AI's advanced editor.", 100L, 3000L),
                SubtitleSegment("s2", "Today we are cinematic grading Swiss landscapes.", 3200L, 6500L),
                SubtitleSegment("s3", "And flying drone cameras over Tokyo's fluorescent skyline!", 7000L, 11000L),
                SubtitleSegment("s4", "Look at those incredible radiant neon colors shimmer!", 11200L, 15000L)
            )
        )
