    var subtitleStyleFont by remember { mutableStateOf("Space Grotesk") } // Space Grotesk, Mono, System, Elegant Sans
    var subtitleStyleAnimation by remember { mutableStateOf("Bounce Zoom") } // Bounce Zoom, Kinetic Scroll, Smooth Fade

