    var aiFaceFocusEnabled by remember { mutableStateOf(false) } // auto camera speaker centering bounding box
    var aiObjectTrackingEnabled by remember { mutableStateOf(false) } // object finder markers
    var beatSyncEnabled by remember { mutableStateOf(false) }

    // WORKSPACE BOTTOM INTERACTIVE TAB
    var activeWorkspaceTab by remember { mutableStateOf("Clips") } // "Clips", "Style FX", "Speech AI", "Audio AI", "Video AI", "Beat & Sound", "Compile"

    // CINEMATIC GRADING/FILTERS SELECTIONS
    var selectedFilterStyle by remember { mutableStateOf("Normal") } // Normal, Cyber Glitch, Vintage Film, Radiant Soft Glow, High Contrast HDR
    var selectedTransitionType by remember { mutableStateOf("None") } // None, Cross Fade, Zoom Blur, Slide, Flash

    // VOLUME MIXERS
    var videoMasterVolume by remember { mutableStateOf(0.8f) }
    var importedMusicVolume by remember { mutableStateOf(0.4f) }
    var selectedMusicTheme by remember { mutableStateOf("Lofi Sunset Groove") } // Lofi, Electronic, Vlog Beats, None

    // EXPORT COMPILATION STATE
    var isExporting by remember { mutableStateOf(false) }
    var exportProgress by remember { mutableStateOf(0.0f) }
    var activeExportLog by remember { mutableStateOf("Idle") }
    val exportTerminalOutput = remember { mutableStateListOf<String>() }
    var selectedExportResolution by remember { mutableStateOf("1080p") } // 480p, 720p, 1080p, 4K
    var selectedExportFps by remember { mutableStateOf(30) } // 24, 30, 60

    // COMPUTED TEXT VALUE FOR SUBTITLE CORRELETION DURING ACTIVE PLAYBACK
    val activeSubtitleText = remember(playbackProgress, subtitlesList) {
