            else -> 170.dp
        }
        val canvasWidthMultiplier = when (selectedAspect) {
            "9:16" -> 0.56f
            "1:1" -> 0.8f
            else -> 1f
        }

        Box(
            modifier = Modifier
                .fillMaxWidth()
                .height(canvasHeight)
                .background(Color.Black, RoundedCornerShape(12.dp))
                .border(0.5.dp, Color.DarkGray.copy(0.5f), RoundedCornerShape(12.dp)),
            contentAlignment = Alignment.Center
        ) {
            // Simulated Video stream output canvas based on active settings
            Box(
                modifier = Modifier
                    .fillMaxHeight()
                    .fillMaxWidth(canvasWidthMultiplier)
                    .clip(RoundedCornerShape(10.dp))
                    .drawBehind {
                        // Drawing professional dynamic gradient backdrops representing filtered stream renders
                        val baseColor = when (selectedFilterStyle) {
                            "Cyber Glitch" -> Color(0xFF1D003E)
                            "Vintage Film" -> Color(0xFF4C3018)
                            "Radiant Soft Glow" -> Color(0xFF144D58)
                            "High Contrast HDR" -> Color(0xFF0C2B1C)
                            else -> Color(0xFF111122)
                        }
                        val accentColor = when (selectedFilterStyle) {
                            "Cyber Glitch" -> Color(0xFFFF007F)
                            "Vintage Film" -> Color(0xFFBA8C63)
                            "Radiant Soft Glow" -> Color(0xFF00FFCC)
                            "High Contrast HDR" -> Color(0xFF39FF14)
                            else -> Color(0xFF4361EE)
                        }

                        // Background removal simulation colors
                        val fillBrush = when (aiBackgroundRemovalMode) {
                            "Solid Cyan" -> Brush.verticalGradient(
                                listOf(
                                    Color(0xFF0099FF),
                                    Color(0xFF00F2FE)
                                )
                            )
                            "Chroma Green" -> Brush.verticalGradient(
                                listOf(
                                    Color(0xFF00FF00),
                                    Color(0xBB00FF00)
                                )
                            )
                            "Studio Gray" -> Brush.linearGradient(
                                listOf(
                                    Color(0xFF232526),
                                    Color(0xFF414345)
                                )
                            )
                            "Bokeh Blur" -> Brush.radialGradient(
                                listOf(
                                    accentColor,
                                    baseColor
                                )
                            )
                            else -> Brush.radialGradient(listOf(accentColor, baseColor))
                        }
                        drawRect(fillBrush)
                    }
            ) {
                // REALTIME ACTIVE CLIP OVERLAYS INFOGRAPHIC
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(10.dp),
                    verticalArrangement = Arrangement.SpaceBetween
                ) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        // Media Info Header overlay
                        Text(
                            text = if (activeClip != null) "${activeClip.name} [${activeClip.resolution}]" else "No Source Clip",
                            fontSize = 8.sp,
                            fontWeight = FontWeight.Bold,
                            color = Color.White.copy(0.6f),
                            maxLines = 1
                        )

                        // Render metrics overlay badge
                        Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                            if (selectedFilterStyle != "Normal") {
                                Box(
                                    modifier = Modifier
                                        .background(NeonPurple.copy(0.3f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 4.dp, vertical = 2.dp)
                                ) {
                                    Text(
                                        text = selectedFilterStyle,
                                        color = NeonPurple,
                                        fontSize = 6.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                            if (aiBackgroundRemovalMode != "None") {
                                Box(
                                    modifier = Modifier
                                        .background(NeonCyan.copy(0.3f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 4.dp, vertical = 2.dp)
                                ) {
                                    Text(
                                        text = "BG: $aiBackgroundRemovalMode",
                                        color = NeonCyan,
                                        fontSize = 6.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }
                        }
                    }

                    // MAIN AUDIO SPECTRUM & SUBJECT ANIMATION PREVIEW MIDDLE CANVAS
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(1f),
                        contentAlignment = Alignment.Center
                    ) {
                        // Drawing actual simulated components (such as human faces, outlines, bounding boxes)
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            Icon(
                                imageVector = if (selectedAspect == "9:16") Icons.Filled.Face else Icons.Filled.VideoCameraBack,
                                contentDescription = "Active subject icon",
                                tint = Color.White.copy(0.12f),
                                modifier = Modifier.size(45.dp)
                            )
                            Spacer(modifier = Modifier.height(6.dp))
                            
                            // Live equalizers waves if playing
                            Row(
                                horizontalArrangement = Arrangement.spacedBy(2.dp),
                                modifier = Modifier.height(10.dp)
                            ) {
                                repeat(8) { index ->
                                    val waveHeight = remember(playbackProgress, isPlaying) {
                                        if (isPlaying) (4..10).random() else 3
                                    }
                                    Box(
                                        modifier = Modifier
                                            .width(2.dp)
                                            .height(waveHeight.dp)
                                            .background(
                                                if (index % 2 == 0) NeonCyan else NeonPurple,
                                                RoundedCornerShape(1.dp)
                                            )
                                    )
                                }
                            }
                        }

                        // INTUITIVE SPEECH IDENTIFICATION BOUNDING BOX
                        if (aiFaceFocusEnabled) {
                            Box(
                                modifier = Modifier
                                    .size(85.dp)
                                    .border(1.dp, Color.Green.copy(0.8f), RoundedCornerShape(4.dp))
                            ) {
                                Text(
                                    text = "AI SPEAKER FOCUS: 98%",
                                    color = Color.Green,
                                    fontSize = 5.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier
                                        .background(Color.Black.copy(0.6f))
                                        .padding(horizontal = 2.dp, vertical = 1.dp)
                                        .align(Alignment.TopStart)
                                )
                                // Bounding target corner widgets
                                Box(modifier = Modifier.size(5.dp).background(Color.Green).align(Alignment.TopStart))
                                Box(modifier = Modifier.size(5.dp).background(Color.Green).align(Alignment.TopEnd))
                                Box(modifier = Modifier.size(5.dp).background(Color.Green).align(Alignment.BottomStart))
                                Box(modifier = Modifier.size(5.dp).background(Color.Green).align(Alignment.BottomEnd))
                            }
                        }

                        // ADAPTIVE OBJECT FOCUS CLUSTEREED BOXES
                        if (aiObjectTrackingEnabled) {
                            Box(
                                modifier = Modifier
                                    .size(110.dp)
                                    .align(Alignment.BottomCenter)
                                    .border(0.5.dp, NeonCyan.copy(0.7f), RoundedCornerShape(2.dp))
                            ) {
                                Text(
                                    text = "DETECTOR: [Vlog Environment] 87%",
                                    color = NeonCyan,
                                    fontSize = 5.sp,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier
                                        .background(Color.Black.copy(0.6f))
                                        .padding(horizontal = 2.dp, vertical = 1.dp)
                                        .align(Alignment.BottomStart)
                                )
                            }
                        }
                    }

                    // INTEGRATED FLOATING CAPTION DIALOG OVERLAY
                    if (subtitlesEnabled && activeSubtitleText.isNotEmpty()) {
                        val typographyWeight = if (subtitleStyleFont == "Space Grotesk") FontWeight.Bold else FontWeight.Normal
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(bottom = 6.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Box(
                                modifier = Modifier
                                    .background(Color.Black.copy(0.7f), RoundedCornerShape(4.dp))
                                    .padding(horizontal = 6.dp, vertical = 3.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                Text(
                                    text = activeSubtitleText,
                                    color = subtitleStyleColor,
                                    fontSize = subtitleStyleSize.sp,
                                    fontWeight = typographyWeight,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }
                    }
                }
            }
        }

        // --- 3. PREMIUM MINI METRIC BAR & PLAYER CONTROLLERS ---
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(vertical = 4.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Time codes (Current / Max duration)
            Text(
                text = String.format(java.util.Locale.US, "%02d:%04.1f s / %02d:%02d s", 0, playbackProgress, 0, totalDurationSeconds.toInt()),
                fontSize = 10.sp,
                color = Color.LightGray,
                fontWeight = FontWeight.Bold
            )

            // Primary control keys
            Row(
                horizontalArrangement = Arrangement.spacedBy(10.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                IconButton(
                    onClick = { handleUndo() },
                    modifier = Modifier.size(32.dp)
                ) {
                    Icon(
                        imageVector = Icons.Filled.Undo,
                        contentDescription = "Undo timeline modification",
                        tint = if (undoStack.isNotEmpty()) Color.White else Color.DarkGray,
                        modifier = Modifier.size(16.dp)
                    )
                }

                IconButton(
                    onClick = { handleRedo() },
                    modifier = Modifier.size(32.dp)
                ) {
                    Icon(
                        imageVector = Icons.Filled.Redo,
                        contentDescription = "Redo timeline modification",
                        tint = if (redoStack.isNotEmpty()) Color.White else Color.DarkGray,
                        modifier = Modifier.size(16.dp)
                    )
                }

                // Aspect Selection Picker Trigger
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(6.dp))
                        .background(Color.White.copy(0.06f))
                        .clickable {
                            selectedAspect = when (selectedAspect) {
                                "16:9" -> "9:16"
                                "9:16" -> "1:1"
                                else -> "16:9"
                            }
                            Toast
                                .makeText(context, "Aspect Ratio: $selectedAspect", Toast.LENGTH_SHORT)
                                .show()
                        }
                        .padding(horizontal = 8.dp, vertical = 4.dp)
                ) {
                    Text(
                        text = "Aspect $selectedAspect",
                        fontSize = 9.sp,
                        color = Color.White,
                        fontWeight = FontWeight.Bold
                    )
                }

                IconButton(
                    onClick = { isPlaying = !isPlaying },
                    modifier = Modifier
                        .size(34.dp)
                        .background(
                            Brush.linearGradient(listOf(NeonCyan, NeonPurple)),
                            CircleShape
                        )
                ) {
                    Icon(
                        imageVector = if (isPlaying) Icons.Filled.Pause else Icons.Filled.PlayArrow,
                        contentDescription = "Play timeline",
                        tint = PureBlack,
                        modifier = Modifier.size(18.dp)
                    )
                }
            }
        }

        // --- 4. HIGH-FIDELITY DYNAMIC TIMELINE AUDIO-COORDINATING SEEK BAR ---
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .padding(bottom = 6.dp)
        ) {
            // Drawing seekbar slider
            Slider(
                value = playbackProgress,
                onValueChange = {
                    playbackProgress = it
                },
                valueRange = 0f..totalDurationSeconds.coerceAtLeast(1f),
                colors = SliderDefaults.colors(
                    activeTrackColor = NeonPurple,
                    inactiveTrackColor = Color.DarkGray,
                    thumbColor = NeonCyan
                )
            )
        }

        // --- 5. INTERACTIVE TIMELINE STACK TRACKS ---
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color(0xFF0F0F1A), RoundedCornerShape(10.dp))
                .border(0.5.dp, Color.DarkGray.copy(0.4f), RoundedCornerShape(10.dp))
                .padding(6.dp)
        ) {
            Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                // TRACK 1: MULTI-VIDEO CLIPS TIMELINE ROW
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Box(
                        modifier = Modifier
                            .width(55.dp)
                            .padding(end = 4.dp)
                    ) {
                        Text("🎬 Clips", fontSize = 8.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                    }

                    // Scrollable Horizontal Segment of Clips Card Structures
                    Row(
                        modifier = Modifier
                            .weight(1f)
                            .horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        clips.forEachIndexed { index, clip ->
                            val isActive = clip.id == activeClipId
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(
                                        if (isActive) Color(0xFF2C1642) else Color(0xFF161623)
                                    )
                                    .border(
                                        1.dp,
                                        if (isActive) NeonPurple else Color.DarkGray.copy(0.6f),
                                        RoundedCornerShape(8.dp)
                                    )
                                    .clickable { activeClipId = clip.id }
                                    .padding(6.dp)
                            ) {
                                Column(modifier = Modifier.width(100.dp)) {
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Text(
                                            text = clip.name,
                                            fontSize = 8.sp,
                                            fontWeight = FontWeight.Bold,
                                            color = Color.White,
                                            maxLines = 1,
                                            overflow = TextOverflow.Ellipsis,
                                            modifier = Modifier.weight(1f)
                                        )
                                        
                                        // Delete clip trigger
                                        IconButton(
                                            onClick = {
                                                val nextClips = clips.filter { it.id != clip.id }
                                                recordHistory(nextClips)
                                                if (activeClipId == clip.id) {
                                                    activeClipId = nextClips.firstOrNull()?.id
                                                }
                                                Toast.makeText(context, "Deleted clip", Toast.LENGTH_SHORT).show()
                                            },
                                            modifier = Modifier.size(14.dp)
                                        ) {
                                            Icon(
                                                imageVector = Icons.Filled.Delete,
                                                contentDescription = "Remove clip from compilation",
                                                tint = Color.Red.copy(alpha = 0.8f),
                                                modifier = Modifier.size(10.dp)
                                            )
                                        }
                                    }

                                    Spacer(modifier = Modifier.height(2.dp))
                                    
                                    // Visual representation of trimmed status
                                    Text(
                                        text = "${clip.startTrim.toInt()}s ➜ ${clip.endTrim.toInt()}s (${clip.activeDuration.toInt()}s)",
                                        fontSize = 7.sp,
                                        color = NeonCyan,
                                        fontWeight = FontWeight.Bold
                                    )

                                    // Move Order buttons
                                    Row(
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        modifier = Modifier.fillMaxWidth()
                                    ) {
                                        Text(
                                            text = "[${clip.format}]",
                                            fontSize = 7.sp,
                                            color = Color.Gray
                                        )
                                        Row(horizontalArrangement = Arrangement.spacedBy(2.dp)) {
                                            if (index > 0) {
                                                Box(
                                                    modifier = Modifier
                                                        .size(10.dp)
                                                        .background(Color.White.copy(0.1f), CircleShape)
                                                        .clickable {
                                                            val reordered = clips.toMutableList()
                                                            val temp = reordered[index]
                                                            reordered[index] = reordered[index - 1]
                                                            reordered[index - 1] = temp
                                                            recordHistory(reordered)
                                                        }
                                                ) {
                                                    Text("◀", fontSize = 5.sp, color = Color.White, modifier = Modifier.align(Alignment.Center))
                                                }
                                            }
                                            if (index < clips.size - 1) {
                                                Box(
                                                    modifier = Modifier
                                                        .size(10.dp)
                                                        .background(Color.White.copy(0.1f), CircleShape)
                                                        .clickable {
                                                            val reordered = clips.toMutableList()
                                                            val temp = reordered[index]
                                                            reordered[index] = reordered[index + 1]
                                                            reordered[index + 1] = temp
                                                            recordHistory(reordered)
                                                        }
                                                ) {
                                                    Text("▶", fontSize = 5.sp, color = Color.White, modifier = Modifier.align(Alignment.Center))
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        // Add Media Button Trigger
                        IconButton(
                            onClick = { showImportDialog = true },
                            modifier = Modifier
                                .size(34.dp)
                                .background(Color.White.copy(0.1f), CircleShape)
                        ) {
                            Icon(
                                imageVector = Icons.Filled.Add,
                                contentDescription = "Import external clips",
                                tint = NeonCyan,
                                modifier = Modifier.size(18.dp)
                            )
                        }
                    }
                }

                // TRACK 2: HIGHLIGHTED CAPTIONS TIMELINE WIDGETS
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Box(
                        modifier = Modifier
                            .width(55.dp)
                            .padding(end = 4.dp)
                    ) {
                        Text("💬 Subs", fontSize = 8.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                    }

                    if (subtitlesEnabled) {
                        Row(
                            modifier = Modifier
                                .weight(1f)
                                .horizontalScroll(rememberScrollState()),
                            horizontalArrangement = Arrangement.spacedBy(4.dp)
                        ) {
                            subtitlesList.forEach { sub ->
                                Box(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(4.dp))
                                        .background(Color(0xFF231C0F))
                                        .border(0.5.dp, Color(0xFFBA8C63).copy(0.5f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 6.dp, vertical = 4.dp)
                                ) {
                                    Column {
                                        Text(
                                            text = sub.text,
                                            fontSize = 7.sp,
                                            fontWeight = FontWeight.Bold,
                                            color = Color.LightGray,
                                            maxLines = 1,
                                            modifier = Modifier.widthIn(max = 140.dp),
                                            overflow = TextOverflow.Ellipsis
                                        )
                                        Text(
                                            text = "${sub.startMs / 1000}s - ${sub.endMs / 1000}s",
                                            fontSize = 6.sp,
                                            color = Color(0xFFBA8C63)
                                        )
                                    }
                                }
                            }
                        }
                    } else {
                        Text(
                            text = "Speech Subtitles disabled. Tap 'Speech AI' tab below to activate dynamic caption tracking.",
                            fontSize = 7.sp,
                            color = Color.DarkGray,
                            fontStyle = androidx.compose.ui.text.font.FontStyle.Italic
                        )
                    }
                }

                // TRACK 3: MUSIC SOUNDTRACK TIMELINE SYNC WIDGET
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Box(
                        modifier = Modifier
                            .width(55.dp)
                            .padding(end = 4.dp)
                    ) {
                        Text("🎵 Audio", fontSize = 8.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                    }

                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(6.dp))
                            .background(
                                if (selectedMusicTheme == "None") Color.Transparent else Color(0xFF0F1A24)
                            )
                            .border(
                                0.5.dp,
                                if (selectedMusicTheme == "None") Color.DarkGray else Color(0xFF00B4DB).copy(0.5f),
                                RoundedCornerShape(6.dp)
                            )
                            .padding(horizontal = 8.dp, vertical = 4.dp)
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text(
                                text = if (selectedMusicTheme == "None") "🔇 Silent Soundtrack (Mix raw system audio)" else "🔊 Track: $selectedMusicTheme.mp3",
                                fontSize = 8.sp,
                                color = if (selectedMusicTheme == "None") Color.Gray else Color(0xFF00B4DB),
                                fontWeight = FontWeight.Bold
                            )
                            if (beatSyncEnabled && selectedMusicTheme != "None") {
                                Box(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(4.dp))
                                        .background(NeonCyan.copy(0.2f))
                                        .padding(horizontal = 4.dp, vertical = 2.dp)
                                ) {
                                    Text(
                                        text = "AI BEAT SYNCED ✅",
                                        fontSize = 6.sp,
                                        fontWeight = FontWeight.Bold,
                                        color = NeonCyan
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // --- 6. FLOATING QUICK EDIT TRIGGER ACTIONS BUTTON BAR ---
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(vertical = 4.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Trim selection
            Button(
                onClick = {
                    if (activeClip != null) {
                        val duration = activeClip.durationSeconds
                        // Trigger a demo crop from 10% to 90%
                        val start = duration * 0.1f
                        val end = duration * 0.9f
                        val updated = clips.map {
                            if (it.id == activeClip.id) it.copy(startTrim = start, endTrim = end) else it
                        }
                        recordHistory(updated)
                        Toast.makeText(context, "Trimmed selected clip", Toast.LENGTH_SHORT).show()
                    } else {
                        Toast.makeText(context, "Select a clip first", Toast.LENGTH_SHORT).show()
                    }
                },
                contentPadding = PaddingValues(horizontal = 8.dp, vertical = 4.dp),
                colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.05f)),
                border = BorderStroke(0.5.dp, Color.Gray),
                modifier = Modifier
                    .weight(1f)
                    .padding(end = 4.dp)
            ) {
                Text("✂️ Trim Active", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
            }

            // Split Selection
            Button(
                onClick = {
                    if (activeClip != null) {
                        val duration = activeClip.activeDuration
                        if (duration > 2f) {
                            // Split mid-point mathematically
                            val midPoint = activeClip.startTrim + (duration / 2f)
                            val leftClip = activeClip.copy(id = activeClip.id + "_L", name = activeClip.name + "_Part1", endTrim = midPoint)
                            val rightClip = activeClip.copy(id = activeClip.id + "_R", name = activeClip.name + "_Part2", startTrim = midPoint)
                            
                            val idx = clips.indexOfFirst { it.id == activeClip.id }
                            if (idx != -1) {
                                val list = clips.toMutableList()
                                list.removeAt(idx)
                                list.add(idx, rightClip)
                                list.add(idx, leftClip)
                                recordHistory(list)
                                activeClipId = leftClip.id
                                Toast.makeText(context, "Split clip in half successfully!", Toast.LENGTH_SHORT).show()
                            }
                        } else {
                            Toast.makeText(context, "Clip is too short to split!", Toast.LENGTH_SHORT).show()
                        }
                    } else {
                        Toast.makeText(context, "Select a clip first", Toast.LENGTH_SHORT).show()
                    }
                },
                contentPadding = PaddingValues(horizontal = 8.dp, vertical = 4.dp),
                colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.05f)),
                border = BorderStroke(0.5.dp, Color.Gray),
                modifier = Modifier
                    .weight(1f)
                    .padding(horizontal = 2.dp)
            ) {
                Text("🥞 Split Split", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
            }

            // Duplicate clip
            Button(
                onClick = {
                    if (activeClip != null) {
                        val clone = activeClip.copy(id = (10..999).random().toString(), name = activeClip.name + " _Copy")
                        val idx = clips.indexOfFirst { it.id == activeClip.id }
                        if (idx != -1) {
                            val list = clips.toMutableList()
                            list.add(idx + 1, clone)
                            recordHistory(list)
                            Toast.makeText(context, "Cloned selected clip!", Toast.LENGTH_SHORT).show()
                        }
                    } else {
                        Toast.makeText(context, "Select a clip first", Toast.LENGTH_SHORT).show()
                    }
                },
                contentPadding = PaddingValues(horizontal = 8.dp, vertical = 4.dp),
                colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.05f)),
                border = BorderStroke(0.5.dp, Color.Gray),
                modifier = Modifier
                    .weight(1f)
                    .padding(horizontal = 2.dp)
            ) {
                Text("👥 Clone clip", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
            }

            // Quick Auto Highlight cuts analyzer
            Button(
                onClick = {
                    coroutineScope.launch {
                        Toast.makeText(context, "AI Analyzer searching high-motion frames...", Toast.LENGTH_SHORT).show()
                        delay(1200)
                        val highActionClips = clips.map {
                            val peakStart = it.startTrim + (it.activeDuration * 0.2f)
                            val peakEnd = peakStart + (it.activeDuration * 0.4f).coerceAtMost(5f)
