                                    coroutineScope.launch {
                                        isExporting = true
                                        exportProgress = 0f
                                        exportTerminalOutput.clear()
                                        exportTerminalOutput.add("[GPU_INITIALIZE]: Loading Vulkan hardware rendering engine kernels...")
                                        
                                        val renderSteps = listOf(
                                            5 to "[PARSER]: Reading timeline clips structural nodes: ${clips.size} segments parsed",
                                            15 to "[TRANSCODER]: Scaling active input sequences to aspect mode ratio: $selectedAspect",
                                            25 to "[SHADERS]: Synthesizing filters and cinematic layers style shaders: $selectedFilterStyle",
                                            45 to "[AUDIO_MUX]: Normalizing sound vocal signals (Noise Reduction: $aiNoiseReductionEnabled / Vocals: $aiVoiceEnhanceEnabled)",
