                                            100 to "[DISK_WRITE]: Recording completed video assembly to local files, packaging outputs..."
                                        )

                                        for (step in 1..100) {
                                            exportProgress = step / 100f
                                            val logToPush = renderSteps.find { it.first == step }
                                            if (logToPush != null) {
                                                exportTerminalOutput.add(logToPush.second)
                                            }
                                            if (step % 12 == 0) {
                                                exportTerminalOutput.add("[SYSTEM]: Compositing frames stack... ${step}% completed")
                                            }
                                            delay(70) // Fast high speed renders
                                        }

