                                            val segmentDurationMs = (totalDurationSeconds * 1000 / generatedLines.size).toLong()
                                            val parsedList = generatedLines.mapIndexed { idx, lineText ->
                                                val cleanedText = lineText.replace(Regex("^\\d+s?:?\\s*\\-?\\s*"), "").trim()
                                                SubtitleSegment(
