@Composable
fun AIVideoEditorWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val history by viewModel.history.collectAsState()
    val userStats by viewModel.userStats.collectAsState()

    val clipTemplates = remember {
        listOf(
            SampleClipTemplate("Vlog Swiss Alps.mp4", 15.0f, "MP4", "1080p", "Scenic Alps horizon.", listOf(Color(0xFF0F2027), Color(0xFF2C5364))),
            SampleClipTemplate("Tokyo Nightlights.mov", 8.0f, "MOV", "4K", "Tokyo urban neon skies.", listOf(Color(0xFFFF007F), Color(0xFF003366))),
            SampleClipTemplate("CEO Interview.mkv", 20.0f, "MKV", "1080p", "Speaker close-up.", listOf(Color(0xFF141E30), Color(0xFF243B55))),
            SampleClipTemplate("Street Dancer.3gp", 9.0f, "3GP", "720p", "Dance sequence under bridge.", listOf(Color(0xFF11998e), Color(0xFF38ef7d))),
            SampleClipTemplate("RGB Mechanical.avi", 12.0f, "AVI", "1080p", "Macro detailed closeups.", listOf(Color(0xFFE100FF), Color(0xFF7F00FF)))
        )
    }

    var clips by remember {
        mutableStateOf(
            listOf(
                VideoClip("1", "Vlog Swiss Alps.mp4", 15.0f, "MP4", "1080p", "Scenic Swiss", 0f, 15.0f),
                VideoClip("2", "Tokyo Nightlights.mov", 8.0f, "MOV", "4K", "Tokyo skyline", 0f, 8.0f)
            )
        )
    }
    
    var undoStack by remember { mutableStateOf(listOf<List<VideoClip>>()) }
    var redoStack by remember { mutableStateOf(listOf<List<VideoClip>>()) }

    fun recordHistory(newClips: List<VideoClip>) {
        undoStack = undoStack + listOf(clips)
        redoStack = emptyList()
        clips = newClips
    }

    fun handleUndo() {
        if (undoStack.isNotEmpty()) {
            redoStack = redoStack + listOf(clips)
            clips = undoStack.last()
            undoStack = undoStack.dropLast(1)
            Toast.makeText(context, "Undo applied", Toast.LENGTH_SHORT).show()
        }
    }

    fun handleRedo() {
        if (redoStack.isNotEmpty()) {
            undoStack = undoStack + listOf(clips)
            clips = redoStack.last()
            redoStack = redoStack.dropLast(1)
            Toast.makeText(context, "Redo applied", Toast.LENGTH_SHORT).show()
        }
    }

    var activeClipId by remember { mutableStateOf<String?>("1") }
    val activeClip = remember(clips, activeClipId) { clips.find { it.id == activeClipId } }
    val totalDurationSeconds = remember(clips) { clips.sumOf { it.activeDuration.toDouble() }.toFloat() }
    var playbackProgress by remember { mutableStateOf(0.0f) }
    var isPlaying by remember { mutableStateOf(false) }

    LaunchedEffect(isPlaying, totalDurationSeconds) {
        if (isPlaying) {
            while (isPlaying) {
                delay(100)
                playbackProgress += 0.1f
                if (playbackProgress >= totalDurationSeconds) {
                    playbackProgress = 0.0f
                    isPlaying = false
                }
            }
        }
    }

    var selectedAspect by remember { mutableStateOf("16:9") }
    var subtitlesEnabled by remember { mutableStateOf(true) }
    var subtitleLanguage by remember { mutableStateOf("English-Hindi") }
    var subtitlesList by remember {
        mutableStateOf(
            listOf(
                SubtitleSegment("s1", "Welcome to Clip AI's advanced editor.", 100L, 3000L),
                SubtitleSegment("s2", "Today we grade beautiful Swiss landscapes.", 3200L, 6500L),
                SubtitleSegment("s3", "And fly drone cameras over Tokyo!", 7000L, 11000L),
                SubtitleSegment("s4", "Incredible radiant neon lights!", 11200L, 15000L)
            )
        )
    }
    
    var subtitleStyleSize by remember { mutableStateOf(13f) }
    var subtitleStyleColor by remember { mutableStateOf(Color(0xFFFFF350)) }
    var subtitleStyleFont by remember { mutableStateOf("Space Grotesk") }

    var showImportDialog by remember { mutableStateOf(false) }
    var showSubtitleDialog by remember { mutableStateOf(false) }
    var showAIThumbDialog by remember { mutableStateOf(false) }

    var aiNoiseReductionEnabled by remember { mutableStateOf(true) }
    var aiVoiceEnhanceEnabled by remember { mutableStateOf(true) }
    var aiBackgroundRemovalMode by remember { mutableStateOf("None") }
    var aiFaceFocusEnabled by remember { mutableStateOf(false) }
    var aiObjectTrackingEnabled by remember { mutableStateOf(false) }
    var beatSyncEnabled by remember { mutableStateOf(false) }
    var activeWorkspaceTab by remember { mutableStateOf("Clips") }

    var selectedFilterStyle by remember { mutableStateOf("Normal") }
    var selectedTransitionType by remember { mutableStateOf("None") }
    var videoMasterVolume by remember { mutableStateOf(0.8f) }
    var selectedMusicTheme by remember { mutableStateOf("Lofi Sunset Groove") }

    var isExporting by remember { mutableStateOf(false) }
    var exportProgress by remember { mutableStateOf(0.0f) }
    val exportTerminalOutput = remember { mutableStateListOf<String>() }
    var selectedExportResolution by remember { mutableStateOf("1080p") }
    var selectedExportFps by remember { mutableStateOf(30) }

    val activeSubtitleText = remember(playbackProgress, subtitlesList) {
        val playMs = (playbackProgress * 1000).toLong()
        subtitlesList.find { playMs in it.startMs..it.endMs }?.text ?: ""
    }

    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFF07070F))
            .padding(8.dp)
    ) {
        // HEADER
        AIVideoEditorHeader(onBack = { viewModel.navigateTo("home") })

        // PLAYER PREVIEW
        AIVideoEditorPlayerFrame(
            activeClip = activeClip,
            playbackProgress = playbackProgress,
            totalDurationSeconds = totalDurationSeconds,
            isPlaying = isPlaying,
            selectedAspect = selectedAspect,
            selectedFilterStyle = selectedFilterStyle,
            aiBackgroundRemovalMode = aiBackgroundRemovalMode,
            aiFaceFocusEnabled = aiFaceFocusEnabled,
            aiObjectTrackingEnabled = aiObjectTrackingEnabled,
            subtitlesEnabled = subtitlesEnabled,
            activeSubtitleText = activeSubtitleText,
            subtitleStyleColor = subtitleStyleColor,
            subtitleStyleSize = subtitleStyleSize,
            subtitleStyleFont = subtitleStyleFont,
            undoStackEmpty = undoStack.isEmpty(),
            redoStackEmpty = redoStack.isEmpty(),
            onUndo = { handleUndo() },
            onRedo = { handleRedo() },
            onAspectChange = {
                selectedAspect = when (selectedAspect) {
                    "16:9" -> "9:16"
                    "9:16" -> "1:1"
                    else -> "16:9"
                }
            },
            onPlayToggle = { isPlaying = !isPlaying }
        )

        Spacer(modifier = Modifier.height(4.dp))

        // SEEK BAR
        Slider(
            value = playbackProgress,
            onValueChange = { playbackProgress = it },
            valueRange = 0f..totalDurationSeconds.coerceAtLeast(1f),
            colors = SliderDefaults.colors(activeTrackColor = NeonPurple, thumbColor = NeonCyan)
        )

        // TIMELINE ROW DISPLAY
        AIVideoEditorTimelineView(
            clips = clips,
            activeClipId = activeClipId,
            subtitlesEnabled = subtitlesEnabled,
            subtitlesList = subtitlesList,
            selectedMusicTheme = selectedMusicTheme,
            beatSyncEnabled = beatSyncEnabled,
            onClipSelect = { activeClipId = it },
            onClipDelete = { id ->
                val remaining = clips.filter { it.id != id }
                recordHistory(remaining)
                if (activeClipId == id) activeClipId = remaining.firstOrNull()?.id
            },
            onAddClipRequest = { showImportDialog = true },
            onMoveClipLeft = { index ->
                if (index > 0) {
                    val list = clips.toMutableList()
                    val temp = list[index]
                    list[index] = list[index - 1]
                    list[index - 1] = temp
                    recordHistory(list)
                }
            },
            onMoveClipRight = { index ->
                if (index < clips.size - 1) {
                    val list = clips.toMutableList()
                    val temp = list[index]
                    list[index] = list[index + 1]
                    list[index + 1] = temp
                    recordHistory(list)
                }
            }
        )

        // SHORTCUT BUTTONS BAR
        AIVideoEditorShortcutBar(
            activeClip = activeClip,
            clips = clips,
            totalDurationSeconds = totalDurationSeconds,
            onTrimClick = {
                activeClip?.let {
                    val updated = clips.map { c ->
                        if (c.id == it.id) c.copy(startTrim = it.durationSeconds * 0.1f, endTrim = it.durationSeconds * 0.9f) else c
                    }
                    recordHistory(updated)
                    Toast.makeText(context, "Trimmed boundaries 10% to 90%", Toast.LENGTH_SHORT).show()
                }
            },
            onSplitClick = {
                activeClip?.let {
                    val duration = it.activeDuration
                    if (duration > 2f) {
                        val midPoint = it.startTrim + (duration / 2f)
                        val left = it.copy(id = it.id + "_L", name = it.name + "_Part1", endTrim = midPoint)
                        val right = it.copy(id = it.id + "_R", name = it.name + "_Part2", startTrim = midPoint)
                        val idx = clips.indexOfFirst { c -> c.id == it.id }
                        if (idx != -1) {
                            val list = clips.toMutableList()
                            list.removeAt(idx)
                            list.add(idx, right)
                            list.add(idx, left)
                            recordHistory(list)
                            activeClipId = left.id
                            Toast.makeText(context, "Split success", Toast.LENGTH_SHORT).show()
                        }
                    }
                }
            },
            onCloneClick = {
                activeClip?.let {
                    val duplicate = it.copy(id = (100..999).random().toString(), name = it.name + "_Clone")
                    val idx = clips.indexOfFirst { c -> c.id == it.id }
                    if (idx != -1) {
                        val list = clips.toMutableList()
                        list.add(idx + 1, duplicate)
                        recordHistory(list)
                        Toast.makeText(context, "Cloned clip!", Toast.LENGTH_SHORT).show()
                    }
                }
            },
            onHighlightClick = {
                coroutineScope.launch {
                    Toast.makeText(context, "Highlight finder active...", Toast.LENGTH_SHORT).show()
                    delay(800)
                    val highlights = clips.map {
                        it.copy(startTrim = it.startTrim + (it.activeDuration * 0.2f), filterSpec = "Cinematic Boost")
                    }
                    recordHistory(highlights)
                    Toast.makeText(context, "AI Highlight generated!", Toast.LENGTH_SHORT).show()
                }
            }
        )

        // TABS NAVIGATION BAR
        AIVideoEditorTabsHeader(
            activeTab = activeWorkspaceTab,
            onTabSelected = { activeWorkspaceTab = it }
        )

        // TAB WORKSPACE CONTROLS ACCORDION
        AIVideoEditorControlsScroller(
            activeTab = activeWorkspaceTab,
            activeClip = activeClip,
            clips = clips,
            selectedFilterStyle = selectedFilterStyle,
            selectedTransitionType = selectedTransitionType,
            subtitlesEnabled = subtitlesEnabled,
            subtitleStyleFont = subtitleStyleFont,
            subtitleStyleColor = subtitleStyleColor,
            subtitleStyleSize = subtitleStyleSize,
            aiNoiseReductionEnabled = aiNoiseReductionEnabled,
            aiVoiceEnhanceEnabled = aiVoiceEnhanceEnabled,
            aiBackgroundRemovalMode = aiBackgroundRemovalMode,
            aiFaceFocusEnabled = aiFaceFocusEnabled,
            aiObjectTrackingEnabled = aiObjectTrackingEnabled,
            selectedMusicTheme = selectedMusicTheme,
            beatSyncEnabled = beatSyncEnabled,
            videoMasterVolume = videoMasterVolume,
            selectedExportResolution = selectedExportResolution,
            selectedExportFps = selectedExportFps,
            isExporting = isExporting,
            exportProgress = exportProgress,
            exportTerminalOutput = exportTerminalOutput,
            onFilterChange = { selectedFilterStyle = it },
            onTransitionChange = { selectedTransitionType = it },
            onSubtitlesToggle = { subtitlesEnabled = it },
            onDialogSubtitleRequest = { showSubtitleDialog = true },
            onClearSilences = {
                coroutineScope.launch {
                    Toast.makeText(context, "Analyzing silences...", Toast.LENGTH_SHORT).show()
                    delay(1000)
                    val optimized = clips.map {
                        if (it.activeDuration > 5f) it.copy(endTrim = it.endTrim - 1.5f) else it
                    }
                    recordHistory(optimized)
                    Toast.makeText(context, "AI Removed 1.5s silence gap!", Toast.LENGTH_SHORT).show()
                }
            },
            onSubFontChange = { subtitleStyleFont = it },
            onSubColorChange = { subtitleStyleColor = it },
            onSubSizeChange = { subtitleStyleSize = it },
            onNoiseToggle = { aiNoiseReductionEnabled = it },
            onVoiceToggle = { aiVoiceEnhanceEnabled = it },
            onBgRemovalChange = { aiBackgroundRemovalMode = it },
            onFaceFocusToggle = { aiFaceFocusEnabled = it },
            onObjectTrackingToggle = { aiObjectTrackingEnabled = it },
            onMusicThemeChange = { selectedMusicTheme = it },
            onBeatSyncToggle = {
                beatSyncEnabled = it
                if (beatSyncEnabled && selectedMusicTheme != "None") {
                    val synced = clips.map { c -> c.copy(endTrim = c.startTrim + c.activeDuration.toInt() - 0.2f) }
                    recordHistory(synced)
                    Toast.makeText(context, "Clip edges aligned to music beat signature!", Toast.LENGTH_SHORT).show()
                }
            },
            onVolumeChange = { videoMasterVolume = it },
            onExportResChange = { selectedExportResolution = it },
            onExportFpsChange = { selectedExportFps = it },
            onShowAIThumb = { showAIThumbDialog = true },
            onCompileRequest = {
                coroutineScope.launch {
                    isExporting = true
                    exportProgress = 0f
                    exportTerminalOutput.clear()
                    exportTerminalOutput.add("[SYSTEM]: Launching GPU parallel rendering pipelines...")
                    
                    val renderSteps = listOf(
                        10 to "[PARSER]: Processing timeline: ${clips.size} clip structures",
                        30 to "[GRADERS]: Executing cinematic style filter matrix: $selectedFilterStyle",
                        50 to "[AUDIO]: Merging layers (Voice Enhances: $aiVoiceEnhanceEnabled, Noise Gates: $aiNoiseReductionEnabled)",
                        70 to "[GENERATOR]: Segmenting portrait background mask layers: $aiBackgroundRemovalMode",
                        90 to "[ENCRYPTOR]: Composing subtitle stream frames: $subtitleStyleFont",
                        100 to "[DISK]: Encoding completes output as H.264 MP4 to persistent folder storage"
                    )

                    for (step in 1..100) {
                        exportProgress = step / 100f
                        renderSteps.find { it.first == step }?.second?.let {
                            exportTerminalOutput.add(it)
                        }
                        if (step % 15 == 0) {
                            exportTerminalOutput.add("[GPU_CORES]: Processed composite frame nodes: $step%")
                        }
                        delay(60)
                    }

                    val detailsReport = """
                        Clip AI Video Generation Details:
                        - Clips: ${clips.size} clips compiled
                        - Time duration: ${totalDurationSeconds}s
                        - Style filter spec: $selectedFilterStyle
                        - Background replace: $aiBackgroundRemovalMode
                        - Rendering mode: $selectedExportResolution at ${selectedExportFps}fps
                        Successfully rendered and persisted to database.
                    """.trimIndent()

                    viewModel.recordVideoEditing(
                        projectName = "Clip AI Project #${(10..99).random()}",
                        clipsCount = clips.size,
                        totalDurationSeconds = totalDurationSeconds,
                        aiFeaturesUsed = "Filter: $selectedFilterStyle | BG: $aiBackgroundRemovalMode",
                        subtitlesLanguage = subtitleLanguage,
                        exportResolution = "$selectedExportResolution at ${selectedExportFps}fps",
                        detailsReport = detailsReport
                    )

                    isExporting = false
                    Toast.makeText(context, "Render complete! Deducted 2 credits.", Toast.LENGTH_LONG).show()
                }
            }
        )
    }

    // DIALOGS POPUPS
    if (showImportDialog) {
        AIVideoEditorDialogImport(
            clipTemplates = clipTemplates,
            onDismiss = { showImportDialog = false },
            onImportSelect = { template ->
                val added = VideoClip(
                    id = (100..999).random().toString(),
                    name = template.name,
                    durationSeconds = template.durationSeconds,
                    format = template.format,
                    resolution = template.resolution,
                    description = template.description
                )
                recordHistory(clips + listOf(added))
                showImportDialog = false
            }
        )
    }

    if (showSubtitleDialog) {
        AIVideoEditorDialogSubtitle(
            clipsSummary = clips.joinToString(", ") { "${it.name} (${it.activeDuration}s)" },
            totalDuration = totalDurationSeconds,
            onDismiss = { showSubtitleDialog = false },
            onTranscriptSuccess = { generatedSubs, lang ->
                subtitlesList = generatedSubs
                subtitleLanguage = lang
                subtitlesEnabled = true
                showSubtitleDialog = false
            }
        )
    }

    if (showAIThumbDialog) {
        AIVideoEditorDialogThumb(
            onDismiss = { showAIThumbDialog = false }
        )
    }
}

// =====================================================================
// MODULAR COMPACT SUBCOMPOSABLES (PREVENT METHOD TOO LARGE RUNTIME LIMIT)
// =====================================================================

@Composable
fun AIVideoEditorHeader(onBack: () -> Unit) {
    Row(
        modifier = Modifier.fillMaxWidth().padding(bottom = 6.dp),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        IconButton(
            onClick = onBack,
            modifier = Modifier.size(36.dp).background(Color.White.copy(0.06f), CircleShape)
        ) {
            Icon(Icons.Filled.ArrowBack, "Exit Workspace", tint = Color.LightGray, modifier = Modifier.size(18.dp))
        }
        Column(horizontalAlignment = Alignment.CenterHorizontally) {
            Text("CLIP AI VIDEO STUDIO", fontSize = 12.sp, fontWeight = FontWeight.Black, color = Color.White, letterSpacing = 1.sp)
            Text("PREMIUM EDITOR SUITE", fontSize = 7.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
        }
        Box(modifier = Modifier.clip(RoundedCornerShape(6.dp)).background(Brush.linearGradient(listOf(NeonCyan, NeonPurple))).padding(horizontal = 8.dp, vertical = 4.dp)) {
            Text("PRO ACTIVE", fontSize = 8.sp, fontWeight = FontWeight.Black, color = PureBlack)
        }
    }
}

@Composable
fun AIVideoEditorPlayerFrame(
    activeClip: VideoClip?,
    playbackProgress: Float,
    totalDurationSeconds: Float,
    isPlaying: Boolean,
    selectedAspect: String,
    selectedFilterStyle: String,
    aiBackgroundRemovalMode: String,
    aiFaceFocusEnabled: Boolean,
    aiObjectTrackingEnabled: Boolean,
    subtitlesEnabled: Boolean,
    activeSubtitleText: String,
    subtitleStyleColor: Color,
    subtitleStyleSize: Float,
    subtitleStyleFont: String,
    undoStackEmpty: Boolean,
    redoStackEmpty: Boolean,
    onUndo: () -> Unit,
    onRedo: () -> Unit,
    onAspectChange: () -> Unit,
    onPlayToggle: () -> Unit
) {
    val canvasHeight = when (selectedAspect) {
        "9:16" -> 230.dp
        "1:1" -> 200.dp
        else -> 150.dp
    }
    val canvasAspectRatio = when (selectedAspect) {
        "9:16" -> 9f / 16f
        "1:1" -> 1f
        else -> 16f / 9f
    }

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .height(250.dp)
            .background(Color.Black, RoundedCornerShape(12.dp))
            .border(0.5.dp, Color.DarkGray, RoundedCornerShape(12.dp)),
        contentAlignment = Alignment.Center
    ) {
        // Player stream backdrop
        Box(
            modifier = Modifier
                .height(canvasHeight)
                .aspectRatio(canvasAspectRatio)
                .clip(RoundedCornerShape(10.dp))
                .drawBehind {
                    val startCol = when (selectedFilterStyle) {
                        "Glitch" -> Color(0xFF1D003E)
                        "Vintage" -> Color(0xFF4C3018)
                        "HDR" -> Color(0xFF0C2B1C)
                        else -> Color(0xFF111122)
                    }
                    val endCol = when (selectedFilterStyle) {
                        "Glitch" -> Color(0xFFFF007F)
                        "Vintage" -> Color(0xFFBA8C63)
                        "HDR" -> Color(0xFF39FF14)
                        else -> Color(0xFF4361EE)
                    }
                    val backgroundBrush = when (aiBackgroundRemovalMode) {
                        "Solid Cyan" -> Brush.verticalGradient(listOf(Color(0xFF0099FF), Color(0xFF00F2FE)))
                        "Chroma Green" -> Brush.verticalGradient(listOf(Color(0xFF00FF00), Color(0xFF00AA00)))
                        "Studio Gray" -> Brush.linearGradient(listOf(Color(0xFF232526), Color(0xFF414345)))
                        else -> Brush.radialGradient(listOf(endCol, startCol))
                    }
                    drawRect(backgroundBrush)
                }
        ) {
            // Live player trackers
            Column(modifier = Modifier.fillMaxSize().padding(8.dp), verticalArrangement = Arrangement.SpaceBetween) {
                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                    Text(text = activeClip?.name ?: "Idle timeline", fontSize = 8.sp, color = Color.White.copy(0.7f), maxLines = 1)
                    if (selectedFilterStyle != "Normal") {
                        Box(modifier = Modifier.background(NeonPurple.copy(0.4f), RoundedCornerShape(4.dp)).padding(horizontal = 4.dp, vertical = 2.dp)) {
                            Text(selectedFilterStyle, color = NeonPurple, fontSize = 6.sp, fontWeight = FontWeight.Bold)
                        }
                    }
                }

                Box(modifier = Modifier.fillMaxWidth().weight(1f), contentAlignment = Alignment.Center) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(if (selectedAspect == "9:16") Icons.Filled.Face else Icons.Filled.VideoCameraBack, null, tint = Color.White.copy(0.12f), modifier = Modifier.size(36.dp))
                        Spacer(modifier = Modifier.height(4.dp))
                        Row(horizontalArrangement = Arrangement.spacedBy(2.dp)) {
                            repeat(6) {
                                Box(modifier = Modifier.width(2.dp).height(if (isPlaying) (3..10).random().dp else 3.dp).background(NeonCyan, RoundedCornerShape(1.dp)))
                            }
                        }
                    }

                    if (aiFaceFocusEnabled) {
                        Box(modifier = Modifier.size(70.dp).border(1.dp, Color.Green, RoundedCornerShape(4.dp))) {
                            Text("AI SENSOR", color = Color.Green, fontSize = 5.sp, modifier = Modifier.background(Color.Black).padding(2.dp), fontWeight = FontWeight.Bold)
                        }
                    }
                    if (aiObjectTrackingEnabled) {
                        Box(modifier = Modifier.size(90.dp).border(0.5.dp, NeonCyan, RoundedCornerShape(2.dp)))
                    }
                }

                if (subtitlesEnabled && activeSubtitleText.isNotEmpty()) {
                    Box(modifier = Modifier.fillMaxWidth(), contentAlignment = Alignment.Center) {
                        Text(
                            text = activeSubtitleText,
                            color = subtitleStyleColor,
                            fontSize = subtitleStyleSize.sp,
                            fontWeight = FontWeight.Bold,
                            textAlign = TextAlign.Center,
                            modifier = Modifier.background(Color.Black.copy(0.7f), RoundedCornerShape(4.dp)).padding(horizontal = 6.dp, vertical = 2.dp)
                        )
                    }
                }
            }
        }
    }

    Spacer(modifier = Modifier.height(4.dp))

    // PREVIEW CONTROLLER ROW
    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
        Text(
            text = String.format(java.util.Locale.US, "%02d:%04.1f s / %02d:%02d s", 0, playbackProgress, 0, totalDurationSeconds.toInt()),
            fontSize = 9.sp,
            color = Color.LightGray,
            fontWeight = FontWeight.Bold
        )

        Row(horizontalArrangement = Arrangement.spacedBy(8.dp), verticalAlignment = Alignment.CenterVertically) {
            IconButton(onClick = onUndo, enabled = !undoStackEmpty, modifier = Modifier.size(30.dp)) {
                Icon(Icons.Filled.Undo, "Undo", tint = if (undoStackEmpty) Color.DarkGray else Color.White, modifier = Modifier.size(15.dp))
            }
            IconButton(onClick = onRedo, enabled = !redoStackEmpty, modifier = Modifier.size(30.dp)) {
                Icon(Icons.Filled.Redo, "Redo", tint = if (redoStackEmpty) Color.DarkGray else Color.White, modifier = Modifier.size(15.dp))
            }
            Box(modifier = Modifier.clip(RoundedCornerShape(6.dp)).background(Color.White.copy(0.06f)).clickable { onAspectChange() }.padding(horizontal = 8.dp, vertical = 4.dp)) {
                Text("Crop $selectedAspect", fontSize = 8.sp, color = Color.White, fontWeight = FontWeight.Bold)
            }
            IconButton(onClick = onPlayToggle, modifier = Modifier.size(32.dp).background(Brush.linearGradient(listOf(NeonCyan, NeonPurple)), CircleShape)) {
                Icon(if (isPlaying) Icons.Filled.Pause else Icons.Filled.PlayArrow, "Toggle playback", tint = PureBlack, modifier = Modifier.size(16.dp))
            }
        }
    }
}

@Composable
fun AIVideoEditorTimelineView(
    clips: List<VideoClip>,
    activeClipId: String?,
    subtitlesEnabled: Boolean,
    subtitlesList: List<SubtitleSegment>,
    selectedMusicTheme: String,
    beatSyncEnabled: Boolean,
    onClipSelect: (String) -> Unit,
    onClipDelete: (String) -> Unit,
    onAddClipRequest: () -> Unit,
    onMoveClipLeft: (Int) -> Unit,
    onMoveClipRight: (Int) -> Unit
) {
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .background(Color(0xFF0F0F1A), RoundedCornerShape(10.dp))
            .border(0.5.dp, Color.DarkGray.copy(0.4f), RoundedCornerShape(10.dp))
            .padding(6.dp)
    ) {
        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
            // CLIPS ROW
            Row(modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                Box(modifier = Modifier.width(45.dp)) {
                    Text("🎬 Clips", fontSize = 8.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                }
                Row(
                    modifier = Modifier.weight(1f).horizontalScroll(rememberScrollState()),
                    horizontalArrangement = Arrangement.spacedBy(6.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    clips.forEachIndexed { idx, clip ->
                        val active = clip.id == activeClipId
                        Box(
                            modifier = Modifier
                                .clip(RoundedCornerShape(6.dp))
                                .background(if (active) Color(0xFF2C1642) else Color(0xFF161623))
                                .border(1.dp, if (active) NeonPurple else Color.DarkGray.copy(0.5f), RoundedCornerShape(6.dp))
                                .clickable { onClipSelect(clip.id) }
                                .padding(5.dp)
                        ) {
                            Column(modifier = Modifier.width(85.dp)) {
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                    Text(clip.name, fontSize = 7.sp, fontWeight = FontWeight.Bold, color = Color.White, maxLines = 1, modifier = Modifier.weight(1f))
                                    IconButton(onClick = { onClipDelete(clip.id) }, modifier = Modifier.size(12.dp)) {
                                        Icon(Icons.Filled.Delete, null, tint = Color.Red.copy(0.8f), modifier = Modifier.size(9.dp))
                                    }
                                }
                                Text("${clip.activeDuration.toInt()}s (${clip.resolution})", fontSize = 6.sp, color = NeonCyan)
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Text("[${clip.format}]", fontSize = 6.sp, color = Color.Gray)
                                    Row(horizontalArrangement = Arrangement.spacedBy(2.dp)) {
                                        if (idx > 0) {
                                            Box(modifier = Modifier.size(8.dp).background(Color.White.copy(0.12f), CircleShape).clickable { onMoveClipLeft(idx) }) {
                                                Text("◀", fontSize = 4.7.sp, color = Color.White, modifier = Modifier.align(Alignment.Center))
                                            }
                                        }
                                        if (idx < clips.size - 1) {
                                            Box(modifier = Modifier.size(8.dp).background(Color.White.copy(0.12f), CircleShape).clickable { onMoveClipRight(idx) }) {
                                                Text("▶", fontSize = 4.7.sp, color = Color.White, modifier = Modifier.align(Alignment.Center))
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                    IconButton(onClick = onAddClipRequest, modifier = Modifier.size(28.dp).background(Color.White.copy(0.1f), CircleShape)) {
                        Icon(Icons.Filled.Add, null, tint = NeonCyan, modifier = Modifier.size(14.dp))
                    }
                }
            }

            Divider(color = Color.DarkGray.copy(0.2f))

            // SUBTITLE TRACK
            Row(modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                Box(modifier = Modifier.width(45.dp)) {
                    Text("💬 Subs", fontSize = 8.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                }
                if (subtitlesEnabled) {
                    Row(modifier = Modifier.weight(1f).horizontalScroll(rememberScrollState()), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        subtitlesList.forEach { sub ->
                            Box(modifier = Modifier.background(Color(0xFF231C0F)).border(0.5.dp, Color(0xFFBA8C63).copy(0.3f), RoundedCornerShape(4.dp)).padding(horizontal = 5.dp, vertical = 2.dp)) {
                                Text(sub.text, fontSize = 7.sp, color = Color.LightGray, modifier = Modifier.widthIn(max = 120.dp), maxLines = 1, overflow = TextOverflow.Ellipsis)
                            }
                        }
                    }
                } else {
                    Text("Auto Captions Disabled", fontSize = 7.sp, color = Color.DarkGray, fontStyle = androidx.compose.ui.text.font.FontStyle.Italic)
                }
            }

            Divider(color = Color.DarkGray.copy(0.2f))

            // AUDIO TRACK
            Row(modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                Box(modifier = Modifier.width(45.dp)) {
                    Text("🎵 Audio", fontSize = 8.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                }
                Box(modifier = Modifier.weight(1f).clip(RoundedCornerShape(4.dp)).background(Color(0xFF0F1A24)).padding(horizontal = 6.dp, vertical = 3.dp)) {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text("BGM: $selectedMusicTheme.mp3", fontSize = 7.sp, color = Color(0xFF00B4DB), fontWeight = FontWeight.Bold)
                        if (beatSyncEnabled) {
                            Text("BEAT SYNCED ACTIVE ✅", fontSize = 6.sp, color = NeonCyan, fontWeight = FontWeight.Black)
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun AIVideoEditorShortcutBar(
    activeClip: VideoClip?,
    clips: List<VideoClip>,
    totalDurationSeconds: Float,
    onTrimClick: () -> Unit,
    onSplitClick: () -> Unit,
    onCloneClick: () -> Unit,
    onHighlightClick: () -> Unit
) {
    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
        Button(onClick = onTrimClick, colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.04f)), border = BorderStroke(0.5.dp, Color.Gray), contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp), modifier = Modifier.weight(1f)) {
            Text("✂️ Smart Trim", color = Color.White, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
        }
        Button(onClick = onSplitClick, colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.04f)), border = BorderStroke(0.5.dp, Color.Gray), contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp), modifier = Modifier.weight(1f)) {
            Text("🥞 Split Mid", color = Color.White, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
        }
        Button(onClick = onCloneClick, colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.04f)), border = BorderStroke(0.5.dp, Color.Gray), contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp), modifier = Modifier.weight(1f)) {
            Text("👥 Clone", color = Color.White, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
        }
        Button(onClick = onHighlightClick, colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.04f)), border = BorderStroke(0.5.dp, NeonPurple), contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp), modifier = Modifier.weight(1f)) {
            Text("🔥 Reels Creator", color = Color.White, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
        }
    }
}

@Composable
fun AIVideoEditorTabsHeader(activeTab: String, onTabSelected: (String) -> Unit) {
    Row(
        modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp).horizontalScroll(rememberScrollState()),
        horizontalArrangement = Arrangement.spacedBy(4.dp)
    ) {
        val sections = listOf(
            "Clips" to "🎞️ Clips",
            "Style FX" to "🎨 Filters",
            "Speech AI" to "🎙️ Speech",
            "Audio AI" to "🔊 Audio",
            "Video AI" to "🎭 Video",
            "Sound track" to "🎵 Music",
            "Compile" to "📤 Export"
        )
        sections.forEach { (key, title) ->
            val active = activeTab == key
            Box(
                modifier = Modifier
                    .clip(RoundedCornerShape(6.dp))
                    .background(if (active) Brush.horizontalGradient(listOf(NeonBlue, NeonPurple)) else Brush.linearGradient(listOf(Color.White.copy(0.04f), Color.White.copy(0.02f))))
                    .clickable { onTabSelected(key) }
                    .padding(horizontal = 10.dp, vertical = 5.dp)
            ) {
                Text(title, fontSize = 8.5.sp, color = if (active) PureBlack else Color.White, fontWeight = FontWeight.Black)
            }
        }
    }
}

@Composable
fun AIVideoEditorControlsScroller(
    activeTab: String,
    activeClip: VideoClip?,
    clips: List<VideoClip>,
    selectedFilterStyle: String,
    selectedTransitionType: String,
    subtitlesEnabled: Boolean,
    subtitleStyleFont: String,
    subtitleStyleColor: Color,
    subtitleStyleSize: Float,
    aiNoiseReductionEnabled: Boolean,
    aiVoiceEnhanceEnabled: Boolean,
    aiBackgroundRemovalMode: String,
    aiFaceFocusEnabled: Boolean,
    aiObjectTrackingEnabled: Boolean,
    selectedMusicTheme: String,
    beatSyncEnabled: Boolean,
    videoMasterVolume: Float,
    selectedExportResolution: String,
    selectedExportFps: Int,
    isExporting: Boolean,
    exportProgress: Float,
    exportTerminalOutput: List<String>,
    onFilterChange: (String) -> Unit,
    onTransitionChange: (String) -> Unit,
    onSubtitlesToggle: (Boolean) -> Unit,
    onDialogSubtitleRequest: () -> Unit,
    onClearSilences: () -> Unit,
    onSubFontChange: (String) -> Unit,
    onSubColorChange: (Color) -> Unit,
    onSubSizeChange: (Float) -> Unit,
    onNoiseToggle: (Boolean) -> Unit,
    onVoiceToggle: (Boolean) -> Unit,
    onBgRemovalChange: (String) -> Unit,
    onFaceFocusToggle: (Boolean) -> Unit,
    onObjectTrackingToggle: (Boolean) -> Unit,
    onMusicThemeChange: (String) -> Unit,
    onBeatSyncToggle: (Boolean) -> Unit,
    onVolumeChange: (Float) -> Unit,
    onExportResChange: (String) -> Unit,
    onExportFpsChange: (Int) -> Unit,
    onShowAIThumb: () -> Unit,
    onCompileRequest: () -> Unit
) {
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .height(130.dp)
            .background(Color(0xFF0F0F1A), RoundedCornerShape(10.dp))
            .border(0.5.dp, Color.DarkGray.copy(0.3f), RoundedCornerShape(10.dp))
            .padding(6.dp)
    ) {
        Column(modifier = Modifier.fillMaxSize().verticalScroll(rememberScrollState()), verticalArrangement = Arrangement.spacedBy(6.dp)) {
            when (activeTab) {
                "Clips" -> {
                    Text("ACTIVE CLIP PROPERTIES", fontSize = 8.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                    if (activeClip != null) {
                        Text("Editing: ${activeClip.name} (${activeClip.format})", fontSize = 8.sp, color = Color.White)
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            Column(modifier = Modifier.weight(1f)) {
                                Text("Trim Start Offset", fontSize = 6.sp, color = Color.Gray)
                                Box(modifier = Modifier.fillMaxWidth().background(Color.White.copy(0.04f)).padding(4.dp)) {
                                    Text("${activeClip.startTrim.toInt()}s", fontSize = 7.2.sp, color = Color.White)
                                }
                            }
                            Column(modifier = Modifier.weight(1f)) {
                                Text("Trim End Offset", fontSize = 6.sp, color = Color.Gray)
                                Box(modifier = Modifier.fillMaxWidth().background(Color.White.copy(0.04f)).padding(4.dp)) {
                                    Text("${activeClip.endTrim.toInt()}s", fontSize = 7.2.sp, color = Color.White)
                                }
                            }
                        }
                    } else {
                        Text("Select a clip to display fine-tuned coordinates.", fontSize = 7.sp, color = Color.Gray)
                    }
                }

                "Style FX" -> {
                    Text("GRADERS FILTERS & SHADERS", fontSize = 8.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        listOf("Normal", "Glitch", "Vintage", "HDR").forEach { flt ->
                            val active = selectedFilterStyle == flt
                            Box(modifier = Modifier.weight(1f).background(if (active) Color(0xFF1E142F) else Color.White.copy(0.02f)).border(0.5.dp, if (active) NeonPurple else Color.Transparent).clickable { onFilterChange(flt) }.padding(4.dp), contentAlignment = Alignment.Center) {
                                Text(flt, fontSize = 7.sp, color = if (active) NeonPurple else Color.LightGray)
                            }
                        }
                    }
                    Spacer(modifier = Modifier.height(2.dp))
                    Text("CINEMATIC TRANSITIONS", fontSize = 7.sp, color = Color.Gray)
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        listOf("None", "Cross Fade", "Zoom Blur").forEach { trs ->
                            val active = selectedTransitionType == trs
                            Box(modifier = Modifier.weight(1f).background(if (active) Color(0xFF141F2F) else Color.White.copy(0.02f)).clickable { onTransitionChange(trs) }.padding(3.dp), contentAlignment = Alignment.Center) {
                                Text(trs, fontSize = 6.6.sp, color = Color.White)
                            }
                        }
                    }
                }

                "Speech AI" -> {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                        Text("AI AUTOMATIC CAPTIONS", fontSize = 8.sp, color = Color.White, fontWeight = FontWeight.Bold)
                        Switch(checked = subtitlesEnabled, onCheckedChange = onSubtitlesToggle, colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan), modifier = Modifier.scale(0.7f))
                    }
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                        Button(onClick = onDialogSubtitleRequest, colors = ButtonDefaults.buttonColors(containerColor = NeonPurple), modifier = Modifier.weight(1.3f)) {
                            Text("Auto Subtitles with Gemini Pro", color = PureBlack, fontSize = 8.sp, fontWeight = FontWeight.Black)
                        }
                        Button(onClick = onClearSilences, colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.05f)), modifier = Modifier.weight(1f)) {
                            Text("✂️ AI Silent Cut", color = Color.White, fontSize = 8.sp)
                        }
                    }
                }

                "Audio AI" -> {
                    Text("AI VOICE CLEANER PRO", fontSize = 8.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text("AI background noise cancellation", fontSize = 7.sp, color = Color.White)
                        Switch(checked = aiNoiseReductionEnabled, onCheckedChange = onNoiseToggle, modifier = Modifier.scale(0.7f))
                    }
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text("Voice speech leveling normalize", fontSize = 7.sp, color = Color.White)
                        Switch(checked = aiVoiceEnhanceEnabled, onCheckedChange = onVoiceToggle, modifier = Modifier.scale(0.7f))
                    }
                }

                "Video AI" -> {
                    Text("AI SPECIAL DETECT SEGMENTATION", fontSize = 8.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        listOf("None", "Solid Cyan", "Chroma Green", "Studio Gray").forEach { mode ->
                            val active = aiBackgroundRemovalMode == mode
                            Box(modifier = Modifier.weight(1f).background(if (active) Color(0xFF1E1D1D) else Color.White.copy(0.02f)).clickable { onBgRemovalChange(mode) }.padding(3.dp), contentAlignment = Alignment.Center) {
                                Text(mode.take(9), fontSize = 6.4.sp, color = if (active) Color.Yellow else Color.White)
                            }
                        }
                    }
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text("Centering Speaker (Auto Crop 9:16)", fontSize = 7.sp, color = Color.White)
                        Switch(checked = aiFaceFocusEnabled, onCheckedChange = onFaceFocusToggle, modifier = Modifier.scale(0.7f))
                    }
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text("Identify overlay bounding scopes", fontSize = 7.sp, color = Color.White)
                        Switch(checked = aiObjectTrackingEnabled, onCheckedChange = onObjectTrackingToggle, modifier = Modifier.scale(0.7f))
                    }
                }

                "Sound track" -> {
                    Text("COMPILATION TRACK MIXING", fontSize = 8.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        listOf("None", "Lofi Sunset Groove", "Happy Vlog Beats", "Cyberpunk Tech Wave").forEach { theme ->
                            val active = selectedMusicTheme == theme
                            Box(modifier = Modifier.weight(1f).background(if (active) Color(0xFF0C2B1D) else Color.White.copy(0.02f)).clickable { onMusicThemeChange(theme) }.padding(3.dp), contentAlignment = Alignment.Center) {
                                Text(theme.take(5), fontSize = 6.4.sp, color = Color.White, maxLines = 1)
                            }
                        }
                    }
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                        Text("AI Beat Sync Trim snapping", fontSize = 7.sp, color = Color.White)
                        Switch(checked = beatSyncEnabled, onCheckedChange = onBeatSyncToggle, modifier = Modifier.scale(0.7f))
                    }
                }

                "Compile" -> {
                    Text("GPU COMPILATION PARAMETERS", fontSize = 8.sp, color = Color.White, fontWeight = FontWeight.Bold)
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                        Row(modifier = Modifier.weight(1f), verticalAlignment = Alignment.CenterVertically) {
                            Text("Res: ", fontSize = 6.8.sp, color = Color.Gray)
                            listOf("1080p", "4K").forEach { r ->
                                val active = selectedExportResolution == r
                                Box(modifier = Modifier.weight(1f).background(if (active) Color(0xFF1E283F) else Color.Transparent).clickable { onExportResChange(r) }.padding(2.dp)) {
                                    Text(r, fontSize = 6.6.sp, color = Color.White, textAlign = TextAlign.Center)
                                }
                            }
                        }
                        Row(modifier = Modifier.weight(1f), verticalAlignment = Alignment.CenterVertically) {
                            Text("Fps: ", fontSize = 6.8.sp, color = Color.Gray)
                            listOf(30, 60).forEach { f ->
                                val active = selectedExportFps == f
                                Box(modifier = Modifier.weight(1f).background(if (active) Color(0xFF1E283F) else Color.Transparent).clickable { onExportFpsChange(f) }.padding(2.dp)) {
                                    Text("${f}fps", fontSize = 6.6.sp, color = Color.White, textAlign = TextAlign.Center)
                                }
                            }
                        }
                    }
                    Spacer(modifier = Modifier.height(2.dp))
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        Button(onClick = onShowAIThumb, colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(0.04f)), border = BorderStroke(0.5.dp, Color.DarkGray), modifier = Modifier.weight(1f)) {
                            Text("Suggest Thumbnail Cover UI", fontSize = 7.5.sp)
                        }
                        Button(onClick = onCompileRequest, colors = ButtonDefaults.buttonColors(containerColor = Color.Transparent), modifier = Modifier.weight(1.2f).background(Brush.linearGradient(listOf(NeonCyan, NeonPurple)), RoundedCornerShape(8.dp))) {
                            Text("📤 COMCOMPILE RENDER", color = PureBlack, fontSize = 8.sp, fontWeight = FontWeight.Black)
                        }
                    }

                    if (isExporting || exportTerminalOutput.isNotEmpty()) {
                        Spacer(modifier = Modifier.height(4.dp))
                        Box(modifier = Modifier.fillMaxWidth().height(65.dp).background(Color.Black).border(0.5.dp, Color.Green).padding(4.dp)) {
                            LazyColumn {
                                items(exportTerminalOutput) { l ->
                                    Text(l, fontSize = 6.sp, color = Color.Green, fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun AIVideoEditorDialogImport(
