                clipTemplates.forEach { template ->
                    Row(
                        modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(6.dp)).background(Brush.linearGradient(template.thumbnailGradient)).clickable { onImportSelect(template) }.padding(6.dp),
