// ==========================================
// MODELS & CONFIGS FOR CLIP AI PREMIUM SPLASH
// ==========================================
data class MiniToolItem(
    val name: String,
    val icon: ImageVector,
    val color: Color,
    val desc: String
)

@Composable
fun SplashScreenView(viewModel: CreatorViewModel) {
    var currentStep by remember { mutableStateOf(1) }
    var loadProgress by remember { mutableStateOf(0f) }
    var isInitialized by remember { mutableStateOf(false) }
    val userStats by viewModel.userStats.collectAsState()

    // Simulating high-tech system initialization over 1500ms
    LaunchedEffect(isInitialized) {
        if (!isInitialized) {
            val duration = 1500L
            val steps = 100
            val stepDelay = duration / steps
            for (i in 0..steps) {
                loadProgress = i / 100f
                delay(stepDelay)
            }
            isInitialized = true
        }
    }

    // Centered logo breathing scale animation
    val infiniteTransition = rememberInfiniteTransition(label = "Splash_Animations")
    val logoScale by infiniteTransition.animateFloat(
        initialValue = 0.95f,
        targetValue = 1.05f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = 3000, easing = FastOutSlowInEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "Logo_Scale"
    )

    // Cinematic neon background glow pulsing speed
    val glowAlpha by infiniteTransition.animateFloat(
        initialValue = 0.35f,
        targetValue = 0.75f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = 2400, easing = LinearEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "Glow_Pulse"
    )

    // Rotation angle for gradient points to generate morphing atmospheric lighting
    val morphTime by infiniteTransition.animateFloat(
        initialValue = 0f,
        targetValue = 2f * Math.PI.toFloat(),
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = 12000, easing = LinearEasing),
            repeatMode = RepeatMode.Restart
        ),
        label = "Morph_Glow"
    )

    // Drift paths for floating background elements
    val driftY1 by infiniteTransition.animateFloat(
        initialValue = -12f,
        targetValue = 12f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = 4000, easing = FastOutSlowInEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "Drift_1"
    )
    val driftY2 by infiniteTransition.animateFloat(
        initialValue = 14f,
        targetValue = -14f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = 4600, easing = FastOutSlowInEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "Drift_2"
    )
    val driftY3 by infiniteTransition.animateFloat(
        initialValue = -8f,
        targetValue = 18f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = 5200, easing = FastOutSlowInEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "Drift_3"
    )

    val miniTools = remember {
        listOf(
            MiniToolItem("AI Chat", Icons.Filled.Chat, NeonCyan, "Cognitive GPT-4o"),
            MiniToolItem("Text to Image", Icons.Filled.Image, NeonPurple, "Flux & SDXL HD"),
            MiniToolItem("Image to Video", Icons.Filled.Movie, NeonBlue, "Luma Dream Motion"),
            MiniToolItem("Text to Video", Icons.Filled.Videocam, NeonCyan, "Veo 3 HyperMotion"),
            MiniToolItem("Voice Clone", Icons.Filled.RecordVoiceOver, NeonPurple, "ElevenLabs HD"),
            MiniToolItem("AI Tutor", Icons.Filled.School, NeonBlue, "Academy Hub"),
            MiniToolItem("PDF Chat", Icons.Filled.Description, NeonCyan, "Doc Insights"),
            MiniToolItem("Website Builder", Icons.Filled.Language, NeonPurple, "HTML5 Gen"),
            MiniToolItem("App Builder", Icons.Filled.DeveloperMode, NeonBlue, "Kotlin Compiler"),
            MiniToolItem("Coding Assistant", Icons.Filled.Code, NeonCyan, "Copilot AI Expert"),
            MiniToolItem("Research Agent", Icons.Filled.Psychology, NeonPurple, "Web DeepSearch"),
            MiniToolItem("Presentation Maker", Icons.Filled.Slideshow, NeonBlue, "Slide Deck Gen"),
            MiniToolItem("AI Thumbnail Maker", Icons.Filled.Brush, NeonCyan, "Vector Banner"),
            MiniToolItem("Video Editor", Icons.Filled.ContentCut, NeonPurple, "Trim Pro & SFX"),
            MiniToolItem("Personal AI Assistant", Icons.Filled.SupportAgent, NeonBlue, "Context Concierge")
        )
    }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(PureBlack)
            .drawBehind {
                val waveX = kotlin.math.sin(morphTime.toDouble()).toFloat()
                val waveY = kotlin.math.cos(morphTime.toDouble()).toFloat()
                
                // Bottom and top ambient colored dust glows
                drawCircle(
                    brush = Brush.radialGradient(
                        colors = listOf(NeonPurpleGlow.copy(alpha = glowAlpha * 0.28f), Color.Transparent),
                        center = Offset(
                            size.width * (0.25f + 0.05f * waveX),
                            size.height * (0.35f + 0.05f * waveY)
                        ),
                        radius = size.width * (0.85f + 0.05f * waveX)
                    )
                )
                drawCircle(
                    brush = Brush.radialGradient(
                        colors = listOf(NeonCyanGlow.copy(alpha = glowAlpha * 0.24f), Color.Transparent),
                        center = Offset(
                            size.width * (0.75f + 0.05f * waveY),
                            size.height * (0.65f + 0.05f * waveX)
                        ),
                        radius = size.width * (0.9f + 0.05f * waveY)
                    )
                )
            }
