                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = if (!isInitialized) "SYSTEM SCANNING" else "STEP $currentStep OF 2",
                    color = NeonCyan,
                    fontSize = 11.sp,
