                        ) {
                            Box(contentAlignment = Alignment.Center) {
                                androidx.compose.foundation.Image(
                                    painter = androidx.compose.ui.res.painterResource(id = com.example.R.drawable.ic_clip_ai_logo),
                                    contentDescription = "Clip AI Logo",
                                    modifier = Modifier.size(160.dp)
                                )
                            }
                            Spacer(modifier = Modifier.height(10.dp))
                            Box(
                                modifier = Modifier
                                    .width(130.dp)
                                    .height(2.5.dp)
                                    .background(
                                        Brush.horizontalGradient(
                                            listOf(Color.Transparent, NeonCyan, NeonPurple, Color.Transparent)
                                        )
                                    )
                            )
                        }

                        Spacer(modifier = Modifier.height(36.dp))

                        Text(
                            text = "ESTABLISHING NEURAL WORKSPACE... ${(loadProgress * 100).toInt()}%",
                            color = Color.LightGray.copy(alpha = 0.55f),
                            fontSize = 11.sp,
                            fontWeight = FontWeight.Bold,
                            letterSpacing = 2.sp,
                            textAlign = TextAlign.Center
                        )

                        Spacer(modifier = Modifier.height(16.dp))

                        // Modern progress bar
