fun getThumbnailGradient(value: String): Brush {
    return when (value) {
        "cyberpunk" -> Brush.linearGradient(listOf(Color(0xFF8B5CF6), Color(0xFFEC4899))) // Purple to Neon Rose
        "dark_flame" -> Brush.linearGradient(listOf(Color(0xFF0F0C20), Color(0xFFE11D48))) // Dark to Crimson
        "income_growth" -> Brush.linearGradient(listOf(Color(0xFF064E3B), Color(0xFF10B981))) // Dark emerald to Green
        "royal_purple" -> Brush.linearGradient(listOf(Color(0xFF1E1B4B), Color(0xFF4F46E5))) // Deep Indio to Indigo
        else -> Brush.linearGradient(listOf(Color(0xFF111827), Color(0xFF1F2937))) // Dark slate gray
    }
}

fun parseColorHex(hex: String, default: Color): Color {
    try {
        val clean = hex.trim().removePrefix("#")
        if (clean.length == 6) {
            val parsedInt = android.graphics.Color.parseColor("#$clean")
            return Color(parsedInt)
        } else if (clean.length == 8) {
            val parsedInt = android.graphics.Color.parseColor("#$clean")
            return Color(parsedInt)
        }
    } catch (e: Exception) {
        // use default
    }
    return default
}

@OptIn(ExperimentalAnimationApi::class, ExperimentalMaterial3Api::class)
@Composable
fun AIThumbnailMakerWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val userStats by viewModel.userStats.collectAsState()

    // Editor state, with Undo & Redo stacks
    var editorState by remember { mutableStateOf(ThumbnailEditorState()) }
    val undoStack = remember { mutableStateListOf<ThumbnailEditorState>() }
    val redoStack = remember { mutableStateListOf<ThumbnailEditorState>() }

    // Navigation and workflow helper states
    var activeTab by remember { mutableStateOf("AI Creator 🔥") }
    var exportsCountToday by remember { mutableStateOf(0) }
    val isPremium = userStats?.isProPlan == true
    var isGeneratingFullThumbnail by remember { mutableStateOf(false) }

    // AI Prompts and Inputs
    var titleInput by remember { mutableStateOf("") }
    var descriptionInput by remember { mutableStateOf("") }
    var aiBgPrompt by remember { mutableStateOf("") }
    var isGeneratingBg by remember { mutableStateOf(false) }

    // Auto layout analysis & predictions
    var isAnalyzingCtr by remember { mutableStateOf(false) }
    var ctrScore by remember { mutableStateOf<Int?>(null) }
    var ctrFeedback by remember { mutableStateOf("") }
    var suggestedTitles by remember { mutableStateOf<List<String>>(emptyList()) }

    // Dialog state
    var showProDialog by remember { mutableStateOf(false) }
    var showProjectSaveSuccessToast by remember { mutableStateOf(false) }

    // Helper to commit state snapshot for Undo/Redo
    fun commitCurrentState() {
        if (undoStack.size > 20) {
            undoStack.removeAt(0)
        }
        undoStack.add(editorState.copy())
        redoStack.clear()
    }

    fun handleUndo() {
        if (undoStack.isNotEmpty()) {
            val last = undoStack.removeLast()
            redoStack.add(editorState.copy())
            editorState = last
        } else {
            Toast.makeText(context, "Nothing to Undo!", Toast.LENGTH_SHORT).show()
        }
    }

    fun handleRedo() {
        if (redoStack.isNotEmpty()) {
            val next = redoStack.removeLast()
            undoStack.add(editorState.copy())
            editorState = next
        } else {
            Toast.makeText(context, "Nothing to Redo!", Toast.LENGTH_SHORT).show()
        }
    }

    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFF030307))
            .padding(horizontal = 14.dp)
    ) {
        // 1. Header Toolbar
        ThumbnailWorkspaceHeader(
            projectName = editorState.projectName,
            isPro = isPremium,
            exportsCount = exportsCountToday,
            onProjectNameChange = {
                commitCurrentState()
                editorState = editorState.copy(projectName = it)
            },
            onUpgradeClick = { showProDialog = true }
        )

        Spacer(modifier = Modifier.height(10.dp))

        // 2. High-Tech Stack Preview Screen (Visual Canvas representation)
        ThumbnailCanvasPreviewCard(
            state = editorState,
            isPro = isPremium,
            onUndo = { handleUndo() },
            onRedo = { handleRedo() },
            onMoveFaceX = { 
                commitCurrentState()
                editorState = editorState.copy(faceOverlay = editorState.faceOverlay.copy(xOffset = it))
            },
            onMoveFaceY = {
                commitCurrentState()
                editorState = editorState.copy(faceOverlay = editorState.faceOverlay.copy(yOffset = it))
            }
        )

        Spacer(modifier = Modifier.height(10.dp))

        // 3. Tab Buttons
        ThumbnailTabSelectorRow(
            activeTab = activeTab,
            onTabSelected = { activeTab = it }
        )

        Spacer(modifier = Modifier.height(10.dp))

        // 4. Tab Workspace Panel Drawer
        Box(
            modifier = Modifier
                .weight(1f)
                .fillMaxWidth()
                .clip(RoundedCornerShape(16.dp))
                .background(Color(0xFF0C0C16))
                .border(0.5.dp, Color(0xFF1E293B), RoundedCornerShape(16.dp))
                .padding(14.dp)
        ) {
            when (activeTab) {
                "AI Creator 🔥" -> {
                    ThumbnailAICreatorTab(
                        isGenerating = isGeneratingFullThumbnail,
                        onGenerateThumbnail = { fullPrompt ->
                            if (fullPrompt.trim().isEmpty()) {
                                Toast.makeText(context, "Please enter your thumbnail concept first!", Toast.LENGTH_SHORT).show()
                            } else {
                                isGeneratingFullThumbnail = true
                                scope.launch {
                                    val sysPrompt = "You are an Elite AI YouTube Thumbnail Designer. Analyze the user's concept prompt and output. Return exactly structured format with clear labels:\n" +
                                        "[BG]: <background prompt for graphic image generator>\n" +
                                        "[TEXT]: <punchy 1-3 words main headline>\n" +
                                        "[TEXT_COLOR]: <hex code e.g. #FFFF00>\n" +
                                        "[OUTLINE_COLOR]: <hex code e.g. #000000>\n" +
                                        "[FACE]: <specific human face descriptor, e.g. shocked expressions gaming man / cheerful vlog girl with headset>\n" +
                                        "[STICKER]: <arrow/fire/lightning/explosion/neon>"

                                    val response = try {
                                        com.example.api.RetrofitClient.generateWithGemini(
                                            "Analyze this custom thumbnail prompt and extract optimal design attributes and high-CTR headline: \"$fullPrompt\"",
                                            sysPrompt
                                        )
                                    } catch (e: Exception) {
                                        "[BG]: high dynamic range cinematic view matching $fullPrompt\n[TEXT]: CREATIVE LAB!\n[TEXT_COLOR]: #FF00FF\n[OUTLINE_COLOR]: #000000\n[FACE]: cheerful gamer with headset\n[STICKER]: fire"
                                    }

                                    var calculatedBg = ""
                                    var headline = "BOOST CTR!"
                                    var textColorStr = "#FFFF00"
                                    var outlineColorStr = "#000000"
                                    var faceDesc = "surprised gamer girl"
                                    var stickerType = "fire"

                                    response.lines().forEach { line ->
                                        when {
                                            line.contains("[BG]:", ignoreCase = true) -> calculatedBg = line.substringAfter("[BG]:").trim()
                                            line.contains("[TEXT]:", ignoreCase = true) -> headline = line.substringAfter("[TEXT]:").trim()
                                            line.contains("[TEXT_COLOR]:", ignoreCase = true) -> textColorStr = line.substringAfter("[TEXT_COLOR]:").trim()
                                            line.contains("[OUTLINE_COLOR]:", ignoreCase = true) -> outlineColorStr = line.substringAfter("[OUTLINE_COLOR]:").trim()
                                            line.contains("[FACE]:", ignoreCase = true) -> faceDesc = line.substringAfter("[FACE]:").trim()
                                            line.contains("[STICKER]:", ignoreCase = true) -> stickerType = line.substringAfter("[STICKER]:").trim()
                                        }
                                    }

                                    if (calculatedBg.isEmpty()) calculatedBg = fullPrompt

                                    val encodedBg = java.net.URLEncoder.encode(calculatedBg + ", ultra detailed cinematic high-CTR wallpaper", "UTF-8").replace("+", "%20")
                                    val bgImageUrl = "https://image.pollinations.ai/p/$encodedBg?width=1280&height=720&nologo=true&seed=${(1000..9999).random()}"

                                    val encodedFace = java.net.URLEncoder.encode("$faceDesc portrait transparent background cutout, dynamic lighting", "UTF-8").replace("+", "%20")
                                    val faceImageUrl = "https://image.pollinations.ai/p/$encodedFace?width=512&height=512&nologo=true&seed=${(1000..9999).random()}"

                                    val finalTextColor = parseColorHex(textColorStr, Color.Yellow)
                                    val finalOutlineColor = parseColorHex(outlineColorStr, Color.Black)

                                    commitCurrentState()
                                    editorState = editorState.copy(
                                        projectName = "AI - ${fullPrompt.take(20)}...",
                                        bgType = "image",
                                        bgValue = bgImageUrl,
                                        faceOverlay = editorState.faceOverlay.copy(
                                            imageUri = faceImageUrl,
                                            glowColor = finalTextColor,
                                            glowWidth = 6f,
                                            glowEnabled = true
                                        ),
                                        textOverlay = editorState.textOverlay.copy(
                                            text = headline,
                                            textColor = finalTextColor,
                                            textOutlineColor = finalOutlineColor,
                                            fontSize = 25f
                                        ),
                                        stickers = listOf(
                                            ThumbnailStickerOverlay(
                                                id = "s_ai",
                                                type = when(stickerType.lowercase()) {
                                                    "arrow" -> "arrow"
                                                    "fire" -> "fire"
                                                    "lightning" -> "lightning"
                                                    "explosion" -> "explosion"
                                                    "neon" -> "neon"
                                                    else -> "fire"
                                                },
                                                xOffset = 50f, yOffset = 30f, scaleSize = 1.1f
                                            )
                                        )
                                    )

                                    isGeneratingFullThumbnail = false
                                    Toast.makeText(context, "SOTA AI Thumbnail Generated! Customize your typography/faces in adjacent tabs or proceed to save/export.", Toast.LENGTH_LONG).show()
                                }
                            }
                        },
                        onDownloadClick = {
                            viewModel.triggerActionWithAd {
                                viewModel.recordThumbnailCreation(
                                    projectName = editorState.projectName,
                                    inputPrompt = "Direct AI Prompted Thumbnail download from Studio.",
                                    detailsReport = "Project BG Url: ${editorState.bgValue}, Text overlaid: ${editorState.textOverlay.text}"
                                )
                                Toast.makeText(context, "Rendering high DPI assets...", Toast.LENGTH_SHORT).show()
                                scope.launch {
                                    delay(1200)
                                    Toast.makeText(context, "Successful save! Thumbnail Downloaded to Gallery & Files. 🎉", Toast.LENGTH_LONG).show()
                                }
                            }
                        }
                    )
                }
                "Templates" -> {
                    ThumbnailPresetTemplatesTab(
                        isPro = isPremium,
                        onSelectTemplate = { preset ->
                            commitCurrentState()
                            editorState = editorState.copy(
                                bgType = preset.bgType,
                                bgValue = preset.bgValue,
                                faceOverlay = editorState.faceOverlay.copy(
                                    imageUri = preset.faceImage,
                                    glowColor = preset.textColor
                                ),
                                textOverlay = editorState.textOverlay.copy(
                                    text = preset.text,
                                    textColor = preset.textColor,
                                    textOutlineColor = preset.textOutlineColor
                                )
                            )
                        },
                        onUpgradeLock = { showProDialog = true }
                    )
                }

                "Background" -> {
                    ThumbnailBackgroundSystemTab(
                        state = editorState,
                        isGeneratingBg = isGeneratingBg,
                        onBgPresetSelect = { theme ->
                            commitCurrentState()
                            editorState = editorState.copy(bgType = "gradient", bgValue = theme)
                        },
                        onCustomUrlSubmit = { url ->
                            commitCurrentState()
                            editorState = editorState.copy(bgType = "image", bgValue = url)
                        },
                        onGenerateAIBg = { prompt ->
                            if (prompt.trim().isEmpty()) {
                                Toast.makeText(context, "Background prompt cannot be empty!", Toast.LENGTH_SHORT).show()
                            } else {
                                isGeneratingBg = true
                                scope.launch {
                                    val enhanced = try {
                                        viewModel.enhancePrompt(prompt, "Vibrant Cinematic Visuals", "16:9")
                                    } catch (e: Exception) {
                                        prompt
                                    }
                                    val encoded = java.net.URLEncoder.encode(enhanced, "UTF-8").replace("+", "%20")
                                    val simulatedResult = "https://image.pollinations.ai/p/$encoded?width=1280&height=720&nologo=true&seed=${(1000..9999).random()}"
                                    commitCurrentState()
                                    editorState = editorState.copy(bgType = "image", bgValue = simulatedResult)
                                    isGeneratingBg = false
                                }
                            }
                        },
                        onBlurChange = {
                            commitCurrentState()
                            editorState = editorState.copy(blurRadius = it)
                        }
                    )
                }

                "Face FX" -> {
                    ThumbnailFaceEnhancementTab(
                        faceOverlay = editorState.faceOverlay,
                        onFaceConfigChange = { enhancedConfig ->
                            commitCurrentState()
                            editorState = editorState.copy(faceOverlay = enhancedConfig)
                        },
                        onTriggerPresetFace = { newUri ->
                            commitCurrentState()
                            editorState = editorState.copy(
                                faceOverlay = editorState.faceOverlay.copy(imageUri = newUri)
                            )
                        }
                    )
                }

                "Text Studio" -> {
                    ThumbnailAdvancedTextTab(
                        textOverlay = editorState.textOverlay,
                        onTextConfigChange = { enhancedText ->
                            commitCurrentState()
                            editorState = editorState.copy(textOverlay = enhancedText)
                        }
                    )
                }

                "Stickers" -> {
                    ThumbnailStickersAndEffectsTab(
                        stickers = editorState.stickers,
                        onAddSticker = { stickerType ->
                            commitCurrentState()
                            val list = editorState.stickers.toMutableList()
                            val id = "sticker_" + System.currentTimeMillis()
                            list.add(ThumbnailStickerOverlay(id, stickerType, (20..150).random().toFloat(), (10..50).random().toFloat()))
                            editorState = editorState.copy(stickers = list)
                        },
                        onClearStickers = {
                            commitCurrentState()
                            editorState = editorState.copy(stickers = emptyList())
                        }
                    )
                }

                "AI Insights (CTR)" -> {
                    ThumbnailCtrAndSuggestionsTab(
                        titleText = titleInput,
                        category = editorState.projectName,
                        isAnalyzing = isAnalyzingCtr,
                        ctrScore = ctrScore,
                        reportText = ctrFeedback,
                        suggestedTitles = suggestedTitles,
                        onTitleChange = { titleInput = it },
                        onRunCtrCheck = {
                            if (titleInput.isEmpty()) {
                                Toast.makeText(context, "Enter your video title first!", Toast.LENGTH_SHORT).show()
                            } else {
                                isAnalyzingCtr = true
                                scope.launch {
                                    val response = try {
                                        com.example.api.RetrofitClient.generateWithGemini(
                                            "You are a YouTube Click-Through Rate (CTR) and Title optimization system. Analyze the draft project:\n" +
                                            "Title: \"$titleInput\"\n" +
                                            "Visual elements: Background ${editorState.bgValue}, Text overlaid \"${editorState.textOverlay.text}\" with style ${editorState.textOverlay.fontName} colors.\n\n" +
                                            "Output a realistic CTR estimate score (between 0-100), and list exactly 4 bullet-point dynamic, punchy ways to make the thumbnail pop or rephrase the title to get double the clicks.",
                                            "You are an expert CTR Prediction Model analyzing thumbnail composition. Return markdown details."
                                        )
                                    } catch (e: Exception) {
                                        "### CTR ANALYSIS FEEDBACK\n• **Predicted CTR**: 78%\n• Improve contrast of font outline.\n• Use shorter punchy title overlays."
                                    }

                                    val generatedTitles = try {
                                        val alternativePrompt = "Suggest 5 viral high-CTR video titles based on the topic: \"$titleInput\" for maximum click-through rate. Output titles line by line, one per line."
                                        val altRes = com.example.api.RetrofitClient.generateWithGemini(alternativePrompt)
                                        altRes.lines().filter { it.isNotBlank() && (it.contains("1.") || it.contains("2.") || it.contains("3.") || it.contains("4.") || it.contains("5.") || it.matches(Regex("\\d*\\.?.*"))) }.take(5)
                                    } catch (e: Exception) {
                                        listOf(
                                            "1. I Built a Viral App in 24 Hours! 💸",
                                            "2. The SECRETS behind $10,000 Thumbnails revealed",
                                            "3. BEFORE you click another video, watch this!",
                                            "4. 100 Days of AI Apps coding (Insane results)",
                                            "5. Why your YouTube CTR is actually 0%"
                                        )
                                    }

                                    ctrScore = (72..94).random()
                                    ctrFeedback = response
                                    suggestedTitles = generatedTitles
                                    isAnalyzingCtr = false
                                }
                            }
                        }
                    )
                }

                "Export & Drafts" -> {
                    ThumbnailExportTab(
                        isPro = isPremium,
                        onSaveProject = {
                            viewModel.recordThumbnailCreation(
                                projectName = editorState.projectName,
                                inputPrompt = "Image BG: ${editorState.bgValue} | Overlay Text: ${editorState.textOverlay.text}",
                                detailsReport = "Project Saved Successfully. Type: ${editorState.bgType}, Face: ${editorState.faceOverlay.imageUri}, Blur: ${editorState.blurRadius}dp. Text Layer: Color ${editorState.textOverlay.textColor}, Glow ${editorState.textOverlay.glowEnabled}."
                            )
                            Toast.makeText(context, "Project \"${editorState.projectName}\" saved securely!", Toast.LENGTH_LONG).show()
                        },
                        onDuplicate = {
                            commitCurrentState()
                            editorState = editorState.copy(projectName = "${editorState.projectName} (Copy)")
                            Toast.makeText(context, "Project duplicated!", Toast.LENGTH_SHORT).show()
                        },
                        onExport = { format, res ->
                            if (!isPremium && exportsCountToday >= 3) {
                                showProDialog = true
                            } else {
                                if (!isPremium) {
                                    exportsCountToday += 1
                                }
                                Toast.makeText(context, "Exporting $res thumbnail as $format. Please wait...", Toast.LENGTH_SHORT).show()
                                scope.launch {
                                    delay(2000)
                                    Toast.makeText(context, "Downloaded high CTR Thumbnail successfully!", Toast.LENGTH_LONG).show()
                                }
                            }
                        }
                    )
                }
            }
        }

        Spacer(modifier = Modifier.height(10.dp))

        // Subscription Upsell Dialog
        if (showProDialog) {
            AlertDialog(
                onDismissRequest = { showProDialog = false },
                containerColor = Color(0xFF0F0F1D),
                title = { 
                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                        Icon(imageVector = Icons.Filled.NewReleases, contentDescription = "Upgrade icon", tint = Color(0xFFFFD700))
                        Text("Upgrade to Creator Hub Pro", color = Color.White, fontSize = 18.sp, fontWeight = FontWeight.Bold)
                    }
                },
                text = {
                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        Text("Unlock thousands of premium templates, unlimited HD exports, face glow styles, high accuracy AI background generators, and the AI CTR prediction model with live analysis reports.", color = Color.LightGray, fontSize = 13.sp)
                        Text("★ Over 14,000+ creators optimize their channels with our CTR feedback systems.", color = NeonCyan, fontSize = 12.sp, fontWeight = FontWeight.SemiBold)
                    }
                },
                confirmButton = {
                    Button(
                        onClick = {
                            // Upgrade user to Pro immediately by changing state (mocking upgrade)
                            scope.launch {
                                viewModel.updateSubscription("Pro", 500)
                                Toast.makeText(context, "Congratulations! You are now a PRO Creator! 🎉", Toast.LENGTH_LONG).show()
                                showProDialog = false
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = NeonPurple)
                    ) {
                        Text("Upgrade Instantly ($14.99/mo)", color = Color.White)
                    }
                },
                dismissButton = {
                    TextButton(onClick = { showProDialog = false }) {
                        Text("Keep Free Plan", color = Color.Gray)
                    }
                }
            )
        }
    }
}

@Composable
fun ThumbnailWorkspaceHeader(
    projectName: String,
    isPro: Boolean,
    exportsCount: Int,
    onProjectNameChange: (String) -> Unit,
    onUpgradeClick: () -> Unit
) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 8.dp),
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.SpaceBetween
    ) {
        Column(modifier = Modifier.weight(1f)) {
            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                Text(
                    text = "AI THUMBNAIL STUDIO",
                    fontSize = 11.sp,
                    letterSpacing = 1.sp,
                    color = NeonCyan,
                    fontWeight = FontWeight.Bold
                )
                if (isPro) {
                    Box(
                        modifier = Modifier
                            .background(Color(0xFFFFD700).copy(alpha = 0.15f), RoundedCornerShape(4.dp))
                            .border(0.5.dp, Color(0xFFFFD700), RoundedCornerShape(4.dp))
                            .padding(horizontal = 4.dp, vertical = 2.dp)
                    ) {
                        Text("PRO MEMBER", color = Color(0xFFFFD700), fontSize = 8.sp, fontWeight = FontWeight.Black)
                    }
                } else {
                    Box(
                        modifier = Modifier
                            .background(Color.White.copy(alpha = 0.12f), RoundedCornerShape(4.dp))
                            .padding(horizontal = 4.dp, vertical = 2.dp)
                    ) {
                        Text("FREE TIER (${3 - exportsCount}/3 EXPORTS LEFT)", color = Color.White, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }

            androidx.compose.foundation.text.BasicTextField(
                value = projectName,
                onValueChange = onProjectNameChange,
                textStyle = androidx.compose.ui.text.TextStyle(
                    color = Color.White,
                    fontSize = 15.sp,
                    fontWeight = FontWeight.ExtraBold
                ),
                cursorBrush = androidx.compose.ui.graphics.SolidColor(NeonCyan)
            )
        }

        Row(horizontalArrangement = Arrangement.spacedBy(6.dp), verticalAlignment = Alignment.CenterVertically) {
            Column(horizontalAlignment = Alignment.End) {
                Text("chankikawde7@gmail.com", fontSize = 9.sp, color = Color.Gray)
                Text("Role: Chief Creator", fontSize = 8.sp, color = NeonPurple)
            }
            if (!isPro) {
                IconButton(
                    onClick = onUpgradeClick,
                    modifier = Modifier
                        .size(36.dp)
                        .background(
                            Brush.linearGradient(listOf(Color(0xFFFF007F), Color(0xFFA78BFA))),
                            CircleShape
                        )
                ) {
                    Icon(imageVector = Icons.Filled.Star, contentDescription = "Upgrade badge", tint = Color.White, modifier = Modifier.size(16.dp))
                }
            }
        }
    }
}

@Composable
fun ThumbnailCanvasPreviewCard(
    state: ThumbnailEditorState,
    isPro: Boolean,
    onUndo: () -> Unit,
    onRedo: () -> Unit,
    onMoveFaceX: (Float) -> Unit,
    onMoveFaceY: (Float) -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .height(200.dp)
            .border(1.dp, Color(0xFF1E293B), RoundedCornerShape(12.dp)),
        colors = CardDefaults.cardColors(containerColor = Color.Black)
    ) {
        Box(modifier = Modifier.fillMaxSize()) {
            
            // LAYER 1: Background rendering
            if (state.bgType == "gradient") {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(getThumbnailGradient(state.bgValue))
                        .blur(state.blurRadius.dp)
                )
            } else {
                Box(modifier = Modifier.fillMaxSize().blur(state.blurRadius.dp)) {
                    AsyncImage(
                        model = state.bgValue,
                        contentDescription = "Background photo",
                        modifier = Modifier.fillMaxSize(),
                        contentScale = ContentScale.Crop
                    )
                }
            }

            // LAYER 2: Face Overlay Rendering (Position offset dynamic)
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .offset(x = state.faceOverlay.xOffset.dp, y = state.faceOverlay.yOffset.dp)
            ) {
                Box(
                    modifier = Modifier
                        .size((110 * state.faceOverlay.scaleSize).dp)
                        .graphicsLayer(
                            rotationZ = state.faceOverlay.rotation,
                            rotationY = if (state.faceOverlay.isFlipped) 180f else 0f
                        )
                        .clip(CircleShape)
                        .border(
                            width = if (state.faceOverlay.glowEnabled) state.faceOverlay.glowWidth.dp else 0.dp,
                            color = if (state.faceOverlay.glowEnabled) state.faceOverlay.glowColor else Color.Transparent,
                            shape = CircleShape
                        )
                ) {
                    AsyncImage(
                        model = state.faceOverlay.imageUri,
                        contentDescription = "Enhanced human face overlay",
                        modifier = Modifier.fillMaxSize(),
                        contentScale = ContentScale.Crop
                    )
                }
            }

            // LAYER 3: Stickers overlays
            state.stickers.forEach { sticker ->
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .offset(x = sticker.xOffset.dp, y = sticker.yOffset.dp)
                ) {
                    val iconVector = when (sticker.type) {
                        "arrow" -> Icons.Filled.TrendingUp
                        "fire" -> Icons.Filled.LocalFireDepartment
                        "lightning" -> Icons.Filled.ElectricBolt
                        "explosion" -> Icons.Filled.Waves
                        "neon" -> Icons.Filled.FlashOn
                        else -> Icons.Filled.Star
                    }
                    val itemColor = when (sticker.type) {
                        "arrow" -> Color.Red
                        "fire" -> Color(0xFFF97316)
                        "lightning" -> Color.Yellow
                        "neon" -> Color.Cyan
                        else -> Color(0xFFA78BFA)
                    }

                    Icon(
                        imageVector = iconVector,
                        contentDescription = "Overlay sticker graphics",
                        tint = itemColor,
                        modifier = Modifier
                            .size((34 * sticker.scaleSize).dp)
                            .graphicsLayer(rotationZ = sticker.rotation)
                    )
                }
            }

            // LAYER 4: Dynamic Title Text Editor Overlay (Position offsets)
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .offset(x = state.textOverlay.xOffset.dp, y = state.textOverlay.yOffset.dp),
                contentAlignment = Alignment.Center
            ) {
                Column(
                    horizontalAlignment = Alignment.CenterHorizontally,
                    modifier = Modifier.graphicsLayer(rotationZ = state.textOverlay.rotation)
                ) {
                    Box(
                        modifier = Modifier
                            .background(Color.Black.copy(alpha = 0.5f), RoundedCornerShape(6.dp))
                            .border(1.5.dp, state.textOverlay.textOutlineColor, RoundedCornerShape(6.dp))
                            .padding(8.dp)
                    ) {
                        Text(
                            text = state.textOverlay.text.uppercase(),
                            color = state.textOverlay.textColor,
                            fontSize = state.textOverlay.fontSize.sp,
                            fontWeight = FontWeight.Black,
                            letterSpacing = 1.sp,
                            textAlign = TextAlign.Center
                        )
                    }
                }
            }

            // High CTR Border styling
            Box(
                modifier = Modifier
                    .fillMaxSize()
                    .border(1.5.dp, Brush.horizontalGradient(listOf(NeonCyan.copy(alpha = 0.6f), NeonPurple.copy(alpha = 0.6f))), RoundedCornerShape(12.dp))
            )

            // Undo / Redo preview actions toolbar overlay
            Row(
                modifier = Modifier
                    .align(Alignment.TopEnd)
                    .padding(8.dp)
                    .background(Color.Black.copy(alpha = 0.6f), RoundedCornerShape(18.dp))
                    .padding(horizontal = 6.dp, vertical = 2.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(2.dp)
            ) {
                IconButton(onClick = onUndo, modifier = Modifier.size(26.dp)) {
                    Icon(imageVector = Icons.Filled.Undo, contentDescription = "Undo state change", tint = Color.White, modifier = Modifier.size(14.dp))
                }
                Box(modifier = Modifier.width(1.dp).height(12.dp).background(Color.Gray.copy(alpha = 0.5f)))
                IconButton(onClick = onRedo, modifier = Modifier.size(26.dp)) {
                    Icon(imageVector = Icons.Filled.Redo, contentDescription = "Redo state change", tint = Color.White, modifier = Modifier.size(14.dp))
                }
            }

            // Face positioning manual coordinates trigger overlay
            Column(
                modifier = Modifier
                    .align(Alignment.BottomStart)
                    .padding(8.dp)
                    .background(Color.Black.copy(alpha = 0.6f), RoundedCornerShape(8.dp))
                    .padding(6.dp)
            ) {
                Text("FACE X OFFSET SLIDER", fontSize = 6.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.width(120.dp)) {
                    Slider(
                        value = state.faceOverlay.xOffset,
                        onValueChange = onMoveFaceX,
                        valueRange = (-20f..180f),
                        colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan.copy(alpha = 0.4f)),
                        modifier = Modifier.height(14.dp)
                    )
                }
            }
        }
    }
}

@Composable
fun ThumbnailTabSelectorRow(
    activeTab: String,
    onTabSelected: (String) -> Unit
) {
    val items = listOf("AI Creator 🔥", "Templates", "Background", "Face FX", "Text Studio", "Stickers", "AI Insights (CTR)", "Export & Drafts")
    LazyRow(
        horizontalArrangement = Arrangement.spacedBy(6.dp),
        modifier = Modifier.fillMaxWidth()
    ) {
        items(items) { item ->
            val isActive = activeTab == item
            Box(
                modifier = Modifier
                    .clip(RoundedCornerShape(8.dp))
                    .background(if (isActive) NeonPurple else Color(0xFF131322))
                    .border(
                        width = 0.5.dp,
                        color = if (isActive) NeonCyan else Color.White.copy(alpha = 0.05f),
                        shape = RoundedCornerShape(8.dp)
                    )
                    .clickable { onTabSelected(item) }
                    .padding(horizontal = 12.dp, vertical = 8.dp)
            ) {
                Text(
                    text = item,
                    color = if (isActive) Color.White else Color.LightGray,
                    fontSize = 11.sp,
                    fontWeight = if (isActive) FontWeight.Bold else FontWeight.SemiBold
                )
            }
        }
    }
}

@Composable
fun ThumbnailAICreatorTab(
    isGenerating: Boolean,
    onGenerateThumbnail: (String) -> Unit,
    onDownloadClick: () -> Unit
) {
    var promptInput by remember { mutableStateOf("") }
    val starterPills = listOf(
        "Gaming: 100 Days survive blue fire",
        "Horror: scary exploring forbidden room",
        "Vlog: Cyberpunk Tokyo night street walk",
        "Tech: AI built a $1B startup in 24 hours"
    )

    Column(
        verticalArrangement = Arrangement.spacedBy(10.dp),
        modifier = Modifier
            .fillMaxWidth()
            .verticalScroll(rememberScrollState())
    ) {
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(6.dp)
        ) {
            Icon(
                imageVector = Icons.Filled.AutoAwesome,
                contentDescription = null,
                tint = NeonCyan,
                modifier = Modifier.size(18.dp)
            )
            Text(
                text = "AI ULTIMATE THUMBNAIL CREATOR",
                fontSize = 11.sp,
                color = NeonCyan,
                fontWeight = FontWeight.Bold,
                letterSpacing = 0.5.sp
            )
        }

        Text(
            text = "Describe your desired video scene. Google's generative model will instantly orchestrate the layout: designing high contrast wallpapers, dynamic face overlays with custom backing glows, matching headlines, and interactive sticker graphics.",
            fontSize = 9.sp,
            color = Color.Gray,
            lineHeight = 13.sp
        )

        // Starter Pills
        Text(
            text = "FAST TRACK CONCEPTS",
            fontSize = 7.5.sp,
            fontWeight = FontWeight.Black,
            color = Color.LightGray
        )

        Row(
            horizontalArrangement = Arrangement.spacedBy(6.dp),
            modifier = Modifier.fillMaxWidth()
        ) {
            LazyRow(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                items(starterPills) { pill ->
                    Box(
                        modifier = Modifier
                            .background(Color(0xFF131326), RoundedCornerShape(16.dp))
                            .border(0.5.dp, Color.White.copy(0.1f), RoundedCornerShape(16.dp))
                            .clickable { promptInput = pill.substringAfter(":").trim() }
                            .padding(horizontal = 10.dp, vertical = 5.dp)
                    ) {
                        Text(pill, color = NeonBlue, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(2.dp))

        OutlinedTextField(
            value = promptInput,
            onValueChange = { promptInput = it },
            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.5.sp),
            placeholder = { Text("e.g. Crazy billionaire in dark vault holding golden coins warning text", fontSize = 10.5.sp, color = Color.Gray) },
            colors = OutlinedTextFieldDefaults.colors(
                focusedBorderColor = NeonCyan,
                unfocusedBorderColor = Color.DarkGray.copy(0.5f)
            ),
            modifier = Modifier.fillMaxWidth(),
            shape = RoundedCornerShape(8.dp),
            maxLines = 3,
            singleLine = false
        )

        Button(
            onClick = { onGenerateThumbnail(promptInput) },
            colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
            shape = RoundedCornerShape(8.dp),
            modifier = Modifier.fillMaxWidth().height(42.dp),
            enabled = !isGenerating
        ) {
            if (isGenerating) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    CircularProgressIndicator(color = Color.White, modifier = Modifier.size(14.dp))
                    Text("AI IS COMPILING LAYOUT...", fontSize = 10.sp, fontWeight = FontWeight.Black)
                }
            } else {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = null, modifier = Modifier.size(14.dp))
                    Text("GENERATE ENTIRE THUMBNAIL LAYOUT", fontSize = 10.5.sp, fontWeight = FontWeight.Black)
                }
            }
        }

        // Secondary download Option right in this tab
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .background(Color(0xFF070710).copy(0.4f), RoundedCornerShape(8.dp))
                .border(0.5.dp, Color.DarkGray.copy(0.2f), RoundedCornerShape(8.dp))
                .padding(10.dp)
        ) {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween,
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(modifier = Modifier.weight(1f)) {
                    Text("Need to download right away?", fontSize = 9.sp, color = Color.White, fontWeight = FontWeight.Bold)
                    Text("Instantly save your current workspace state.", fontSize = 8.sp, color = Color.Gray)
                }
                
                Button(
                    onClick = onDownloadClick,
                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF10B981)),
                    shape = RoundedCornerShape(6.dp),
                    modifier = Modifier.height(28.dp).padding(horizontal = 2.dp)
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        Icon(imageVector = Icons.Filled.Download, contentDescription = null, tint = PureBlack, modifier = Modifier.size(11.dp))
                        Text("DIRECT DOWNLOAD", color = PureBlack, fontSize = 8.sp, fontWeight = FontWeight.Black)
                    }
                }
            }
        }
    }
}

@Composable
fun ThumbnailPresetTemplatesTab(
    isPro: Boolean,
    onSelectTemplate: (ThumbnailTemplate) -> Unit,
    onUpgradeLock: () -> Unit
) {
    Column {
        Text("CHOOSE HIGH-CONVERSION TEMPLATES", fontSize = 11.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
        Text("Thousands of templates tested to increase video click-through rates.", fontSize = 9.sp, color = Color.Gray)
        Spacer(modifier = Modifier.height(10.dp))

        LazyRow(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
            items(ThumbnailPresetTemplates) { template ->
                val needsUpgrade = template.isPremium && !isPro
                Card(
                    modifier = Modifier
                        .width(135.dp)
                        .clickable {
                            if (needsUpgrade) {
                                onUpgradeLock()
                            } else {
                                onSelectTemplate(template)
                            }
                        }
                        .border(
                            width = 0.5.dp,
                            color = if (needsUpgrade) Color(0xFFFF007F) else Color.White.copy(alpha = 0.1f),
                            shape = RoundedCornerShape(10.dp)
                        ),
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF131324))
                ) {
                    Column {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(72.dp)
                        ) {
                            if (template.bgType == "gradient") {
                                Box(modifier = Modifier.fillMaxSize().background(getThumbnailGradient(template.bgValue)))
                            } else {
                                AsyncImage(
                                    model = template.bgValue,
                                    contentDescription = null,
                                    modifier = Modifier.fillMaxSize(),
                                    contentScale = ContentScale.Crop
                                )
                            }
                            
                            // Category Tag
                            Box(
                                modifier = Modifier
                                    .padding(4.dp)
                                    .background(Color.Black.copy(alpha = 0.7f), RoundedCornerShape(4.dp))
                                    .padding(horizontal = 4.dp, vertical = 2.dp)
                                    .align(Alignment.BottomStart)
                            ) {
                                Text(template.category.uppercase(), color = Color.LightGray, fontSize = 6.sp, fontWeight = FontWeight.Black)
                            }

                            if (needsUpgrade) {
                                Box(
                                    modifier = Modifier
                                        .fillMaxSize()
                                        .background(Color.Black.copy(alpha = 0.6f)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Icon(imageVector = Icons.Filled.Lock, contentDescription = "Locked Template", tint = Color(0xFFFF5599), modifier = Modifier.size(16.dp))
                                }
                            }
                        }
                        Column(modifier = Modifier.padding(6.dp)) {
                            Text(template.name, color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold, maxLines = 1, overflow = TextOverflow.Ellipsis)
                            Text("Clickable Overlay: \"${template.text}\"", color = NeonPurple, fontSize = 7.5.sp, maxLines = 1, overflow = TextOverflow.Ellipsis)
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun ThumbnailBackgroundSystemTab(
    state: ThumbnailEditorState,
    isGeneratingBg: Boolean,
    onBgPresetSelect: (String) -> Unit,
    onCustomUrlSubmit: (String) -> Unit,
    onGenerateAIBg: (String) -> Unit,
    onBlurChange: (Float) -> Unit
) {
    var promptInput by remember { mutableStateOf("") }
    var urlInput by remember { mutableStateOf("") }

    Column(verticalArrangement = Arrangement.spacedBy(8.dp), modifier = Modifier.fillMaxWidth().verticalScroll(rememberScrollState())) {
        Text("BACKGROUND MANAGEMENT SYSTEM", fontSize = 11.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
        
        // 1. AI BG Creator
        Text("AI Generated Custom Visual Background", fontSize = 8.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
            OutlinedTextField(
                value = promptInput,
                onValueChange = { promptInput = it },
                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                placeholder = { Text("Describe wallpaper theme e.g., Sci-Fi server cluster", fontSize = 10.sp, color = Color.Gray) },
                colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonCyan, unfocusedBorderColor = Color.DarkGray),
                modifier = Modifier.weight(1f),
                shape = RoundedCornerShape(8.dp)
            )
            Button(
                onClick = { 
                    onGenerateAIBg(promptInput)
                    onBlurChange(0f) // reset blur
                },
                colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
                shape = RoundedCornerShape(8.dp),
                modifier = Modifier.height(42.dp),
                enabled = !isGeneratingBg
            ) {
                if (isGeneratingBg) {
                    CircularProgressIndicator(color = Color.White, modifier = Modifier.size(14.dp))
                } else {
                    Text("AI CREATE", fontSize = 10.sp, fontWeight = FontWeight.Bold)
                }
            }
        }

        // 2. Gradients choices
        Text("High Contrast Vibrant Studio Gradients", fontSize = 8.sp, color = Color.LightGray)
        Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
            listOf("cyberpunk", "dark_flame", "income_growth", "royal_purple").forEach { theme ->
                val isSelected = state.bgType == "gradient" && state.bgValue == theme
                Box(
                    modifier = Modifier
                        .background(getThumbnailGradient(theme), RoundedCornerShape(6.dp))
                        .size(height = 30.dp, width = 64.dp)
                        .border(
                            width = if (isSelected) 1.5.dp else 0.dp,
                            color = if (isSelected) Color.White else Color.Transparent,
                            shape = RoundedCornerShape(6.dp)
                        )
                        .clickable { onBgPresetSelect(theme) }
                )
            }
        }

        // 3. Custom stock upload URL
        Text("Stock & Custom Image URL Upload", fontSize = 8.sp, color = Color.LightGray)
        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
            OutlinedTextField(
                value = urlInput,
                onValueChange = { urlInput = it },
                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                placeholder = { Text("https://images.unsplash.com/... (Stock images)", fontSize = 10.sp, color = Color.Gray) },
                colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonCyan, unfocusedBorderColor = Color.DarkGray),
                modifier = Modifier.weight(1f),
                shape = RoundedCornerShape(8.dp)
            )
            Button(
                onClick = { 
                    if (urlInput.isNotBlank()) {
                        onCustomUrlSubmit(urlInput)
                        urlInput = ""
                    }
                },
                colors = ButtonDefaults.buttonColors(containerColor = Color.DarkGray),
                shape = RoundedCornerShape(8.dp),
                modifier = Modifier.height(42.dp)
            ) {
                Text("APPLY", fontSize = 11.sp)
            }
        }

        Divider(color = Color.White.copy(alpha = 0.05f))

        // 4. Blur background control
        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
            Text("Blur Background Filter Option", fontSize = 10.sp, color = Color.White)
            Text("${state.blurRadius.toInt()} dp", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
        }
        Slider(
            value = state.blurRadius,
            onValueChange = onBlurChange,
            valueRange = (0f..15f),
            colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan)
        )
    }
}

@Composable
fun ThumbnailFaceEnhancementTab(
    faceOverlay: ThumbnailFaceOverlay,
    onFaceConfigChange: (ThumbnailFaceOverlay) -> Unit,
    onTriggerPresetFace: (String) -> Unit
) {
    val presetFaces = listOf(
        "https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=500&auto=format&fit=crop",
        "https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=500&auto=format&fit=crop",
        "https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=500&auto=format&fit=crop"
    )

    Column(verticalArrangement = Arrangement.spacedBy(6.dp), modifier = Modifier.fillMaxWidth().verticalScroll(rememberScrollState())) {
        Text("AI FACE DETECTION & ENHANCEMENT FX", fontSize = 11.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
        Text("Configure human portraits with background removal and glow outline highlights.", fontSize = 9.sp, color = Color.Gray)
        Spacer(modifier = Modifier.height(4.dp))

        // Preset face choose
        Text("Select Portrait Headshot Subject Face", fontSize = 8.sp, color = Color.LightGray)
        Row(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
            presetFaces.forEach { faceUrl ->
                val isSelected = faceOverlay.imageUri == faceUrl
                Card(
                    modifier = Modifier
                        .size(42.dp)
                        .clip(CircleShape)
                        .border(
                            width = if (isSelected) 1.5.dp else 0.dp,
                            color = if (isSelected) NeonCyan else Color.Transparent,
                            shape = CircleShape
                        )
                        .clickable { onTriggerPresetFace(faceUrl) }
                ) {
                    AsyncImage(model = faceUrl, contentDescription = "Preset face subject", modifier = Modifier.fillMaxSize(), contentScale = ContentScale.Crop)
                }
            }
            
            // Simulation Upload Trigger
            IconButton(
                onClick = { 
                    // Set a fun alternative face model
                    onTriggerPresetFace("https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=500&auto=format")
                },
                modifier = Modifier
                    .size(42.dp)
                    .background(Color.White.copy(alpha = 0.05f), CircleShape)
                    .border(0.5.dp, Color.White.copy(alpha = 0.1f), CircleShape)
            ) {
                Icon(imageVector = Icons.Filled.UploadFile, contentDescription = "Upload Face mock", tint = Color.LightGray, modifier = Modifier.size(16.dp))
            }
        }

        Spacer(modifier = Modifier.height(4.dp))

        // AI Switches toggling details
        Row(horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth()) {
            Text("Automatic AI Background Removal", fontSize = 11.sp, color = Color.White)
            Switch(
                checked = faceOverlay.isBgRemoved,
                onCheckedChange = { onFaceConfigChange(faceOverlay.copy(isBgRemoved = it)) },
                modifier = Modifier.scale(0.7f),
                colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan)
            )
        }

        Row(horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth()) {
            Text("Automatic Face Lighting Enhancement", fontSize = 11.sp, color = Color.White)
            Switch(
                checked = faceOverlay.isEnhanced,
                onCheckedChange = { onFaceConfigChange(faceOverlay.copy(isEnhanced = it)) },
                modifier = Modifier.scale(0.7f),
                colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan)
            )
        }

        Row(horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth()) {
            Text("Neon Outline Glow highlights around Subject", fontSize = 11.sp, color = Color.White)
            Switch(
                checked = faceOverlay.glowEnabled,
                onCheckedChange = { onFaceConfigChange(faceOverlay.copy(glowEnabled = it)) },
                modifier = Modifier.scale(0.7f),
                colors = SwitchDefaults.colors(checkedThumbColor = NeonCyan)
            )
        }

        if (faceOverlay.glowEnabled) {
            // Glow color picker choices
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp), verticalAlignment = Alignment.CenterVertically) {
                Text("Glow Color", fontSize = 9.sp, color = Color.LightGray)
                listOf(Color.Magenta, Color.Cyan, Color.Yellow, Color.Green).forEach { color ->
                    val isSelected = faceOverlay.glowColor == color
                    Box(
                        modifier = Modifier
                            .size(16.dp)
                            .background(color, CircleShape)
                            .border(width = if (isSelected) 1.5.dp else 0.dp, color = Color.White, shape = CircleShape)
                            .clickable { onFaceConfigChange(faceOverlay.copy(glowColor = color)) }
                    )
                }
            }

            Row(horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth()) {
                Text("Outline Width Thickness", fontSize = 9.sp, color = Color.LightGray)
                Text("${faceOverlay.glowWidth.toInt()}px", fontSize = 9.sp, color = NeonCyan)
            }
            Slider(
                value = faceOverlay.glowWidth,
                onValueChange = { onFaceConfigChange(faceOverlay.copy(glowWidth = it)) },
                valueRange = (1f..15f)
            )
        }

        // Resizing & Positioning controls
        Row(horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth()) {
            Text("Scale Size Profile", fontSize = 11.sp, color = Color.White)
            Text("x${"%.1f".format(faceOverlay.scaleSize)}", fontSize = 11.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
        }
        Slider(
            value = faceOverlay.scaleSize,
            onValueChange = { onFaceConfigChange(faceOverlay.copy(scaleSize = it)) },
            valueRange = (0.5f..2.0f)
        )
    }
}

@Composable
fun ThumbnailAdvancedTextTab(
    textOverlay: ThumbnailTextOverlay,
    onTextConfigChange: (ThumbnailTextOverlay) -> Unit
) {
    val pairingFonts = listOf("Space Grotesk", "Passion One", "Impact Ultra", "Montserrat Black")
    val colorsList = listOf(Color.Yellow, Color.White, Color.Cyan, Color.Red, Color(0xFFF97316))

    Column(verticalArrangement = Arrangement.spacedBy(6.dp), modifier = Modifier.fillMaxWidth().verticalScroll(rememberScrollState())) {
        Text("ADVANCED INTERACTIVE TEXT STUDIO", fontSize = 11.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
        
        OutlinedTextField(
            value = textOverlay.text,
            onValueChange = { onTextConfigChange(textOverlay.copy(text = it)) },
            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold),
            placeholder = { Text("What text overlay do you want?", color = Color.Gray) },
            colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonCyan, unfocusedBorderColor = Color.DarkGray),
            modifier = Modifier.fillMaxWidth(),
            shape = RoundedCornerShape(8.dp)
        )

        Spacer(modifier = Modifier.height(4.dp))

        // Font selection
        Text("CTR-Optimized Visual Font Styles", fontSize = 9.sp, color = Color.LightGray)
        Row(horizontalArrangement = Arrangement.spacedBy(6.dp), modifier = Modifier.fillMaxWidth()) {
            pairingFonts.forEach { font ->
                val isSelected = textOverlay.fontName == font
                Box(
                    modifier = Modifier
                        .background(if (isSelected) NeonPurple else Color(0xFF13132B), RoundedCornerShape(6.dp))
                        .border(width = 0.5.dp, color = if (isSelected) NeonCyan else Color.Transparent, shape = RoundedCornerShape(6.dp))
                        .clickable { onTextConfigChange(textOverlay.copy(fontName = font)) }
                        .padding(horizontal = 8.dp, vertical = 6.dp)
                ) {
                    Text(font, color = Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                }
            }
        }

        Spacer(modifier = Modifier.height(4.dp))

        // Text & outline configurations
        Row(horizontalArrangement = Arrangement.spacedBy(12.dp), verticalAlignment = Alignment.CenterVertically) {
            Text("Main Text Tint", fontSize = 9.sp, color = Color.LightGray)
            colorsList.forEach { color ->
                val isSelected = textOverlay.textColor == color
                Box(
                    modifier = Modifier
                        .size(16.dp)
                        .background(color, CircleShape)
                        .border(width = if (isSelected) 1.5.dp else 0.dp, color = Color.White, shape = CircleShape)
                        .clickable { onTextConfigChange(textOverlay.copy(textColor = color)) }
                    )
            }
        }

        Row(horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth()) {
            Text("Text Font Size Scale", fontSize = 10.sp, color = Color.White)
            Text("${textOverlay.fontSize.toInt()} sp", fontSize = 10.sp, color = NeonCyan)
        }
        Slider(
            value = textOverlay.fontSize,
            onValueChange = { onTextConfigChange(textOverlay.copy(fontSize = it)) },
            valueRange = (14f..36f)
        )

        Row(horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth()) {
            Text("Rotation Angle Tilt", fontSize = 10.sp, color = Color.White)
            Text("${textOverlay.rotation.toInt()}°", fontSize = 10.sp, color = NeonPurple)
        }
        Slider(
            value = textOverlay.rotation,
            onValueChange = { onTextConfigChange(textOverlay.copy(rotation = it)) },
            valueRange = (-25f..25f)
        )

        Row(horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically, modifier = Modifier.fillMaxWidth()) {
            Text("Background Shield Outline Thickness", fontSize = 10.sp, color = Color.White)
            Text("${textOverlay.textOutlineWidth.toInt()}px", fontSize = 10.sp, color = NeonCyan)
        }
        Slider(
            value = textOverlay.textOutlineWidth,
            onValueChange = { onTextConfigChange(textOverlay.copy(textOutlineWidth = it)) },
            valueRange = (0f..10f)
        )
    }
}

@Composable
fun ThumbnailStickersAndEffectsTab(
    stickers: List<ThumbnailStickerOverlay>,
    onAddSticker: (String) -> Unit,
    onClearStickers: () -> Unit
) {
    val items = listOf(
        Pair("Red High Arrow", "arrow"),
        Pair("Hot Flame", "fire"),
        Pair("Lightning Volt", "lightning"),
        Pair("Shock Wave Blur", "explosion"),
        Pair("Neon Cyber Bulb", "neon")
    )
    Column {
        Text("STICKERS, GRAPHICS & GLOW OVERLAYS", fontSize = 11.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
        Text("High click thumbnails use bright arrows and badges pointing to key elements.", fontSize = 9.sp, color = Color.Gray)
        Spacer(modifier = Modifier.height(10.dp))

        LazyVerticalGrid(
            columns = GridCells.Fixed(2),
            horizontalArrangement = Arrangement.spacedBy(10.dp),
            verticalArrangement = Arrangement.spacedBy(10.dp),
            modifier = Modifier.fillMaxWidth().height(120.dp)
        ) {
            items(items) { info ->
                Card(
                    modifier = Modifier
                        .clickable { onAddSticker(info.second) }
                        .border(0.5.dp, Color.White.copy(alpha = 0.05f), RoundedCornerShape(8.dp)),
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF131326))
                ) {
                    Row(
                        modifier = Modifier.padding(10.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        val stickerIcon = when (info.second) {
                            "arrow" -> Icons.Filled.TrendingUp
                            "fire" -> Icons.Filled.LocalFireDepartment
                            "lightning" -> Icons.Filled.ElectricBolt
                            "explosion" -> Icons.Filled.Waves
                            "neon" -> Icons.Filled.FlashOn
                            else -> Icons.Filled.Star
                        }
                        Icon(imageVector = stickerIcon, contentDescription = null, tint = NeonCyan, modifier = Modifier.size(18.dp))
                        Text(info.first, color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.SemiBold)
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(6.dp))

        if (stickers.isNotEmpty()) {
            OutlinedButton(
                onClick = onClearStickers,
                border = BorderStroke(1.dp, Color.Red.copy(alpha = 0.5f)),
                shape = RoundedCornerShape(8.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Remove All Stickers (${stickers.size})", color = Color.Red, fontSize = 11.sp)
            }
        }
    }
}

