// ==========================================
// AI VOICE GENERATOR STUDIO MODULE
// ==========================================

data class VoiceProfile(
    val id: String,
    val name: String,
    val gender: String, // "Male", "Female", "Child", "Elder"
    val accent: String, // "Indian", "American", "British", "Australian"
    val isPremium: Boolean,
    val previewDescription: String,
    val isFavorite: Boolean = false
)

fun playSynthesizedSpeech(
    text: String,
    gender: String,
    pitchFactor: Float,
    speedFactor: Float,
    volumePercent: Float
) {
    try {
        val sampleRate = 16000
        val durationSec = (0.6f + text.length * 0.07f) / speedFactor
        val totalSamples = (sampleRate * durationSec).toInt().coerceIn(8000, 160000)
        val buffer = ShortArray(totalSamples)

        val baseFreq = when (gender) {
            "Female" -> 210f
            "Child" -> 290f
            "Elder" -> 145f
            else -> 115f // Male
        } * pitchFactor

        for (i in 0 until totalSamples) {
            val t = i.toFloat() / sampleRate
            
            // Basic word pacing envelope
            val envelope = Math.sin(2.0 * Math.PI * (3.8f * speedFactor) * t).toFloat()
                .coerceAtLeast(-0.2f).plus(0.6f).coerceIn(0f, 1f)

            // Syllable sweeps representing dynamic resonance (vowels)
            val f1 = 480f + 220f * Math.sin(2.0 * Math.PI * 1.6f * t).toFloat()
            val f2 = 1450f + 450f * Math.cos(2.0 * Math.PI * 2.3f * t).toFloat()

            val carrier = Math.sin(2.0 * Math.PI * baseFreq * t) +
                           0.35f * Math.sin(2.0 * Math.PI * f1 * t) +
                           0.22f * Math.sin(2.0 * Math.PI * f2 * t)

            // Consonant sibilance s/t bursts
            val noise = if (Math.random() < 0.08) (Math.random() * 2 - 1).toFloat() * 0.12f else 0f

            buffer[i] = ((carrier * envelope + noise) * Short.MAX_VALUE * volumePercent)
                .toInt().coerceIn(Short.MIN_VALUE.toInt(), Short.MAX_VALUE.toInt()).toShort()
        }

        val audioTrack = android.media.AudioTrack.Builder()
            .setAudioAttributes(
                android.media.AudioAttributes.Builder()
                    .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
                    .setContentType(android.media.AudioAttributes.CONTENT_TYPE_SPEECH)
                    .build()
            )
            .setAudioFormat(
                android.media.AudioFormat.Builder()
                    .setEncoding(android.media.AudioFormat.ENCODING_PCM_16BIT)
                    .setSampleRate(sampleRate)
                    .setChannelMask(android.media.AudioFormat.CHANNEL_OUT_MONO)
                    .build()
            )
            .setBufferSizeInBytes(totalSamples * 2)
            .setTransferMode(android.media.AudioTrack.MODE_STATIC)
            .build()

        audioTrack.write(buffer, 0, totalSamples)
        audioTrack.play()
    } catch (e: Exception) {
        e.printStackTrace()
    }
}

fun saveVoiceWavFile(
    context: android.content.Context,
    fileName: String,
    text: String,
    gender: String,
    pitch: Float,
    speed: Float
): java.io.File? {
    try {
        val sampleRate = 16000
        val durationSec = (0.6f + text.length * 0.07f) / speed
        val totalSamples = (sampleRate * durationSec).toInt().coerceIn(8000, 160000)
        val pcmBuffer = ShortArray(totalSamples)

        val baseFreq = when (gender) {
            "Female" -> 210f
            "Child" -> 290f
            "Elder" -> 145f
            else -> 115f
        } * pitch

        for (i in 0 until totalSamples) {
            val t = i.toFloat() / sampleRate
            val envelope = Math.sin(2.0 * Math.PI * (3.8f * speed) * t).toFloat()
                .coerceAtLeast(-0.2f).plus(0.6f).coerceIn(0f, 1f)
            val f1 = 480f + 220f * Math.sin(2.0 * Math.PI * 1.6f * t).toFloat()
            val f2 = 1450f + 450f * Math.cos(2.0 * Math.PI * 2.3f * t).toFloat()
            val carrier = Math.sin(2.0 * Math.PI * baseFreq * t) +
                           0.35f * Math.sin(2.0 * Math.PI * f1 * t) +
                           0.22f * Math.sin(2.0 * Math.PI * f2 * t)
            val noise = if (Math.random() < 0.08) (Math.random() * 2 - 1).toFloat() * 0.12f else 0f
            pcmBuffer[i] = ((carrier * envelope + noise) * Short.MAX_VALUE)
                .toInt().coerceIn(Short.MIN_VALUE.toInt(), Short.MAX_VALUE.toInt()).toShort()
        }

        val cacheDir = context.cacheDir
        val audioFile = java.io.File(cacheDir, fileName)
        val fos = java.io.FileOutputStream(audioFile)

        val totalAudioLen = totalSamples * 2
        val totalDataLen = totalAudioLen + 36
        val channels = 1
        val byteRate = sampleRate * channels * 2

        val header = ByteArray(44)
        header[0] = 'R'.toByte()
        header[1] = 'I'.toByte()
        header[2] = 'F'.toByte()
        header[3] = 'F'.toByte()
        header[4] = (totalDataLen and 0xff).toByte()
        header[5] = ((totalDataLen shr 8) and 0xff).toByte()
        header[6] = ((totalDataLen shr 16) and 0xff).toByte()
        header[7] = ((totalDataLen shr 24) and 0xff).toByte()
        header[8] = 'W'.toByte()
        header[9] = 'A'.toByte()
        header[10] = 'V'.toByte()
        header[11] = 'E'.toByte()
        header[12] = 'f'.toByte()
        header[13] = 'm'.toByte()
        header[14] = 't'.toByte()
        header[15] = ' '.toByte()
        header[16] = 16
        header[17] = 0
        header[18] = 0
        header[19] = 0
        header[20] = 1 // Format PCM = 1
        header[21] = 0
        header[22] = channels.toByte()
        header[23] = 0
        header[24] = (sampleRate and 0xff).toByte()
        header[25] = ((sampleRate shr 8) and 0xff).toByte()
        header[26] = ((sampleRate shr 16) and 0xff).toByte()
        header[27] = ((sampleRate shr 24) and 0xff).toByte()
        header[28] = (byteRate and 0xff).toByte()
        header[29] = ((byteRate shr 8) and 0xff).toByte()
        header[30] = ((byteRate shr 16) and 0xff).toByte()
        header[31] = ((byteRate shr 24) and 0xff).toByte()
        header[32] = 2 // block check align
        header[33] = 0
        header[34] = 16 // bits
        header[35] = 0
        header[36] = 'd'.toByte()
        header[37] = 'a'.toByte()
        header[38] = 't'.toByte()
        header[39] = 'a'.toByte()
        header[40] = (totalAudioLen and 0xff).toByte()
        header[41] = ((totalAudioLen shr 8) and 0xff).toByte()
        header[42] = ((totalAudioLen shr 16) and 0xff).toByte()
        header[43] = ((totalAudioLen shr 24) and 0xff).toByte()

        fos.write(header)

        val byteBuffer = ByteArray(totalAudioLen)
        for (i in 0 until totalSamples) {
            byteBuffer[i * 2] = (pcmBuffer[i].toInt() and 0xff).toByte()
            byteBuffer[i * 2 + 1] = ((pcmBuffer[i].toInt() shr 8) and 0xff).toByte()
        }
        fos.write(byteBuffer)
        fos.close()

        return audioFile
    } catch (e: Exception) {
        e.printStackTrace()
        return null
    }
}

@Composable
fun WaveformVisualizer(
    isPlaying: Boolean,
    modifier: Modifier = Modifier
) {
    val infiniteTransition = rememberInfiniteTransition()
    val waveProgress by infiniteTransition.animateFloat(
        initialValue = 0f,
        targetValue = 2f * Math.PI.toFloat(),
        animationSpec = infiniteRepeatable(
            animation = tween(1500, easing = LinearEasing),
            repeatMode = RepeatMode.Restart
        )
    )

    Canvas(modifier = modifier) {
        val barCount = 42
        val spacing = 3.dp.toPx()
        val totalWidth = size.width
        val barWidth = (totalWidth - (barCount - 1) * spacing) / barCount

        for (i in 0 until barCount) {
            val waveHeightFactor = if (isPlaying) {
                val phase = (i.toFloat() / barCount) * 2f * Math.PI.toFloat()
                0.2f + 0.8f * Math.abs(Math.sin(waveProgress.toDouble() + phase).toFloat())
            } else {
                0.15f + 0.08f * Math.sin(i * 0.45).toFloat()
            }

            val bHeight = size.height * waveHeightFactor
            val x = i * (barWidth + spacing)
            val y = (size.height - bHeight) / 2f

            drawRoundRect(
                color = if (isPlaying) NeonCyan else Color.Gray.copy(alpha = 0.5f),
                topLeft = Offset(x, y),
                size = Size(barWidth, bHeight),
                cornerRadius = androidx.compose.ui.geometry.CornerRadius(4f, 4f)
            )
        }
    }
}

