                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color.Black.copy(alpha = 0.4f), RoundedCornerShape(8.dp))
                        .padding(8.dp)
                ) {
                    Text(
                        text = if (scriptInput.isBlank()) "(Enter some transcript script below to play)" else "\"$scriptInput\"",
                        fontSize = 11.sp,
                        color = Color.LightGray,
                        maxLines = 2,
                        overflow = TextOverflow.Ellipsis
                    )
                }

                // Audio Playback Controls Row
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                        Button(
                            onClick = {
                                if (isPlayingSpeech) {
                                    isPlayingSpeech = false
                                } else {
                                    isPlayingSpeech = true
                                    scope.launch {
                                        playSynthesizedSpeech(scriptInput, selectedVoice.gender, speechPitch, speechSpeed, speechVolume)
                                        // Auto reset play state when synthesis finishes (takes length proportional)
                                        val expectedDuration = (600 + scriptInput.length * 70) / speechSpeed
                                        delay(expectedDuration.toLong())
                                        isPlayingSpeech = false
                                    }
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = NeonCyan),
                            contentPadding = PaddingValues(horizontal = 12.dp, vertical = 4.dp),
                            enabled = scriptInput.isNotBlank() && !isGenerating,
                            shape = RoundedCornerShape(6.dp)
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                Icon(
                                    imageVector = if (isPlayingSpeech) Icons.Filled.Pause else Icons.Filled.PlayArrow,
                                    contentDescription = null,
                                    tint = PureBlack,
                                    modifier = Modifier.size(14.dp)
                                )
                                Text(
                                    text = if (isPlayingSpeech) "PAUSE" else "PLAY PREVIEW",
                                    color = PureBlack,
                                    fontSize = 9.sp,
                                    fontWeight = FontWeight.Bold
                                )
                            }
                        }

                        OutlinedButton(
                            onClick = { isPlayingSpeech = false },
                            border = BorderStroke(0.5.dp, Color.Gray),
                            colors = ButtonDefaults.outlinedButtonColors(contentColor = Color.LightGray),
                            contentPadding = PaddingValues(horizontal = 12.dp, vertical = 4.dp),
                            shape = RoundedCornerShape(6.dp)
                        ) {
                            Text("STOP", fontSize = 9.sp, fontWeight = FontWeight.Bold)
                        }
                    }

                    // Share and download file references
                    Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        IconButton(
                            onClick = {
                                val file = saveVoiceWavFile(context, "voice_creation_${System.currentTimeMillis()}.wav", scriptInput, selectedVoice.gender, speechPitch, speechSpeed)
                                if (file != null) {
                                    val shareIntent = Intent(Intent.ACTION_SEND).apply {
                                        type = "audio/wav"
                                        putExtra(Intent.EXTRA_STREAM, Uri.fromFile(file))
                                        putExtra(Intent.EXTRA_SUBJECT, "AI Generated Voice Narration")
                                        putExtra(Intent.EXTRA_TEXT, "Generated via AI Voice Generator Pro: \"$scriptInput\"")
                                    }
                                    context.startActivity(Intent.createChooser(shareIntent, "Share Audio Output"))
                                } else {
                                    Toast.makeText(context, "Failed to compile WAV file", Toast.LENGTH_SHORT).show()
                                }
                            },
                            modifier = Modifier
                                .size(30.dp)
                                .background(Color.White.copy(alpha = 0.05f), CircleShape)
                        ) {
                            Icon(imageVector = Icons.Filled.Share, contentDescription = "Share generated audio", tint = Color.White, modifier = Modifier.size(14.dp))
                        }

                        IconButton(
                            onClick = {
                                val fName = "audio_narration_${System.currentTimeMillis()}.wav"
                                val file = saveVoiceWavFile(context, fName, scriptInput, selectedVoice.gender, speechPitch, speechSpeed)
                                if (file != null) {
                                    Toast.makeText(context, "Saved $fName to Downloads and Workspace history!", Toast.LENGTH_LONG).show()
                                    viewModel.recordVoiceGeneration(
                                        text = scriptInput,
                                        voiceName = selectedVoice.name,
                                        language = selectedLanguage,
                                        emotion = selectedEmotion,
                                        audioSettings = "Pitch ${speechPitch}x, Speed ${speechSpeed}x, Vol ${(speechVolume * 100).toInt()}%",
                                        audioMetadata = "File: $fName, Size: ${file.length() / 1024} KB, Duration: ${String.format("%.1f", (0.6f + scriptInput.length * 0.07f) / speechSpeed)}s"
                                    )
                                } else {
                                    Toast.makeText(context, "Error compiling script audio", Toast.LENGTH_SHORT).show()
                                }
                            },
                            modifier = Modifier
                                .size(30.dp)
                                .background(Color.White.copy(alpha = 0.05f), CircleShape)
                        ) {
                            Icon(imageVector = Icons.Filled.Save, contentDescription = "Download custom WAV audio", tint = NeonCyan, modifier = Modifier.size(14.dp))
                        }
                    }
                }
            }
        }

        // Script Input Area
        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
            Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                Text("TRANSLATION SCRIPT TEXT TO SPEAK", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                
                // Pause insert option
                TextButton(
                    onClick = {
                        scriptInput = "$scriptInput [pause_1s]"
                    },
                    contentPadding = PaddingValues(0.dp),
                    modifier = Modifier.height(20.dp)
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(imageVector = Icons.Filled.Timer, contentDescription = "Add Pause", tint = NeonPurple, modifier = Modifier.size(12.dp))
                        Spacer(modifier = Modifier.width(2.dp))
                        Text("+ INSERT PAUSE", fontSize = 8.5.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                    }
                }
            }

            OutlinedTextField(
                value = scriptInput,
                onValueChange = {
                    if (it.length <= maxChars) {
                        scriptInput = it
                    }
                },
                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 12.sp),
                modifier = Modifier
                    .fillMaxWidth()
                    .height(100.dp),
                colors = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor = NeonCyan,
                    unfocusedBorderColor = Color.DarkGray,
                    focusedContainerColor = Color(0xFF06060F),
                    unfocusedContainerColor = Color(0xFF06060F)
                ),
                shape = RoundedCornerShape(8.dp),
                placeholder = { Text("Compose voice speech transcript...", fontSize = 11.sp, color = Color.Gray) }
            )

            Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                // Characters count
                Text(
                    text = "${scriptInput.length} / $maxChars characters",
                    fontSize = 9.sp,
                    color = if (scriptInput.length >= maxChars) Color.Red else Color.Gray
                )
                
                // Gemini rewrite assistant hook
                TextButton(
                    onClick = {
                        isGenerating = true
                        scope.launch {
                            val response = try {
                                com.example.api.RetrofitClient.generateWithGemini(
                                    "Create a highly-converting, viral-style voiceover opening hook based on the transcript proposal:\n" +
                                    "\"$scriptInput\"\n\n" +
                                    "Optimize for high retention holding speed. Return only a short paragraph under 40 words.",
                                    "You are an expert copywriter script optimizer."
                                )
                            } catch (e: Exception) {
                                "🔥 What if I told you everything you knew about viral scripts was completely wrong? Watch until the end to discover how!"
                            }
                            suggestedHookText = response
                            scriptInput = response
                            isGenerating = false
                        }
                    },
                    modifier = Modifier.height(22.dp),
                    contentPadding = PaddingValues(0.dp)
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = "Gemini", tint = Color.Yellow, modifier = Modifier.size(12.dp))
                        Text("GEMINI REWRITE HOOK", fontSize = 8.5.sp, color = Color.Yellow, fontWeight = FontWeight.Bold)
                    }
                }
            }
        }

        // Voice Profile Grid & Catalog (with Search & filters)
        Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
            Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                Text("SPEECH VOCAL PROFILES CATALOGUE", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                
                // Show favorites trigger
                Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.clickable { showOnlyFavoritesFilter = !showOnlyFavoritesFilter }) {
                    Icon(
                        imageVector = if (showOnlyFavoritesFilter) Icons.Filled.Favorite else Icons.Outlined.FavoriteBorder,
                        contentDescription = "fav",
                        tint = if (showOnlyFavoritesFilter) Color.Red else Color.Gray,
                        modifier = Modifier.size(12.dp)
                    )
                    Spacer(modifier = Modifier.width(3.dp))
                    Text("FAVORITES ONLY", fontSize = 8.sp, color = if (showOnlyFavoritesFilter) Color.Red else Color.Gray, fontWeight = FontWeight.Bold)
                }
            }

            // Keyword search across profiles
            OutlinedTextField(
                value = keywordSearchInput,
                onValueChange = { keywordSearchInput = it },
                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 10.sp),
                modifier = Modifier
                    .fillMaxWidth()
                    .height(34.dp),
                placeholder = { Text("Search voice profile accent, age or pitch...", fontSize = 9.sp, color = Color.Gray) },
                colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPurple, unfocusedBorderColor = Color.DarkGray),
                shape = RoundedCornerShape(6.dp),
                leadingIcon = { Icon(imageVector = Icons.Filled.Search, contentDescription = null, modifier = Modifier.size(12.dp)) }
            )

            Spacer(modifier = Modifier.height(2.dp))

            // Voices List Grid
            val filteredVoices = voiceListState.filter {
                val matchesKeyword = it.name.contains(keywordSearchInput, ignoreCase = true) || 
                                      it.accent.contains(keywordSearchInput, ignoreCase = true) ||
                                      it.gender.contains(keywordSearchInput, ignoreCase = true)
                val matchesFav = !showOnlyFavoritesFilter || it.isFavorite
                matchesKeyword && matchesFav
            }

            LazyRow(horizontalArrangement = Arrangement.spacedBy(10.dp), modifier = Modifier.fillMaxWidth()) {
                itemsIndexed(filteredVoices) { index, voice ->
                    val isSelected = selectedVoice.id == voice.id
                    val needsUpgrade = voice.isPremium && !isPro

                    Card(
                        modifier = Modifier
                            .width(130.dp)
                            .clickable {
                                if (needsUpgrade) {
                                    showUpgradeDialog = true
                                } else {
                                    selectedVoice = voice
                                }
                            }
                            .border(
                                width = if (isSelected) 1.5.dp else 0.5.dp,
                                color = if (isSelected) NeonCyan else Color.White.copy(alpha = 0.08f),
                                shape = RoundedCornerShape(10.dp)
                            ),
                        colors = CardDefaults.cardColors(containerColor = if (isSelected) Color(0xFF131326) else Color(0xFF080811))
                    ) {
                        Column(modifier = Modifier.padding(8.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text(
                                    text = voice.name,
                                    color = Color.White,
                                    fontSize = 11.sp,
                                    fontWeight = FontWeight.Bold,
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis
                                )

                                // Favorite Toggle
                                Icon(
                                    imageVector = if (voice.isFavorite) Icons.Filled.Favorite else Icons.Outlined.FavoriteBorder,
                                    contentDescription = "Favorite",
                                    tint = if (voice.isFavorite) Color.Red else Color.Gray,
                                    modifier = Modifier
                                        .size(14.dp)
                                        .clickable {
                                            val voiceIdx = voiceListState.indexOfFirst { it.id == voice.id }
                                            if (voiceIdx != -1) {
                                                voiceListState[voiceIdx] = voice.copy(isFavorite = !voice.isFavorite)
                                            }
                                        }
                                )
                            }

                            Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                Box(
                                    modifier = Modifier
                                        .background(
                                            if (voice.gender == "Male" || voice.gender == "Elder") Color(0xFF1E40AF) else Color(0xFF9D174D),
                                            RoundedCornerShape(3.dp)
                                        )
                                        .padding(horizontal = 4.dp, vertical = 1.5.dp)
                                ) {
                                    Text(voice.gender.uppercase(), color = Color.White, fontSize = 6.sp, fontWeight = FontWeight.Bold)
                                }
                                Box(
                                    modifier = Modifier
                                        .background(Color.White.copy(alpha = 0.1f), RoundedCornerShape(3.dp))
                                        .padding(horizontal = 4.dp, vertical = 1.5.dp)
                                ) {
                                    Text(voice.accent.uppercase(), color = Color.LightGray, fontSize = 6.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            Text(
                                voice.previewDescription,
                                fontSize = 8.sp,
                                color = Color.Gray,
                                maxLines = 2,
                                overflow = TextOverflow.Ellipsis,
                                modifier = Modifier.height(20.dp)
                            )

                            // Quick sample preview button
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                if (needsUpgrade) {
                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                        Icon(imageVector = Icons.Filled.Lock, contentDescription = null, tint = Color(0xFFFF5599), modifier = Modifier.size(10.dp))
                                        Spacer(modifier = Modifier.width(3.dp))
                                        Text("PREMIUM", color = Color(0xFFFF5599), fontSize = 7.sp, fontWeight = FontWeight.Black)
                                    }
                                } else {
                                    Text("Preview Active", color = NeonCyan, fontSize = 7.sp, fontWeight = FontWeight.Bold)
                                }

                                IconButton(
                                    onClick = {
                                        if (needsUpgrade) {
                                            showUpgradeDialog = true
                                        } else {
                                            scope.launch {
                                                playSynthesizedSpeech("Hello! I am ${voice.name}.", voice.gender, 1.0f, 1.0f, 0.8f)
                                            }
                                        }
                                    },
                                    modifier = Modifier
                                        .size(18.dp)
                                        .background(NeonPurple.copy(alpha = 0.2f), CircleShape)
                                ) {
                                    Icon(imageVector = Icons.Filled.VolumeUp, contentDescription = null, tint = NeonCyan, modifier = Modifier.size(11.dp))
                                }
                            }
                        }
                    }
                }
            }
        }

        // Modulation Sliders Drawer Card
        Card(
            modifier = Modifier
                .fillMaxWidth()
                .border(0.5.dp, Color(0xFF1E293B), RoundedCornerShape(10.dp)),
            colors = CardDefaults.cardColors(containerColor = Color(0xFF070710))
        ) {
            Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                Text("PITCH, TEMPO & SPEECHES SOUND CONTROL", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)

                // Pitch slider
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                    Text("Voice Tone Pitch Base", fontSize = 10.sp, color = Color.LightGray)
                    Text("${String.format("%.2f", speechPitch)}x", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.ExtraBold)
                }
                Slider(
                    value = speechPitch,
                    onValueChange = { speechPitch = it },
                    valueRange = (0.5f..1.8f),
                    colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan)
                )

                // Tempo/Speed slider
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                    Text("Speech Delivery Speed Ratio", fontSize = 10.sp, color = Color.LightGray)
                    Text("${String.format("%.2f", speechSpeed)}x", fontSize = 10.sp, color = NeonPurple, fontWeight = FontWeight.ExtraBold)
                }
                Slider(
                    value = speechSpeed,
                    onValueChange = { speechSpeed = it },
                    valueRange = (0.5f..2.0f),
                    colors = SliderDefaults.colors(thumbColor = NeonPurple, activeTrackColor = NeonPurple)
                )

                // Volume slider
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                    Text("Total Master Amplification Volume", fontSize = 10.sp, color = Color.LightGray)
                    Text("${(speechVolume * 100).toInt()}%", fontSize = 10.sp, color = Color.White, fontWeight = FontWeight.Bold)
                }
                Slider(
                    value = speechVolume,
                    onValueChange = { speechVolume = it },
                    valueRange = (0f..1f),
                    colors = SliderDefaults.colors(thumbColor = Color.White, activeTrackColor = Color.White)
                )
            }
        }

        // Global Languages Selector & Emotions Selector (Row Layout)
        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(10.dp)) {
            Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                Text("GLOBAL LANGUAGE", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                val languages = listOf("English (US)", "Hindi", "Japanese", "Spanish", "French")
                
                var showDrop by remember { mutableStateOf(false) }
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clip(RoundedCornerShape(6.dp))
                        .background(Color(0xFF080815))
                        .border(0.5.dp, Color.DarkGray, RoundedCornerShape(6.dp))
                        .clickable { showDrop = true }
                        .padding(horizontal = 8.dp, vertical = 10.dp)
                ) {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                        Text(selectedLanguage, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.SemiBold)
                        Icon(imageVector = Icons.Filled.ArrowDropDown, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(14.dp))
                    }

                    DropdownMenu(
                        expanded = showDrop,
                        onDismissRequest = { showDrop = false },
                        modifier = Modifier.background(Color(0xFF0F0F23))
                    ) {
                        languages.forEach { lang ->
                            DropdownMenuItem(
                                text = { Text(lang, color = Color.White, fontSize = 11.sp) },
                                onClick = {
                                    selectedLanguage = lang
                                    showDrop = false
                                }
                            )
                        }
                    }
                }
            }

            Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                Text("EMOTION PROFILE", fontSize = 9.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                val emotions = listOf("Calm", "Happy", "Sad", "Angry", "Excited", "Confident")
                
                var showDropEmo by remember { mutableStateOf(false) }
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clip(RoundedCornerShape(6.dp))
                        .background(Color(0xFF080815))
                        .border(0.5.dp, Color.DarkGray, RoundedCornerShape(6.dp))
                        .clickable { showDropEmo = true }
                        .padding(horizontal = 8.dp, vertical = 10.dp)
                ) {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                        Text(selectedEmotion, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.SemiBold)
                        Icon(imageVector = Icons.Filled.ArrowDropDown, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(14.dp))
                    }

                    DropdownMenu(
                        expanded = showDropEmo,
                        onDismissRequest = { showDropEmo = false },
                        modifier = Modifier.background(Color(0xFF0F0F23))
                    ) {
                        emotions.forEach { emo ->
                            DropdownMenuItem(
                                text = { Text(emo, color = Color.White, fontSize = 11.sp) },
                                onClick = {
                                    selectedEmotion = emo
                                    showDropEmo = false
                                }
                            )
                        }
                    }
                }
            }
        }

        // Action: Generate natural sound button
        Button(
            onClick = {
                isGenerating = true
                scope.launch {
                    delay(1500)
                    isGenerating = false
                    isPlayingSpeech = true
                    playSynthesizedSpeech(scriptInput, selectedVoice.gender, speechPitch, speechSpeed, speechVolume)
                    // Auto duration
                    val duration = (600 + scriptInput.length * 70) / speechSpeed
                    delay(duration.toLong())
                    isPlayingSpeech = false
                }
            },
            colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
            shape = RoundedCornerShape(8.dp),
            modifier = Modifier
                .fillMaxWidth()
                .height(44.dp),
            enabled = scriptInput.isNotBlank() && !isGenerating
        ) {
            if (isGenerating) {
                CircularProgressIndicator(color = Color.White, modifier = Modifier.size(16.dp))
                Spacer(modifier = Modifier.width(8.dp))
                Text("Synthesizing Vocal Tracks...", fontSize = 12.sp, color = Color.White)
            } else {
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Icon(imageVector = Icons.Filled.RocketLaunch, contentDescription = null, tint = Color.White, modifier = Modifier.size(16.dp))
                    Text("GENERATE HIGH CTR VOICEOVER", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.ExtraBold)
                }
            }
        }

        Divider(color = Color.White.copy(alpha = 0.05f))

        // History list & Search
        Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
            Text("YOUR SPEECH SYNTHESIS HISTORY", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
            
            val voiceCreations = creationsHistory.filter { it.toolName == "AI Voice Generator" }
            if (voiceCreations.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFF070710), RoundedCornerShape(8.dp))
                        .padding(20.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text("No local history items yet. Try generating your first transcript above!", fontSize = 11.sp, color = Color.Gray, textAlign = TextAlign.Center)
                }
            } else {
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    voiceCreations.reversed().forEach { item ->
                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .border(0.5.dp, Color.White.copy(alpha = 0.05f), RoundedCornerShape(8.dp)),
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF090912))
                        ) {
                            Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Text("PROCESSED TRANSLATION", color = NeonCyan, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                    Text(
                                        text = android.text.format.DateFormat.format("hh:mm a", item.timestamp).toString(),
                                        color = Color.Gray,
                                        fontSize = 8.sp
                                    )
                                }

                                Text(item.inputPrompt, fontSize = 11.sp, color = Color.White)
                                Text(item.outputText, fontSize = 9.sp, color = NeonPurple)

                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.End, verticalAlignment = Alignment.CenterVertically) {
                                    IconButton(
                                        onClick = {
                                            // Replay past script voice simulation
                                            val t = item.inputPrompt.substringAfter("Text: \"").substringBefore("\"")
                                            val vGender = if (item.inputPrompt.contains("Aanya") || item.inputPrompt.contains("Emma") || item.inputPrompt.contains("Serena")) "Female" else "Male"
                                            scope.launch {
                                                playSynthesizedSpeech(t, vGender, 1.0f, 1.0f, 0.85f)
                                            }
                                        },
                                        modifier = Modifier.size(24.dp)
                                    ) {
                                        Icon(imageVector = Icons.Filled.VolumeUp, contentDescription = "Play back history item", tint = NeonCyan, modifier = Modifier.size(12.dp))
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(20.dp))
    }

    // Pro Upsell modal
    if (showUpgradeDialog) {
        AlertDialog(
            onDismissRequest = { showUpgradeDialog = false },
            containerColor = Color(0xFF0F0F1D),
            title = {
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Icon(imageVector = Icons.Filled.NewReleases, contentDescription = null, tint = Color(0xFFFFD700))
                    Text("Unlock Voice Generator Pro", color = Color.White, fontSize = 16.sp, fontWeight = FontWeight.Bold)
                }
            },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text("Gain access to HD Premium child/elder voices, emotion presets (Angry, Excited, Sad), prioritizing servers, commercial usage rights, and a character limits upgrade up to 5,000 chars per generation.", color = Color.LightGray, fontSize = 13.sp)
                    Text("★ Generate audio transcripts 10x faster with professional high accuracy accents.", color = NeonCyan, fontSize = 11.sp, fontWeight = FontWeight.SemiBold)
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        scope.launch {
                            viewModel.updateSubscription("Pro", 500)
                            Toast.makeText(context, "Congratulations! Voice Studio PRO is now Active! 🎉", Toast.LENGTH_LONG).show()
                            showUpgradeDialog = false
                        }
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple)
                ) {
                    Text("Upgrade instantly ($14.99/mo)", color = Color.White)
                }
            },
            dismissButton = {
                TextButton(onClick = { showUpgradeDialog = false }) {
                    Text("Stay on Free plan", color = Color.Gray)
                }
            }
        )
    }
}

// ==========================================
// AI VOICE CLONE STUDIO MODULE
// ==========================================

data class ClonedVoiceModel(
    val id: String,
    val name: String,
    val trainingStatus: String, // "Ready", "Training", "Failed"
    val language: String,
    val qualityScore: Double, // 0.0 to 10.0
    val audioSamplesCount: Int,
    val totalRecordedSeconds: Int,
    val createdDate: Long = System.currentTimeMillis(),
    val usageCount: Int = 0,
    val isFavorite: Boolean = false,
    val isDefault: Boolean = false,
    val baseFrequency: Float = 165f,
    val clarityScore: Int = 94,
    val micRating: Int = 88,
    val ambientNoiseLevel: Int = -58 // dB
)

@OptIn(ExperimentalAnimationApi::class, ExperimentalMaterial3Api::class)
@Composable
fun AIVoiceCloneWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()

    val userStats by viewModel.userStats.collectAsState()
    val creationsHistory by viewModel.history.collectAsState()

    val isPro = userStats?.isProPlan == true
    val maxClones = if (isPro) 15 else 2

    // Main workspace sub-tabs
    val tabs = listOf("DASHBOARD", "RECORD & TRAIN", "GENERATE (TTS)", "HISTORY")
    var selectedTabIdx by remember { mutableStateOf(0) }

    // List of active custom voice models
    val voiceModelsList = remember {
        mutableStateListOf(
            ClonedVoiceModel(
                id = "clone_my_voice",
                name = "My Natural voice",
                trainingStatus = "Ready",
                language = "Hindi / English",
                qualityScore = 9.2,
                audioSamplesCount = 4,
                totalRecordedSeconds = 120,
                isFavorite = true,
                isDefault = true,
                baseFrequency = 145f,
                clarityScore = 95,
                micRating = 91,
                ambientNoiseLevel = -62
            ),
            ClonedVoiceModel(
                id = "clone_elder_narrator",
                name = "Deep Podcaster Clone",
                trainingStatus = "Ready",
                language = "English (US)",
                qualityScore = 8.6,
                audioSamplesCount = 3,
                totalRecordedSeconds = 180,
                isFavorite = false,
                isDefault = false,
                baseFrequency = 110f,
                clarityScore = 88,
                micRating = 85,
                ambientNoiseLevel = -54
            )
        )
    }

    var selectedCloneModel by remember { mutableStateOf(voiceModelsList[0]) }

    // TTS inputs
    var textInput by remember { mutableStateOf("Testing voice clone replication. This is the custom digital replica speaking back your copy script with high fidelity results.") }
    var selectedTtsLanguage by remember { mutableStateOf("Hindi") }
    var selectedTtsEmotion by remember { mutableStateOf("Friendly") }
    var speedSetting by remember { mutableStateOf(1.0f) }
    var pitchSetting by remember { mutableStateOf(1.0f) }
    var volumeSetting by remember { mutableStateOf(0.9f) }
    var customPronunciationWord by remember { mutableStateOf("") }
    var customPhonemeHelp by remember { mutableStateOf("") }
    var isPlayingTts by remember { mutableStateOf(false) }
    var isGeneratingTts by remember { mutableStateOf(false) }

    // Training states
    var newCloneName by remember { mutableStateOf("Digital Twin Studio") }
    var selectedTrainLanguage by remember { mutableStateOf("English (US)") }
    var isConsented by remember { mutableStateOf(false) }
    var isRecordingTrainAudio by remember { mutableStateOf(false) }
    var recordElapsedSeconds by remember { mutableStateOf(0) }
    var isTrainingActive by remember { mutableStateOf(false) }
    var trainingProgressPct by remember { mutableStateOf(0) }
    var uploadedAudioFileName by remember { mutableStateOf<String?>(null) }
    var uploadedAudioBytes by remember { mutableStateOf<Long?>(null) }
    var selectedRecordingDurationSec by remember { mutableStateOf(0) }

    // Quality check sliders & simulation values
    var micQualityScoreSim by remember { mutableStateOf(92) }
    var backgroundNoiseLevelSim by remember { mutableStateOf(-58) } // dB
    val calculatedFeasibilityScore = remember(micQualityScoreSim, backgroundNoiseLevelSim) {
        val noiseDiff = (backgroundNoiseLevelSim + 80).coerceIn(0, 40)
        ((micQualityScoreSim + noiseDiff * 0.5) * 0.1).coerceIn(0.0, 10.0)
    }

    // Noise Reduction configurations
    var preserveOriginalStyleAccent by remember { mutableStateOf(true) }
    var noiseCancellationEnabled by remember { mutableStateOf(true) }
    var ecoCancellationEnabled by remember { mutableStateOf(true) }
    var normalizeAudioVolumeEnabled by remember { mutableStateOf(true) }

    // Workspace search filter
    var queryFilterText by remember { mutableStateOf("") }

    // Dialog state
    var showUpgradeDialog by remember { mutableStateOf(false) }
    var showRenameDialog by remember { mutableStateOf<ClonedVoiceModel?>(null) }
    var renamedNewName by remember { mutableStateOf("") }
    var showPronunciationHelper by remember { mutableStateOf(false) }

    // Timer loop for recording simulation
    LaunchedEffect(isRecordingTrainAudio) {
        if (isRecordingTrainAudio) {
            recordElapsedSeconds = 0
            while (isRecordingTrainAudio) {
                delay(1000)
                recordElapsedSeconds++
                selectedRecordingDurationSec = recordElapsedSeconds
            }
        }
    }

    // Timer loop for training simulation
    LaunchedEffect(isTrainingActive) {
        if (isTrainingActive) {
            trainingProgressPct = 0
            while (trainingProgressPct < 100) {
                delay(140)
                trainingProgressPct += 2
            }
            isTrainingActive = false
            // Add new model
            val addedModel = ClonedVoiceModel(
                id = "clone_${System.currentTimeMillis()}",
                name = newCloneName,
                trainingStatus = "Ready",
                language = selectedTrainLanguage,
                qualityScore = Math.round(calculatedFeasibilityScore * 10.0) / 10.0,
                audioSamplesCount = if (uploadedAudioFileName != null) 1 else 3,
                totalRecordedSeconds = if (uploadedAudioFileName != null) 140 else selectedRecordingDurationSec,
                isFavorite = false,
                isDefault = false,
                baseFrequency = if (newCloneName.lowercase().contains("deep")) 115f else 155f,
                clarityScore = micQualityScoreSim + 3,
                micRating = micQualityScoreSim,
                ambientNoiseLevel = backgroundNoiseLevelSim
            )
            voiceModelsList.add(addedModel)
            selectedCloneModel = addedModel
            
            viewModel.recordVoiceClone(
                modelName = newCloneName,
                trainingStatus = "Success",
                qualityScore = "${addedModel.qualityScore}/10",
                metadata = "Samples: ${addedModel.audioSamplesCount}, Base Freq: ${addedModel.baseFrequency}Hz, Mic Rating: ${addedModel.micRating}%"
            )
            Toast.makeText(context, "Voice Clone Model '${newCloneName}' successfully trained! 🎉", Toast.LENGTH_LONG).show()
            selectedTabIdx = 2 // Move to generation tab auto
        }
    }

    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFF030309))
            .padding(horizontal = 14.dp)
            .verticalScroll(rememberScrollState()),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        Spacer(modifier = Modifier.height(6.dp))

        // Module Header Section
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                    Text(
                        "AI VOICE CLONING LAB",
                        fontSize = 11.sp,
                        letterSpacing = 1.sp,
                        color = NeonPurple,
                        fontWeight = FontWeight.Bold
                    )
                    Box(
                        modifier = Modifier
                            .background(if (isPro) Color(0xFFFFD700).copy(alpha = 0.15f) else Color.White.copy(alpha = 0.1f), RoundedCornerShape(4.dp))
                            .border(0.5.dp, if (isPro) Color(0xFFFFD700) else Color.Gray, RoundedCornerShape(4.dp))
                            .padding(horizontal = 4.dp, vertical = 2.dp)
                    ) {
                        Text(
                            text = if (isPro) "PRO MAX" else "BASIC FREE",
                            color = if (isPro) Color(0xFFFFD700) else Color.White,
                            fontSize = 7.5.sp,
                            fontWeight = FontWeight.Black
                        )
                    }
                }
                Text("Synthesize realistic replica vocals from audio samples.", fontSize = 12.sp, color = Color.LightGray)
            }

            if (!isPro) {
                Button(
                    onClick = { showUpgradeDialog = true },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
                    shape = RoundedCornerShape(6.dp),
                    contentPadding = PaddingValues(horizontal = 8.dp, vertical = 3.dp)
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(3.dp)) {
                        Icon(imageVector = Icons.Filled.Star, contentDescription = null, tint = Color.White, modifier = Modifier.size(11.dp))
                        Text("UPGRADE", fontSize = 8.sp, fontWeight = FontWeight.Black)
                    }
                }
            }
        }

        // Sub Navigation Tabs Row
        TabRow(
            selectedTabIndex = selectedTabIdx,
            containerColor = Color(0xFF0A0A16),
            contentColor = NeonCyan,
            indicator = { tabPositions ->
                TabRowDefaults.SecondaryIndicator(
                    modifier = Modifier.tabIndicatorOffset(tabPositions[selectedTabIdx]),
                    color = NeonPurple
                )
            },
            modifier = Modifier
                .fillMaxWidth()
                .clip(RoundedCornerShape(8.dp))
                .border(0.5.dp, Color.DarkGray.copy(alpha = 0.3f), RoundedCornerShape(8.dp))
        ) {
            tabs.forEachIndexed { idx, title ->
                Tab(
                    selected = selectedTabIdx == idx,
                    onClick = { selectedTabIdx = idx },
                    text = { Text(title, fontSize = 9.sp, fontWeight = FontWeight.Bold, color = if (selectedTabIdx == idx) Color.White else Color.Gray) }
                )
            }
        }

        // TAB SCREEN ROUTING
        when (selectedTabIdx) {
            0 -> {
                // DASHBOARD SCREEN: Voice list + Usage statistics + Quick operations
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    // Header counter item
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF0E0E1F), RoundedCornerShape(10.dp))
                            .padding(12.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text("ACTIVE VOICE MODELS LIMIT", fontSize = 9.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                            Text("${voiceModelsList.size} / $maxClones Custom Clones Trained", fontSize = 13.sp, color = Color.White, fontWeight = FontWeight.ExtraBold)
                        }

                        Box(
                            modifier = Modifier
                                .background(NeonCyan.copy(alpha = 0.12f), RoundedCornerShape(6.dp))
                                .padding(horizontal = 8.dp, vertical = 4.dp)
                        ) {
                            Text(
                                "LIMIT CAP: ${(voiceModelsList.size.toFloat() / maxClones * 100).toInt()}% USED",
                                color = NeonCyan,
                                fontSize = 8.1.sp,
                                fontWeight = FontWeight.Black
                            )
                        }
                    }

                    // Model Search filter
                    OutlinedTextField(
                        value = queryFilterText,
                        onValueChange = { queryFilterText = it },
                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(38.dp),
                        placeholder = { Text("Filter trained clones by name or target language...", fontSize = 10.sp, color = Color.Gray) },
                        colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPurple, unfocusedBorderColor = Color.DarkGray),
                        shape = RoundedCornerShape(6.dp),
                        leadingIcon = { Icon(imageVector = Icons.Filled.Search, contentDescription = null, tint = Color.Gray, modifier = Modifier.size(13.dp)) }
                    )

                    Text("YOUR CLONED IDENTITIES", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.Bold)

                    val filteredModels = voiceModelsList.filter {
                        it.name.contains(queryFilterText, ignoreCase = true) || it.language.contains(queryFilterText, ignoreCase = true)
                    }

                    if (filteredModels.isEmpty()) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF060611), RoundedCornerShape(10.dp))
                                .padding(24.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text("No voice models matching selection. Tap 'RECORD & TRAIN' tab to build one!", color = Color.Gray, fontSize = 11.sp)
                        }
                    } else {
                        filteredModels.forEach { model ->
                            val isDefault = selectedCloneModel.id == model.id
                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .border(
                                        width = if (isDefault) 1.dp else 0.5.dp,
                                        color = if (isDefault) NeonCyan else Color.White.copy(alpha = 0.05f),
                                        shape = RoundedCornerShape(10.dp)
                                    ),
                                colors = CardDefaults.cardColors(containerColor = if (isDefault) Color(0xFF0F0F23) else Color(0xFF060610))
                            ) {
                                Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                        Column {
                                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                                Text(model.name, color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Bold)
                                                if (model.isDefault) {
                                                    Box(
                                                        modifier = Modifier
                                                            .background(Color(0xFF0D9488), RoundedCornerShape(4.dp))
                                                            .padding(horizontal = 4.dp, vertical = 1.5.dp)
                                                    ) {
                                                        Text("DEFAULT SPEECHER", color = Color.White, fontSize = 6.sp, fontWeight = FontWeight.Bold)
                                                    }
                                                }
                                            }
                                            Text("Trained: ${android.text.format.DateFormat.format("dd MMM yyyy", model.createdDate)}", fontSize = 9.sp, color = Color.Gray)
                                        }

                                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                            // Favorite Toggle
                                            IconButton(
                                                onClick = {
                                                    val idx = voiceModelsList.indexOfFirst { it.id == model.id }
                                                    if (idx != -1) {
                                                        voiceModelsList[idx] = model.copy(isFavorite = !model.isFavorite)
                                                    }
                                                },
                                                modifier = Modifier.size(24.dp)
                                            ) {
                                                Icon(
                                                    imageVector = if (model.isFavorite) Icons.Filled.Favorite else Icons.Outlined.FavoriteBorder,
                                                    contentDescription = "Fav",
                                                    tint = if (model.isFavorite) Color.Red else Color.Gray,
                                                    modifier = Modifier.size(13.dp)
                                                )
                                            }

                                            // Rename
                                            IconButton(
                                                onClick = {
                                                    showRenameDialog = model
                                                    renamedNewName = model.name
                                                },
                                                modifier = Modifier.size(24.dp)
                                            ) {
                                                Icon(imageVector = Icons.Filled.Edit, contentDescription = "Rename", tint = Color.LightGray, modifier = Modifier.size(13.dp))
                                            }

                                            // Delete Model
                                            IconButton(
                                                onClick = {
                                                    if (voiceModelsList.size > 1) {
                                                        voiceModelsList.remove(model)
                                                        if (selectedCloneModel.id == model.id) {
                                                            selectedCloneModel = voiceModelsList[0]
                                                        }
                                                        Toast.makeText(context, "Voice model deleted", Toast.LENGTH_SHORT).show()
                                                    } else {
                                                        Toast.makeText(context, "You need at least one custom voice profile", Toast.LENGTH_SHORT).show()
                                                    }
                                                },
                                                modifier = Modifier.size(24.dp)
                                            ) {
                                                Icon(imageVector = Icons.Filled.Delete, contentDescription = "Delete", tint = Color.Red.copy(alpha = 0.8f), modifier = Modifier.size(13.dp))
                                            }
                                        }
                                    }

                                    // Display attributes
                                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                        Column {
                                            Text("Language Target", fontSize = 8.sp, color = Color.Gray)
                                            Text(model.language, fontSize = 10.sp, color = Color.White, fontWeight = FontWeight.Bold)
                                        }
                                        Column {
                                            Text("Feasibility Clone Score", fontSize = 8.sp, color = Color.Gray)
                                            Row(verticalAlignment = Alignment.CenterVertically) {
                                                Icon(imageVector = Icons.Filled.CheckCircle, contentDescription = null, tint = NeonCyan, modifier = Modifier.size(10.dp))
                                                Spacer(modifier = Modifier.width(3.dp))
                                                Text("${model.qualityScore} / 10.0", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                                            }
                                        }
                                        Column {
                                            Text("Estimated Clarity", fontSize = 8.sp, color = Color.Gray)
                                            Text("${model.clarityScore}% High fidelity", fontSize = 10.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                                        }
                                        Column {
                                            Text("Audio Cloned Hours", fontSize = 8.sp, color = Color.Gray)
                                            Text("${model.audioSamplesCount} Samples (${model.totalRecordedSeconds}s)", fontSize = 10.sp, color = Color.LightGray)
                                        }
                                    }

                                    Divider(color = Color.White.copy(alpha = 0.05f))

                                    // Duplicate, set as target, preview speech triggers
                                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                        Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                            TextButton(
                                                onClick = {
                                                    // Duplicate Model
                                                    val dupe = model.copy(
                                                        id = "clone_dupe_${System.currentTimeMillis()}",
                                                        name = "${model.name} Copy"
                                                    )
                                                    voiceModelsList.add(dupe)
                                                    Toast.makeText(context, "Duplicated model successfully", Toast.LENGTH_SHORT).show()
                                                },
                                                contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp),
                                                modifier = Modifier.height(24.dp)
                                            ) {
                                                Row(verticalAlignment = Alignment.CenterVertically) {
                                                    Icon(imageVector = Icons.Filled.ContentCopy, contentDescription = null, tint = NeonCyan, modifier = Modifier.size(9.dp))
                                                    Spacer(modifier = Modifier.width(2.dp))
                                                    Text("DUPLICATE", fontSize = 8.sp, color = NeonCyan)
                                                }
                                            }

                                            if (!isDefault) {
                                                TextButton(
                                                    onClick = {
                                                        selectedCloneModel = model
                                                        Toast.makeText(context, "${model.name} set as synthesis speech target!", Toast.LENGTH_SHORT).show()
                                                    },
                                                    contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp),
                                                    modifier = Modifier.height(24.dp)
                                                ) {
                                                    Text("SET DEFAULT TARGET", fontSize = 8.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                                                }
                                            }
                                        }

                                        Button(
                                            onClick = {
                                                selectedCloneModel = model
                                                selectedTabIdx = 2 // Switch to generation tab
                                            },
                                            colors = ButtonDefaults.buttonColors(containerColor = if (isDefault) NeonCyan else Color.White.copy(alpha = 0.1f)),
                                            shape = RoundedCornerShape(4.dp),
                                            contentPadding = PaddingValues(horizontal = 10.dp, vertical = 2.dp),
                                            modifier = Modifier.height(22.dp)
                                        ) {
                                            Text("USE FOR TTS", color = if (isDefault) PureBlack else Color.White, fontSize = 8.sp, fontWeight = FontWeight.Black)
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }

            1 -> {
                // RECORD & TRAIN SCREEN: Consent check + mic recording/uploading panel + quality check + training progress
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    
                    // Ethics and User consent warning card
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .border(0.5.dp, Color(0xFFEA580C).copy(alpha = 0.5f), RoundedCornerShape(10.dp)),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF2C1408))
                    ) {
                        Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                Icon(imageVector = Icons.Filled.Info, contentDescription = null, tint = Color(0xFFEA580C), modifier = Modifier.size(15.dp))
                                Text("RESPONSIBLE USE & EXPLICIT BIOMETRIC CONSENT", color = Color(0xFFFF8A4D), fontSize = 10.sp, fontWeight = FontWeight.Black)
                            }
                            Text(
                                text = "Consent confirms you own the submitted audio. We strictly forbid cloning public figures, identity fraud, impersonation, or dangerous deepfakes. All audio holds active encrypted watermarks to guarantee abuse tracking and rate checking.",
                                color = Color.LightGray,
                                fontSize = 9.5.sp
                            )
                            Spacer(modifier = Modifier.height(2.dp))
                            Row(verticalAlignment = Alignment.CenterVertically) {
                                Checkbox(
                                    checked = isConsented,
                                    onCheckedChange = { isConsented = it },
                                    colors = CheckboxDefaults.colors(checkedColor = NeonCyan)
                                )
                                Text("I authorize and consent to clone my own voice records.", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }

                    // Model naming & Language
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                        Column(modifier = Modifier.weight(1.2f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("CUSTOM MODEL NICKNAME", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                            OutlinedTextField(
                                value = newCloneName,
                                onValueChange = { newCloneName = it },
                                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                                colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonCyan, unfocusedBorderColor = Color.DarkGray),
                                shape = RoundedCornerShape(6.dp),
                                modifier = Modifier.height(44.dp)
                            )
                        }

                        Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("BASE LANGUAGE", fontSize = 9.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                            val languages = listOf("English (US)", "Hindi", "Spanish", "Arabic", "French", "German", "Japanese")
                            var showLgDrop by remember { mutableStateOf(false) }

                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(44.dp)
                                    .clip(RoundedCornerShape(6.dp))
                                    .background(Color(0xFF0F0F26))
                                    .border(0.5.dp, Color.DarkGray, RoundedCornerShape(6.dp))
                                    .clickable { showLgDrop = true }
                                    .padding(horizontal = 8.dp, vertical = 10.dp)
                            ) {
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Text(selectedTrainLanguage, color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold, maxLines = 1)
                                    Icon(imageVector = Icons.Filled.ArrowDropDown, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(14.dp))
                                }

                                DropdownMenu(
                                    expanded = showLgDrop,
                                    onDismissRequest = { showLgDrop = false },
                                    modifier = Modifier.background(Color(0xFF0F0F23))
                                ) {
                                    languages.forEach { lang ->
                                        DropdownMenuItem(
                                            text = { Text(lang, color = Color.White, fontSize = 10.sp) },
                                            onClick = {
                                                selectedTrainLanguage = lang
                                                showLgDrop = false
                                            }
                                        )
                                    }
                                }
                            }
                        }
                    }

                    // AUDIO ACQUISITION: Mic capture OR Upload audio references
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .border(0.5.dp, Color(0xFF1E293B), RoundedCornerShape(10.dp)),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF070712))
                    ) {
                        Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
                            Text("RECORD STUDIO OR FILE UPLOADER (MIN 30 SECS REQUIRED)", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)

                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(12.dp)) {
                                // Microphone recorder button block
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .background(Color(0xFF0B0B1F), RoundedCornerShape(8.dp))
                                        .border(
                                            0.5.dp,
                                            if (isRecordingTrainAudio) NeonPurple else Color.DarkGray,
                                            RoundedCornerShape(8.dp)
                                        )
                                        .padding(10.dp)
                                ) {
                                    Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(4.dp), modifier = Modifier.fillMaxWidth()) {
                                        IconButton(
                                            onClick = {
                                                if (!isConsented) {
                                                    Toast.makeText(context, "Please review and tick ethical Biometric Consent checkbox first", Toast.LENGTH_LONG).show()
                                                } else {
                                                    isRecordingTrainAudio = !isRecordingTrainAudio
                                                    if (isRecordingTrainAudio) {
                                                        uploadedAudioFileName = null
                                                    }
                                                }
                                            },
                                            modifier = Modifier
                                                .size(34.dp)
                                                .background(if (isRecordingTrainAudio) Color.Red else NeonPurple, CircleShape)
                                        ) {
                                            Icon(
                                                imageVector = if (isRecordingTrainAudio) Icons.Filled.Stop else Icons.Filled.Mic,
                                                contentDescription = "Capture audio",
                                                tint = Color.White,
                                                modifier = Modifier.size(18.dp)
                                            )
                                        }

                                        Text(
                                            text = if (isRecordingTrainAudio) "RECORDING IN PROGRESS..." else "START CAPTURE MIC",
                                            fontSize = 8.sp,
                                            fontWeight = FontWeight.Bold,
                                            color = if (isRecordingTrainAudio) Color.Red else Color.LightGray
                                        )

                                        if (isRecordingTrainAudio) {
                                            Text(
                                                text = "${recordElapsedSeconds}s elapsed / Rec 1-5 mins",
                                                fontSize = 9.sp,
                                                color = NeonCyan,
                                                fontWeight = FontWeight.Black
                                            )
                                        } else if (selectedRecordingDurationSec > 0) {
                                            Text(
                                                text = "Captured ${selectedRecordingDurationSec}s audio successfully!",
                                                fontSize = 8.5.sp,
                                                color = Color.Green,
                                                fontWeight = FontWeight.Bold
                                            )
                                        }
                                    }
                                }

                                // Upload audio files button block
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .background(Color(0xFF0B0B1F), RoundedCornerShape(8.dp))
                                        .border(0.5.dp, Color.DarkGray, RoundedCornerShape(8.dp))
                                        .clickable {
                                            if (!isConsented) {
                                                Toast.makeText(context, "Tick Consent checkbox first", Toast.LENGTH_SHORT).show()
                                            } else {
                                                // mock choice
                                                uploadedAudioFileName = "voice_sample_interview_3m.wav"
                                                uploadedAudioBytes = 4851200 // 4.8MB
                                                selectedRecordingDurationSec = 180
                                                Toast.makeText(context, "Successfully loaded virtual wav sample file!", Toast.LENGTH_SHORT).show()
                                            }
                                        }
                                        .padding(10.dp)
                                ) {
                                    Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(4.dp), modifier = Modifier.fillMaxWidth()) {
                                        Icon(
                                            imageVector = Icons.Filled.CloudUpload,
                                            contentDescription = "Upload files",
                                            tint = NeonCyan,
                                            modifier = Modifier.size(24.dp)
                                        )

                                        Text("UPLOAD WAV / MP3 / M4A", fontSize = 8.sp, fontWeight = FontWeight.Bold, color = Color.White)
                                        Text("Max upload limits: 35MB size validation.", fontSize = 7.5.sp, color = Color.Gray)

                                        if (uploadedAudioFileName != null) {
                                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                                Text(uploadedAudioFileName ?: "", fontSize = 8.sp, color = Color.Green, fontWeight = FontWeight.Bold)
                                                Text("Size: ${String.format("%.1f", (uploadedAudioBytes ?: 0L) / 1024f / 1024f)} MB", fontSize = 7.sp, color = Color.Gray)
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }

                    // AUDIO QUALITY CHECK ANALYZER PANEL
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .border(0.5.dp, Color(0xFF1E293B), RoundedCornerShape(10.dp)),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF060613))
                    ) {
                        Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("DYNAMIC CLONE FEASIBILITY ANALYZER", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                                Box(
                                    modifier = Modifier
                                        .background(Color.White.copy(alpha = 0.05f), RoundedCornerShape(4.dp))
                                        .padding(horizontal = 4.dp, vertical = 2.dp)
                                ) {
                                    Text("ACCENT: INDIAN/MID-ATL DEP", color = Color.LightGray, fontSize = 7.sp, fontWeight = FontWeight.Bold)
                                }
                            }

                            // Microphone score slider
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("Microphone Input Quality", fontSize = 9.sp, color = Color.LightGray)
                                Text("$micQualityScoreSim %", fontSize = 9.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = micQualityScoreSim.toFloat(),
                                onValueChange = { micQualityScoreSim = it.toInt() },
                                valueRange = (30f..100f),
                                colors = SliderDefaults.colors(thumbColor = NeonPurple, activeTrackColor = NeonPurple)
                            )

                            // Noise floor slider
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("Room Ambient Noise level", fontSize = 9.sp, color = Color.LightGray)
                                Text("$backgroundNoiseLevelSim dB (Target: < -50dB)", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = backgroundNoiseLevelSim.toFloat(),
                                onValueChange = { backgroundNoiseLevelSim = it.toInt() },
                                valueRange = (-80f..-10f),
                                colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan)
                            )

                            // Status metrics
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Text("Speech Clarity:", fontSize = 8.5.sp, color = Color.Gray)
                                    Text(if (micQualityScoreSim > 75) "Excellent (HQ)" else "Standard Dynamic", fontSize = 8.5.sp, color = Color.White, fontWeight = FontWeight.Bold)
                                }
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Text("Consistent Volume:", fontSize = 8.5.sp, color = Color.Gray)
                                    Text(if (backgroundNoiseLevelSim < -45) "Highly Balanced" else "Echo Detected", fontSize = 8.5.sp, color = Color.White, fontWeight = FontWeight.Bold)
                                }
                            }

                            Divider(color = Color.White.copy(alpha = 0.05f))

                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Column {
                                    Text("ESTIMATED TRAINING FIDELITY RATING", fontSize = 8.sp, color = Color.Gray)
                                    Text("${String.format("%.1f", calculatedFeasibilityScore)} / 10.0 Rating", fontSize = 12.sp, color = NeonCyan, fontWeight = FontWeight.ExtraBold)
                                }

                                if (calculatedFeasibilityScore < 5.0) {
                                    Text("⚠️ Not enough voice sample quality", color = Color.Red, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                                } else {
                                    Text("✅ Ready for training pipeline", color = Color.Green, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }

                    // SOUND ENHANCEMENT CONTROLS BLOCK
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF050510))
                    ) {
                        Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
                            Text("DETERMINATED PRE-PROCESSING AUDIO ENHANCEMENTS", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)

                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("Original Speaker Accent Styles Preservation", fontSize = 9.sp, color = Color.White)
                                Switch(checked = preserveOriginalStyleAccent, onCheckedChange = { preserveOriginalStyleAccent = it }, modifier = Modifier.scale(0.7f))
                            }
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("Advanced Ambient Background Noise Reduction", fontSize = 9.sp, color = Color.White)
                                Switch(checked = noiseCancellationEnabled, onCheckedChange = { noiseCancellationEnabled = it }, modifier = Modifier.scale(0.7f))
                            }
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("Active Vocal Echo Cancellation Sub-system", fontSize = 9.sp, color = Color.White)
                                Switch(checked = ecoCancellationEnabled, onCheckedChange = { ecoCancellationEnabled = it }, modifier = Modifier.scale(0.7f))
                            }
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("Smart Levels Audio Signal Normalization", fontSize = 9.sp, color = Color.White)
                                Switch(checked = normalizeAudioVolumeEnabled, onCheckedChange = { normalizeAudioVolumeEnabled = it }, modifier = Modifier.scale(0.7f))
                            }
                        }
                    }

                    // Action Button: TRAIN VOICE CLONE
                    if (isTrainingActive) {
                        Column(
                            verticalArrangement = Arrangement.spacedBy(6.dp),
                            horizontalAlignment = Alignment.CenterHorizontally,
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF0B0B24), RoundedCornerShape(8.dp))
                                .padding(12.dp)
                        ) {
                            Text("Synthesizing Neural Voice Embeddings...", fontSize = 11.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                            LinearProgressIndicator(
                                progress = { trainingProgressPct / 100f },
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(6.dp)
                                    .clip(RoundedCornerShape(3.dp)),
                                color = NeonPurple,
                                trackColor = Color.DarkGray
                            )
                            Text("Overall progress: $trainingProgressPct% complete", fontSize = 9.sp, color = Color.LightGray)
                        }
                    } else {
                        Button(
                            onClick = {
                                if (!isConsented) {
                                    Toast.makeText(context, "Explicit speaker consent check is REQUIRED to train model", Toast.LENGTH_LONG).show()
                                } else if (selectedRecordingDurationSec < 30) {
                                    Toast.makeText(context, "Minimum 30 seconds of speech required to start clone model", Toast.LENGTH_LONG).show()
                                } else if (newCloneName.isBlank()) {
                                    Toast.makeText(context, "Please name the voice clone model first", Toast.LENGTH_SHORT).show()
                                } else {
                                    isTrainingActive = true
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(44.dp),
                            shape = RoundedCornerShape(8.dp)
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                Icon(imageVector = Icons.Filled.RecordVoiceOver, contentDescription = null, tint = Color.White, modifier = Modifier.size(16.dp))
                                Text("COMPILE RECORDS & TRAIN VOICE MODEL", fontSize = 11.sp, fontWeight = FontWeight.ExtraBold)
                            }
                        }
                    }
                }
            }

            2 -> {
                // GENERATE WORKSPACE: TTS with selected clone model + pitch/tempo/volume/emotion sliders + pronunciation editor
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    
                    // Selected Cloned Model selector card
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .border(0.5.dp, NeonCyan, RoundedCornerShape(10.dp)),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF040A1A))
                    ) {
                        Row(
                            modifier = Modifier
                                .clickable { selectedTabIdx = 0 }
                                .padding(12.dp),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                Icon(imageVector = Icons.Filled.RecordVoiceOver, contentDescription = null, tint = NeonCyan, modifier = Modifier.size(24.dp))
                                Column {
                                    Text("PRIMARY VOICE REPLICA ACTIVE", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                                    Text(selectedCloneModel.name, fontSize = 14.sp, color = Color.White, fontWeight = FontWeight.ExtraBold)
                                    Text("Clone Loyalty Rating: ${selectedCloneModel.qualityScore} / 10.0 (HQ)", fontSize = 10.sp, color = Color.Gray)
                                }
                            }

                            Box(
                                modifier = Modifier
                                    .background(NeonPurple.copy(alpha = 0.2f), RoundedCornerShape(6.dp))
                                    .padding(horizontal = 6.dp, vertical = 3.dp)
                            ) {
                                Text("CHANGE MODEL", color = NeonPurple, fontSize = 8.sp, fontWeight = FontWeight.Black)
                            }
                        }
                    }

                    // Simulated live playback waveform + player status block
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF050510))
                    ) {
                        Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Box(
                                        modifier = Modifier
                                            .size(6.dp)
                                            .background(if (isPlayingTts) Color.Green else Color.Gray, CircleShape)
                                    )
                                    Text(
                                        text = if (isPlayingTts) "SPEAKING CLONED DUPLICATE VOCALS..." else "TTS SYNTHESIS ENGINE READY",
                                        fontSize = 8.5.sp,
                                        fontWeight = FontWeight.Bold,
                                        color = if (isPlayingTts) Color.Green else Color.LightGray
                                    )
                                }

                                Text("EMBEDDING: ${selectedCloneModel.id.uppercase().take(8)}", color = Color.Gray, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            }

                            // Dynamic Waveform visualizer
                            WaveformVisualizer(
                                isPlaying = isPlayingTts,
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(34.dp)
                            )

                            // Controls Row
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Button(
                                        onClick = {
                                            if (isPlayingTts) {
                                                isPlayingTts = false
                                            } else {
                                                isPlayingTts = true
                                                scope.launch {
                                                    playSynthesizedSpeech(textInput, "Male", pitchSetting * (selectedCloneModel.baseFrequency / 145f), speedSetting, volumeSetting)
                                                    val delta = (600 + textInput.length * 70) / speedSetting
                                                    delay(delta.toLong())
                                                    isPlayingTts = false
                                                }
                                            }
                                        },
                                        colors = ButtonDefaults.buttonColors(containerColor = NeonCyan),
                                        shape = RoundedCornerShape(6.dp),
                                        contentPadding = PaddingValues(horizontal = 12.dp, vertical = 2.dp),
                                        modifier = Modifier.height(28.dp),
                                        enabled = textInput.isNotBlank() && !isGeneratingTts
                                    ) {
                                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                            Icon(
                                                imageVector = if (isPlayingTts) Icons.Filled.Pause else Icons.Filled.PlayArrow,
                                                contentDescription = null,
                                                tint = PureBlack,
                                                modifier = Modifier.size(13.dp)
                                            )
                                            Text(if (isPlayingTts) "PAUSE" else "PLAY REPLICA", color = PureBlack, fontSize = 8.5.sp, fontWeight = FontWeight.Bold)
                                        }
                                    }

                                    OutlinedButton(
                                        onClick = { isPlayingTts = false },
                                        shape = RoundedCornerShape(6.dp),
                                        border = BorderStroke(0.5.dp, Color.Gray),
                                        modifier = Modifier.height(28.dp),
                                        contentPadding = PaddingValues(horizontal = 12.dp, vertical = 2.dp)
                                    ) {
                                        Text("STOP", color = Color.White, fontSize = 8.5.sp)
                                    }
                                }

                                Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    IconButton(
                                        onClick = {
                                            val file = saveVoiceWavFile(context, "voice_clone_export_${System.currentTimeMillis()}.wav", textInput, "Male", pitchSetting * (selectedCloneModel.baseFrequency / 145f), speedSetting)
                                            if (file != null) {
                                                val shar = Intent(Intent.ACTION_SEND).apply {
                                                    type = "audio/wav"
                                                    putExtra(Intent.EXTRA_STREAM, Uri.fromFile(file))
                                                    putExtra(Intent.EXTRA_TEXT, "Generated voice replication using Digital Clone - ${selectedCloneModel.name}")
                                                }
                                                context.startActivity(Intent.createChooser(shar, "Share Digital Clone Replica"))
                                            } else {
                                                Toast.makeText(context, "Failed to compile audio records", Toast.LENGTH_SHORT).show()
                                            }
                                        },
                                        modifier = Modifier
                                            .size(28.dp)
                                            .background(Color.White.copy(alpha = 0.05f), CircleShape)
                                    ) {
                                        Icon(imageVector = Icons.Filled.Share, contentDescription = "Share", tint = Color.White, modifier = Modifier.size(13.dp))
                                    }

                                    IconButton(
                                        onClick = {
                                            val outFileName = "digital_clone_audio_${System.currentTimeMillis()}.wav"
                                            val file = saveVoiceWavFile(context, outFileName, textInput, "Male", pitchSetting * (selectedCloneModel.baseFrequency / 145f), speedSetting)
                                            if (file != null) {
                                                Toast.makeText(context, "Exported successfully: $outFileName!", Toast.LENGTH_SHORT).show()
                                                viewModel.recordVoiceCloneGeneration(
                                                    text = textInput,
                                                    voiceModelName = selectedCloneModel.name,
                                                    language = selectedTtsLanguage,
                                                    emotion = selectedTtsEmotion,
                                                    audioSettings = "Refactor Base: ${selectedCloneModel.baseFrequency}Hz, Pitch: ${pitchSetting}x, Tempo: ${speedSetting}x",
                                                    audioMetadata = "File: $outFileName, Format: WAV PCM, Size: ${file.length() / 1024} KB"
                                                )
                                            } else {
                                                Toast.makeText(context, "Error writing outputs wav", Toast.LENGTH_SHORT).show()
                                            }
                                        },
                                        modifier = Modifier
                                            .size(28.dp)
                                            .background(Color.White.copy(alpha = 0.05f), CircleShape)
                                    ) {
                                        Icon(imageVector = Icons.Filled.Save, contentDescription = "Save", tint = NeonCyan, modifier = Modifier.size(13.dp))
                                    }
                                }
                            }
                        }
                    }

                    // Input Textbox Box
                    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                            Text("SPEECH CLONE TRANSCRIPT SCRIPT (MULTI-PARAGRAPH)", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                            
                            Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                TextButton(
                                    onClick = { textInput = "$textInput [pause_2s]" },
                                    modifier = Modifier.height(20.dp),
                                    contentPadding = PaddingValues(0.dp)
                                ) {
                                    Text("+ INSERT PAUSE", fontSize = 8.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                                }

                                TextButton(
                                    onClick = { showPronunciationHelper = true },
                                    modifier = Modifier.height(20.dp),
                                    contentPadding = PaddingValues(0.dp)
                                ) {
                                    Text("PRONUNCIATION ED", fontSize = 8.sp, color = Color.Yellow, fontWeight = FontWeight.Bold)
                                }
                            }
                        }

                        OutlinedTextField(
                            value = textInput,
                            onValueChange = { textInput = it },
                            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 12.sp),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(110.dp),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedBorderColor = NeonCyan,
                                unfocusedBorderColor = Color.DarkGray,
                                focusedContainerColor = Color(0xFF070712),
                                unfocusedContainerColor = Color(0xFF070712)
                            ),
                            shape = RoundedCornerShape(8.dp),
                            placeholder = { Text("Write paragraph for your replica voice to read aloud...", color = Color.Gray, fontSize = 11.sp) }
                        )

                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                            Text("${textInput.length} characters", fontSize = 8.5.sp, color = Color.Gray)

                            // Gemini Assist
                            TextButton(
                                onClick = {
                                    isGeneratingTts = true
                                    scope.launch {
                                        val prompt = "Rewrite this script paragraph with fluent narrative flow hooks for voice narration: \"$textInput\""
                                        textInput = try {
                                            com.example.api.RetrofitClient.generateWithGemini(prompt, "You are a professional voice script content enhancer solver.")
                                        } catch (e: Exception) {
                                            "Hello! Testing custom voice duplicate fidelity system. The speaker's traits are preserved automatically with advanced emotion curves."
                                        }
                                        isGeneratingTts = false
                                    }
                                },
                                modifier = Modifier.height(22.dp),
                                contentPadding = PaddingValues(0.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = null, tint = Color.Yellow, modifier = Modifier.size(12.dp))
                                    Text("GEMINI REFINE TEXT", fontSize = 8.5.sp, color = Color.Yellow, fontWeight = FontWeight.Bold)
                                }
                            }
                        }
                    }

                    // Configuration Sliders: pitch, tempo, volume
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF060613))
                    ) {
                        Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(6.dp)) {
                            Text("SPEECH ATTRIBUTES INTONATION CHANNELS", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)

                            // Tempo
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Speech Delivery Speed Ratio", fontSize = 9.sp, color = Color.LightGray)
                                Text("${speedSetting}x", fontSize = 9.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = speedSetting,
                                onValueChange = { speedSetting = it },
                                valueRange = (0.5f..2.0f),
                                colors = SliderDefaults.colors(thumbColor = NeonPurple, activeTrackColor = NeonPurple)
                            )

                            // Pitch
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                Text("Vocal Intonation Pitch Factor", fontSize = 9.sp, color = Color.LightGray)
                                Text("${pitchSetting}x", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                            }
                            Slider(
                                value = pitchSetting,
                                onValueChange = { pitchSetting = it },
                                valueRange = (0.5f..1.8f),
                                colors = SliderDefaults.colors(thumbColor = NeonCyan, activeTrackColor = NeonCyan)
                            )
                        }
                    }

                    // Languages & Emotions Rows
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                        Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("TARGET FLUENCY LANGUAGE", fontSize = 9.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                            val ttsLanguages = listOf("Hindi", "English", "Spanish", "Arabic", "French", "German", "Japanese")
                            var showTtsLgDrop by remember { mutableStateOf(false) }

                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .clip(RoundedCornerShape(6.dp))
                                    .background(Color(0xFF0A0A1F))
                                    .border(0.5.dp, Color.DarkGray, RoundedCornerShape(6.dp))
                                    .clickable { showTtsLgDrop = true }
                                    .padding(horizontal = 8.dp, vertical = 10.dp)
                            ) {
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Text(selectedTtsLanguage, color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    Icon(imageVector = Icons.Filled.ArrowDropDown, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(14.dp))
                                }

                                DropdownMenu(
                                    expanded = showTtsLgDrop,
                                    onDismissRequest = { showTtsLgDrop = false },
                                    modifier = Modifier.background(Color(0xFF0F0F23))
                                ) {
                                    ttsLanguages.forEach { lang ->
                                        DropdownMenuItem(
                                            text = { Text(lang, color = Color.White, fontSize = 10.sp) },
                                            onClick = {
                                                selectedTtsLanguage = lang
                                                showTtsLgDrop = false
                                            }
                                        )
                                    }
                                }
                            }
                        }

                        Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("SPEAKER EMOTION OVERLAY", fontSize = 9.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                            val emotionsPresetList = listOf("Friendly", "Happy", "Sad", "Excited", "Calm", "Angry", "Confident", "Storytelling")
                            var showTtsEmoDrop by remember { mutableStateOf(false) }

                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .clip(RoundedCornerShape(6.dp))
                                    .background(Color(0xFF0A0A1F))
                                    .border(0.5.dp, Color.DarkGray, RoundedCornerShape(6.dp))
                                    .clickable { showTtsEmoDrop = true }
                                    .padding(horizontal = 8.dp, vertical = 10.dp)
                            ) {
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Text(selectedTtsEmotion, color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    Icon(imageVector = Icons.Filled.ArrowDropDown, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(14.dp))
                                }

                                DropdownMenu(
                                    expanded = showTtsEmoDrop,
                                    onDismissRequest = { showTtsEmoDrop = false },
                                    modifier = Modifier.background(Color(0xFF0F0F23))
                                ) {
                                    emotionsPresetList.forEach { emo ->
                                        DropdownMenuItem(
                                            text = { Text(emo, color = Color.White, fontSize = 10.sp) },
                                            onClick = {
                                                selectedTtsEmotion = emo
                                                showTtsEmoDrop = false
                                            }
                                        )
                                    }
                                }
                            }
                        }
                    }

                    // GENERATE AUDIO ACTION BUTTON
                    Button(
                        onClick = {
                            isGeneratingTts = true
                            scope.launch {
                                delay(1200)
                                isGeneratingTts = false
                                isPlayingTts = true
                                playSynthesizedSpeech(textInput, "Male", pitchSetting * (selectedCloneModel.baseFrequency / 145f), speedSetting, volumeSetting)
                                val delta = (600 + textInput.length * 70) / speedSetting
                                delay(delta.toLong())
                                isPlayingTts = false
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = NeonPurple),
                        shape = RoundedCornerShape(8.dp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(44.dp),
                        enabled = textInput.isNotBlank() && !isGeneratingTts
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            if (isGeneratingTts) {
                                CircularProgressIndicator(color = Color.White, modifier = Modifier.size(16.dp))
                                Text("Encoding digital twin pitch signals...", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            } else {
                                Icon(imageVector = Icons.Filled.OfflineBolt, contentDescription = null, tint = Color.White, modifier = Modifier.size(16.dp))
                                Text("SYNTHESIZE SPEECH FROM CLONE", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.ExtraBold)
                            }
                        }
                    }
                }
            }

            3 -> {
                // HISTORY SUMMARY
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text("SPEECH CLONING PERSISTENCE DICTIONARY", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.Bold)

                    val cloneTransactionsList = creationsHistory.filter { it.toolName == "Voice Clone" || it.toolName == "Voice Clone Training" }
                    if (cloneTransactionsList.isEmpty()) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF060613), RoundedCornerShape(10.dp))
                                .padding(24.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text("No cloning transactions found. Try training a clone or generating replica TTS speech!", color = Color.Gray, fontSize = 11.sp)
                        }
                    } else {
                        cloneTransactionsList.reversed().forEach { tx ->
                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .border(0.5.dp, Color.White.copy(alpha = 0.05f), RoundedCornerShape(8.dp)),
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF06060F))
                            ) {
                                Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                        Box(
                                            modifier = Modifier
                                                .background(
                                                    if (tx.toolName.contains("Training")) NeonPurple.copy(alpha = 0.15f) else NeonCyan.copy(alpha = 0.15f),
                                                    RoundedCornerShape(4.dp)
                                                )
                                                .padding(horizontal = 6.dp, vertical = 2.dp)
                                        ) {
                                            Text(tx.toolName.uppercase(), color = if (tx.toolName.contains("Training")) NeonPurple else NeonCyan, fontSize = 7.sp, fontWeight = FontWeight.Black)
                                        }

                                        Text(
                                            text = android.text.format.DateFormat.format("hh:mm a - dd MMM", tx.timestamp).toString(),
                                            color = Color.Gray,
                                            fontSize = 8.sp
                                        )
                                    }

                                    Text(tx.inputPrompt, fontSize = 11.sp, color = Color.White)
                                    Text(tx.outputText, fontSize = 9.sp, color = NeonPurple)

                                    if (!tx.toolName.contains("Training")) {
                                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.End) {
                                            IconButton(
                                                onClick = {
                                                    val rawText = tx.inputPrompt.substringAfter("Text: \"").substringBefore("\"")
                                                    scope.launch {
                                                        playSynthesizedSpeech(rawText, "Male", 1.1f, 1.0f, 0.9f)
                                                    }
                                                },
                                                modifier = Modifier.size(24.dp)
                                            ) {
                                                Icon(imageVector = Icons.Filled.VolumeUp, contentDescription = "Play back clone text", tint = NeonCyan, modifier = Modifier.size(12.dp))
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(24.dp))
    }

    // Modal dialogue rename voice model
    showRenameDialog?.let { model ->
        AlertDialog(
            onDismissRequest = { showRenameDialog = null },
            containerColor = Color(0xFF0F0F1E),
            title = { Text("Rename Cloned Voice Model", color = Color.White, fontSize = 15.sp, fontWeight = FontWeight.Bold) },
            text = {
                OutlinedTextField(
                    value = renamedNewName,
                    onValueChange = { renamedNewName = it },
                    textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 12.sp),
                    colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonCyan, unfocusedBorderColor = Color.DarkGray),
                    shape = RoundedCornerShape(6.dp),
                    modifier = Modifier.fillMaxWidth()
                )
            },
            confirmButton = {
                Button(
                    onClick = {
                        val idx = voiceModelsList.indexOfFirst { it.id == model.id }
                        if (idx != -1 && renamedNewName.isNotBlank()) {
                            voiceModelsList[idx] = model.copy(name = renamedNewName)
                            if (selectedCloneModel.id == model.id) {
                                selectedCloneModel = voiceModelsList[idx]
                            }
                        }
                        showRenameDialog = null
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple)
                ) {
                    Text("SAVE", color = Color.White)
                }
            },
            dismissButton = {
                TextButton(onClick = { showRenameDialog = null }) {
                    Text("CANCEL", color = Color.Gray)
                }
            }
        )
    }

    // Modal dialogue option Pronunciation editor
    if (showPronunciationHelper) {
        AlertDialog(
            onDismissRequest = { showPronunciationHelper = false },
            containerColor = Color(0xFF0F0F23),
            title = {
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                    Icon(imageVector = Icons.Filled.Settings, contentDescription = null, tint = NeonCyan, modifier = Modifier.size(16.dp))
                    Text("Pronunciation phoneme Helper", color = Color.White, fontSize = 14.sp, fontWeight = FontWeight.Bold)
                }
            },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text("Substitute specific words with exact phonetic phonemes to fix clone vocal translation loops (e.g. replace 'AI' with 'Aye Eye'):", color = Color.LightGray, fontSize = 11.sp)
                    
                    OutlinedTextField(
                        value = customPronunciationWord,
                        onValueChange = { customPronunciationWord = it },
                        placeholder = { Text("Original word (e.g., Creator)", color = Color.Gray, fontSize = 10.sp) },
                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                        colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonCyan, unfocusedBorderColor = Color.DarkGray),
                        shape = RoundedCornerShape(6.dp),
                        modifier = Modifier.height(38.dp)
                    )

                    OutlinedTextField(
                        value = customPhonemeHelp,
                        onValueChange = { customPhonemeHelp = it },
                        placeholder = { Text("Phoneme key replacement (e.g., Cree-ay-tor)", color = Color.Gray, fontSize = 10.sp) },
                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                        colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPurple, unfocusedBorderColor = Color.DarkGray),
                        shape = RoundedCornerShape(6.dp),
                        modifier = Modifier.height(38.dp)
                    )
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        if (customPronunciationWord.isNotBlank() && customPhonemeHelp.isNotBlank()) {
                            textInput = textInput.replace(customPronunciationWord, customPhonemeHelp, ignoreCase = true)
                            Toast.makeText(context, "Substitute mapping applied to paragraph script", Toast.LENGTH_SHORT).show()
                        }
                        showPronunciationHelper = false
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple)
                ) {
                    Text("APPLY TO TEXT", color = Color.White)
                }
            },
            dismissButton = {
                TextButton(onClick = { showPronunciationHelper = false }) {
                    Text("DISMISS", color = Color.Gray)
                }
            }
        )
    }

    // Modal upgrade subscription
    if (showUpgradeDialog) {
        AlertDialog(
            onDismissRequest = { showUpgradeDialog = false },
            containerColor = Color(0xFF0F0F1F),
            title = {
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Icon(imageVector = Icons.Filled.NewReleases, contentDescription = null, tint = Color(0xFFFFD700))
                    Text("Unlock Voice Cloning Pro", color = Color.White, fontSize = 16.sp, fontWeight = FontWeight.Bold)
                }
            },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text("Pro tier allows high-fidelity voice profiles training up to 15 voice clones with unlimited characters input speed, custom emotion presets, commercial permission ownership, and ultra-high dynamic quality check models.", color = Color.LightGray, fontSize = 13.sp)
                    Text("★ Train realistic duplicates with raw interviews or audio voice over recording lists.", color = NeonCyan, fontSize = 11.sp, fontWeight = FontWeight.SemiBold)
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        scope.launch {
                            viewModel.updateSubscription("Pro", 500)
                            Toast.makeText(context, "Congratulations! Voice Cloning Studio is now PRO activated! 🎉", Toast.LENGTH_LONG).show()
                            showUpgradeDialog = false
                        }
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple)
                ) {
                    Text("Upgrade instantly ($14.99/mo)", color = Color.White)
                }
            },
            dismissButton = {
                TextButton(onClick = { showUpgradeDialog = false }) {
                    Text("Stay simple", color = Color.Gray)
                }
            }
        )
    }
}

// =========================================================================
// AI PRESENTATION MAKER MODULE
// =========================================================================

data class PresentationSlide(
    val id: String,
    var slideNumber: Int,
    var title: String,
    var layoutType: String, // "Title", "Agenda", "Content", "Comparison", "Chart", "Summary", "ThankYou"
    var contentLines: List<String>,
    var speakerNotes: String,
    var imageUrl: String? = null,
    var chartType: String? = null, // "Pie", "Bar", "Line", "Area", "Donut", "None"
    var chartLabels: List<String> = emptyList(),
    var chartValues: List<Float> = emptyList(),
    var selectedBackgroundStyle: String = "Velvet Midnight"
)

data class AIPresentationModel(
    val id: String,
    var title: String,
    val topic: String,
    var templateStyle: String, // "Slate Indigo", "Cosmic Midnight", "Velvet Dark", "Minimal Charcoal"
    val language: String,
    val createdDate: Long = System.currentTimeMillis(),
    val slides: MutableList<PresentationSlide> = mutableListOf(),
    val totalSlides: Int = slides.size,
    val isFavorite: Boolean = false,
    val downloadCount: Int = 0
)

data class SlideComment(
    val id: String,
    val userEmail: String,
    val text: String,
    val timestamp: Long = System.currentTimeMillis()
)

data class DraftVersionLog(
    val id: String,
    val summary: String,
    val timestamp: Long = System.currentTimeMillis()
)

@OptIn(ExperimentalAnimationApi::class, ExperimentalMaterial3Api::class)
@Composable
fun AIPresentationMakerWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val NeonPrimary = NeonCyan

    val userStats by viewModel.userStats.collectAsState()
    val isPro = userStats?.isProPlan == true
    val maxPresentations = if (isPro) 50 else 3

    // State managers
    var activeTabIdx by remember { mutableStateOf(0) } // 0: Dashboard, 1: Create Deck, 2: Interactive Slide Editor, 3: Collaboration & Comments
    
    // Loaded list of presentations
    val deckList = remember {
        mutableStateListOf(
            AIPresentationModel(
                id = "deck_101",
                title = "Aeroscapes Logistics: Pitch Deck",
                topic = "Autonomous cargo drones offering next-day regional freight delivery solutions.",
                templateStyle = "Slate Indigo",
                language = "English",
                slides = mutableListOf(
                    PresentationSlide(
                        id = "slide_101_1",
                        slideNumber = 1,
                        title = "AEROSCAPES LOGISTICS",
                        layoutType = "Title",
                        contentLines = listOf(
                            "Regional Air Cargo Reimagined",
                            "Pitch Presentation 2026",
                            "Presented by Aeroscape Founders Team"
                        ),
                        speakerNotes = "Welcome the investors. Introduce the visionaries behind Aeroscape and mention that our cargo drone project solves the mid-mile freight delivery logjam.",
                        imageUrl = "https://picsum.photos/600/360?sig=101"
                    ),
                    PresentationSlide(
                        id = "slide_101_2",
                        slideNumber = 2,
                        title = "The Regional Freight Problem",
                        layoutType = "Comparison",
                        contentLines = listOf(
                            "Traditional Trucking: slow freeway congestion, driver shortages, rising diesel tariffs.",
                            "Commercial Airlines: restricted airport access, high warehousing delays, rigid timetables."
                        ),
                        speakerNotes = "Highlight slide 2 comparison. Middle mile ground shipping is congested and air shipping is cost-prohibitive for secondary airports.",
                        imageUrl = "https://picsum.photos/600/360?sig=102"
                    ),
                    PresentationSlide(
                        id = "slide_101_3",
                        slideNumber = 3,
                        title = "Drone Feasibility: Transit Time Save",
                        layoutType = "Chart",
                        contentLines = listOf(
                            "Average transit times (Hours) for regional segments of 100-300 miles.",
                            "Drone delivery cuts standard ground transport times by nearly 74%."
                        ),
                        speakerNotes = "Here is our core advantage. Look at the chart rendering drone transit speeds. We operate instantly without waiting for runway slots.",
                        chartType = "Bar",
                        chartLabels = listOf("Trucking Express", "Freight Rail", "Aeroscape Drone", "Courier Moto"),
                        chartValues = listOf(14.5f, 22.0f, 3.8f, 18.2f)
                    ),
                    PresentationSlide(
                        id = "slide_101_4",
                        slideNumber = 4,
                        title = "Projected Fleet Expansion (Units)",
                        layoutType = "Chart",
                        contentLines = listOf(
                            "Our aggressive fleet scaling targets for active delivery quadcopters.",
                            "Expecting profitability transition once active fleet beats 80 units."
                        ),
                        speakerNotes = "Scale plan is straightforward. By Year 2, we target 120 operational drones servicing 8 regional cargo stations.",
                        chartType = "Line",
                        chartLabels = listOf("Q1 2026", "Q2 2026", "Q3 2026", "Q4 2026"),
                        chartValues = listOf(15f, 40f, 75f, 130f)
                    ),
                    PresentationSlide(
                        id = "slide_101_5",
                        slideNumber = 5,
                        title = "Next Action Milestones",
                        layoutType = "Content",
                        contentLines = listOf(
                            "Milestone 1: Dynamic FAA airworthiness certificate validation (Q3).",
                            "Milestone 2: Expand charging station agreements with 5 regional hubs.",
                            "Milestone 3: Secure Series-A equity capitalization window ($8.5M cap target)."
                        ),
                        speakerNotes = "Conclude the core slide with actionable next steps. Emphasize FAA clearance schedules and the ongoing series funding rounds.",
                        imageUrl = "https://picsum.photos/600/360?sig=105"
                    ),
                    PresentationSlide(
                        id = "slide_101_6",
                        slideNumber = 6,
                        title = "Thank You for Joining Us!",
                        layoutType = "ThankYou",
                        contentLines = listOf(
                            "Aeroscape: Elevating Middle Mile Logistics",
                            "Email: invest@aeroscape.co | Web: aeroscape.co",
                            "Q&A session now open!"
                        ),
                        speakerNotes = "Open up floor for questions. Leave our contact details on the board."
                    )
                )
            ),
            AIPresentationModel(
                id = "deck_102",
                title = "Intro to Quantum Machine Learning",
                topic = "Exploring superposition, tensor products, and variational quantum classifiers in Python.",
                templateStyle = "Cosmic Midnight",
                language = "English",
                slides = mutableListOf(
                    PresentationSlide(
                        id = "slide_102_1",
                        slideNumber = 1,
                        title = "Quantum Machine Learning",
                        layoutType = "Title",
                        contentLines = listOf(
                            "Next Frontier of High-Speed Computation",
                            "Research Seminar Outline",
                            "Dr. Raymond Chandra, Quantum AI Lab"
                        ),
                        speakerNotes = "Welcome the research group. Outline how quantum mechanical paradigms elevate neural network training speeds."
                    ),
                    PresentationSlide(
                        id = "slide_102_2",
                        slideNumber = 2,
                        title = "Classical Neural Networks vs. QML",
                        layoutType = "Comparison",
                        contentLines = listOf(
                            "Classical: Bits (0 or 1), gradient optimization backprop, high thermal cost.",
                            "Quantum: Qubits (Superposition), quantum gate operators, instant parallel mapping."
                        ),
                        speakerNotes = "Contrast the computing primitives. A classical bits network vs quantum state space vector mappings."
                    ),
                    PresentationSlide(
                        id = "slide_102_3",
                        slideNumber = 3,
                        title = "Qubit Energy Efficiency comparison",
                        layoutType = "Chart",
                        contentLines = listOf(
                            "Energy dispersion profile per petaflop equivalent calculation.",
                            "Variational quantum classifiers bypass standard high dissipation."
                        ),
                        speakerNotes = "This pie chart model illustrates how carbon footprints degrade as we move processing circuits to cryogenic qubit states.",
                        chartType = "Pie",
                        chartLabels = listOf("Nvidia Hopper H100", "TPU Capable ASICs", "Supercon Qubit", "Liquid Hel Cryo"),
                        chartValues = listOf(55f, 35f, 4f, 6f)
                    ),
                    PresentationSlide(
                        id = "slide_102_4",
                        slideNumber = 4,
                        title = "Summary & Conclusion",
                        layoutType = "Summary",
                        contentLines = listOf(
                            "Key Point 1: Qubits allow multi-dimensional tensor search speeds unreachable on classical silica.",
                            "Key Point 2: Standard noisy intermediate-scale quantum devices are ideal for small parameter classifiers.",
                            "Conclusion: Variational circuits offer scalable alternatives for predictive bioinformatics pipelines."
                        ),
                        speakerNotes = "Re-cap. QML provides faster optimizations. Our bio-informatics team ready to push trials with liquid helium rigs."
                    )
                )
            )
        )
    }

    // Active presentation model state
    var selectedPresentation by remember { mutableStateOf(deckList[0]) }
    var currentSlideIdx by remember { mutableStateOf(0) }
    val currentSlide = remember(selectedPresentation, currentSlideIdx) {
        if (selectedPresentation.slides.isNotEmpty() && currentSlideIdx in selectedPresentation.slides.indices) {
            selectedPresentation.slides[currentSlideIdx]
        } else {
            null
        }
    }

    // Input States for New Decks (Create Deck)
    var inputPrompt by remember { mutableStateOf("Create a 6-slide startup presentation on Renewable Fusion Energy solutions for urban real-estate.") }
    var inputTopic by remember { mutableStateOf("Greenhouse Hydrogen Generator") }
    var selectedSlidesCount by remember { mutableStateOf(6) }
    var selectedStyle by remember { mutableStateOf("Slate Indigo") }
    var selectedLanguage by remember { mutableStateOf("English (US)") }
    var selectedTone by remember { mutableStateOf("Professional") }
    var outlineInputLines by remember { mutableStateOf("Introduction\nThe Urban Grid Problem\nHydrogen Fusion Loop Design\nComparative Costs vs Solar\nMilestones & Series-A Close") }
    
    // File upload simulators
    var docFileName by remember { mutableStateOf<String?>(null) }
    var docFileSizeKb by remember { mutableStateOf(0) }
    var docFileProcessing by remember { mutableStateOf(false) }
    var docFileProcessedPct by remember { mutableStateOf(0) }

    // Navigation and status UI states
    var searchFilterText by remember { mutableStateOf("") }
    var isGeneratingDeck by remember { mutableStateOf(false) }
    var autoSaveProgressTimer by remember { mutableStateOf(100) }
    var isSavingNow by remember { mutableStateOf(false) }
    var isExportingNow by remember { mutableStateOf(false) }
    var exportFormatSelected by remember { mutableStateOf("PPTX") }
    var exportProgressPct by remember { mutableStateOf(0) }
    var showExportDialog by remember { mutableStateOf(false) }
    var showUpgradeDialog by remember { mutableStateOf(false) }

    // Presentation properties editor temporary states
    var tempSlideTitle by remember { mutableStateOf("") }
    var tempSlideNotes by remember { mutableStateOf("") }
    
    // Sync temporary title & notes when currentSlide changes
    LaunchedEffect(currentSlide) {
        if (currentSlide != null) {
            tempSlideTitle = currentSlide.title
            tempSlideNotes = currentSlide.speakerNotes
        }
    }

    // Undo/Redo stack simulations
    var undoStackSize by remember { mutableStateOf(0) }
    var redoStackSize by remember { mutableStateOf(0) }

    // Comments list simulation
    val slideCommentsMap = remember {
        mutableStateMapOf<String, List<SlideComment>>().apply {
            put("slide_101_1", listOf(
                SlideComment("c1", "chankikawde7@gmail.com", "Let's change the background subtitle color here to NeonPurple."),
                SlideComment("c2", "designer_jane@aistudio.com", "Approved! Also made the font size slightly thicker to prevent camera cutting.")
            ))
            put("slide_101_3", listOf(
                SlideComment("c3", "chankikawde7@gmail.com", "Double check the bar chart calculations! Trucking Express is showing 14.5 hours.")
            ))
        }
    }
    var currentCommentInputText by remember { mutableStateOf("") }

    // Dynamic Version Logs
    val historyVersionLogs = remember {
        mutableStateListOf(
            DraftVersionLog("v1", "Initial draft generated on topic Renewable Fusion"),
            DraftVersionLog("v2", "Added Bar Chart component illustrating Year Profitability"),
            DraftVersionLog("v3", "Synchronized Team feedback comments on Slide 2 title layout")
        )
    }

    // Simulation auto saver
    LaunchedEffect(tempSlideTitle, tempSlideNotes) {
        if (currentSlide != null && (tempSlideTitle != currentSlide.title || tempSlideNotes != currentSlide.speakerNotes)) {
            currentSlide.title = tempSlideTitle
            currentSlide.speakerNotes = tempSlideNotes
            
            // Trigger automatic background save simulation
            isSavingNow = true
            autoSaveProgressTimer = 0
            while (autoSaveProgressTimer < 100) {
                delay(12)
                autoSaveProgressTimer += 10
            }
            isSavingNow = false
            undoStackSize++
        }
    }

    // Export progress simulator
    LaunchedEffect(isExportingNow) {
        if (isExportingNow) {
            exportProgressPct = 0
            while (exportProgressPct < 100) {
                delay(35)
                exportProgressPct += 5
            }
            isExportingNow = false
            showExportDialog = false
            Toast.makeText(context, "Presentation successfully exported as ${exportFormatSelected}! 📥 Check downloads folder.", Toast.LENGTH_LONG).show()
            
            viewModel.recordPresentationGeneration(
                title = selectedPresentation.title,
                topic = selectedPresentation.topic,
                slidesCount = selectedPresentation.slides.size,
                templateStyle = selectedPresentation.templateStyle,
                metadata = "Format: $exportFormatSelected, Size: 4.8MB, Slides: ${selectedPresentation.slides.size}"
            )
        }
    }

    // Slide Generation simulation
    LaunchedEffect(isGeneratingDeck) {
        if (isGeneratingDeck) {
            delay(2800) // Mock heavy AI Slide Layout computation
            isGeneratingDeck = false
            
            // Create a brand new Deck
            val slideLen = selectedSlidesCount.coerceIn(5, 50)
            val generatedSlides = mutableListOf<PresentationSlide>()
            
            // Slide 1: Title
            generatedSlides.add(
                PresentationSlide(
                    id = "gen_slide_1_${System.currentTimeMillis()}",
                    slideNumber = 1,
                    title = inputTopic.uppercase(),
                    layoutType = "Title",
                    contentLines = listOf(
                        "Strategic Overview of the Topic Arena",
                        "Generated Automatically via Prompts",
                        "High Fidelity Layout Design"
                    ),
                    speakerNotes = "Pitch presentation starter. Welcome everyone. Introduce '$inputTopic' and frame our central solution."
                )
            )

            // Slide 2: Agenda / Outline
            generatedSlides.add(
                PresentationSlide(
                    id = "gen_slide_2_${System.currentTimeMillis()}",
                    slideNumber = 2,
                    title = "Presentation Agenda & Objectives",
                    layoutType = "Agenda",
                    contentLines = listOf(
                        "1. Introduction and Primary Core Problem Statement",
                        "2. AI Powered Technical Architecture Breakdown",
                        "3. Comparative Segment Competitors & Profit Scales",
                        "4. Dynamic Financial Outlook Timeline Model",
                        "5. Strategic Implementation Roadmap & Next Milestones"
                    ),
                    speakerNotes = "Review the agenda quickly. Make sure stakeholders understand the flow and that we leave room for dialogue at the end."
                )
            )

            // Generate content slides based on slides count
            for (i in 3 until slideLen) {
                if (i == 4 && i < slideLen - 1) {
                    // Generate a Chart Slide
                    generatedSlides.add(
                        PresentationSlide(
                            id = "gen_slide_${i}_${System.currentTimeMillis()}",
                            slideNumber = i,
                            title = "Strategic Competitor Comparison Benchmarks",
                            layoutType = "Chart",
                            contentLines = listOf(
                                "Average performance scores (Score index 1-100) across test arrays.",
                                "Our technology proposal achieves 88% higher throughput metrics."
                            ),
                            speakerNotes = "Analyze the visual data on slide $i. Our segment (illustrated in Cyan color) stands ahead of generic alternatives.",
                            chartType = if (i % 2 == 0) "Bar" else "Pie",
                            chartLabels = listOf("Generic Alpha", "Manual Beta", "AI Prime Custom", "Legacy System"),
                            chartValues = listOf(18f, 32f, 85f, 44f)
                        )
                    )
                } else if (i == 5 && i < slideLen - 1) {
                    // Generate a Comparison slide
                    generatedSlides.add(
                        PresentationSlide(
                            id = "gen_slide_${i}_${System.currentTimeMillis()}",
                            slideNumber = i,
                            title = "Core Comparative Advantages Matrix",
                            layoutType = "Comparison",
                            contentLines = listOf(
                                "Our Architecture: zero-emission hydrogen gas feedback loop, 140x faster optimization.",
                                "Traditional Competitors: heavy heat dissipation and high ambient noise leakage."
                            ),
                            speakerNotes = "Explain the slide comparisons. Point out our technical resilience and cost benefits."
                        )
                    )
                } else {
                    // Standard content slide
                    generatedSlides.add(
                        PresentationSlide(
                            id = "gen_slide_${i}_${System.currentTimeMillis()}",
                            slideNumber = i,
                            title = "Key Tactical Pillar - Segment $i",
                            layoutType = "Content",
                            contentLines = listOf(
                                "Operational metric: scalable deployment arrays with auto-regulating thermals.",
                                "Optimization focus: cloud integrations offering multi-channel metric analysis.",
                                "Security assurance: high-grade encrypted pipelines with zero credentials leak risk."
                            ),
                            speakerNotes = "Discuss Section $i. We are optimizing structural parameters. Touch upon security structures and automated safety switches."
                        )
                    )
                }
            }

            // Final Slide: Thank you
            generatedSlides.add(
                PresentationSlide(
                    id = "gen_slide_${slideLen}_${System.currentTimeMillis()}",
                    slideNumber = slideLen,
                    title = "Core Summary & Call to Action",
                    layoutType = "Summary",
                    contentLines = listOf(
                        "Summary Key 1: Direct integration cuts overhead by 40% immediately.",
                        "Summary Key 2: Cloud analytics track multi-channel metrics in real-time.",
                        "Call to Action: Join our early developer pilot or schedule a deep-dive workshop."
                    ),
                    speakerNotes = "We have reviewed the core benefits. Let's start building the prototype."
                )
            )

            val newlyGeneratedDeck = AIPresentationModel(
                id = "deck_${System.currentTimeMillis()}",
                title = inputTopic.ifBlank { "Untitled AI Slide Deck" },
                topic = inputPrompt.ifBlank { "Text Prompt: AI Presentation Layout Content" },
                templateStyle = selectedStyle,
                language = selectedLanguage,
                slides = generatedSlides
            )

            deckList.add(newlyGeneratedDeck)
            selectedPresentation = newlyGeneratedDeck
            currentSlideIdx = 0
            
            viewModel.recordPresentationGeneration(
                title = newlyGeneratedDeck.title,
                topic = newlyGeneratedDeck.topic,
                slidesCount = newlyGeneratedDeck.slides.size,
                templateStyle = newlyGeneratedDeck.templateStyle,
                metadata = "Slides count: ${newlyGeneratedDeck.totalSlides}, Style selected: ${newlyGeneratedDeck.templateStyle}"
            )

            Toast.makeText(context, "Beautiful ${slideLen}-slide Deck successfully built! Ready for edits. 🎨", Toast.LENGTH_LONG).show()
            activeTabIdx = 2 // Move directly to Slide Editor tab
        }
    }

    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFF020207))
            .padding(horizontal = 14.dp)
            .verticalScroll(rememberScrollState()),
        verticalArrangement = Arrangement.spacedBy(10.dp)
    ) {
        Spacer(modifier = Modifier.height(6.dp))

        // Module Headers
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column {
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                    Text(
                        "AI PRESENTATION DESIGN HUB",
                        fontSize = 11.sp,
                        letterSpacing = 1.sp,
                        color = NeonPrimary,
                        fontWeight = FontWeight.Bold
                    )
                    Box(
                        modifier = Modifier
                            .background(if (isPro) Color(0xFFFFD700).copy(alpha = 0.15f) else Color.White.copy(alpha = 0.1f), RoundedCornerShape(4.dp))
                            .border(0.5.dp, if (isPro) Color(0xFFFFD700) else Color.Gray, RoundedCornerShape(4.dp))
                            .padding(horizontal = 4.dp, vertical = 2.dp)
                    ) {
                        Text(
                            text = if (isPro) "ENTERPRISE PRO" else "FREE ACCOUNT",
                            color = if (isPro) Color(0xFFFFD700) else Color.White,
