                    shape = RoundedCornerShape(6.dp),
                    contentPadding = PaddingValues(horizontal = 8.dp, vertical = 4.dp)
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        Icon(imageVector = Icons.Filled.Star, contentDescription = null, tint = Color.White, modifier = Modifier.size(12.dp))
                        Text("UPGRADE", fontSize = 8.5.sp, fontWeight = FontWeight.Black)
                    }
                }
            }
        }

        // Sub Navigation Tabs
        TabRow(
            selectedTabIndex = activeTabIdx,
            containerColor = Color(0xFF080816),
            contentColor = NeonCyan,
            indicator = { tabPositions ->
