                    modifier = Modifier.tabIndicatorOffset(tabPositions[activeTabIdx]),
                    color = NeonPrimary
                )
            },
            modifier = Modifier
                .fillMaxWidth()
                .clip(RoundedCornerShape(8.dp))
                .border(0.5.dp, Color.DarkGray.copy(alpha = 0.3f), RoundedCornerShape(8.dp))
        ) {
            val workspaceTabs = listOf("RECENT DECKS", "CREATE NEW", "SLIDE EDITOR", "COLLABORATIVE")
            workspaceTabs.forEachIndexed { idx, name ->
                Tab(
                    selected = activeTabIdx == idx,
                    onClick = { activeTabIdx = idx },
                    text = { Text(name, fontSize = 8.sp, fontWeight = FontWeight.Bold, color = if (activeTabIdx == idx) Color.White else Color.Gray) }
                )
            }
        }

        // -------------------------------------------------------------
        // TAB: RECENT DECKS (DASHBOARD)
        // -------------------------------------------------------------
        if (activeTabIdx == 0) {
            Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                
                // Account limits card
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFF0B0B1F), RoundedCornerShape(10.dp))
                        .padding(12.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column {
                        Text("SAVED PROJECTS CAPACITY", fontSize = 9.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                        Text("${deckList.size} / $maxPresentations Decks Used", fontSize = 13.sp, color = Color.White, fontWeight = FontWeight.ExtraBold)
                    }

                    Box(
                        modifier = Modifier
                            .background(NeonPrimary.copy(alpha = 0.12f), RoundedCornerShape(6.dp))
                            .padding(horizontal = 8.dp, vertical = 4.dp)
                    ) {
                        Text(
                            "STORAGE: ${(deckList.size.toFloat() / maxPresentations * 100).toInt()}% FULL",
                            color = NeonPrimary,
                            fontSize = 8.1.sp,
                            fontWeight = FontWeight.Black
                        )
                    }
                }

                // Filtering bar
                OutlinedTextField(
                    value = searchFilterText,
                    onValueChange = { searchFilterText = it },
                    textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(38.dp),
                    placeholder = { Text("Search slide decks by title or keyword content...", fontSize = 10.sp, color = Color.Gray) },
                    colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPrimary, unfocusedBorderColor = Color.DarkGray),
                    shape = RoundedCornerShape(6.dp),
                    leadingIcon = { Icon(imageVector = Icons.Filled.Search, contentDescription = null, tint = Color.Gray, modifier = Modifier.size(13.dp)) }
                )

                Text("RECENT PRESENTATIONS", fontSize = 10.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)

                val filteredDecks = deckList.filter {
                    it.title.contains(searchFilterText, ignoreCase = true) || it.topic.contains(searchFilterText, ignoreCase = true)
                }

                if (filteredDecks.isEmpty()) {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF040410), RoundedCornerShape(10.dp))
                            .padding(24.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text("No presentations match current filter. Go back or Tap 'CREATE NEW' tab!", color = Color.Gray, fontSize = 11.sp)
                    }
                } else {
                    filteredDecks.forEach { deck ->
                        val isSelected = selectedPresentation.id == deck.id
                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .border(
                                    width = if (isSelected) 1.2.dp else 0.5.dp,
                                    color = if (isSelected) NeonPrimary else Color.White.copy(alpha = 0.05f),
                                    shape = RoundedCornerShape(10.dp)
                                ),
                            colors = CardDefaults.cardColors(containerColor = if (isSelected) Color(0xFF080820) else Color(0xFF04040A)),
                            onClick = {
                                selectedPresentation = deck
                                currentSlideIdx = 0
