                            }
                        ) {
                            Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Column(modifier = Modifier.weight(1f)) {
                                        Text(deck.title, color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Bold)
                                        Text(deck.topic, fontSize = 10.sp, color = Color.Gray, maxLines = 1, overflow = TextOverflow.Ellipsis)
                                    }

                                    Row(horizontalArrangement = Arrangement.spacedBy(4.dp), verticalAlignment = Alignment.CenterVertically) {
                                        Icon(imageVector = Icons.Filled.List, contentDescription = null, tint = Color.Gray, modifier = Modifier.size(11.dp))
                                        Text("${deck.slides.size} Slides", color = Color.LightGray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                    }
                                }

                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Row(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                        Column {
                                            Text("TEMPLATE SKIN", fontSize = 8.sp, color = Color.Gray)
                                            Text(deck.templateStyle, fontSize = 9.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                                        }
                                        Column {
                                            Text("LANGUAGE", fontSize = 8.sp, color = Color.Gray)
                                            Text(deck.language, fontSize = 9.sp, color = Color.White)
                                        }
                                        Column {
                                            Text("LAST UPDATED", fontSize = 8.sp, color = Color.Gray)
                                            Text(android.text.format.DateFormat.format("dd MMM yyyy", deck.createdDate).toString(), fontSize = 9.sp, color = Color.LightGray)
                                        }
                                    }

                                    Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                        IconButton(
                                            onClick = {
                                                // Delete deck
                                                if (deckList.size > 1) {
                                                    deckList.remove(deck)
                                                    if (selectedPresentation.id == deck.id) {
                                                        selectedPresentation = deckList[0]
                                                    }
                                                    Toast.makeText(context, "Deleted project", Toast.LENGTH_SHORT).show()
                                                } else {
                                                    Toast.makeText(context, "Must retain at least one project", Toast.LENGTH_SHORT).show()
                                                }
                                            },
                                            modifier = Modifier.size(24.dp)
                                        ) {
                                            Icon(imageVector = Icons.Filled.Delete, contentDescription = "Delete", tint = Color.Red.copy(alpha = 0.8f), modifier = Modifier.size(12.dp))
                                        }

                                        IconButton(
                                            onClick = {
                                                // Duplicate deck
                                                val dupeSlides = deck.slides.map { it.copy(id = "slide_${System.currentTimeMillis()}_${(10..99).random()}") }.toMutableList()
                                                val dupe = deck.copy(
                                                    id = "deck_${System.currentTimeMillis()}",
                                                    title = "${deck.title} Duplicated Draft",
                                                    slides = dupeSlides
                                                )
                                                deckList.add(dupe)
                                                Toast.makeText(context, "Presentation Duplicated!", Toast.LENGTH_SHORT).show()
                                            },
                                            modifier = Modifier.size(24.dp)
                                        ) {
                                            Icon(imageVector = Icons.Filled.ContentCopy, contentDescription = "Duplicate", tint = NeonPrimary, modifier = Modifier.size(12.dp))
                                        }
                                    }
                                }

                                Divider(color = Color.White.copy(alpha = 0.04f))

                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Text("Status: Synchronized Encrypted Cloud Backup", fontSize = 8.sp, color = Color.Gray)
                                    Button(
                                        onClick = {
                                            selectedPresentation = deck
                                            currentSlideIdx = 0
