                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // TAB: Create New Presenter (Channel Generator Selector)
        // -------------------------------------------------------------
        if (activeTabIdx == 1) {
            var selectedCreationInputTab by remember { mutableStateOf(0) } // 0: Prompt-to-Presenter, 1: Document, 2: Outline
            
            Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                
                // Prompt / Doc / Outline Segment Row buttons
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFF050510), RoundedCornerShape(8.dp))
