                                .border(
                                    0.5.dp,
                                    if (selectedCreationInputTab == cidx) NeonPrimary else Color.Transparent,
                                    RoundedCornerShape(6.dp)
                                )
                                .clickable { selectedCreationInputTab = cidx }
                                .padding(vertical = 8.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(
                                wordName,
                                color = if (selectedCreationInputTab == cidx) Color.White else Color.Gray,
                                fontSize = 9.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }
                }

                // Sub form for Prompt-to-presentation (0)
                if (selectedCreationInputTab == 0) {
                    Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Text("ENTER AI GENERATION PROMPT", fontSize = 9.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                        
                        OutlinedTextField(
                            value = inputPrompt,
                            onValueChange = { inputPrompt = it },
                            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(65.dp),
                            colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPrimary, unfocusedBorderColor = Color.DarkGray),
