                            Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Text("OUTPUT LANGUAGE", fontSize = 9.sp, color = Color.LightGray)
                                val trainLanguages = listOf("English (US)", "Hindi", "Spanish", "Arabic", "French", "German", "Japanese")
                                var showLangDrop by remember { mutableStateOf(false) }

                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(38.dp)
                                        .clip(RoundedCornerShape(6.dp))
