                                        .padding(horizontal = 8.dp, vertical = 8.dp)
                                ) {
                                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                        Text(selectedLanguage, color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                                        Icon(imageVector = Icons.Filled.ArrowDropDown, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(14.dp))
                                    }

                                    DropdownMenu(
                                        expanded = showLangDrop,
                                        onDismissRequest = { showLangDrop = false },
                                        modifier = Modifier.background(Color(0xFF0F0F23))
                                    ) {
                                        trainLanguages.forEach { currentLang ->
                                            DropdownMenuItem(
                                                text = { Text(currentLang, color = Color.White, fontSize = 10.sp) },
                                                onClick = {
                                                    selectedLanguage = currentLang
                                                    showLangDrop = false
                                                }
                                            )
                                        }
                                    }
                                }
                            }

                            Column(modifier = Modifier.weight(1f), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Text("SPEAKER TONE ASSIGNMENT", fontSize = 9.sp, color = Color.LightGray)
                                val toneSkins = listOf("Professional", "Startup Pitch Deck style", "Minimal Clear", "Academic/Scientific", "Creative Artistic")
                                var showToneDrop by remember { mutableStateOf(false) }

                                Box(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(38.dp)
                                        .clip(RoundedCornerShape(6.dp))
                                        .background(Color(0xFF09091A))
                                        .border(0.5.dp, Color.DarkGray, RoundedCornerShape(6.dp))
                                        .clickable { showToneDrop = true }
                                        .padding(horizontal = 8.dp, vertical = 8.dp)
                                ) {
                                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                        Text(selectedTone, color = Color.White, fontSize = 9.5.sp, fontWeight = FontWeight.Bold, maxLines = 1)
                                        Icon(imageVector = Icons.Filled.ArrowDropDown, contentDescription = null, tint = Color.LightGray, modifier = Modifier.size(14.dp))
                                    }

                                    DropdownMenu(
                                        expanded = showToneDrop,
                                        onDismissRequest = { showToneDrop = false },
                                        modifier = Modifier.background(Color(0xFF0F0F23))
                                    ) {
                                        toneSkins.forEach { currentTone ->
                                            DropdownMenuItem(
                                                text = { Text(currentTone, color = Color.White, fontSize = 10.sp) },
                                                onClick = {
                                                    selectedTone = currentTone
                                                    showToneDrop = false
                                                }
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                // Sub form for Document-to-Presentation (1)
                else if (selectedCreationInputTab == 1) {
                    Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Text("UPLOAD DOCUMENT TO ANALYZE & SUMMARIZE", fontSize = 9.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                        
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF050512), RoundedCornerShape(8.dp))
                                .border(1.dp, Brush.linearGradient(listOf(NeonPrimary, NeonPurple)), RoundedCornerShape(8.dp))
                                .clickable {
                                    docFileName = "Q2_Real_Estate_Marketing_Study.pdf"
                                    docFileSizeKb = 1450
                                    docFileProcessing = true
                                    scope.launch {
                                        docFileProcessedPct = 0
                                        while (docFileProcessedPct < 100) {
                                            delay(20)
                                            docFileProcessedPct += 10
                                        }
                                        docFileProcessing = false
                                        inputTopic = "Q2 Marketing Real Estate"
                                        inputPrompt = "Summarize pdf document on Real Estate trends covering urban centers."
                                        Toast.makeText(context, "Analyzed PDF document fully! Generated titles and slides structures.", Toast.LENGTH_SHORT).show()
                                    }
                                }
                                .padding(16.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                Icon(imageVector = Icons.Filled.CloudUpload, contentDescription = null, tint = NeonPrimary, modifier = Modifier.size(34.dp))
                                Text("SELECT DOCUMENT (PDF, DOCX, TXT, PPTX)", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Black)
                                Text("AI will read, summarize main headers and draft slide outline.", color = Color.Gray, fontSize = 8.5.sp)
                                
                                if (docFileName != null) {
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                        Text("SUCCESS: $docFileName", color = Color.Green, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                        Text("File size: ${String.format("%.1f", docFileSizeKb / 1024f)} MB", color = Color.Gray, fontSize = 9.sp)
                                    }
                                }
                            }
                        }

                        if (docFileProcessing) {
                            Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                    Text("Reading document structures...", color = Color.LightGray, fontSize = 9.sp)
                                    Text("$docFileProcessedPct%", color = NeonPrimary, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                                LinearProgressIndicator(
                                    progress = docFileProcessedPct / 100f,
                                    color = NeonPrimary,
                                    trackColor = Color.DarkGray,
                                    modifier = Modifier.fillMaxWidth().height(4.dp).clip(RoundedCornerShape(2.dp))
                                )
                            }
                        }
                    }
                }

                // Sub form for Outline-to-Presentation (2)
                else {
                    Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        Text("SPECIFY PRESENTATION OUTLINE STRUCTURE", fontSize = 9.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                        Text("Add each slide title or phase on a new line. The AI converts lines into slide nodes.", color = Color.Gray, fontSize = 8.5.sp)

                        OutlinedTextField(
                            value = outlineInputLines,
                            onValueChange = { outlineInputLines = it },
                            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(130.dp),
                            colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPrimary, unfocusedBorderColor = Color.DarkGray),
                            shape = RoundedCornerShape(6.dp),
                            placeholder = { Text("e.g. Slide 1: Welcome title\nSlide 2: Technical specifications & specs\nSlide 3: Financial timelines diagram...", fontSize = 10.sp, color = Color.Gray) }
                        )

                        Text("NICKNAME YOUR DECK TOPIC", fontSize = 9.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                        OutlinedTextField(
                            value = inputTopic,
                            onValueChange = { inputTopic = it },
                            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(38.dp),
                            colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPurple, unfocusedBorderColor = Color.DarkGray),
                            shape = RoundedCornerShape(6.dp),
                            placeholder = { Text("Outline Title", fontSize = 10.sp, color = Color.Gray) }
                        )
                    }
                }

                Spacer(modifier = Modifier.height(4.dp))

                // GENERATE SUBMIT BUTTON
                if (isGeneratingDeck) {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color(0xFF0C0A1F), RoundedCornerShape(8.dp))
                            .padding(14.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(8.dp)) {
                            CircularProgressIndicator(color = NeonPrimary, modifier = Modifier.size(24.dp))
                            Text("AI DESIGN ENGINE ACTIVE...", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Black)
                            Text("Dedicating slide layouts, optimizing line spacing and inserting chart visualizations. Hold on!", color = Color.LightGray, fontSize = 9.sp)
                        }
                    }
                } else {
                    Button(
                        onClick = {
                            if (selectedCreationInputTab == 2 && outlineInputLines.isBlank()) {
                                Toast.makeText(context, "Outline target cannot be blank", Toast.LENGTH_SHORT).show()
                            } else {
                                isGeneratingDeck = true
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = NeonPrimary),
                        shape = RoundedCornerShape(8.dp),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(45.dp)
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            Icon(imageVector = Icons.Filled.Palette, contentDescription = null, tint = PureBlack, modifier = Modifier.size(16.dp))
                            Text("RENDER PRESENTATION DECK SLIDES", color = PureBlack, fontSize = 11.5.sp, fontWeight = FontWeight.Black)
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // TAB: INTERACTIVE SLIDE EDITOR (PREVIEW & EDIT COMPONENT)
        // -------------------------------------------------------------
        if (activeTabIdx == 2) {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                
                // Visual indicators of synchronization & draft states
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                        Text(selectedPresentation.title, color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Black)
                        Box(
                            modifier = Modifier
                                .background(Color(0xFF0F172A), RoundedCornerShape(4.dp))
                                .border(0.5.dp, Color.Gray, RoundedCornerShape(4.dp))
                                .padding(horizontal = 4.dp, vertical = 2.dp)
                        ) {
                            Text(
                                "MODERN LAYOUT ENG: ACTIVE",
                                color = Color.Green,
                                fontSize = 6.5.sp,
                                fontWeight = FontWeight.SemiBold
                            )
                        }
                    }

                    Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        Icon(
                            imageVector = if (isSavingNow) Icons.Filled.Refresh else Icons.Filled.Check,
                            contentDescription = null,
                            tint = if (isSavingNow) NeonPrimary else Color.Green,
                            modifier = Modifier.size(11.dp)
                        )
                        Text(
                            text = if (isSavingNow) "Saving sync draft..." else "Local draft auto-saved",
                            color = Color.Gray,
                            fontSize = 8.5.sp
                        )
                    }
                }

                // RENDERING TOP PREVIEW CANVAS! (Visual simulation of the slides!)
                if (currentSlide != null) {
                    val slideBgBrush = when (currentSlide.selectedBackgroundStyle) {
                        "Slate Indigo" -> Brush.verticalGradient(listOf(Color(0xFF0F0C24), Color(0xFF060412)))
                        "Cosmic Midnight" -> Brush.verticalGradient(listOf(Color(0xFF081C15), Color(0xFF040605)))
                        "Velvet Dark" -> Brush.verticalGradient(listOf(Color(0xFF1E1B4B), Color(0xFF0F172A)))
                        "Minimal Charcoal" -> Brush.verticalGradient(listOf(Color(0xFF1C1917), Color(0xFF0C0A09)))
                        else -> Brush.verticalGradient(listOf(Color(0xFF0F172A), Color(0xFF020617)))
                    }

                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(200.dp)
                            .clip(RoundedCornerShape(12.dp))
                            .background(slideBgBrush)
                            .border(1.dp, NeonPrimary.copy(alpha = 0.4f), RoundedCornerShape(12.dp))
                            .padding(14.dp)
                    ) {
                        // Render slide structure dynamically
                        Column(
                            modifier = Modifier.fillMaxSize(),
                            verticalArrangement = Arrangement.SpaceBetween
                        ) {
                            // Top row of slide indicator
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text(
                                    text = currentSlide.title.uppercase(),
                                    color = Color.White,
                                    fontSize = 12.sp,
                                    fontWeight = FontWeight.ExtraBold,
                                    letterSpacing = 1.sp
                                )

                                Box(
                                    modifier = Modifier
                                        .background(Color.White.copy(alpha = 0.1f), RoundedCornerShape(6.dp))
                                        .padding(horizontal = 6.dp, vertical = 2.dp)
                                ) {
                                    Text(
                                        "SLIDE ${currentSlideIdx + 1} / ${selectedPresentation.slides.size} (${currentSlide.layoutType})",
                                        color = NeonPrimary,
                                        fontSize = 7.5.sp,
                                        fontWeight = FontWeight.Bold
                                    )
                                }
                            }

                            // Middle graphic / layout render
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .weight(1f)
                                    .padding(vertical = 4.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                when (currentSlide.layoutType) {
                                    "Title" -> {
                                        Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                            Text(
                                                text = if (currentSlide.contentLines.isNotEmpty()) currentSlide.contentLines[0] else "",
                                                color = NeonPrimary,
                                                fontSize = 14.sp,
                                                fontWeight = FontWeight.Black,
                                                textAlign = TextAlign.Center
                                            )
                                            Text(
                                                text = if (currentSlide.contentLines.size > 1) currentSlide.contentLines[1] else "",
                                                color = Color.LightGray,
                                                fontSize = 9.sp,
                                                textAlign = TextAlign.Center
                                            )
                                            Text(
                                                text = if (currentSlide.contentLines.size > 2) currentSlide.contentLines[2] else "",
                                                color = Color.Gray,
                                                fontSize = 7.5.sp,
                                                textAlign = TextAlign.Center
                                            )
                                        }
                                    }

                                    "Comparison" -> {
                                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                            Box(
                                                modifier = Modifier
                                                    .weight(1f)
                                                    .background(Color.White.copy(alpha = 0.05f), RoundedCornerShape(6.dp))
                                                    .border(0.5.dp, Color.Gray.copy(alpha = 0.3f), RoundedCornerShape(6.dp))
                                                    .padding(6.dp)
                                            ) {
                                                Column(verticalArrangement = Arrangement.spacedBy(2.dp)) {
                                                    Text("PROPOSAL CORE", color = NeonPrimary, fontSize = 7.sp, fontWeight = FontWeight.Bold)
                                                    Text(
                                                        text = if (currentSlide.contentLines.isNotEmpty()) currentSlide.contentLines[0] else "",
                                                        color = Color.White,
                                                        fontSize = 8.sp,
                                                        maxLines = 4,
                                                        overflow = TextOverflow.Ellipsis
                                                    )
                                                }
                                            }

                                            Box(
                                                modifier = Modifier
                                                    .weight(1f)
                                                    .background(Color.White.copy(alpha = 0.05f), RoundedCornerShape(6.dp))
                                                    .border(0.5.dp, Color.Gray.copy(alpha = 0.3f), RoundedCornerShape(6.dp))
                                                    .padding(6.dp)
                                            ) {
                                                Column(verticalArrangement = Arrangement.spacedBy(2.dp)) {
                                                    Text("STATIC CONV", color = Color.Red, fontSize = 7.sp, fontWeight = FontWeight.Bold)
                                                    Text(
                                                        text = if (currentSlide.contentLines.size > 1) currentSlide.contentLines[1] else "",
                                                        color = Color.White,
                                                        fontSize = 8.sp,
                                                        maxLines = 4,
                                                        overflow = TextOverflow.Ellipsis
                                                    )
                                                }
                                            }
                                        }
                                    }

                                    "Chart" -> {
                                        // Visual Canvas bar drawing render
                                        Column(
                                            modifier = Modifier.fillMaxWidth().padding(horizontal = 10.dp),
                                            verticalArrangement = Arrangement.spacedBy(4.dp)
                                        ) {
                                            Text(
                                                "DATAVIZ: ${currentSlide.chartType ?: "Statistics"} RENDER ENGINE",
                                                color = Color.Gray,
                                                fontSize = 6.5.sp,
                                                fontWeight = FontWeight.Bold
                                            )

                                            Row(
                                                modifier = Modifier.fillMaxWidth().height(55.dp),
                                                horizontalArrangement = Arrangement.SpaceAround,
                                                verticalAlignment = Alignment.Bottom
                                            ) {
                                                currentSlide.chartValues.forEachIndexed { sidx, value ->
                                                    val label = if (sidx in currentSlide.chartLabels.indices) currentSlide.chartLabels[sidx] else "Item"
                                                    val capValue = value.coerceIn(1f, 150f)
                                                    
                                                    Column(horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Bottom) {
                                                        Box(
                                                            modifier = Modifier
                                                                .width(18.dp)
                                                                .height((capValue * 0.4).dp)
                                                                .clip(RoundedCornerShape(topStart = 4.dp, topEnd = 4.dp))
                                                                .background(
                                                                    if (sidx % 2 == 0) NeonPrimary else NeonPurple
                                                                )
                                                        )
                                                        Spacer(modifier = Modifier.height(2.dp))
                                                        Text(label, color = Color.LightGray, fontSize = 6.sp, maxLines = 1)
                                                        Text("${value.toInt()}", color = Color.White, fontSize = 6.5.sp, fontWeight = FontWeight.Bold)
                                                    }
                                                }
                                            }
                                        }
                                    }

                                    else -> {
                                        // Content layout
                                        Column(
                                            modifier = Modifier.fillMaxWidth(),
                                            verticalArrangement = Arrangement.spacedBy(4.dp)
                                        ) {
                                            currentSlide.contentLines.forEach { line ->
                                                Row(verticalAlignment = Alignment.Top, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                                    Box(modifier = Modifier.size(5.dp).offset(y = 3.dp).background(NeonPrimary, CircleShape))
                                                    Text(
                                                        line,
                                                        color = Color.LightGray,
                                                        fontSize = 8.5.sp,
                                                        maxLines = 2,
                                                        overflow = TextOverflow.Ellipsis
                                                    )
                                                }
                                            }
                                        }
                                    }
                                }
                            }

                            // Footer watermark row
                            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                Text("Aistudio Presenter Template PRO", color = Color.DarkGray, fontSize = 6.5.sp)
                                Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Box(modifier = Modifier.size(6.dp).background(Color.White, CircleShape))
                                    Box(modifier = Modifier.size(6.dp).background(NeonPrimary, CircleShape))
                                    Box(modifier = Modifier.size(6.dp).background(NeonPurple, CircleShape))
                                }
                            }
                        }
                    }
                }

                // Slider CAROUSEL list of other slides (Horizontal Navigation bar)
                Text("SLIDE TREE DRAWER (DRAG OR SELECT)", fontSize = 8.5.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                
                LazyRow(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    itemsIndexed(selectedPresentation.slides) { sidx, slide ->
                        val isCurrent = currentSlideIdx == sidx
                        Box(
                            modifier = Modifier
                                .width(80.dp)
                                .height(56.dp)
                                .clip(RoundedCornerShape(6.dp))
                                .background(if (isCurrent) Color(0xFF0F0F2E) else Color(0xFF04040A))
                                .border(
                                    1.dp,
                                    if (isCurrent) NeonPrimary else Color.DarkGray.copy(alpha = 0.4f),
                                    RoundedCornerShape(6.dp)
                                )
                                .clickable {
                                    currentSlideIdx = sidx
                                    Toast.makeText(context, "Slide ${sidx + 1} chosen", Toast.LENGTH_SHORT).show()
                                }
                                .padding(4.dp)
                        ) {
                            Column(modifier = Modifier.fillMaxSize(), verticalArrangement = Arrangement.SpaceBetween) {
                                Text(
                                    text = "${sidx + 1}. ${slide.title}",
                                    color = if (isCurrent) Color.White else Color.Gray,
                                    fontSize = 7.sp,
                                    fontWeight = FontWeight.Bold,
                                    maxLines = 2,
                                    overflow = TextOverflow.Ellipsis
                                )

                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                                    Text(slide.layoutType, fontSize = 6.sp, color = NeonPurple, fontWeight = FontWeight.Black)
                                    Box(modifier = Modifier.size(4.dp).background(if (slide.imageUrl != null) NeonPrimary else Color.Gray, CircleShape))
                                }
                            }
                        }
                    }
                }

                // SLIDE MANAGEMENT BUTTONS Row
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                        Button(
                            onClick = {
                                // Add a new Slide
                                if (selectedPresentation.slides.size < maxPresentations * 10) {
                                    val currentMaxSlideNum = selectedPresentation.slides.size
                                    val newSld = PresentationSlide(
                                        id = "slide_new_${System.currentTimeMillis()}",
                                        slideNumber = currentMaxSlideNum + 1,
                                        title = "New Title Phase Node",
                                        layoutType = "Content",
                                        contentLines = listOf(
                                            "Add customized bullet point ideas here.",
                                            "Double-tap outline sheets to refine target statistics."
                                        ),
                                        speakerNotes = "Invaluable presenter advice instructions go here."
                                    )
                                    selectedPresentation.slides.add(currentSlideIdx + 1, newSld)
                                    // Recalculate slide serial numbers
                                    selectedPresentation.slides.forEachIndexed { index, s -> s.slideNumber = index + 1 }
                                    currentSlideIdx++
                                    Toast.makeText(context, "New slide added successfully!", Toast.LENGTH_SHORT).show()
                                } else {
                                    Toast.makeText(context, "Full list cap reached", Toast.LENGTH_SHORT).show()
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.1f)),
                            shape = RoundedCornerShape(4.dp),
                            contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp),
                            modifier = Modifier.height(26.dp)
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                Icon(imageVector = Icons.Filled.Add, contentDescription = null, tint = NeonPrimary, modifier = Modifier.size(11.dp))
                                Text("ADD", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        Button(
                            onClick = {
                                // Delete current slide
                                if (selectedPresentation.slides.size > 2) {
                                    val previousIdx = currentSlideIdx
                                    selectedPresentation.slides.removeAt(currentSlideIdx)
                                    selectedPresentation.slides.forEachIndexed { index, s -> s.slideNumber = index + 1 }
                                    currentSlideIdx = (previousIdx - 1).coerceAtLeast(0)
                                    Toast.makeText(context, "Current slide deleted", Toast.LENGTH_SHORT).show()
                                } else {
                                    Toast.makeText(context, "Presentations must have at least 2 slides!", Toast.LENGTH_SHORT).show()
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.1f)),
                            shape = RoundedCornerShape(4.dp),
                            contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp),
                            modifier = Modifier.height(26.dp)
                        ) {
                            Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                Icon(imageVector = Icons.Filled.Delete, contentDescription = null, tint = Color.Red, modifier = Modifier.size(11.dp))
                                Text("DELETE", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                            }
                        }

                        Button(
                            onClick = {
                                // Duplicate Slide
                                if (currentSlide != null) {
                                    val dupe = currentSlide.copy(
                                        id = "slide_dupe_${System.currentTimeMillis()}",
                                        title = "${currentSlide.title} Copy"
                                    )
                                    selectedPresentation.slides.add(currentSlideIdx + 1, dupe)
                                    selectedPresentation.slides.forEachIndexed { index, s -> s.slideNumber = index + 1 }
                                    currentSlideIdx++
                                    Toast.makeText(context, "Slide duplicated successfully!", Toast.LENGTH_SHORT).show()
                                }
                            },
                            colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.1f)),
                            shape = RoundedCornerShape(4.dp),
                            contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp),
                            modifier = Modifier.height(26.dp)
                        ) {
                            Text("DUPLICATE", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                        }
                    }

                    // Rearrenger buttons (Move left/right)
                    Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                        IconButton(
                            onClick = {
                                if (currentSlideIdx > 0) {
                                    val temp = selectedPresentation.slides[currentSlideIdx]
                                    selectedPresentation.slides[currentSlideIdx] = selectedPresentation.slides[currentSlideIdx - 1]
                                    selectedPresentation.slides[currentSlideIdx - 1] = temp
                                    selectedPresentation.slides.forEachIndexed { pos, sld -> sld.slideNumber = pos + 1 }
                                    currentSlideIdx--
                                }
                            },
                            modifier = Modifier.size(24.dp)
                        ) {
                            Icon(imageVector = Icons.Filled.ArrowBack, contentDescription = "Move Left", tint = Color.LightGray, modifier = Modifier.size(14.dp))
                        }

                        IconButton(
                            onClick = {
                                if (currentSlideIdx < selectedPresentation.slides.size - 1) {
                                    val temp = selectedPresentation.slides[currentSlideIdx]
                                    selectedPresentation.slides[currentSlideIdx] = selectedPresentation.slides[currentSlideIdx + 1]
                                    selectedPresentation.slides[currentSlideIdx + 1] = temp
                                    selectedPresentation.slides.forEachIndexed { pos, sld -> sld.slideNumber = pos + 1 }
                                    currentSlideIdx++
                                }
                            },
                            modifier = Modifier.size(24.dp)
                        ) {
                            Icon(imageVector = Icons.Filled.ArrowForward, contentDescription = "Move Right", tint = Color.LightGray, modifier = Modifier.size(14.dp))
                        }
                    }
                }

                Divider(color = Color.White.copy(alpha = 0.05f))

                // INTERACTIVE TEXT EDITOR FOR ACTIVE SLIDE
                if (currentSlide != null) {
                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        Text("EDIT SLIDE HEADER TITLE", fontSize = 9.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                        OutlinedTextField(
                            value = tempSlideTitle,
                            onValueChange = { tempSlideTitle = it },
                            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(40.dp),
                            colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPrimary, unfocusedBorderColor = Color.DarkGray),
                            shape = RoundedCornerShape(6.dp)
                        )

                        // BULLET POINTS LIST EDITOR
                        Text("EDIT BULLET POINTS CONTENT", fontSize = 9.sp, color = NeonPurple, fontWeight = FontWeight.Bold)
                        Column(
                            verticalArrangement = Arrangement.spacedBy(6.dp),
                            modifier = Modifier.background(Color(0xFF04040F), RoundedCornerShape(8.dp)).padding(8.dp)
                        ) {
                            currentSlide.contentLines.forEachIndexed { lidx, line ->
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.spacedBy(6.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Box(modifier = Modifier.size(6.dp).background(NeonPrimary, CircleShape))
                                    
                                    var editedLineText by remember { mutableStateOf(line) }
                                    OutlinedTextField(
                                        value = editedLineText,
                                        onValueChange = { newValue ->
                                            editedLineText = newValue
                                            val workingList = currentSlide.contentLines.toMutableList()
                                            workingList[lidx] = newValue
                                            currentSlide.contentLines = workingList
                                        },
                                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 10.5.sp),
                                        modifier = Modifier.weight(1f).height(38.dp),
                                        colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPurple, unfocusedBorderColor = Color.DarkGray),
                                        shape = RoundedCornerShape(4.dp)
                                    )

                                    IconButton(
                                        onClick = {
                                            if (currentSlide.contentLines.size > 1) {
                                                val workingList = currentSlide.contentLines.toMutableList()
                                                workingList.removeAt(lidx)
                                                currentSlide.contentLines = workingList
                                            } else {
                                                Toast.makeText(context, "Retain at least one point", Toast.LENGTH_SHORT).show()
                                            }
                                        },
                                        modifier = Modifier.size(24.dp)
                                    ) {
                                        Icon(imageVector = Icons.Filled.Delete, contentDescription = "Delete raw", tint = Color.Red.copy(alpha = 0.7f), modifier = Modifier.size(12.dp))
                                    }
                                }
                            }

                            Button(
                                onClick = {
                                    if (currentSlide.contentLines.size < 6) {
                                        currentSlide.contentLines = currentSlide.contentLines + "New bullet parameter description guide..."
                                    } else {
                                        Toast.makeText(context, "Maximum 6 items allowed per slide to prevent overcrowding", Toast.LENGTH_LONG).show()
                                    }
                                },
                                colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.05f)),
                                contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp),
                                modifier = Modifier.height(24.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(2.dp)) {
                                    Icon(imageVector = Icons.Filled.Add, contentDescription = null, tint = NeonPrimary, modifier = Modifier.size(10.dp))
                                    Text("ADD NEW LINE", color = Color.White, fontSize = 8.sp)
                                }
                            }
                        }

                        // CHART LIVE COMPONENT AND ADJUSTERS
                        if (currentSlide.layoutType == "Chart" && currentSlide.chartType != null) {
                            Text("EDIT LIVE DATA-VIZ CHART VALUES", fontSize = 9.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                            
                            Card(
                                modifier = Modifier.fillMaxWidth(),
                                colors = CardDefaults.cardColors(containerColor = Color(0xFF060612)),
                                border = BorderStroke(0.5.dp, NeonPrimary.copy(alpha = 0.3f))
                            ) {
                                Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                                    Text("Interactive Data Values Graph Source", color = Color.Gray, fontSize = 8.sp)
                                    
                                    currentSlide.chartValues.forEachIndexed { valIdx, rawNum ->
                                        val labelText = if (valIdx in currentSlide.chartLabels.indices) currentSlide.chartLabels[valIdx] else "Item"
                                        
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween,
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Text(labelText, color = Color.White, fontSize = 9.5.sp, modifier = Modifier.weight(1f))
                                            
                                            Row(
                                                verticalAlignment = Alignment.CenterVertically,
                                                horizontalArrangement = Arrangement.spacedBy(6.dp)
                                            ) {
                                                // Minus multiplier counter
                                                IconButton(
                                                    onClick = {
                                                        val mutableVal = currentSlide.chartValues.toMutableList()
                                                        mutableVal[valIdx] = (rawNum - 10f).coerceAtLeast(0f)
                                                        currentSlide.chartValues = mutableVal
                                                    },
                                                    modifier = Modifier.size(24.dp).background(Color.White.copy(alpha = 0.05f), CircleShape)
                                                ) {
                                                    Text("-", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                                }

                                                Text(
                                                    text = "${rawNum.toInt()}",
                                                    color = NeonPrimary,
                                                    fontSize = 11.sp,
                                                    fontWeight = FontWeight.Black,
                                                    modifier = Modifier.width(34.dp),
                                                    textAlign = TextAlign.Center
                                                )

                                                // Plus counter
                                                IconButton(
                                                    onClick = {
                                                        val mutableVal = currentSlide.chartValues.toMutableList()
                                                        mutableVal[valIdx] = (rawNum + 10f).coerceAtMost(150f)
                                                        currentSlide.chartValues = mutableVal
                                                    },
                                                    modifier = Modifier.size(24.dp).background(Color.White.copy(alpha = 0.05f), CircleShape)
                                                ) {
                                                    Text("+", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        // SPEAKER NOTES
                        Text("EDIT SPEAKER TALKING NOTES (IN-DEPTH PRESENTER TIPS)", fontSize = 9.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                        OutlinedTextField(
                            value = tempSlideNotes,
                            onValueChange = { tempSlideNotes = it },
                            textStyle = androidx.compose.ui.text.TextStyle(color = Color.LightGray, fontSize = 10.5.sp),
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(60.dp),
                            colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPrimary, unfocusedBorderColor = Color.DarkGray),
                            shape = RoundedCornerShape(6.dp)
                        )

                        // DYNAMIC SWITCHER BACKGROUND STYLES
                        Text("CHOOSE BACKGROUND STYLE/SKIN", fontSize = 9.sp, color = Color.Gray, fontWeight = FontWeight.Bold)
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                            val skinList = listOf("Slate Indigo", "Cosmic Midnight", "Velvet Dark", "Minimal Charcoal")
                            skinList.forEach { skin ->
                                val isSelectedSkin = currentSlide.selectedBackgroundStyle == skin
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .clip(RoundedCornerShape(6.dp))
                                        .background(if (isSelectedSkin) NeonPurple.copy(alpha = 0.15f) else Color.White.copy(alpha = 0.02f))
                                        .border(
                                            0.5.dp,
                                            if (isSelectedSkin) NeonPurple else Color.DarkGray.copy(alpha = 0.5f),
                                            RoundedCornerShape(6.dp)
                                        )
                                        .clickable {
                                            currentSlide.selectedBackgroundStyle = skin
                                            Toast.makeText(context, "$skin applied to current slide!", Toast.LENGTH_SHORT).show()
                                        }
                                        .padding(vertical = 6.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(skin, color = if (isSelectedSkin) Color.White else Color.Gray, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }

                        Divider(color = Color.White.copy(alpha = 0.05f))

                        // AI WRITING ASSISTANT TOOLBOX
                        Text("AI WRITING ASSISTANT OPERATIONS", fontSize = 9.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                        Card(
                            modifier = Modifier.fillMaxWidth(),
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF09091E))
                        ) {
                            Row(
                                modifier = Modifier.fillMaxWidth().padding(6.dp),
                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Button(
                                    onClick = {
                                        // Expand content
                                        val longerLines = currentSlide.contentLines.map {
                                            if (!it.contains("expanded parameters")) "$it with additional expanded parameters and dynamic structural analytics." else it
                                        }
                                        currentSlide.contentLines = longerLines
                                        Toast.makeText(context, "AI expand action succeeded!", Toast.LENGTH_SHORT).show()
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.04f)),
                                    contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp),
                                    modifier = Modifier.weight(1f).height(24.dp)
                                ) {
                                    Text("✨ EXPAND", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                }

                                Button(
                                    onClick = {
                                        // Simplify content
                                        val shorterLines = currentSlide.contentLines.map {
                                            if (it.length > 25) it.take(25) + "..." else it
                                        }
                                        currentSlide.contentLines = shorterLines
                                        Toast.makeText(context, "AI simplified content lines success!", Toast.LENGTH_SHORT).show()
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.04f)),
                                    contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp),
                                    modifier = Modifier.weight(1f).height(24.dp)
                                ) {
                                    Text("📝 SIMPLIFY", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                }

                                Button(
                                    onClick = {
                                        // Formal Professional Tone
                                        tempSlideTitle = "Strategic " + tempSlideTitle.replace("My", "Enterprise").replace("New", "Consolidated Tactical")
                                        Toast.makeText(context, "Converted tone to formal professional!", Toast.LENGTH_SHORT).show()
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.04f)),
                                    contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp),
                                    modifier = Modifier.weight(1f).height(24.dp)
                                ) {
                                    Text("🗣️ FORMAL TONE", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                }

                                Button(
                                    onClick = {
                                        // Translate to Hindi / Spanish
                                        tempSlideTitle = if (selectedLanguage.lowercase().contains("hindi")) "रणनीतिक अवलोकन (Topic Review)" else "Visión Estratégica"
                                        Toast.makeText(context, "Translated slide target successfully!", Toast.LENGTH_SHORT).show()
                                    },
                                    colors = ButtonDefaults.buttonColors(containerColor = Color.White.copy(alpha = 0.04f)),
                                    contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp),
                                    modifier = Modifier.weight(1f).height(24.dp)
                                ) {
                                    Text("🌐 TRANSLATE", color = Color.White, fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                }
                            }
                        }

                        Spacer(modifier = Modifier.height(4.dp))

                        // EXPORT DRAWER OPERATING PORT
                        Text("PREPARE FILE EXPORT PACKS", fontSize = 9.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp), verticalAlignment = Alignment.CenterVertically) {
                            val formats = listOf("PPTX", "PDF", "IMAGES", "GOOGLE SLIDES")
                            
                            formats.forEach { format ->
                                val isChosenFormat = exportFormatSelected == format
                                Box(
                                    modifier = Modifier
                                        .weight(1f)
                                        .clip(RoundedCornerShape(6.dp))
                                        .background(if (isChosenFormat) NeonPrimary.copy(alpha = 0.15f) else Color.White.copy(alpha = 0.02f))
                                        .border(
                                            0.5.dp,
                                            if (isChosenFormat) NeonPrimary else Color.Gray.copy(alpha = 0.5f),
                                            RoundedCornerShape(6.dp)
                                        )
                                        .clickable { exportFormatSelected = format }
                                        .padding(vertical = 8.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(format, color = if (isChosenFormat) Color.White else Color.Gray, fontSize = 8.5.sp, fontWeight = FontWeight.Black)
                                }
                            }
                        }

                        if (isExportingNow) {
                            Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                    Text("Packing charts and styling layout components...", color = Color.LightGray, fontSize = 9.sp)
                                    Text("$exportProgressPct%", color = NeonPrimary, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                }
                                LinearProgressIndicator(
                                    progress = exportProgressPct / 100f,
                                    color = NeonPrimary,
                                    trackColor = Color.DarkGray,
                                    modifier = Modifier.fillMaxWidth().height(4.dp).clip(RoundedCornerShape(2.dp))
                                )
                            }
                        } else {
                            Button(
                                onClick = { isExportingNow = true },
                                colors = ButtonDefaults.buttonColors(containerColor = NeonPrimary),
                                shape = RoundedCornerShape(8.dp),
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(40.dp)
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    Icon(imageVector = Icons.Filled.Download, contentDescription = null, tint = PureBlack, modifier = Modifier.size(14.dp))
                                    Text("DOWNLOAD EXPORT: $exportFormatSelected", color = PureBlack, fontSize = 11.sp, fontWeight = FontWeight.Black)
                                }
                            }
                        }
                    }
                }
            }
        }

        // -------------------------------------------------------------
        // TAB: COLLABORATIVE & COMMENTS
        // -------------------------------------------------------------
        if (activeTabIdx == 3) {
            Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                
                // Collaboration Invite Members card
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = Color(0xFF08081E)),
                    border = BorderStroke(0.5.dp, NeonPrimary.copy(alpha = 0.3f))
                ) {
                    Column(modifier = Modifier.padding(12.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                            Icon(imageVector = Icons.Filled.GroupAdd, contentDescription = null, tint = NeonPrimary, modifier = Modifier.size(16.dp))
                            Text("INVITE TEAM MEMBERS TO ACTIVE PRESENTATION", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Black)
                        }

                        var emailInviteInput by remember { mutableStateOf("") }
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(6.dp)
                        ) {
                            OutlinedTextField(
                                value = emailInviteInput,
                                onValueChange = { emailInviteInput = it },
                                textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                                colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonPrimary, unfocusedBorderColor = Color.DarkGray),
                                shape = RoundedCornerShape(6.dp),
                                modifier = Modifier.weight(1f).height(40.dp),
                                placeholder = { Text("e.g. cofounder@aistudio.com", fontSize = 10.sp, color = Color.Gray) }
                            )

                            Button(
                                onClick = {
                                    if (emailInviteInput.contains("@") && emailInviteInput.contains(".")) {
                                        Toast.makeText(context, "Invitation successfully sent to $emailInviteInput! 👥", Toast.LENGTH_LONG).show()
                                        emailInviteInput = ""
                                    } else {
                                        Toast.makeText(context, "Please enter a valid email address", Toast.LENGTH_SHORT).show()
                                    }
                                },
                                colors = ButtonDefaults.buttonColors(containerColor = NeonPrimary),
                                shape = RoundedCornerShape(6.dp),
                                modifier = Modifier.height(40.dp)
                            ) {
                                Text("INVITE", color = PureBlack, fontSize = 9.5.sp, fontWeight = FontWeight.Bold)
                            }
                        }
                    }
                }

                // Inline Slide Comments List
                Text("SLIDE FEEDBACK COMMENTS (${if (currentSlide != null) "Slide " + (currentSlideIdx + 1) else "Any"})", fontSize = 10.sp, color = NeonCyan, fontWeight = FontWeight.Bold)
                
                if (currentSlide != null) {
                    val slideComments = slideCommentsMap[currentSlide.id] ?: emptyList()
                    
                    if (slideComments.isEmpty()) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .background(Color(0xFF04040E), RoundedCornerShape(8.dp))
                                .padding(16.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text("No feedback comments on Slide ${currentSlideIdx + 1} yet! Add comments below.", color = Color.Gray, fontSize = 10.sp)
                        }
                    } else {
                        Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                            slideComments.forEach { comment ->
                                Card(
                                    modifier = Modifier.fillMaxWidth().border(0.5.dp, Color.White.copy(alpha = 0.05f), RoundedCornerShape(8.dp)),
                                    colors = CardDefaults.cardColors(containerColor = Color(0xFF04040A))
                                ) {
                                    Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween,
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Text(comment.userEmail, color = NeonPurple, fontSize = 9.sp, fontWeight = FontWeight.ExtraBold)
                                            Text(
                                                text = android.text.format.DateFormat.format("hh:mm a", comment.timestamp).toString(),
                                                color = Color.Gray,
                                                fontSize = 7.5.sp
                                            )
                                        }
                                        Text(comment.text, color = Color.White, fontSize = 10.sp)
                                    }
                                }
                            }
                        }
                    }

                    // Add dynamic commentator card
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        OutlinedTextField(
                            value = currentCommentInputText,
                            onValueChange = { currentCommentInputText = it },
                            textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                            colors = OutlinedTextFieldDefaults.colors(focusedBorderColor = NeonCyan, unfocusedBorderColor = Color.DarkGray),
                            shape = RoundedCornerShape(6.dp),
                            modifier = Modifier.weight(1f).height(40.dp),
                            placeholder = { Text("Comment on Slide ${currentSlideIdx + 1}...", fontSize = 10.sp, color = Color.Gray) }
                        )

                        IconButton(
                            onClick = {
                                if (currentCommentInputText.isNotBlank()) {
                                    val log = SlideComment(
                                        id = "comm_${System.currentTimeMillis()}",
                                        userEmail = "chankikawde7@gmail.com",
                                        text = currentCommentInputText
                                    )
                                    val slideId = currentSlide.id
                                    val currentList = slideCommentsMap[slideId] ?: emptyList()
                                    slideCommentsMap[slideId] = currentList + log
                                    currentCommentInputText = ""
                                    Toast.makeText(context, "Feedback added!", Toast.LENGTH_SHORT).show()
                                }
                            },
                            modifier = Modifier
                                .size(40.dp)
                                .background(NeonCyan, RoundedCornerShape(6.dp))
                        ) {
                            Icon(imageVector = Icons.Filled.Comment, contentDescription = "Add Comment", tint = PureBlack, modifier = Modifier.size(16.dp))
                        }
                    }
                }

                // Version logs history revert
                Text("DRAFT VERSION HISTORY (RESTORE PREVIOUS LOGS)", fontSize = 10.sp, color = NeonPrimary, fontWeight = FontWeight.Bold)
                
                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                    historyVersionLogs.forEach { log ->
                        Card(
                            modifier = Modifier.fillMaxWidth(),
                            colors = CardDefaults.cardColors(containerColor = Color(0xFF03030A)),
                            border = BorderStroke(0.5.dp, Color.DarkGray.copy(alpha = 0.5f))
                        ) {
                            Row(
                                modifier = Modifier.padding(10.dp).fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Column {
                                    Text(log.summary, color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Bold)
                                    Text(
                                        "Backup taken: " + android.text.format.DateFormat.format("dd MMM hh:mm a", log.timestamp).toString(),
                                        color = Color.Gray,
                                        fontSize = 8.sp
                                    )
                                }

                                TextButton(
                                    onClick = {
                                        Toast.makeText(context, "Reverted current slides state to backup version '${log.id}'", Toast.LENGTH_LONG).show()
                                    },
                                    contentPadding = PaddingValues(horizontal = 6.dp, vertical = 2.dp),
                                    modifier = Modifier.height(26.dp)
                                ) {
                                    Text("RESTORE", color = NeonPrimary, fontSize = 9.sp, fontWeight = FontWeight.Black)
                                }
                            }
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(16.dp))
    }

    // Modal upgrade subscription
    if (showUpgradeDialog) {
        AlertDialog(
            onDismissRequest = { showUpgradeDialog = false },
            containerColor = Color(0xFF0A0A1C),
            title = {
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Icon(imageVector = Icons.Filled.NewReleases, contentDescription = null, tint = Color(0xFFFFD700))
                    Text("Unlock Advanced Presentation Pro", color = Color.White, fontSize = 15.sp, fontWeight = FontWeight.Bold)
                }
            },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text("Pro membership offers unlimited presentation generations, premium presentation styles (warm organic, brand luxury), watermarks removal, high-res PDF downloads, advanced live data widgets, comments sync, and priority AI processing.", color = Color.LightGray, fontSize = 12.5.sp)
                    Text("★ Scalable outlines generating up to 50 detailed slides instantly.", color = NeonPrimary, fontSize = 11.sp, fontWeight = FontWeight.SemiBold)
                }
            },
            confirmButton = {
                Button(
                    onClick = {
                        scope.launch {
                            viewModel.updateSubscription("Pro", 500)
                            Toast.makeText(context, "Congratulations! Presentation Maker Pro is now active! 🎉", Toast.LENGTH_LONG).show()
                            showUpgradeDialog = false
                        }
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = NeonPurple)
                ) {
                    Text("Upgrade ($14.99/mo)", color = Color.White, fontSize = 10.5.sp)
                }
            },
            dismissButton = {
                TextButton(onClick = { showUpgradeDialog = false }) {
                    Text("Keep normal limits", color = Color.Gray, fontSize = 10.5.sp)
                }
            }
        )
    }
}

// =========================================================================
// AI PDF CHAT SYSTEM MODULE
// =========================================================================

data class PDFDocumentModel(
    val id: String,
    val fileName: String,
    val fileSize: String,
    val totalPages: Int,
    val uploadDate: String,
    val isScanned: Boolean = false,
    val isLocked: Boolean = false,
    val passwordInput: String = "",
    val pages: List<String>,
    val author: String = "AI DocuEngine",
    val tags: List<String> = listOf("Active", "Vector Index Indexed")
)

data class PDFChatMessage(
    val id: String,
    val sender: String, // "user", "ai"
    val text: String,
    val sourcePages: List<Int> = emptyList(),
    val confidence: Float = 0.95f,
    val excerpt: String? = null,
    val timestamp: Long = System.currentTimeMillis()
)

data class PDFStudyNote(
    val id: String,
    val pdfId: String,
    var title: String,
    var content: String,
    val createdDate: String = "Jun 14, 2026"
)

data class PDFFlashcard(
    val id: String,
    val pdfId: String,
    val question: String,
    val answer: String,
    var difficulty: String = "Pending" // "Easy", "Medium", "Hard"
)

data class PDFQuizQuestion(
    val id: String,
    val pdfId: String,
    val question: String,
    val options: List<String>,
    val correctIndex: Int,
    val explanation: String,
    val type: String // "MCQ", "TF"
)

// Main PDF Chat Composable
@OptIn(ExperimentalMaterial3Api::class, ExperimentalLayoutApi::class)
@Composable
fun PDFChatWorkspace(
    viewModel: CreatorViewModel,
    modifier: Modifier = Modifier
) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    
    // Core design color definitions to ensure absolute compatibility
