    val LocalNeonMagenta = Color(0xFFEC4899)
    val LocalCardBg = Color(0xFF0F0F1E)
    val LocalDarkBg = Color(0xFF070714)
    val LocalNeonGreen = Color(0xFF10B981)

    // Live user statistics
    val userStats by viewModel.userStats.collectAsState()

    // Subscriptions count mock-up limits
    var uploadCount by remember { mutableStateOf(1) }
    val maxFreeUploads = 3
    val isPremiumPlan = userStats?.isProPlan == true

    // --- Hardcoded preloaded PDF Store ---
    val initialPdfs = remember {
        mutableStateListOf(
            PDFDocumentModel(
                id = "business_report",
                fileName = "Q2_Sales_and_Operation_Overview.pdf",
                fileSize = "2.4 MB",
                totalPages = 3,
                uploadDate = "Jun 10, 2026",
                isScanned = false,
                pages = listOf(
                    "Q2 Performance Overview. Total corporate revenue of $4.2M represents a 12% quarterly growth rate and 18% year-over-year increase. Hardware sales account for $2.5M, while cloud software subscriptions reached $1.7M. Key drivers are increased enterprise cloud adoption in Europe and Asia-Pacific regional warehouses.",
                    "Supply Chain Operations. Delivery latency increased by average 4.2 days due to global maritime freight delays. Regional fulfillment hubs are operating at 92% peak capacity. Inventory turnover ratio shifted from 6.1 to 5.4. Mitigating actions: establishing secondary sourcing in Mexico.",
                    "Core Strategic Recommendations. 1) Allocate $1.2M capital for warehouse automation. 2) Scale European data compliance and gdpr teams. 3) Push hybrid-cloud contracts with premium tiered pricing structures. Projected Q3 sales revenue is estimated at $4.5M - $4.8M."
                )
            ),
            PDFDocumentModel(
                id = "ai_thesis",
                fileName = "Neural_Symbolic_Reasoning_In_LLMs.pdf",
                fileSize = "4.1 MB",
                totalPages = 4,
                uploadDate = "Jun 11, 2026",
                isScanned = true,
                pages = listOf(
                    "Neuro-Symbolic integration combines deep connectionist models with discrete logical structures or constraints. It directly addresses systemic reasoning errors like hallucinations, catastrophic forgetting, or arithmetic mistakes.",
                    "Methodology Framework. Outlines LLM-guided code generation coupled with an external execution verification checker (SAT-solver, Python compilers). Evaluates benchmarks on GSM8K, MATH, and LogicQA datasets.",
                    "Experimental Results. The Neuro-Symbolic feedback evaluation loop shows an average accuracy hike of 14.5% on multi-hop deductive datasets. Symbolic execution corrects logic flaws in 38% of initial model outputs.",
                    "Future Research Horizons. Investigating backpropagation directly through symbolic proofs for deep parameter weights optimization, establishing sound neural-symbolic loss components."
                )
