            ),
            PDFDocumentModel(
                id = "real_estate_study",
                fileName = "Q2_Real_Estate_Marketing_Study.pdf",
                fileSize = "3.8 MB",
                totalPages = 5,
                uploadDate = "Jun 13, 2026",
                isScanned = false,
                pages = listOf(
                    "Introduction & Market Overview. This comprehensive study tracks real estate yield changes, supply chain structures, and metropolitan workspace performance across Compact Urban Cores vs Suburban Zones during early 2026.",
                    "Rental Yield Dynamics. Suburban residential properties scored a surprising 6.4% average yield, outgrowing metropolitan core apartments (4.1%) due to massive work-from-home structural flexibility extensions.",
                    "Corporate Workspace Portfolio. Commercial office spaces have faced extremely high vacancy rates of 21% in downtown centers. Office-to-residential zoning conversions have surged by 34% nationally to solve lodging grids.",
                    "Capital Funding Patterns. Primary bank lending rates hovered around 6.5%. Investment capital shifted to industrial logistics parks, high-capacity cold rooms, and self-storage networks rather than high-rise office towers.",
                    "Long-Term Market Forecasting. Models suggest stable single-family detached pricing with a 3.8% annual compound increase, while corporate office layouts face lease pricing and compression through late 2028."
                )
            )
        )
    }

    // Selected PDF active model
    var selectedPdfId by remember { mutableStateOf("business_report") }
    val currentPdf = remember(selectedPdfId) {
        initialPdfs.find { it.id == selectedPdfId } ?: initialPdfs.firstOrNull()
    }

    // Password input state for locked PDFs
    var enteredPassword by remember { mutableStateOf("") }
    var isUnlockedByPassword by remember { mutableStateOf(false) }

    // Upload simulation statuses
    var showUploadModal by remember { mutableStateOf(false) }
    var uploadProgress by remember { mutableStateOf(0f) }
    var isUploadingNow by remember { mutableStateOf(false) }
    var selectedCustomFileUri by remember { mutableStateOf<Uri?>(null) }
    var uploadedFileNameSim by remember { mutableStateOf("") }
    var uploadedFileSizeSim by remember { mutableStateOf("") }
    var isCustomPasswordProtected by remember { mutableStateOf(false) }
    var isCustomScannedPdf by remember { mutableStateOf(false) }

    // Chat states
    val chatMessagesMap = remember {
        mutableStateMapOf<String, List<PDFChatMessage>>().apply {
            put("business_report", listOf(
                PDFChatMessage("m1", "ai", "Hello! I have completed full semantic embedding text-chunking and indexing of **Q2 Sales Overview**. Ask me any analytical question, request a summary or generate notes/quizzes!")
            ))
            put("ai_thesis", listOf(
                PDFChatMessage("m2", "ai", "Hi there! I am ready to discuss **Neural Symbolic Reasoning** thesis. Feel free to ask about logical solvers, mathematical evaluation or structural reasoning benchmarks!")
            ))
            put("product_spec", listOf(
                PDFChatMessage("m3", "ai", "Secure document **Project Neon Core Specs** successfully decrypted. Pose questions regarding gRPC, FlatBuffers, Rust or Kubernetes infrastructure.")
            ))
            put("real_estate_study", listOf(
                PDFChatMessage("m4", "ai", "Market study **Real Estate Trends 2026** loaded. Ask me about suburban yield metrics, commercial vacancies (21%), or zoning conversions!")
            ))
        }
    }
    
    var currentChatInputText by remember { mutableStateOf("") }
    var isWaitingForAiAnswer by remember { mutableStateOf(false) }

    // Multi-PDF analytical comparison state
    var isMultiPdfModeActive by remember { mutableStateOf(false) }
    val selectedMultiplePdfIds = remember { mutableStateListOf("business_report") }

    // Active screen workspace tab: 0: Doc Hub Explorer, 1: Conversation, 2: Interactive PDF Viewer, 3: AI Notes & Revision Kits, 4: Admin Panel
    var activeWorkspaceTabIdx by remember { mutableStateOf(1) }

    // Interactive PDF Viewer variables
    var pdfViewerZoomPct by remember { mutableStateOf(100) }
    var pdfViewerActivePageIdx by remember { mutableStateOf(0) }
    var pdfSearchQueryText by remember { mutableStateOf("") }
    val bookmarkedPages = remember { mutableStateListOf<Pair<String, Int>>() } // pdfId, pageIndex

    // Generative features outputs
    var dynamicDocSummaryType by remember { mutableStateOf("Executive Summary") } // Short, Detailed, Chapter-wise, Key Findings
    var generatedSummaryText by remember { mutableStateOf("") }
    var isGeneratingSummary by remember { mutableStateOf(false) }

    // Generated Study Notes states
    val savedPdfNotesList = remember {
        mutableStateListOf(
            PDFStudyNote("n1", "business_report", "Q2 Budget Actions", "• Allocate $1.2M capital for warehouse automation immediately\n• European GDPR audit setup needs 3 new staff compliance officers\n• Focus key corporate contracts in digital cloud services to boost recurring margins"),
            PDFStudyNote("n2", "ai_thesis", "Core Neuro-Symbolic Concept", "• Integration bridges the gap between deep neural nets (pattern systems) and discrete logical engines.\n• Directly curbs hallucination rates by checking programmatic logic constraints.\n• 14.5% precision hike verified on GSM8K math benchmarks.")
        )
    }
    var newlyGeneratedNotesDraftTitle by remember { mutableStateOf("") }
    var newlyGeneratedNotesDraftContent by remember { mutableStateOf("") }
    var isGeneratingNotesNow by remember { mutableStateOf(false) }

    // Flashcards states
    val savedFlashcardsStore = remember {
        mutableStateListOf(
            PDFFlashcard("f1", "business_report", "What is the total sales revenue reported in Q2?", "Total revenue is $4.2M (with hardware accounting for $2.5M and cloud at $1.7M).", "Easy"),
            PDFFlashcard("f2", "business_report", "What operating delays occurred in the supply chain?", "Delivery latency increased by an average of 4.2 days due to maritime transport delays.", "Medium"),
            PDFFlashcard("f3", "ai_thesis", "What benchmarks were utilized to check logic structures?", "GSM8K, MATH, and LogicQA datasets.", "Pending"),
            PDFFlashcard("f4", "product_spec", "Why does Project Neon use FlatBuffers instead of standard JSON?", "To achieve 4x faster data parsing speed for low-latency web socket channels.", "Pending")
        )
    }
    var currentFlashcardIdx by remember { mutableStateOf(0) }
    var isFlashcardFlipped by remember { mutableStateOf(false) }
    var isGeneratingFlashcards by remember { mutableStateOf(false) }

    // Quiz generator states
    val savedQuizQuestionsList = remember {
        mutableStateListOf(
            PDFQuizQuestion("q1", "business_report", "What was the year-over-year revenue increase in Q2?", listOf("12%", "18%", "25%", "6%"), 1, "The report states hardware/cloud sales drove an 18% YoY growth alongside 12% quarterly growth.", "MCQ"),
            PDFQuizQuestion("q2", "business_report", "What mitigating action is taken to resolve supply chain delays?", listOf("Close European warehouses", "Establish secondary sourcing in Mexico", "Postpone Q3 deployments", "Request federal subsidies"), 1, "Establishing secondary sourcing in Mexico acts as the primary mitigation plan.", "MCQ"),
            PDFQuizQuestion("q3", "ai_thesis", "Neuro-symbolic execution loop corrected how many percent of initial error queries?", listOf("14.5%", "38%", "92%", "21%"), 1, "Symbolic checking structures fixed logic issues on 38% of initial LLM outputs.", "MCQ"),
            PDFQuizQuestion("q4", "product_spec", "Project Neon's target scalability capacity per cluster node is:", listOf("10k concurrent channels", "50k concurrent channels", "100k concurrent channels", "1 Million channels"), 2, "The spec outline highlights capacity of 100k channels securely.", "MCQ"),
            PDFQuizQuestion("q5", "real_estate_study", "Corporate office space faced what vacancy rate in downtown centers?", listOf("4.1%", "21%", "34%", "6.5%"), 1, "Downtown offices suffered commercial vacancies reaching 21%.", "MCQ")
        )
    }
    val targetFilteredQuizList = remember(selectedPdfId) {
        savedQuizQuestionsList.filter { it.pdfId == selectedPdfId }
    }
    var activeQuizQuestionIdx by remember { mutableStateOf(0) }
    var selectedQuizAnswerOptionIdx by remember { mutableStateOf<Int?>(null) }
    var hasSubmittedQuizAnswer by remember { mutableStateOf(false) }
    var totalCorrectQuizScore by remember { mutableStateOf(0) }
    var hasFinishedQuizSequence by remember { mutableStateOf(false) }
    var isGeneratingQuizByAi by remember { mutableStateOf(false) }

    // Relational Concept Mind Map states
    var isMindMapNodeExpandedMap = remember { mutableStateMapOf<String, Boolean>() }
    var isGeneratingMindMap by remember { mutableStateOf(false) }

    // Translation Selector state
    var selectedTranslationTargetLang by remember { mutableStateOf("No Translation") } // French, Spanish, Hindi, German, Japanese, Arabic
    val translationLanguagesOptions = listOf("No Translation", "हिंदी (Hindi)", "Español (Spanish)", "Français (French)", "Deutsch (German)", "日本語 (Japanese)")

    // Voice Features (TTS Engine) simulation
    var isTtsAudioPlaying by remember { mutableStateOf(false) }
    var activeTtsPlayingMessageId by remember { mutableStateOf("") }
    var ttsPlaybackProgressSim by remember { mutableStateOf(0f) }
    var ttsAudioSpeedDial by remember { mutableStateOf(1.0f) }
    var ttsPitchDial by remember { mutableStateOf(1.0f) }
    var selectedSpeechProfile by remember { mutableStateOf("Vibrant Male Accent") } // "Warm Female Accent", "Cybernetic Robotic Tone"
    val ttsSpeechProfiles = listOf("Vibrant Male Accent", "Warm Female Accent", "Cybernetic Robotic Tone")

    // Cloud saving history logs mock
    val cloudDraftBackupLogs = remember {
        mutableStateListOf(
            DraftVersionLog("b1", "Saved automatic backup of notes (Q2 Budget Actions)"),
            DraftVersionLog("b2", "Synced 12 flashcards to Cloud Repository (Auto-Sync: OK)")
        )
    }

    // Interactive File Upload Launcher using real Android contracts!
    val filePickerLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.GetContent()
    ) { uri: Uri? ->
        if (uri != null) {
            selectedCustomFileUri = uri
            uploadedFileNameSim = uri.lastPathSegment ?: "external_document.pdf"
            if (!uploadedFileNameSim.lowercase().endsWith(".pdf")) {
                uploadedFileNameSim = "$uploadedFileNameSim.pdf"
            }
            uploadedFileSizeSim = "1.8 MB" // Default fallback size representation
            
            // Query real context resolver details if possible
            try {
                context.contentResolver.query(uri, null, null, null, null)?.use { cursor ->
                    val nameIndex = cursor.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                    val sizeIndex = cursor.getColumnIndex(android.provider.OpenableColumns.SIZE)
                    if (cursor.moveToFirst()) {
                        if (nameIndex != -1) {
                            val originalName = cursor.getString(nameIndex)
                            uploadedFileNameSim = if (originalName.lowercase().endsWith(".pdf")) originalName else "$originalName.pdf"
                        }
                        if (sizeIndex != -1) {
                            val bytesCount = cursor.getLong(sizeIndex)
                            uploadedFileSizeSim = if (bytesCount > 1024 * 1024) {
                                String.format("%.2f MB", bytesCount / (1024f * 1024f))
                            } else {
                                String.format("%.1f KB", bytesCount / 1024f)
                            }
                        }
                    }
                }
            } catch (e: Exception) {
                // Log and keep defaults
            }
            Toast.makeText(context, "Loaded $uploadedFileNameSim successfully! Select parameters to process OCR.", Toast.LENGTH_SHORT).show()
        }
    }

    // TTS continuous simulation worker
    LaunchedEffect(isTtsAudioPlaying) {
        if (isTtsAudioPlaying) {
            while (isTtsAudioPlaying) {
                kotlinx.coroutines.delay(100)
                ttsPlaybackProgressSim += 0.02f
                if (ttsPlaybackProgressSim >= 1f) {
                    isTtsAudioPlaying = false
                    ttsPlaybackProgressSim = 0f
                }
            }
        }
    }

    // PDF decryption checker
    val isDocumentViewBlocked = currentPdf?.isLocked == true && !isUnlockedByPassword && currentPdf.id == selectedPdfId

    // ==========================================
    // ACTIONS & INTEGRATIONS BLOCK
    // ==========================================
    
    // Core chat submission trigger calling real Gemini API!
    val triggerChatSubmission: (String) -> Unit = { queryText ->
        if (queryText.isNotBlank()) {
            val processedQuery = queryText.trim()
            currentChatInputText = ""

            // Append user message
            val list = chatMessagesMap[selectedPdfId] ?: emptyList()
            val userMsg = PDFChatMessage("user_${System.currentTimeMillis()}", "user", processedQuery)
            chatMessagesMap[selectedPdfId] = list + userMsg

            isWaitingForAiAnswer = true
            activeWorkspaceTabIdx = 1 // Make sure chat tab is active
            
            scope.launch {
                // Compile context block from target active documents in semantic search
                val contextBuilder = StringBuilder()
                
                if (isMultiPdfModeActive) {
                    selectedMultiplePdfIds.forEach { pid ->
                        val pdf = initialPdfs.find { it.id == pid }
                        if (pdf != null) {
                            contextBuilder.append("Document: ${pdf.fileName}\n")
                            pdf.pages.forEachIndexed { index, pageText ->
                                contextBuilder.append("[Page ${index + 1}]: $pageText\n")
                            }
                            contextBuilder.append("\n")
                        }
                    }
                } else {
                    currentPdf?.let { pdf ->
                        contextBuilder.append("Document: ${pdf.fileName}\n")
                        pdf.pages.forEachIndexed { index, pageText ->
                            contextBuilder.append("[Page ${index + 1}]: $pageText\n")
                        }
                    }
                }

                val sysInstruction = """
                    You are a highly efficient and advanced PDF Document Assistant. 
                    You are provided with verified text extracts from the active PDF document(s).
                    Your goal is to answer the user's questions based strictly on the text extracts.
                    Ensure maximum compliance and accuracy. Refer to page numbers and cited pages like [Page 1], [Page 2] or the appropriate document name in your output.
                    If the question is unrelated to the text context, answers should still address it politely while warning the user that it falls outside the uploaded document metadata.
                    
                    Here are the document contents:
                    $contextBuilder
                """.trimIndent()

                var finalPrompt = processedQuery
                if (selectedTranslationTargetLang != "No Translation") {
                    finalPrompt += " (Please output your complete response in $selectedTranslationTargetLang)"
                }

                // Call Gemini!
                val rawResponseText = try {
                    com.example.api.RetrofitClient.generateWithGemini(finalPrompt, sysInstruction)
                } catch (e: Exception) {
                    "AI Error: Unable to perform inference. Details: ${e.localizedMessage}"
                }

                // Analyze citations from extracted text to display beautifully under bubble links!
                val citedPagesList = mutableListOf<Int>()
                currentPdf?.let { pdf ->
                    pdf.pages.forEachIndexed { index, pageText ->
                        val pNum = index + 1
                        if (rawResponseText.contains("page $pNum", ignoreCase = true) || 
                            rawResponseText.contains("[$pNum]", ignoreCase = true) ||
                            rawResponseText.contains("[Page $pNum]", ignoreCase = true) ||
                            processedQuery.contains("page $pNum", ignoreCase = true)) {
                            citedPagesList.add(pNum)
                        }
                    }
                }
                if (citedPagesList.isEmpty()) {
                    citedPagesList.add(1) // Default to Page 1 fallback
                }

                val aiMsg = PDFChatMessage(
                    id = "ai_${System.currentTimeMillis()}",
                    sender = "ai",
                    text = rawResponseText,
                    sourcePages = citedPagesList.distinct(),
                    excerpt = "Extracted analysis representing selected PDF query matches."
                )

                val updatedList = chatMessagesMap[selectedPdfId] ?: emptyList()
                chatMessagesMap[selectedPdfId] = updatedList + aiMsg
                isWaitingForAiAnswer = false
                
                // Track usage
                viewModel.recordPdfChatQuery(currentPdf?.fileName ?: "Multi-PDF Search", processedQuery)
            }
        }
    }

    // Core AI Summary trigger calling real Gemini API
    val triggerSummaryGeneration: (String) -> Unit = { summaryType ->
        isGeneratingSummary = true
        scope.launch {
            val textToAnalyze = currentPdf?.pages?.joinToString("\n") ?: "No document selected."
            val styleInstruction = when(summaryType) {
                "Detailed Summary" -> "Highlight granular operational breakdowns, numbers, formulas, structures, and direct recommendations."
                "Chapter-wise Summary" -> "Iterate page by page, compiling a structured, section-by-section bulletin format."
                "Key Findings" -> "Compile a bulleted list of 10 major insights and surprising takeaways."
                else -> "Draft an elegant high-level executive briefing suite for corporate presentation."
            }

            val systemInstruction = "You are an expert technical editor. Summarize the user's text. Style constraint: $styleInstruction"
            val prompt = "Please write a comprehensive, gorgeous $summaryType based on the following document content:\n\n$textToAnalyze"

            val result = try {
                com.example.api.RetrofitClient.generateWithGemini(prompt, systemInstruction)
            } catch (e: Exception) {
                "Error generating summary: ${e.localizedMessage}"
            }

            generatedSummaryText = result
            isGeneratingSummary = false
        }
    }

    // Core Notes generator trigger calling real Gemini API
    val triggerNotesGeneration: () -> Unit = {
        isGeneratingNotesNow = true
        scope.launch {
            val textData = currentPdf?.pages?.joinToString("\n") ?: ""
            val promptString = "Analyze the text and produce ready-to-use study/revision flash notes decorated with rich bullet points, styled subheadings, definitions of key acronyms, and direct action checklists.\n\nText: $textData"
            val systemStr = "You are a professional research scientist and educator. Return notes outputs."

            val result = try {
                com.example.api.RetrofitClient.generateWithGemini(promptString, systemStr)
            } catch (e: Exception) {
                "Failed notes: ${e.localizedMessage}"
            }

            newlyGeneratedNotesDraftTitle = "Study Notes - ${(currentPdf?.fileName ?: "Doc").substringBeforeLast(".")}"
            newlyGeneratedNotesDraftContent = result
            isGeneratingNotesNow = false
        }
    }

    // Core Flashcard generator trigger calling real Gemini API
    val triggerFlashcardGeneration: () -> Unit = {
        isGeneratingFlashcards = true
        scope.launch {
            val textData = currentPdf?.pages?.joinToString("\n") ?: ""
            val promptStr = "From this document, extract exactly 4 highly memorable and diverse Q&A review questions. Output them strictly in a clean plain-text format with each card separated by '***'. Format: Question: [Your text query?] Answer: [Precise response answer value.]"
            val systemStr = "You are an expert instructional designer."

            val result = try {
                com.example.api.RetrofitClient.generateWithGemini(promptStr, systemStr)
            } catch (e: Exception) {
                "Question: Error Question?\nAnswer: Error loading details."
            }

            // Parse result into Flashcards list
            val parsedBlocks = result.split("***")
            parsedBlocks.forEachIndexed { index, block ->
                if (block.contains("Question:", ignoreCase = true) && block.contains("Answer:", ignoreCase = true)) {
                    val qText = block.substringAfter("Question:").substringBefore("Answer:").trim()
                    val aText = block.substringAfter("Answer:").trim()
                    if (qText.length > 5 && aText.length > 5) {
                        savedFlashcardsStore.add(
                            PDFFlashcard(
                                id = "fc_custom_${System.currentTimeMillis()}_$index",
                                pdfId = selectedPdfId,
                                question = qText,
                                answer = aText,
                                difficulty = "Pending"
                            )
                        )
                    }
                }
            }
            if (savedFlashcardsStore.none { it.pdfId == selectedPdfId }) {
                // Generate simulated ones if parsing failed
                savedFlashcardsStore.add(PDFFlashcard("fc_fallback_1", selectedPdfId, "What does this document primarily explain?", "Key themes including data indicators, core deliverables, and operational models.", "Medium"))
            }
            isGeneratingFlashcards = false
            Toast.makeText(context, "AI created custom flashcards! Check them out in the Study tab.", Toast.LENGTH_SHORT).show()
        }
    }

    // Main layout
    Column(
        modifier = modifier
            .fillMaxSize()
            .background(LocalDarkBg)
    ) {
        // Module Title bar
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(bottom = 12.dp)
                .background(LocalCardBg, RoundedCornerShape(bottomStart = 16.dp, bottomEnd = 16.dp))
                .padding(14.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.SpaceBetween
        ) {
            Column {
                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                    Box(
                        modifier = Modifier
                            .size(10.dp)
                            .background(LocalNeonCyan, CircleShape)
                            .blur(2.dp)
                    )
                    Text(
                        text = "AI PDF CHAT STUDIO",
                        color = Color.White,
                        fontSize = 14.sp,
                        fontWeight = FontWeight.Black
                    )
                    Box(
                        modifier = Modifier
                            .background(LocalNeonPurple.copy(alpha = 0.2f), RoundedCornerShape(4.dp))
                            .padding(horizontal = 4.dp, vertical = 1f.dp)
                    ) {
                        Text("ACTIVE ENGINES", color = LocalNeonPurple, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                    }
                }
                Text("Real-time Multimodal RAG Chunking, Embeddings & Interactive Study Kits", color = Color.Gray, fontSize = 9.sp)
            }

            // Settings buttons
            Row(horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                IconButton(
                    onClick = {
                        isMultiPdfModeActive = !isMultiPdfModeActive
