                    },
                    modifier = Modifier
                        .size(32.dp)
                        .background(if (isMultiPdfModeActive) LocalNeonPurple.copy(alpha = 0.2f) else Color.White.copy(alpha = 0.04f), CircleShape)
                ) {
                    Icon(
                        imageVector = Icons.Filled.Collections,
                        contentDescription = "Multi-PDF Comparative Core",
                        tint = if (isMultiPdfModeActive) LocalNeonPurple else Color.LightGray,
                        modifier = Modifier.size(15.dp)
                    )
                }
                
                IconButton(
                    onClick = { showUploadModal = true },
                    modifier = Modifier
                        .background(LocalNeonCyan, CircleShape)
                        .size(32.dp)
                ) {
                    Icon(imageVector = Icons.Filled.Add, contentDescription = "Add pdf", tint = PureBlack, modifier = Modifier.size(18.dp))
                }
            }
        }

        // Sub Navigation Tabs: Explorer, Conversation Chat, PDF Visual Viewer, Study Lab, Cloud & Core Admin
        TabRow(
            selectedTabIndex = activeWorkspaceTabIdx,
            containerColor = Color.Transparent,
            contentColor = LocalNeonCyan,
            indicator = { tabPositions ->
                TabRowDefaults.SecondaryIndicator(
                    Modifier.tabIndicatorOffset(tabPositions[activeWorkspaceTabIdx]),
                    color = LocalNeonCyan
                )
            },
            divider = {}
        ) {
            val tabTitles = listOf("EXPLORER", "CHAT CABIN", "PDF READER", "STUDY LAB", "AI CLOUD")
            val tabIcons = listOf(Icons.Filled.FolderOpen, Icons.Filled.Forum, Icons.Filled.MenuBook, Icons.Filled.AutoFixHigh, Icons.Filled.CloudSync)
            
            tabTitles.forEachIndexed { index, title ->
                Tab(
                    selected = activeWorkspaceTabIdx == index,
                    onClick = { activeWorkspaceTabIdx = index },
                    text = { Text(title, fontSize = 9.sp, fontWeight = FontWeight.Bold, maxLines = 1) },
                    icon = { Icon(tabIcons[index], contentDescription = null, modifier = Modifier.size(14.dp)) }
                )
            }
        }

        Spacer(modifier = Modifier.height(8.dp))

        // Document Decryption block
        if (isDocumentViewBlocked) {
            Column(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth()
                    .padding(24.dp)
                    .background(LocalCardBg, RoundedCornerShape(14.dp))
                    .padding(20.dp),
                verticalArrangement = Arrangement.Center,
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Icon(imageVector = Icons.Filled.Lock, contentDescription = "Locked PDF Document", tint = LocalNeonMagenta, modifier = Modifier.size(48.dp))
                Spacer(modifier = Modifier.height(14.dp))
                Text(currentPdf?.fileName ?: "Encrypted PDF file", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 14.sp)
                Text("This document contains industrial-grade 256-bit credentials. Please enter your configured password to index embeddings.", color = Color.Gray, fontSize = 10.sp, textAlign = TextAlign.Center)
                Spacer(modifier = Modifier.height(16.dp))
                
                OutlinedTextField(
                    value = enteredPassword,
                    onValueChange = { enteredPassword = it },
                    label = { Text("Password", fontSize = 10.sp) },
                    singleLine = true,
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = LocalNeonMagenta,
                        unfocusedBorderColor = Color.DarkGray,
                        focusedLabelColor = LocalNeonMagenta
                    ),
                    modifier = Modifier.fillMaxWidth()
                )
                Spacer(modifier = Modifier.height(16.dp))
                
                Button(
                    onClick = {
                        if (enteredPassword == currentPdf?.passwordInput) {
                            isUnlockedByPassword = true
                            Toast.makeText(context, "Access Granted! Loading OCR vector partitions.", Toast.LENGTH_SHORT).show()
                        } else {
                            Toast.makeText(context, "Invalid key credentials. Please check password hint.", Toast.LENGTH_LONG).show()
                        }
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = LocalNeonMagenta),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Text("Decrypt & Synchronize Embeddings Link", color = Color.White)
                }
                
                Text("Hint for simulator: use password 'neon123'", color = Color.DarkGray, fontSize = 9.sp, modifier = Modifier.padding(top = 10.dp))
            }
        } else {
            // Main sub-tabs content routing
            Box(modifier = Modifier.weight(1f)) {
                when (activeWorkspaceTabIdx) {
                    0 -> {
                        // TAB 0: DOCUMENTS EXPLORER & METADATA OVERVIEW
                        LazyColumn(
                            modifier = Modifier.fillMaxSize().padding(horizontal = 14.dp),
                            verticalArrangement = Arrangement.spacedBy(10.dp)
                        ) {
                            item {
                                Text("SELECT CONTEXT DOCUMENT", color = LocalNeonCyan, fontSize = 9.sp, fontWeight = FontWeight.ExtraBold, modifier = Modifier.padding(vertical = 4.dp))
                            }
                            
                            items(initialPdfs) { pdf ->
                                val isActive = pdf.id == selectedPdfId
                                val isSelectedMulti = selectedMultiplePdfIds.contains(pdf.id)
                                val borderStroke = if (isActive) BorderStroke(1.5.dp, LocalNeonCyan) else if (isSelectedMulti && isMultiPdfModeActive) BorderStroke(1.5.dp, LocalNeonPurple) else null
                                
                                Card(
                                    onClick = {
                                        selectedPdfId = pdf.id
                                        isUnlockedByPassword = false // Reset password lock for subsequent decryptions
                                        enteredPassword = ""
                                        if (isMultiPdfModeActive) {
                                            if (selectedMultiplePdfIds.contains(pdf.id)) {
                                                if (selectedMultiplePdfIds.size > 1) {
                                                    selectedMultiplePdfIds.remove(pdf.id)
                                                }
                                            } else {
                                                selectedMultiplePdfIds.add(pdf.id)
                                            }
                                        }
                                    },
                                    colors = CardDefaults.cardColors(containerColor = if (isActive) LocalNeonCyan.copy(alpha = 0.08f) else LocalCardBg),
                                    border = borderStroke,
                                    modifier = Modifier.fillMaxWidth()
                                ) {
                                    Row(
                                        modifier = Modifier.padding(12.dp),
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Icon(
                                            imageVector = if (pdf.isLocked) Icons.Filled.Lock else Icons.Filled.PictureAsPdf,
                                            contentDescription = "PDF File Representation",
                                            tint = if (pdf.isLocked) LocalNeonMagenta else LocalNeonCyan,
                                            modifier = Modifier.size(34.dp)
                                        )
                                        Spacer(modifier = Modifier.width(12.dp))
                                        Column(modifier = Modifier.weight(1f)) {
                                            Text(pdf.fileName, color = Color.White, fontSize = 11.5.sp, fontWeight = FontWeight.Bold, maxLines = 1)
                                            Row(horizontalArrangement = Arrangement.spacedBy(8.dp), verticalAlignment = Alignment.CenterVertically) {
                                                Text("Size: ${pdf.fileSize}", color = Color.Gray, fontSize = 9.sp)
                                                Text("•", color = Color.DarkGray, fontSize = 9.sp)
                                                Text("Pages: ${pdf.totalPages}", color = Color.Gray, fontSize = 9.sp)
                                                if (pdf.isScanned) {
                                                    Text("•", color = Color.DarkGray, fontSize = 9.sp)
                                                    Text("OCR Scanned", color = LocalNeonPurple, fontSize = 8.sp, fontWeight = FontWeight.SemiBold)
                                                }
                                            }
                                        }
                                        
                                        if (isMultiPdfModeActive) {
                                            Checkbox(
                                                checked = isSelectedMulti,
                                                onCheckedChange = { _ ->
                                                    if (selectedMultiplePdfIds.contains(pdf.id)) {
                                                        if (selectedMultiplePdfIds.size > 1) {
                                                            selectedMultiplePdfIds.remove(pdf.id)
                                                        }
                                                    } else {
                                                        selectedMultiplePdfIds.add(pdf.id)
                                                    }
                                                },
                                                colors = CheckboxDefaults.colors(checkedColor = LocalNeonPurple)
                                            )
                                        } else {
                                            RadioButton(
                                                selected = isActive,
                                                onClick = { selectedPdfId = pdf.id },
                                                colors = RadioButtonDefaults.colors(selectedColor = LocalNeonCyan)
                                            )
                                        }
                                    }
                                }
                            }

                            item {
                                Spacer(modifier = Modifier.height(10.dp))
                                Text("VECTOR SCHEMA INDEX CHUNKING STATUS", color = LocalNeonPurple, fontSize = 9.sp, fontWeight = FontWeight.ExtraBold)
                                Spacer(modifier = Modifier.height(4.dp))
                                
                                Card(
                                    colors = CardDefaults.cardColors(containerColor = LocalCardBg),
                                    modifier = Modifier.fillMaxWidth()
                                ) {
                                    Column(modifier = Modifier.padding(12.dp)) {
                                        Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                                            Text("Selected Document:", fontSize = 10.sp, color = Color.LightGray)
                                            Text(currentPdf?.fileName ?: "None", fontSize = 10.sp, color = LocalNeonCyan, fontWeight = FontWeight.Bold)
                                        }
                                        Spacer(modifier = Modifier.height(6.dp))
                                        Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                                            Text("Chunk Overlap Structure:", fontSize = 10.sp, color = Color.LightGray)
                                            Text("150 Characters (Section-Aware Intelligents)", fontSize = 10.sp, color = Color.Gray)
                                        }
                                        Spacer(modifier = Modifier.height(4.dp))
                                        Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                                            Text("Indexing Engine Namespace:", fontSize = 10.sp, color = Color.LightGray)
                                            Text("User-${viewModel.userStats.value?.id ?: "007"}-isolated", fontSize = 10.sp, color = LocalNeonPurple, fontWeight = FontWeight.Bold)
                                        }
                                        Spacer(modifier = Modifier.height(4.dp))
                                        Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                                            Text("Embedding Version Tracking:", fontSize = 10.sp, color = Color.LightGray)
                                            Text("gemini-embedding-2-preview (Auto)", fontSize = 10.sp, color = LocalNeonGreen, fontWeight = FontWeight.SemiBold)
                                        }
                                        Spacer(modifier = Modifier.height(12.dp))
                                        LinearProgressIndicator(
                                            progress = 1.0f,
                                            color = LocalNeonCyan,
                                            trackColor = Color.DarkGray,
                                            modifier = Modifier.fillMaxWidth().height(4.dp)
                                        )
                                        Text("✔ Metadata and structured vector trees compiled fully into memory.", color = Color.Gray, fontSize = 8.5.sp, modifier = Modifier.padding(top = 4.dp))
                                    }
                                }
                            }
                        }
                    }

                    1 -> {
                        // TAB 1: DISCUSSION CONVERSATION CABIN
                        Column(modifier = Modifier.fillMaxSize().padding(horizontal = 14.dp)) {
                            // Selected file status strip
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .background(LocalCardBg, RoundedCornerShape(8.dp))
                                    .padding(8.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(imageVector = Icons.Filled.MenuBook, contentDescription = null, tint = LocalNeonCyan, modifier = Modifier.size(16.dp))
                                    Spacer(modifier = Modifier.width(6.dp))
                                    Text(
                                        text = if (isMultiPdfModeActive) "Comparative Core [${selectedMultiplePdfIds.size} files]" else currentPdf?.fileName ?: "No file chosen",
                                        color = Color.White,
                                        fontSize = 11.sp,
                                        fontWeight = FontWeight.Bold,
                                        maxLines = 1
                                    )
                                }
                                
                                // Direct language choice selector in chat header
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(imageVector = Icons.Filled.Translate, contentDescription = "Translation Selector", tint = LocalNeonPurple, modifier = Modifier.size(14.dp))
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Box {
                                        var showLangDropdown by remember { mutableStateOf(false) }
                                        Text(
                                            text = selectedTranslationTargetLang,
                                            color = LocalNeonPurple,
                                            fontSize = 9.sp,
                                            fontWeight = FontWeight.Bold,
                                            modifier = Modifier.clickable { showLangDropdown = true }
                                        )
                                        DropdownMenu(
                                            expanded = showLangDropdown,
                                            onDismissRequest = { showLangDropdown = false },
                                            containerColor = Color(0xFF0F0F2A)
                                        ) {
                                            translationLanguagesOptions.forEach { lang ->
                                                DropdownMenuItem(
                                                    text = { Text(lang, color = Color.White, fontSize = 11.sp) },
                                                    onClick = {
                                                        selectedTranslationTargetLang = lang
                                                        showLangDropdown = false
                                                        Toast.makeText(context, "AI answers target updated: $lang", Toast.LENGTH_SHORT).show()
                                                    }
                                                )
                                            }
                                        }
                                    }
                                }
                            }

                            // Message stream list
                            val currentMessageList = remember(selectedPdfId, chatMessagesMap[selectedPdfId]) {
                                chatMessagesMap[selectedPdfId] ?: emptyList()
                            }
                            
                            LazyColumn(
                                modifier = Modifier
                                    .weight(1f)
                                    .fillMaxWidth()
                                    .padding(vertical = 10.dp),
                                verticalArrangement = Arrangement.spacedBy(10.dp)
                            ) {
                                items(currentMessageList) { msg ->
                                    val isUser = msg.sender == "user"
                                    Column(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalAlignment = if (isUser) Alignment.End else Alignment.Start
                                    ) {
                                        Row(
                                            verticalAlignment = Alignment.Top,
                                            horizontalArrangement = if (isUser) Arrangement.End else Arrangement.Start,
                                            modifier = Modifier.fillMaxWidth(0.9f)
                                        ) {
                                            if (!isUser) {
                                                Box(
                                                    modifier = Modifier
                                                        .size(26.dp)
                                                        .background(LocalNeonCyan.copy(alpha = 0.2f), CircleShape),
                                                    contentAlignment = Alignment.Center
                                                ) {
                                                    Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = "AI", tint = LocalNeonCyan, modifier = Modifier.size(14.dp))
                                                }
                                                Spacer(modifier = Modifier.width(8.dp))
                                            }

                                            Card(
                                                colors = CardDefaults.cardColors(
                                                    containerColor = if (isUser) LocalNeonCyan.copy(alpha = 0.15f) else LocalCardBg
                                                ),
                                                border = if (isUser) BorderStroke(0.5.dp, LocalNeonCyan.copy(alpha = 0.4f)) else null,
                                                modifier = Modifier.weight(1f, fill = false)
                                            ) {
                                                Column(modifier = Modifier.padding(10.dp)) {
                                                    Text(msg.text, color = Color.White, fontSize = 11.5.sp)
                                                    
                                                    // Display citations tags if present
                                                    if (msg.sourcePages.isNotEmpty() && !isUser) {
                                                        Spacer(modifier = Modifier.height(6.dp))
                                                        FlowRow(
                                                            horizontalArrangement = Arrangement.spacedBy(6.dp),
                                                            verticalArrangement = Arrangement.spacedBy(4.dp)
                                                        ) {
                                                            msg.sourcePages.forEach { pageNum ->
                                                                Row(
                                                                    modifier = Modifier
                                                                        .background(LocalNeonPurple.copy(alpha = 0.15f), RoundedCornerShape(4.dp))
                                                                        .border(0.5.dp, LocalNeonPurple.copy(alpha = 0.4f), RoundedCornerShape(4.dp))
                                                                        .clickable {
                                                                            pdfViewerActivePageIdx = pageNum - 1
                                                                            activeWorkspaceTabIdx = 2 // Jump to PDF Viewer
                                                                            Toast.makeText(context, "Jumping to Page $pageNum in Viewer!", Toast.LENGTH_SHORT).show()
                                                                        }
                                                                        .padding(horizontal = 6.dp, vertical = 2.dp),
                                                                    verticalAlignment = Alignment.CenterVertically
                                                                ) {
                                                                    Icon(imageVector = Icons.Filled.Bookmark, contentDescription = null, tint = LocalNeonPurple, modifier = Modifier.size(8.dp))
                                                                    Spacer(modifier = Modifier.width(3.dp))
                                                                    Text("Page $pageNum Reference", color = LocalNeonPurple, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                                                                }
                                                            }
                                                        }
                                                    }
                                                }
                                            }

                                            if (isUser) {
                                                Spacer(modifier = Modifier.width(8.dp))
                                                Box(
                                                    modifier = Modifier
                                                        .size(26.dp)
                                                        .background(LocalNeonPurple.copy(alpha = 0.2f), CircleShape),
                                                    contentAlignment = Alignment.Center
                                                ) {
                                                    Icon(imageVector = Icons.Filled.Person, contentDescription = "User", tint = LocalNeonPurple, modifier = Modifier.size(14.dp))
                                                }
                                            }
                                        }

                                        // Text To Speech action row for answers
                                        if (!isUser) {
                                            val isPlayingTtsActive = isTtsAudioPlaying && activeTtsPlayingMessageId == msg.id
                                            Row(
                                                modifier = Modifier.padding(horizontal = 34.dp, vertical = 2.dp),
                                                horizontalArrangement = Arrangement.spacedBy(10.dp),
                                                verticalAlignment = Alignment.CenterVertically
                                            ) {
                                                IconButton(
                                                    onClick = {
                                                        if (isPlayingTtsActive) {
                                                            isTtsAudioPlaying = false
                                                        } else {
                                                            activeTtsPlayingMessageId = msg.id
                                                            ttsPlaybackProgressSim = 0f
                                                            isTtsAudioPlaying = true
                                                            Toast.makeText(context, "Speaking answer with $selectedSpeechProfile...", Toast.LENGTH_SHORT).show()
                                                        }
                                                    },
                                                    modifier = Modifier.size(22.dp)
                                                ) {
                                                    Icon(
                                                        imageVector = if (isPlayingTtsActive) Icons.Filled.PauseCircle else Icons.Filled.VolumeUp,
                                                        contentDescription = "Text To Speech Speak",
                                                        tint = if (isPlayingTtsActive) LocalNeonMagenta else Color.Gray,
                                                        modifier = Modifier.size(14.dp)
                                                    )
                                                }
                                                
                                                if (isPlayingTtsActive) {
                                                    LinearProgressIndicator(
                                                        progress = ttsPlaybackProgressSim,
                                                        color = LocalNeonMagenta,
                                                        trackColor = Color.DarkGray,
                                                        modifier = Modifier.width(80.dp).height(2.dp).clip(CircleShape)
                                                    )
                                                    Text("Synthesizer Active Voice", color = LocalNeonMagenta, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                                                }
                                            }
                                        }
                                    }
                                }

                                if (isWaitingForAiAnswer) {
                                    item {
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                                            modifier = Modifier.padding(10.dp)
                                        ) {
                                            CircularProgressIndicator(color = LocalNeonCyan, modifier = Modifier.size(16.dp))
                                            Text("Gemini is searching vectorized index tree, compiling page references & reasoning response...", color = Color.Gray, fontSize = 9.5.sp)
                                        }
                                    }
                                }
                            }

                            // Quick sample questions options
                            val sampleQuestionsList = listOf(
                                "Summarize this document in 2 sentences.",
                                "What are the core concluding risks?",
                                "Explain page 1 operations.",
                                "Compare contents."
                            )
                            
                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(6.dp),
                                modifier = Modifier.padding(vertical = 4.dp)
                            ) {
                                items(sampleQuestionsList) { sample ->
                                    Box(
                                        modifier = Modifier
                                            .background(Color.White.copy(alpha = 0.03f), RoundedCornerShape(12.dp))
                                            .border(0.5.dp, Color.DarkGray, RoundedCornerShape(12.dp))
                                            .clickable { triggerChatSubmission(sample) }
                                            .padding(horizontal = 10.dp, vertical = 6.dp)
                                    ) {
                                        Text(sample, color = Color.LightGray, fontSize = 9.5.sp)
                                    }
                                }
                            }

                            // Send panel
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(vertical = 8.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                OutlinedTextField(
                                    value = currentChatInputText,
                                    onValueChange = { currentChatInputText = it },
                                    placeholder = { Text("Pose a question to document page indexes...", fontSize = 11.sp, color = Color.Gray) },
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = LocalNeonCyan,
                                        unfocusedBorderColor = Color.DarkGray
                                    ),
                                    shape = RoundedCornerShape(12.dp),
                                    modifier = Modifier.weight(1f),
                                    maxLines = 3,
                                    keyboardOptions = KeyboardOptions(imeAction = androidx.compose.ui.text.input.ImeAction.Send),
                                    keyboardActions = KeyboardActions(onSend = { 
                                        triggerChatSubmission(currentChatInputText)
                                    })
                                )

                                IconButton(
                                    onClick = { triggerChatSubmission(currentChatInputText) },
                                    modifier = Modifier
                                        .background(LocalNeonCyan, RoundedCornerShape(12.dp))
                                        .size(44.dp)
                                ) {
                                    Icon(imageVector = Icons.Filled.Send, contentDescription = "Query", tint = PureBlack, modifier = Modifier.size(18.dp))
                                }
                            }
                        }
                    }

                    2 -> {
                        // TAB 2: PDF RENDERER VIEWER
                        Column(modifier = Modifier.fillMaxSize().padding(horizontal = 14.dp)) {
                            // Toolbar controls
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .background(LocalCardBg, RoundedCornerShape(8.dp))
                                    .padding(8.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) {
                                    Text("Page:", color = Color.Gray, fontSize = 10.sp)
                                    Text("${pdfViewerActivePageIdx + 1} of ${currentPdf?.totalPages ?: 1}", color = Color.White, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                    
                                    IconButton(
                                        onClick = { if (pdfViewerActivePageIdx > 0) pdfViewerActivePageIdx-- },
                                        enabled = pdfViewerActivePageIdx > 0,
                                        modifier = Modifier.size(24.dp)
                                    ) {
                                        Icon(imageVector = Icons.Filled.ChevronLeft, contentDescription = "Back Page", tint = Color.LightGray)
                                    }
                                    IconButton(
                                        onClick = { if (pdfViewerActivePageIdx < (currentPdf?.pages?.size ?: 1) - 1) pdfViewerActivePageIdx++ },
                                        enabled = pdfViewerActivePageIdx < (currentPdf?.pages?.size ?: 1) - 1,
                                        modifier = Modifier.size(24.dp)
                                    ) {
                                        Icon(imageVector = Icons.Filled.ChevronRight, contentDescription = "Next Page", tint = Color.LightGray)
                                    }
                                }

                                Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                                    IconButton(
                                        onClick = { if (pdfViewerZoomPct > 50) pdfViewerZoomPct -= 25 },
                                        modifier = Modifier.size(24.dp)
                                    ) {
                                        Icon(imageVector = Icons.Filled.Remove, contentDescription = "Zoom out", tint = Color.LightGray)
                                    }
                                    Text("$pdfViewerZoomPct%", color = Color.White, fontSize = 10.sp, fontWeight = FontWeight.Black)
                                    IconButton(
                                        onClick = { if (pdfViewerZoomPct < 200) pdfViewerZoomPct += 25 },
                                        modifier = Modifier.size(24.dp)
                                    ) {
                                        Icon(imageVector = Icons.Filled.ZoomIn, contentDescription = "Zoom in", tint = Color.LightGray)
                                    }
                                    
                                    val isPageBookmarked = bookmarkedPages.contains(Pair(selectedPdfId, pdfViewerActivePageIdx))
                                    IconButton(
                                        onClick = {
                                            val key = Pair(selectedPdfId, pdfViewerActivePageIdx)
                                            if (isPageBookmarked) {
                                                bookmarkedPages.remove(key)
                                                Toast.makeText(context, "Bookmark removed", Toast.LENGTH_SHORT).show()
                                            } else {
                                                bookmarkedPages.add(key)
                                                Toast.makeText(context, "Page ${pdfViewerActivePageIdx + 1} Bookmarked!", Toast.LENGTH_SHORT).show()
                                            }
                                        },
                                        modifier = Modifier.size(24.dp)
                                    ) {
                                        Icon(
                                            imageVector = if (isPageBookmarked) Icons.Filled.Bookmark else Icons.Outlined.BookmarkBorder,
                                            contentDescription = "Bookmark",
                                            tint = if (isPageBookmarked) LocalNeonCyan else Color.LightGray
                                        )
                                    }
                                }
                            }

                            // Search bar in reader
                            OutlinedTextField(
                                value = pdfSearchQueryText,
                                onValueChange = { pdfSearchQueryText = it },
                                placeholder = { Text("Highlight text search key inside PDF viewer...", fontSize = 10.sp, color = Color.Gray) },
                                colors = OutlinedTextFieldDefaults.colors(
                                    focusedBorderColor = LocalNeonCyan,
                                    unfocusedBorderColor = Color.DarkGray
                                ),
                                shape = RoundedCornerShape(6.dp),
                                modifier = Modifier.fillMaxWidth().height(42.dp).padding(vertical = 2.dp),
                                singleLine = true,
                                trailingIcon = {
                                    if (pdfSearchQueryText.isNotEmpty()) {
                                        IconButton(onClick = { pdfSearchQueryText = "" }) {
                                            Icon(imageVector = Icons.Filled.Close, contentDescription = "Clear", tint = Color.Gray, modifier = Modifier.size(14.dp))
                                        }
                                    }
                                }
                            )

                            // Page render container simulating active page zoom & highlighting
                            val pageRawText = currentPdf?.pages?.getOrNull(pdfViewerActivePageIdx) ?: "End of Document text contents reached."
                            Box(
                                modifier = Modifier
                                    .weight(1f)
                                    .fillMaxWidth()
                                    .padding(vertical = 10.dp)
                                    .background(Color.White, RoundedCornerShape(12.dp))
                                    .border(2.dp, LocalNeonCyan.copy(alpha = 0.5f), RoundedCornerShape(12.dp))
                                    .verticalScroll(rememberScrollState())
                                    .padding(16.dp)
                            ) {
                                val textScale = pdfViewerZoomPct / 100f
                                Column(
                                    modifier = Modifier.graphicsLayer(scaleX = textScale, scaleY = textScale)
                                ) {
                                    Row(
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        modifier = Modifier.fillMaxWidth()
                                    ) {
                                        Text(currentPdf?.fileName?.uppercase() ?: "DOCUMENT", fontSize = 8.sp, color = Color.Gray, fontWeight = FontWeight.Black)
                                        Text("PAGE ${pdfViewerActivePageIdx + 1}", fontSize = 8.sp, color = LocalNeonPurple, fontWeight = FontWeight.Bold)
                                    }
                                    Spacer(modifier = Modifier.height(14.dp))
                                    
                                    // Handle custom highlight searches!
                                    val formattedText = buildAnnotatedString {
                                        if (pdfSearchQueryText.isNotEmpty() && pageRawText.contains(pdfSearchQueryText, ignoreCase = true)) {
                                            var currentIndex = 0
                                            while (currentIndex < pageRawText.length) {
                                                val foundIdx = pageRawText.indexOf(pdfSearchQueryText, currentIndex, ignoreCase = true)
                                                if (foundIdx == -1) {
                                                    append(pageRawText.substring(currentIndex))
                                                    break
                                                } else {
                                                    append(pageRawText.substring(currentIndex, foundIdx))
                                                    withStyle(style = SpanStyle(background = Color.Yellow, color = PureBlack, fontWeight = FontWeight.Bold)) {
                                                        append(pageRawText.substring(foundIdx, foundIdx + pdfSearchQueryText.length))
                                                    }
                                                    currentIndex = foundIdx + pdfSearchQueryText.length
                                                }
                                            }
                                        } else {
                                            append(pageRawText)
                                        }
                                    }
                                    
                                    Text(
                                        text = formattedText,
                                        color = Color.DarkGray,
                                        fontSize = 13.sp,
                                        lineHeight = 20.sp,
                                        fontFamily = androidx.compose.ui.text.font.FontFamily.SansSerif
                                    )
                                }
                            }

                            // Flat Page thumbnails list for rapid jumping click
                            LazyRow(
                                horizontalArrangement = Arrangement.spacedBy(8.dp),
                                modifier = Modifier.padding(bottom = 8.dp)
                            ) {
                                itemsIndexed(currentPdf?.pages ?: emptyList()) { idx, text ->
                                    val isCurrentPageNode = idx == pdfViewerActivePageIdx
                                    Box(
                                        modifier = Modifier
                                            .size(width = 64.dp, height = 48.dp)
                                            .clip(RoundedCornerShape(6.dp))
                                            .background(if (isCurrentPageNode) LocalNeonCyan.copy(alpha = 0.2f) else LocalCardBg)
                                            .border(1.dp, if (isCurrentPageNode) LocalNeonCyan else Color.DarkGray, RoundedCornerShape(6.dp))
                                            .clickable { pdfViewerActivePageIdx = idx }
                                            .padding(4.dp),
                                        contentAlignment = Alignment.Center
                                    ) {
                                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                            Text("Page ${idx + 1}", color = Color.White, fontSize = 7.5.sp, fontWeight = FontWeight.Bold)
                                            Text("${text.take(15)}...", color = Color.Gray, fontSize = 6.sp, overflow = TextOverflow.Ellipsis)
                                        }
                                    }
                                }
                            }
                        }
                    }

                    3 -> {
                        // TAB 3: AI STUDY LAB - NOTES, FLASHCARDS, QUIZZES, CONCEPT MIND MAP
                        Column(modifier = Modifier.fillMaxSize().padding(horizontal = 14.dp)) {
                            var activeStudyHubSubTabIdx by remember { mutableStateOf(0) } // 0: Summaries, 1: Revision Notes, 2: Study Flashcards, 3: Quiz Prep, 4: Mind Map
                            
                            ScrollableTabRow(
                                selectedTabIndex = activeStudyHubSubTabIdx,
                                containerColor = Color.Transparent,
                                contentColor = LocalNeonCyan,
                                edgePadding = 0.dp,
                                divider = {}
                            ) {
                                val labelList = listOf("AI SUMMARIZER", "STUDY NOTES", "FLASHCARDS", "QUIZ LAB", "CONCEPT MAP")
                                labelList.forEachIndexed { sidx, text ->
                                    Tab(
                                        selected = activeStudyHubSubTabIdx == sidx,
                                        onClick = { activeStudyHubSubTabIdx = sidx },
                                        text = { Text(text, fontSize = 8.5.sp, fontWeight = FontWeight.Black) }
                                    )
                                }
                            }

                            Spacer(modifier = Modifier.height(10.dp))

                            when (activeStudyHubSubTabIdx) {
                                0 -> {
                                    // SUB TAB 0: DETAILED SUMMARIZER ARCHITECTURE
                                    Column(
                                        modifier = Modifier.fillMaxSize().verticalScroll(rememberScrollState()),
                                        verticalArrangement = Arrangement.spacedBy(10.dp)
                                    ) {
                                        Row(
                                            horizontalArrangement = Arrangement.spacedBy(6.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            val summaryTypes = listOf("Executive Summary", "Short Summary", "Detailed Summary", "Key Findings")
                                            summaryTypes.forEach { type ->
                                                val isSelected = type == dynamicDocSummaryType
                                                Box(
                                                    modifier = Modifier
                                                        .background(if (isSelected) LocalNeonCyan else Color.DarkGray.copy(alpha = 0.3f), RoundedCornerShape(12.dp))
                                                        .clickable { dynamicDocSummaryType = type }
                                                        .padding(horizontal = 10.dp, vertical = 6.dp)
                                                ) {
                                                    Text(type, color = if (isSelected) PureBlack else Color.White, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                                }
                                            }
                                        }

                                        Button(
                                            onClick = { triggerSummaryGeneration(dynamicDocSummaryType) },
                                            colors = ButtonDefaults.buttonColors(containerColor = LocalNeonCyan),
                                            modifier = Modifier.fillMaxWidth(),
                                            enabled = !isGeneratingSummary
                                        ) {
                                            if (isGeneratingSummary) {
                                                CircularProgressIndicator(color = PureBlack, modifier = Modifier.size(16.dp))
                                                Spacer(modifier = Modifier.width(6.dp))
                                                Text("Synthesizing Summary context with Gemini...", color = PureBlack, fontSize = 11.sp)
                                            } else {
                                                Icon(imageVector = Icons.Filled.AutoAwesome, contentDescription = null, tint = PureBlack, modifier = Modifier.size(14.dp))
                                                Spacer(modifier = Modifier.width(6.dp))
                                                Text("GENERATE $dynamicDocSummaryType" .uppercase(), color = PureBlack, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                                            }
                                        }

                                        if (generatedSummaryText.isNotEmpty()) {
                                            Text("GENERATED RESULT", fontSize = 9.sp, color = LocalNeonCyan, fontWeight = FontWeight.Black)
                                            
                                            Box(
                                                modifier = Modifier
                                                    .fillMaxWidth()
                                                    .background(LocalCardBg, RoundedCornerShape(12.dp))
                                                    .padding(14.dp)
                                            ) {
                                                SelectionContainer {
                                                    Text(
                                                        generatedSummaryText,
                                                        color = Color.White,
                                                        fontSize = 11.5.sp,
                                                        lineHeight = 17.sp
                                                    )
                                                }
                                            }
                                            
                                            // Action row to copy or save
                                            Row(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                                                TextButton(
                                                    onClick = {
                                                        val clipboard = context.getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                                        clipboard.setPrimaryClip(android.content.ClipData.newPlainText("PDF Summary", generatedSummaryText))
                                                        Toast.makeText(context, "Copied summary to clipboard!", Toast.LENGTH_SHORT).show()
                                                    }
                                                ) {
                                                    Icon(imageVector = Icons.Filled.ContentCopy, contentDescription = null, tint = LocalNeonPurple, modifier = Modifier.size(14.dp))
                                                    Spacer(modifier = Modifier.width(4.dp))
                                                    Text("Copy text", color = LocalNeonPurple, fontSize = 10.sp)
                                                }
                                                
                                                TextButton(
                                                    onClick = {
                                                        savedPdfNotesList.add(
                                                            PDFStudyNote(
                                                                id = "note_summary_${System.currentTimeMillis()}",
                                                                pdfId = selectedPdfId,
                                                                title = "$dynamicDocSummaryType Notes",
                                                                content = generatedSummaryText
                                                            )
                                                        )
                                                        Toast.makeText(context, "Saved summary into Study Notes tab!", Toast.LENGTH_SHORT).show()
                                                    }
                                                ) {
                                                    Icon(imageVector = Icons.Filled.Save, contentDescription = null, tint = LocalNeonGreen, modifier = Modifier.size(14.dp))
                                                    Spacer(modifier = Modifier.width(4.dp))
                                                    Text("Export to Notes", color = LocalNeonGreen, fontSize = 10.sp)
                                                }
                                            }
                                        } else {
                                            Box(
                                                modifier = Modifier
                                                    .fillMaxWidth()
                                                    .height(100.dp)
                                                    .background(LocalCardBg, RoundedCornerShape(12.dp)),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text("Empty. Generate custom dynamic summary metrics.", color = Color.Gray, fontSize = 10.sp)
                                            }
                                        }
                                    }
                                }

                                1 -> {
                                    // SUB TAB 1: STUDY & MEETING NOTES REVISION PANELS
                                    Column(
                                        modifier = Modifier.fillMaxSize().verticalScroll(rememberScrollState()),
                                        verticalArrangement = Arrangement.spacedBy(10.dp)
                                    ) {
                                        val activePdfNotes = savedPdfNotesList.filter { it.pdfId == selectedPdfId }
                                        
                                        Row(
                                            horizontalArrangement = Arrangement.SpaceBetween,
                                            verticalAlignment = Alignment.CenterVertically,
                                            modifier = Modifier.fillMaxWidth()
                                        ) {
                                            Text("SAVED REVISION NOTES (${activePdfNotes.size})", color = Color.Gray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                            
                                            Button(
                                                onClick = { triggerNotesGeneration() },
                                                colors = ButtonDefaults.buttonColors(containerColor = LocalNeonPurple),
                                                enabled = !isGeneratingNotesNow,
                                                modifier = Modifier.height(28.dp),
                                                contentPadding = PaddingValues(horizontal = 8.dp, vertical = 2.dp)
                                            ) {
                                                if (isGeneratingNotesNow) {
                                                    CircularProgressIndicator(color = Color.White, modifier = Modifier.size(12.dp))
                                                } else {
                                                    Icon(imageVector = Icons.Filled.AutoFixNormal, contentDescription = null, tint = Color.White, modifier = Modifier.size(12.dp))
                                                    Spacer(modifier = Modifier.width(4.dp))
                                                    Text("Auto Notes with AI", color = Color.White, fontSize = 8.5.sp)
                                                }
                                            }
                                        }

                                        // Draft new generating buffer layout
                                        if (newlyGeneratedNotesDraftContent.isNotEmpty()) {
                                            Card(
                                                colors = CardDefaults.cardColors(containerColor = LocalNeonPurple.copy(alpha = 0.08f)),
                                                border = BorderStroke(1.dp, LocalNeonPurple),
                                                modifier = Modifier.fillMaxWidth()
                                            ) {
                                                Column(modifier = Modifier.padding(12.dp)) {
                                                    Text("CURRENT REVISION NOTES DRAFT GENERATED", color = LocalNeonPurple, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                                    
                                                    Spacer(modifier = Modifier.height(6.dp))
                                                    OutlinedTextField(
                                                        value = newlyGeneratedNotesDraftTitle,
                                                        onValueChange = { newlyGeneratedNotesDraftTitle = it },
                                                        label = { Text("Notes Document Title", fontSize = 9.sp) },
                                                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                                                        modifier = Modifier.fillMaxWidth()
                                                    )
                                                    Spacer(modifier = Modifier.height(6.dp))
                                                    OutlinedTextField(
                                                        value = newlyGeneratedNotesDraftContent,
                                                        onValueChange = { newlyGeneratedNotesDraftContent = it },
                                                        label = { Text("Content Notes Editor", fontSize = 9.sp) },
                                                        textStyle = androidx.compose.ui.text.TextStyle(color = Color.White, fontSize = 11.sp),
                                                        modifier = Modifier.fillMaxWidth().heightIn(min = 120.dp, max = 200.dp)
                                                    )
                                                    Spacer(modifier = Modifier.height(8.dp))
                                                    Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                                        Button(
                                                            onClick = {
                                                                savedPdfNotesList.add(
                                                                    PDFStudyNote(
                                                                        id = "note_custom_${System.currentTimeMillis()}",
                                                                        pdfId = selectedPdfId,
                                                                        title = newlyGeneratedNotesDraftTitle,
                                                                        content = newlyGeneratedNotesDraftContent
                                                                    )
                                                                )
                                                                newlyGeneratedNotesDraftContent = ""
                                                                newlyGeneratedNotesDraftTitle = ""
                                                                Toast.makeText(context, "Notes Saved Successfully!", Toast.LENGTH_SHORT).show()
                                                            },
                                                            colors = ButtonDefaults.buttonColors(containerColor = LocalNeonGreen)
                                                        ) {
                                                            Text("Save Note File", color = Color.White, fontSize = 10.sp)
                                                        }
                                                        TextButton(onClick = { newlyGeneratedNotesDraftContent = "" }) {
                                                            Text("Discard", color = Color.Gray, fontSize = 10.sp)
                                                        }
                                                    }
                                                }
                                            }
                                        }

                                        if (activePdfNotes.isEmpty()) {
                                            Box(
                                                modifier = Modifier
                                                    .fillMaxWidth()
                                                    .height(100.dp)
                                                    .background(LocalCardBg, RoundedCornerShape(12.dp)),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text("None compiled yet. Press 'Auto Notes with AI' to trigger analysis.", color = Color.Gray, fontSize = 9.5.sp)
                                            }
                                        } else {
                                            activePdfNotes.forEach { note ->
                                                Card(
                                                    colors = CardDefaults.cardColors(containerColor = LocalCardBg),
                                                    modifier = Modifier.fillMaxWidth()
                                                ) {
                                                    Column(modifier = Modifier.padding(12.dp)) {
                                                        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                                                            Text(note.title, color = LocalNeonCyan, fontSize = 12.sp, fontWeight = FontWeight.Bold)
                                                            Text(note.createdDate, color = Color.Gray, fontSize = 9.sp)
                                                        }
                                                        
                                                        HorizontalDivider(modifier = Modifier.padding(vertical = 6.dp), color = Color.DarkGray)
                                                        Text(note.content, color = Color.LightGray, fontSize = 11.sp, lineHeight = 16.sp)
                                                        
                                                        Row(
                                                            horizontalArrangement = Arrangement.End,
                                                            modifier = Modifier.fillMaxWidth()
                                                        ) {
                                                            IconButton(
                                                                onClick = {
                                                                    savedPdfNotesList.remove(note)
                                                                    Toast.makeText(context, "Note removed", Toast.LENGTH_SHORT).show()
                                                                },
                                                                modifier = Modifier.size(28.dp)
                                                            ) {
                                                                Icon(imageVector = Icons.Filled.Delete, contentDescription = "Delete", tint = LocalNeonMagenta, modifier = Modifier.size(14.dp))
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }

                                2 -> {
                                    // SUB TAB 2: SPACED-REPETITION FLASHCARDS WITH FLIP LAYOUT
                                    val filteredFlashcards = savedFlashcardsStore.filter { it.pdfId == selectedPdfId }
                                    
                                    Column(
                                        modifier = Modifier.fillMaxSize().verticalScroll(rememberScrollState()),
                                        verticalArrangement = Arrangement.spacedBy(10.dp),
                                        horizontalAlignment = Alignment.CenterHorizontally
                                    ) {
                                        Row(
                                            horizontalArrangement = Arrangement.SpaceBetween,
                                            verticalAlignment = Alignment.CenterVertically,
                                            modifier = Modifier.fillMaxWidth()
                                        ) {
                                            Text("FLIP STUDY FLASHCARDS (${filteredFlashcards.size} available)", color = Color.Gray, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                            
                                            Button(
                                                onClick = { triggerFlashcardGeneration() },
                                                colors = ButtonDefaults.buttonColors(containerColor = LocalNeonCyan),
                                                enabled = !isGeneratingFlashcards,
                                                modifier = Modifier.height(28.dp),
                                                contentPadding = PaddingValues(horizontal = 8.dp)
                                            ) {
                                                if (isGeneratingFlashcards) {
                                                    CircularProgressIndicator(color = PureBlack, modifier = Modifier.size(12.dp))
                                                } else {
                                                    Text("Generate by AI", color = PureBlack, fontSize = 9.sp, fontWeight = FontWeight.Bold)
                                                }
                                            }
                                        }

                                        if (filteredFlashcards.isNotEmpty()) {
                                            val safeIndex = currentFlashcardIdx.coerceIn(0, filteredFlashcards.size - 1)
                                            val activeCard = filteredFlashcards[safeIndex]
                                            
                                            // Interactive Flip Card!
                                            Box(
                                                modifier = Modifier
                                                    .fillMaxWidth()
                                                    .height(180.dp)
                                                    .clip(RoundedCornerShape(16.dp))
                                                    .background(if (isFlashcardFlipped) LocalNeonPurple.copy(alpha = 0.12f) else LocalNeonCyan.copy(alpha = 0.12f))
                                                    .border(2.dp, if (isFlashcardFlipped) LocalNeonPurple else LocalNeonCyan, RoundedCornerShape(16.dp))
                                                    .clickable { isFlashcardFlipped = !isFlashcardFlipped }
                                                    .padding(16.dp),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                                    Box(
                                                        modifier = Modifier
                                                            .background(if (isFlashcardFlipped) LocalNeonPurple else LocalNeonCyan, RoundedCornerShape(4.dp))
                                                            .padding(horizontal = 6.dp, vertical = 2.dp)
                                                    ) {
                                                        Text(
                                                            text = if (isFlashcardFlipped) "ANSWER CORE" else "QUESTION",
                                                            color = PureBlack,
                                                            fontSize = 8.sp,
                                                            fontWeight = FontWeight.Black
                                                        )
                                                    }
                                                    
                                                    Spacer(modifier = Modifier.height(12.dp))
                                                    Text(
                                                        text = if (isFlashcardFlipped) activeCard.answer else activeCard.question,
                                                        color = Color.White,
                                                        fontSize = 12.5.sp,
                                                        fontWeight = FontWeight.Bold,
                                                        textAlign = TextAlign.Center,
                                                        lineHeight = 18.sp
                                                    )
                                                    Spacer(modifier = Modifier.height(14.dp))
                                                    Text("Click anywhere to flip details and reveal", color = Color.Gray, fontSize = 8.sp)
                                                }
                                            }

                                            // Navigator
                                            Row(
                                                modifier = Modifier.fillMaxWidth(),
                                                horizontalArrangement = Arrangement.SpaceBetween,
                                                verticalAlignment = Alignment.CenterVertically
                                            ) {
                                                IconButton(
                                                    onClick = {
                                                        isFlashcardFlipped = false
                                                        if (currentFlashcardIdx > 0) currentFlashcardIdx--
                                                    },
                                                    enabled = safeIndex > 0
                                                ) {
                                                    Icon(imageVector = Icons.Filled.ArrowBack, contentDescription = "Prev", tint = Color.LightGray)
                                                }
                                                
                                                Text("Card ${safeIndex + 1} of ${filteredFlashcards.size}", color = Color.White, fontSize = 11.sp)
                                                
                                                IconButton(
                                                    onClick = {
                                                        isFlashcardFlipped = false
                                                        if (currentFlashcardIdx < filteredFlashcards.size - 1) currentFlashcardIdx++
                                                    },
                                                    enabled = safeIndex < filteredFlashcards.size - 1
                                                ) {
                                                    Icon(imageVector = Icons.Filled.ArrowForward, contentDescription = "Next", tint = Color.LightGray)
                                                }
                                            }

                                            // Spaced Repetition feedback rating!
                                            if (isFlashcardFlipped) {
                                                Text("Rate Difficulty (Active Leitner Spaced-Repetitions):", color = Color.Gray, fontSize = 9.sp)
                                                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                                                    listOf("Hard", "Medium", "Easy").forEach { level ->
                                                        val isSelected = activeCard.difficulty == level
                                                        val cValue = when(level) {
                                                            "Easy" -> LocalNeonGreen
                                                            "Medium" -> LocalNeonCyan
                                                            else -> LocalNeonMagenta
                                                        }
                                                        
                                                        Button(
                                                            onClick = {
                                                                activeCard.difficulty = level
                                                                Toast.makeText(context, "$level recorded! Automatically rescheduling study loops.", Toast.LENGTH_SHORT).show()
                                                            },
                                                            colors = ButtonDefaults.buttonColors(
                                                                containerColor = if (isSelected) cValue else Color.DarkGray.copy(alpha = 0.4f)
                                                            ),
                                                            modifier = Modifier.height(28.dp),
                                                            contentPadding = PaddingValues(horizontal = 10.dp)
                                                        ) {
                                                            Text(level, color = Color.White, fontSize = 9.sp)
                                                        }
                                                    }
                                                }
                                            }
                                        } else {
                                            Box(
                                                modifier = Modifier
                                                    .fillMaxWidth()
                                                    .height(120.dp)
                                                    .background(LocalCardBg, RoundedCornerShape(12.dp)),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text("No flashcards found. Create standard cards using AI.", color = Color.Gray, fontSize = 9.5.sp)
                                            }
                                        }
                                    }
                                }

                                3 -> {
                                    // SUB TAB 3: MCQ PREP QUIZ LABS & LIVE SCORE BOARD
                                    Column(
                                        modifier = Modifier.fillMaxSize().verticalScroll(rememberScrollState()),
                                        verticalArrangement = Arrangement.spacedBy(10.dp)
                                    ) {
                                        if (targetFilteredQuizList.isNotEmpty() && !hasFinishedQuizSequence) {
                                            val safeQuizIdx = activeQuizQuestionIdx.coerceIn(0, targetFilteredQuizList.size - 1)
                                            val quizItem = targetFilteredQuizList[safeQuizIdx]
                                            
                                            // Progress bar
                                            Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) {
                                                Text("Question ${safeQuizIdx + 1} of ${targetFilteredQuizList.size}", color = Color.LightGray, fontSize = 10.sp)
                                                Text("Score: $totalCorrectQuizScore / ${targetFilteredQuizList.size}", color = LocalNeonGreen, fontSize = 10.sp, fontWeight = FontWeight.Black)
                                            }
                                            
                                            LinearProgressIndicator(
                                                progress = (safeQuizIdx + 1) / targetFilteredQuizList.size.toFloat(),
                                                color = LocalNeonCyan,
                                                trackColor = Color.DarkGray,
                                                modifier = Modifier.fillMaxWidth().height(4.dp).clip(CircleShape)
                                            )

                                            Card(
                                                colors = CardDefaults.cardColors(containerColor = LocalCardBg),
                                                modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp)
                                            ) {
                                                Column(modifier = Modifier.padding(14.dp)) {
                                                    Text(quizItem.question, color = Color.White, fontSize = 13.sp, fontWeight = FontWeight.Bold, lineHeight = 19.sp)
                                                    
                                                    Spacer(modifier = Modifier.height(14.dp))
                                                    
                                                    // Display answer options in vertical list
                                                    quizItem.options.forEachIndexed { oidx, optText ->
                                                        val isSelected = selectedQuizAnswerOptionIdx == oidx
                                                        val isCorrect = oidx == quizItem.correctIndex
                                                        val optionBg = if (hasSubmittedQuizAnswer) {
                                                            if (isCorrect) LocalNeonGreen.copy(alpha = 0.2f)
                                                            else if (isSelected) LocalNeonMagenta.copy(alpha = 0.2f)
                                                            else Color.DarkGray.copy(alpha = 0.05f)
                                                        } else {
                                                            if (isSelected) LocalNeonCyan.copy(alpha = 0.15f)
                                                            else Color.DarkGray.copy(alpha = 0.02f)
                                                        }
                                                        
                                                        val optionBorder = if (isSelected) {
                                                            BorderStroke(1.dp, if (hasSubmittedQuizAnswer && !isCorrect) LocalNeonMagenta else LocalNeonCyan)
                                                        } else if (hasSubmittedQuizAnswer && isCorrect) {
                                                            BorderStroke(1.dp, LocalNeonGreen)
                                                        } else {
                                                            BorderStroke(0.5.dp, Color.DarkGray)
                                                        }

                                                        Row(
                                                            modifier = Modifier
                                                                .fillMaxWidth()
                                                                .padding(vertical = 4.dp)
                                                                .background(optionBg, RoundedCornerShape(8.dp))
                                                                .border(optionBorder, RoundedCornerShape(8.dp))
                                                                .clickable { if (!hasSubmittedQuizAnswer) selectedQuizAnswerOptionIdx = oidx }
                                                                .padding(10.dp),
                                                            verticalAlignment = Alignment.CenterVertically
                                                        ) {
                                                            Text(
                                                                text = "${('A' + oidx)}.   $optText",
                                                                color = if (isSelected) Color.White else Color.LightGray,
                                                                fontSize = 11.sp,
                                                                fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal
                                                            )
                                                        }
                                                    }
                                                }
                                            }

                                            // Answer actions
                                            if (!hasSubmittedQuizAnswer) {
                                                Button(
                                                    onClick = {
                                                        if (selectedQuizAnswerOptionIdx != null) {
                                                            hasSubmittedQuizAnswer = true
                                                            if (selectedQuizAnswerOptionIdx == quizItem.correctIndex) {
                                                                totalCorrectQuizScore++
                                                                Toast.makeText(context, "Correct Answer! 🎉", Toast.LENGTH_SHORT).show()
                                                            } else {
                                                                Toast.makeText(context, "Incorrect. Let's study explanation.", Toast.LENGTH_SHORT).show()
                                                            }
                                                        }
                                                    },
                                                    colors = ButtonDefaults.buttonColors(containerColor = LocalNeonCyan),
                                                    modifier = Modifier.fillMaxWidth(),
                                                    enabled = selectedQuizAnswerOptionIdx != null
                                                ) {
                                                    Text("SUBMIT CHECK ANSWER", color = PureBlack, fontWeight = FontWeight.Bold, fontSize = 11.sp)
                                                }
                                            } else {
                                                // Display explanation
                                                Card(
                                                    colors = CardDefaults.cardColors(containerColor = LocalNeonPurple.copy(alpha = 0.05f)),
                                                    border = BorderStroke(0.5.dp, LocalNeonPurple),
                                                    modifier = Modifier.fillMaxWidth()
                                                ) {
                                                    Column(modifier = Modifier.padding(10.dp)) {
                                                        Text("EXPLANATION & PROOF", color = LocalNeonPurple, fontSize = 8.sp, fontWeight = FontWeight.Black)
                                                        Spacer(modifier = Modifier.height(3.dp))
                                                        Text(quizItem.explanation, color = Color.LightGray, fontSize = 10.sp, lineHeight = 14.sp)
                                                    }
                                                }

                                                Button(
                                                    onClick = {
                                                        if (safeQuizIdx < targetFilteredQuizList.size - 1) {
                                                            activeQuizQuestionIdx++
                                                            selectedQuizAnswerOptionIdx = null
                                                            hasSubmittedQuizAnswer = false
                                                        } else {
                                                            hasFinishedQuizSequence = true
                                                        }
                                                    },
                                                    colors = ButtonDefaults.buttonColors(containerColor = LocalNeonPurple),
                                                    modifier = Modifier.fillMaxWidth()
                                                ) {
                                                    Text(
                                                        text = if (safeQuizIdx < targetFilteredQuizList.size - 1) "NEXT QUESTION ➔" else "FINISH QUIZ SEQUENCE",
                                                        color = Color.White,
                                                        fontSize = 11.sp
                                                    )
                                                }
                                            }
                                        } else if (hasFinishedQuizSequence) {
                                            // Score banner UI
                                            Card(
                                                colors = CardDefaults.cardColors(containerColor = LocalCardBg),
