@Composable
fun AdMobBannerView(adUnitId: String, modifier: Modifier = Modifier) {
    Box(
        modifier = modifier
            .fillMaxWidth()
            .wrapContentHeight()
            .background(Color.Transparent),
        contentAlignment = Alignment.Center
    ) {
        AndroidView(
            modifier = Modifier.fillMaxWidth().wrapContentHeight(),
            factory = { context ->
                var activityContext = context
                while (activityContext is android.content.ContextWrapper && activityContext !is android.app.Activity) {
                    activityContext = activityContext.baseContext
                }
                
                val adView = AdView(activityContext ?: context).apply {
                    setAdSize(AdSize.BANNER)
                    this.adUnitId = adUnitId
                    layoutParams = android.widget.FrameLayout.LayoutParams(
                        android.widget.FrameLayout.LayoutParams.MATCH_PARENT,
                        android.widget.FrameLayout.LayoutParams.WRAP_CONTENT
                    )
                    adListener = object : com.google.android.gms.ads.AdListener() {
                        override fun onAdLoaded() {
                            android.util.Log.d("AdMobBanner", "Ad loaded successfully")
                        }
                        override fun onAdFailedToLoad(adError: com.google.android.gms.ads.LoadAdError) {
                            android.util.Log.e("AdMobBanner", "Ad failed to load: ${adError.message}")
                        }
                    }
                    loadAd(AdRequest.Builder().build())
                }
                adView
            },
            update = { adView ->
                if (adView.adUnitId != adUnitId) {
                    adView.adUnitId = adUnitId
                    adView.loadAd(AdRequest.Builder().build())
                }
            }
        )
    }
}

