@Composable
fun RewardedAdOverlay(
    viewModel: com.example.ui.CreatorViewModel,
    adUnitId: String
) {
    val showRewardedAdOverlay by viewModel.showRewardedAdOverlay.collectAsState()
    val context = LocalContext.current
    var isAdLoading by remember { mutableStateOf(false) }

    val activity = remember(context) {
        var activityContext = context
        while (activityContext is android.content.ContextWrapper && activityContext !is android.app.Activity) {
            activityContext = activityContext.baseContext
        }
        activityContext as? android.app.Activity
    }

    LaunchedEffect(showRewardedAdOverlay) {
        if (showRewardedAdOverlay && activity != null) {
            isAdLoading = true
            val adRequest = AdRequest.Builder().build()
            
            com.google.android.gms.ads.rewarded.RewardedAd.load(
                context, 
                adUnitId, 
                adRequest, 
                object : com.google.android.gms.ads.rewarded.RewardedAdLoadCallback() {
                    override fun onAdLoaded(ad: com.google.android.gms.ads.rewarded.RewardedAd) {
                        isAdLoading = false
                        ad.fullScreenContentCallback = object : com.google.android.gms.ads.FullScreenContentCallback() {
                            override fun onAdDismissedFullScreenContent() {
                                viewModel.dismissRewardedAd()
                            }
                            override fun onAdFailedToShowFullScreenContent(error: com.google.android.gms.ads.AdError) {
                                viewModel.completeRewardedAd()
                            }
                        }
                        
                        ad.show(activity) { _ ->
                            viewModel.completeRewardedAd()
                        }
                    }
                    override fun onAdFailedToLoad(error: com.google.android.gms.ads.LoadAdError) {
                        isAdLoading = false
                        viewModel.completeRewardedAd()
                    }
                }
            )
        }
    }

    if (showRewardedAdOverlay && isAdLoading) {
        androidx.compose.ui.window.Dialog(
            onDismissRequest = { viewModel.dismissRewardedAd() },
            properties = androidx.compose.ui.window.DialogProperties(
                dismissOnBackPress = false,
                dismissOnClickOutside = false
            )
        ) {
            Box(
                modifier = Modifier
                    .size(200.dp)
                    .background(Color(0xFF131024), RoundedCornerShape(16.dp)),
                contentAlignment = Alignment.Center
            ) {
                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    CircularProgressIndicator(color = NeonCyan)
                    Spacer(modifier = Modifier.height(16.dp))
                    Text("Loading Ad...", color = Color.White, fontWeight = FontWeight.Bold)
                }
            }
        }
    }
}

